function applyStaticI18n(){
  document.querySelectorAll("[data-i18n]").forEach(el=>{ const k=el.getAttribute("data-i18n"); if(UI[k]) el.textContent=t(UI[k]); });
  const pi=document.getElementById("promptInput"); if(pi) pi.placeholder=t(UI.say);
  const pt=document.getElementById("ptInput"); if(pt) pt.placeholder=t(UI.ptType);
  document.getElementById("langCode").textContent=(LANGS.find(l=>l.c===lang)||{}).n||"EN";
  document.querySelectorAll("[data-i18n-title]").forEach(el=>{ const k=el.getAttribute("data-i18n-title"); if(UI[k]) el.title=t(UI[k]); });
}

