function silhouette(){
  return "data:image/svg+xml;utf8," + encodeURIComponent(
    "<svg xmlns='http://www.w3.org/2000/svg' width='240' height='520'>"+
    "<defs><radialGradient id='g' cx='50%' cy='30%'><stop offset='0%' stop-color='#3a5591'/>"+
    "<stop offset='100%' stop-color='#22345f'/></radialGradient></defs>"+
    "<ellipse cx='120' cy='120' rx='60' ry='66' fill='url(#g)'/>"+
    "<path d='M120 180 C60 180 44 260 50 420 C52 500 188 500 190 420 C196 260 180 180 120 180 Z' fill='url(#g)'/></svg>");
}
function charImgEl(name){
  const img=new Image(); img.decoding="async";
  const local="assets/chars/"+name+".png", remote=ASSETS.chars[name]||null;
  img.dataset.stage="local";
  img.onerror=function(){ if(img.dataset.stage==="local"&&remote){img.dataset.stage="remote";img.src=remote;}
    else{img.dataset.stage="fail";img.onerror=null;
      img.src=(window.buildCharArt?window.buildCharArt(T&&T.id,name):silhouette()); } };
  img.src=local; return img;
}
