    sleeping_castle:{x:260,y:220,c:'#dfeaff',r:0.12}, thorn_wood:{x:500,y:180,c:'#b8c8b0',r:0.08}, forest_sb:{x:620,y:120,c:'#eaffc0',r:0.2},
    chamber:{x:500,y:150,c:'#ffd6e2',r:0.16}, garden_sb:{x:500,y:200,c:WARM,r:0.2},
    aul:{x:760,y:220,c:WARM,r:0.2}, aldar_home:{x:760,y:240,c:WARM,r:0.18}, bai_yurt:{x:500,y:220,c:WARM,r:0.2},
