function artKey(name){ const id=(T&&T.id)||'';
  if(id==='sleeping_beauty'){ if(name==='garden')return 'garden_sb'; if(name==='forest')return 'forest_sb'; }
  if(id==='aldar_kose'){ if(name==='river')return 'river_al'; }
  return name; }
function loadSceneBg(el,name,done){
  const sd=(SCENES&&SCENES[name])||{};
  const local="assets/scenes/"+name+".webp",remote=(ASSETS&&ASSETS.scenes&&ASSETS.scenes[name])||null;
  const g=sd.grad||SCENE_GRAD[name]||["#1a2748","#070c19"];
  el.style.backgroundImage="linear-gradient(180deg,"+g[0]+","+g[1]+")";
  // hand-drawn storybook illustration — offline, resolution-independent, negligible weight
  try{ const art=window.buildSceneArt&&window.buildSceneArt(artKey(name),g); if(art) el.style.backgroundImage='url("'+art+'")'; }catch(e){}
  function tryUrl(url,next){ if(!url){next();return;} const im=new Image();
    im.onload=function(){el.style.backgroundImage='url("'+url+'")';if(done)done(true);}; im.onerror=next; im.src=url; }
  tryUrl(local,function(){tryUrl(remote,function(){if(done)done(false);});});
}
function loadArt(name){ return {local:"assets/art/"+name+".webp",remote:ASSETS.art[name]||null}; }

