/* ================= STATE ================= */
const LAST_KEY="sqlib_last";
let S=null;
function saveKey(id){ return "sqlib_"+(id||(T?T.id:"none")); }
function freshState(pk,path){ return {player:pk, path:path||pk, ci:0, bi:0, seen:{}, met:{}, relics:[], log:[], found:{},
  lang:lang, voice:true, sound:true, started:Date.now()}; }
function save(){ try{ if(!S||!T) return; S.lang=lang; localStorage.setItem(saveKey(),JSON.stringify(S));
  localStorage.setItem(LAST_KEY,T.id); }catch(e){} }
function loadFor(id){ try{ const r=localStorage.getItem(saveKey(id)); return r?JSON.parse(r):null; }catch(e){ return null; } }
function load(){ return loadFor(); }

/* ================= DOM ================= */
const $=s=>document.querySelector(s);
const screens={}; ["library","select","world","ending"].forEach(id=>screens[id]=$("#"+id));
let current="library";
function show(id){ if(screens[current]) screens[current].classList.remove("on"); current=id; screens[id].classList.add("on"); }

/* ================= FX ================= */
const fx=$("#fx"), fxc=fx.getContext("2d");
let parts=[], fxType="snow", fxRAF=0, fxW=0, fxH=0, auroraT=0;
let windX=0, windTarget=0;
function sizeFx(){ fxW=fx.width=innerWidth; fxH=fx.height=innerHeight; }
addEventListener("resize", sizeFx);
/* a gust of wind: blows the weather sideways and makes the cast brace against it */
function windGust(strength){ windTarget=(strength||1)*(2.0+Math.random()*1.8)*(Math.random()<0.5?-1:1); gustActors(); }
function gustActors(){ if(typeof actors==="undefined"||current!=="world") return;
  Object.values(actors).forEach(a=>{ if(!a||!a.breathe||a.busyUntil>nowMs()) return;
    a.breathe.classList.add("gust"); setTimeout(()=>{ if(a.breathe) a.breathe.classList.remove("gust"); }, 1100); }); }
function newPart(){ return {x:Math.random()*fxW,y:Math.random()*fxH,r:1+Math.random()*2.6,s:0.3+Math.random()*1.2,
  drift:(Math.random()-0.5)*0.8,a:0.3+Math.random()*0.6,ph:Math.random()*6.28,d:Math.random()}; }
function seedFx(type){ fxType=type; parts=[];
  const n=type==="aurora"?24:(type==="ember"?46:type==="petal"?40:type==="gleam"?30:(type==="steam"||type==="drift")?36
    :(type==="dust")?54:(type==="pollen")?34:(type==="fireflies")?26:(type==="frost")?44:110);
  for(let i=0;i<n;i++) parts.push(newPart());
  if(!fxRAF) fxRAF=requestAnimationFrame(tickFx); }
function tickFx(){
  fxc.clearRect(0,0,fxW,fxH);
  windX+=(windTarget-windX)*0.04; windTarget*=0.985;      // wind eases in and decays
  if(fxType==="aurora") drawAurora();
  for(const p of parts){
    if(fxType==="ember"){ p.y-=p.s*0.7; p.x+=Math.sin(p.y*0.02+p.ph)*0.6+p.drift;
      fxc.globalAlpha=p.a*(0.5+0.5*Math.sin(Date.now()*0.005+p.ph)); fxc.fillStyle="rgba(255,180,90,1)";
      fxc.beginPath(); fxc.arc(p.x,p.y,p.r,0,6.28); fxc.fill(); if(p.y<-10){p.y=fxH+10;p.x=Math.random()*fxW;} }
    else if(fxType==="petal"){ p.y+=p.s*0.7; p.x+=Math.sin(p.y*0.02+p.ph)*1.1+p.drift;
      fxc.globalAlpha=p.a; fxc.fillStyle="rgba(255,190,210,.9)"; fxc.save(); fxc.translate(p.x,p.y); fxc.rotate(p.y*0.03+p.ph);
      fxc.beginPath(); fxc.ellipse(0,0,p.r*2.2,p.r,0,0,6.28); fxc.fill(); fxc.restore(); if(p.y>fxH+10){p.y=-10;p.x=Math.random()*fxW;} }
    else if(fxType==="gleam"){ p.ph+=0.03; fxc.globalAlpha=0.3+0.4*Math.abs(Math.sin(p.ph));
      fxc.fillStyle="rgba(255,235,190,1)"; fxc.beginPath(); fxc.arc(p.x,p.y,p.r*0.8,0,6.28); fxc.fill(); }
    else if(fxType==="steam"||fxType==="drift"){ p.y-=p.s*0.4; p.x+=Math.sin(p.y*0.015+p.ph)*0.5+p.drift;
      fxc.globalAlpha=p.a*0.4; fxc.fillStyle="rgba(220,235,255,1)"; fxc.beginPath(); fxc.arc(p.x,p.y,p.r*1.4,0,6.28); fxc.fill();
      if(p.y<-10){p.y=fxH+10;p.x=Math.random()*fxW;} }
    else if(fxType==="dust"){ p.x+=p.s*0.6+p.drift; p.y+=Math.sin(p.x*0.01+p.ph)*0.3;
      fxc.globalAlpha=p.a*0.5; fxc.fillStyle="rgba(214,180,120,1)"; fxc.beginPath(); fxc.arc(p.x,p.y,p.r*1.1,0,6.28); fxc.fill();
      if(p.x>fxW+10){p.x=-10;p.y=Math.random()*fxH;} }
    else if(fxType==="pollen"){ p.y-=p.s*0.5; p.x+=Math.sin(p.y*0.02+p.ph)*0.9+p.drift;
      fxc.globalAlpha=0.35+0.35*Math.abs(Math.sin(p.ph+p.y*0.02)); fxc.fillStyle="rgba(255,236,170,1)";
      fxc.beginPath(); fxc.arc(p.x,p.y,p.r*0.9,0,6.28); fxc.fill(); if(p.y<-10){p.y=fxH+10;p.x=Math.random()*fxW;} }
    else if(fxType==="fireflies"){ p.ph+=0.02; p.x+=Math.sin(p.ph)*0.5; p.y+=Math.cos(p.ph*0.7)*0.4;
      fxc.globalAlpha=0.2+0.8*Math.pow(Math.abs(Math.sin(p.ph*1.3)),3); fxc.fillStyle="rgba(255,224,120,1)";
      fxc.beginPath(); fxc.arc(p.x,p.y,p.r*0.9,0,6.28); fxc.fill(); }
    else if(fxType==="frost"){ p.ph+=0.05; p.y-=p.s*0.3; p.x+=Math.sin(p.ph)*0.4+windX*0.5;
      const tw=0.25+0.6*Math.abs(Math.sin(p.ph*1.5)); fxc.globalAlpha=tw; fxc.fillStyle="rgba(206,236,255,1)";
      const rr=p.r*(0.5+p.d*0.6); fxc.beginPath(); fxc.arc(p.x,p.y,rr,0,6.28); fxc.fill();
      fxc.globalAlpha=tw*0.5; fxc.fillRect(p.x-rr*2.2,p.y-0.4,rr*4.4,0.8); fxc.fillRect(p.x-0.4,p.y-rr*2.2,0.8,rr*4.4);
      if(p.y<-10){p.y=fxH+10;p.x=Math.random()*fxW;} }
    else { const dep=0.55+p.d; p.y+=p.s*dep; p.x+=Math.sin(p.y*0.01+p.ph)*0.7+p.drift+windX*dep;
      fxc.globalAlpha=p.a*(0.45+0.55*p.d); fxc.fillStyle="rgba(240,248,255,1)";
      fxc.beginPath(); fxc.arc(p.x,p.y,p.r*(0.55+p.d*0.7),0,6.28); fxc.fill();
      if(p.y>fxH+6){p.y=-6;p.x=Math.random()*fxW;} if(p.x>fxW+12)p.x=-12; else if(p.x<-12)p.x=fxW+12; }
  }
  fxc.globalAlpha=1; fxRAF=requestAnimationFrame(tickFx);
}
function drawAurora(){ auroraT+=0.006;
  for(let b=0;b<3;b++){ const grad=fxc.createLinearGradient(0,0,0,fxH*0.6);
    grad.addColorStop(0,"rgba(120,255,190,0)");
    grad.addColorStop(0.5,"rgba("+(b===1?"140,200,255":"120,255,180")+","+(0.10+0.05*Math.sin(auroraT+b))+")");
    grad.addColorStop(1,"rgba(120,255,190,0)"); fxc.fillStyle=grad; fxc.beginPath(); fxc.moveTo(0,fxH*0.5);
    for(let x=0;x<=fxW;x+=20){ const y=fxH*0.28+Math.sin(x*0.006+auroraT*2+b)*40+Math.sin(x*0.02+auroraT+b)*18; fxc.lineTo(x,y); }
    fxc.lineTo(fxW,0); fxc.lineTo(0,0); fxc.closePath(); fxc.fill(); } }

/* ===== MUSIC + AMBIENCE DATA (rendered offline: fluidsynth orchestral themes + sox soundscapes) ===== */
const SNOW_MUSIC = {"warm": "data:audio/mpeg;base64,", "cold": "data:audio/mpeg;base64,", "tender": "data:audio/mpeg;base64,", "tense": "data:audio/mpeg;base64,", "wonder": "data:audio/mpeg;base64,"};
const SNOW_AMB = {"wind": "data:audio/mpeg;base64,", "water": "data:audio/mpeg;base64,", "fire": "data:audio/mpeg;base64,", "forest": "data:audio/mpeg;base64,"};

/* ================= MUSIC + AMBIENCE BEDS (real rendered loops, offline) ================= */
const SCENE_BED={
  attic:["warm","forest"], village:["cold","wind"], mountains:["tense","wind"],
  river:["tender","water"], garden:["warm","forest"], palacehall:["wonder",null],
  camp:["tense","fire"], lapland:["cold","wind"], finland:["tender","fire"],
  palace:["cold","wind"], clockwork_chapel:["wonder",null], forest:["tender","forest"],
  wishing_well:["tender","water"], aurora_tent:["wonder",null],
  // Sleeping Beauty scenes
  great_hall:["wonder",null], throne_room:["wonder",null], tower:["tense","wind"],
  sleeping_castle:["cold","wind"], thorn_wood:["tender","forest"], chamber:["tender",null]
};
let musicEl=null, ambEl=null, curMood=null, curAmb=null;
let musicVol=0.30, ambVol=0.42, bedDuck=1, bedSwell=1, bedsOn=true;
function _fadeEl(el,to,ms,onDone){ if(!el) return; const from=(el.volume!=null?el.volume:0), t0=performance.now();
  if(el.__iv) clearInterval(el.__iv);
  el.__iv=setInterval(()=>{ const k=ms>0?Math.min(1,(performance.now()-t0)/ms):1;
    try{ el.volume=Math.max(0,Math.min(1, from+(to-from)*k)); }catch(e){ clearInterval(el.__iv); el.__iv=null; return; }
    if(k>=1){ clearInterval(el.__iv); el.__iv=null; if(to<=0){ try{el.pause();}catch(e){} } if(onDone) onDone(); } }, 40); }
function _startLoop(uri,vol){ try{ const a=new Audio(uri); a.loop=true; a.volume=0; a.preload="auto";
  const p=a.play(); if(p&&p.catch)p.catch(()=>{}); _fadeEl(a,vol,1400); return a; }catch(e){ return null; } }
function musicTarget(){ return bedsOn? Math.max(0,Math.min(1,musicVol*bedDuck*bedSwell)) : 0; }
function ambTarget(){ return bedsOn? Math.max(0,Math.min(1,ambVol*(bedDuck<1?0.7:1))) : 0; }
/* pick the mood + ambience for a scene and crossfade to it */
function setBeds(scene){
  if(!bedsOn) return;
  const bed=SCENE_BED[scene]||["tender",null]; const mood=bed[0], amb=bed[1];
  if(mood!==curMood){ const old=musicEl;
    if(old){ _fadeEl(old,0,900,()=>{ try{old.pause();}catch(e){} }); }
    musicEl=(mood&&typeof SNOW_MUSIC!=="undefined"&&SNOW_MUSIC[mood])? _startLoop(SNOW_MUSIC[mood],musicTarget()):null;
    curMood=mood; }
  if(amb!==curAmb){ const old=ambEl;
    if(old){ _fadeEl(old,0,900,()=>{ try{old.pause();}catch(e){} }); }
    ambEl=(amb&&typeof SNOW_AMB!=="undefined"&&SNOW_AMB[amb])? _startLoop(SNOW_AMB[amb],ambTarget()):null;
    curAmb=amb; }
}
/* music/ambience soften under any voice so dialogue always stays clear */
function duckBeds(on){ bedDuck=on?0.42:1;
  if(musicEl) _fadeEl(musicEl,musicTarget(),on?220:750);
  if(ambEl)   _fadeEl(ambEl,ambTarget(),on?260:750); }
/* momentary swell for transitions / emotional beats */
let swellTimer=null;
function swellBeds(x,ms,hold){ bedSwell=x; if(musicEl) _fadeEl(musicEl,musicTarget(),ms||500);
  if(swellTimer) clearTimeout(swellTimer);
  if(hold) swellTimer=setTimeout(()=>{ bedSwell=1; if(musicEl) _fadeEl(musicEl,musicTarget(),900); }, hold); }
function stopBeds(){ [musicEl,ambEl].forEach(a=>{ if(a){ _fadeEl(a,0,500,()=>{ try{a.pause();}catch(e){} }); } });
  musicEl=ambEl=null; curMood=curAmb=null; }
function bedsEnabled(on){ bedsOn=on;
  if(!on){ if(musicEl)_fadeEl(musicEl,0,400); if(ambEl)_fadeEl(ambEl,0,400); }
  else { if(musicEl){ const p=musicEl.play&&musicEl.play(); if(p&&p.catch)p.catch(()=>{}); _fadeEl(musicEl,musicTarget(),700); }
         if(ambEl){ const p=ambEl.play&&ambEl.play(); if(p&&p.catch)p.catch(()=>{}); _fadeEl(ambEl,ambTarget(),700); } } }

/* ================= AUDIO ================= */
let AC=null, master=null, ambientNodes=[], musicTimer=null, reverb=null, wetGain=null;
function makeImpulse(dur,decay){ const n=Math.floor(AC.sampleRate*dur), buf=AC.createBuffer(2,n,AC.sampleRate);
  for(let c=0;c<2;c++){ const d=buf.getChannelData(c); for(let i=0;i<n;i++) d[i]=(Math.random()*2-1)*Math.pow(1-i/n,decay); } return buf; }
function initAudio(){ if(AC) return; try{ AC=new (window.AudioContext||window.webkitAudioContext)();
  master=AC.createGain(); master.gain.value=0; master.connect(AC.destination);
  try{ reverb=AC.createConvolver(); reverb.buffer=makeImpulse(2.8,2.2); wetGain=AC.createGain(); wetGain.gain.value=0;
    master.connect(reverb); reverb.connect(wetGain); wetGain.connect(AC.destination); }catch(e){ reverb=null; }
  }catch(e){ AC=null; } }
/* spatial depth: cavernous scenes get more reverb tail */
const REVERB_BY_SCENE={ palace:0.42, palacehall:0.34, clockwork_chapel:0.4, finland:0.3, mountains:0.28, lapland:0.22, forest:0.16 };
function setReverb(scene){ if(!wetGain||!AC) return; const amt=REVERB_BY_SCENE[scene]!=null?REVERB_BY_SCENE[scene]:0.1;
  wetGain.gain.setTargetAtTime(amt, AC.currentTime, 0.6); }
/* master carries music + ambient + SFX (never the voice). We DUCK it under any
   voice so narration/dialogue always stays clear — like a produced audiobook. */
let baseGain=0, ducking=false; const DUCK_LEVEL=0.30;
function rampMasterTo(v,tm){ if(!master||!AC) return; const now=AC.currentTime;
  master.gain.cancelScheduledValues(now); master.gain.setValueAtTime(master.gain.value,now); master.gain.linearRampToValueAtTime(v,now+(tm||0.3)); }
function fadeMaster(to,tm){ baseGain=to; rampMasterTo(baseGain*(ducking?DUCK_LEVEL:1), tm||1.2); }
function duckAudio(on){ if(ducking===on) return; ducking=on; rampMasterTo(baseGain*(on?DUCK_LEVEL:1), on?0.14:0.5); duckBeds(on); }
const SNOW_SCENE_MOOD={ camp:{root:174.6,scale:[0,3,5,7,10],pad:"warm"}, garden:{root:196,scale:[0,2,4,7,9],pad:"bright"},
  attic:{root:207.6,scale:[0,2,4,7,9],pad:"bright"}, palacehall:{root:220,scale:[0,4,7,11,14],pad:"bright"},
  palace:{root:130.8,scale:[0,2,3,7,8],pad:"cold"}, clockwork_chapel:{root:146.8,scale:[0,1,5,7,8],pad:"cold"},
  finland:{root:174.6,scale:[0,3,5,7,10],pad:"warm"} };
function moodFor(s){ return SCENE_MOOD[s]||{root:155.6,scale:[0,3,5,7,10],pad:"cold"}; }
function startAmbient(scene){
  stopAmbient();
  setBeds(scene);                       // real orchestral music + ambience beds (rendered offline)
  if(!AC) return;
  setReverb(scene);                     // spatial reverb tail for the SFX bus
  startFlavor(scene);                   // living one-shot SFX accents (bells, birds, crackles…)
}
function stopAmbient(){ if(musicTimer){clearTimeout(musicTimer);musicTimer=null;} stopFlavor();
  ambientNodes.forEach(n=>{ try{if(n.stop)n.stop();}catch(e){} try{n.disconnect();}catch(e){} }); ambientNodes=[]; }
function sfx(kind){ if(!AC||!S||!S.sound) return; const tm=AC.currentTime;
  if(kind==="step"){ const o=AC.createOscillator(),g=AC.createGain(); o.type="sine"; o.frequency.value=90+Math.random()*30;
    o.connect(g); g.connect(master); g.gain.setValueAtTime(0.05,tm); g.gain.exponentialRampToValueAtTime(0.0001,tm+0.12); o.start(tm); o.stop(tm+0.14); }
  else if(kind==="chime"){ [0,4,7,12].forEach((s,i)=>{ const o=AC.createOscillator(),g=AC.createGain(); o.type="sine";
    o.frequency.value=523.25*Math.pow(2,s/12); o.connect(g); g.connect(master); const tt=tm+i*0.06;
    g.gain.setValueAtTime(0,tt); g.gain.linearRampToValueAtTime(0.08,tt+0.02); g.gain.exponentialRampToValueAtTime(0.0001,tt+0.9); o.start(tt); o.stop(tt+1); }); }
  else if(kind==="sparkle"){ [12,16,19,24,26].forEach((s,i)=>{ const o=AC.createOscillator(),g=AC.createGain(); o.type="sine";
    o.frequency.value=523.25*Math.pow(2,s/12); o.connect(g); g.connect(master); const tt=tm+i*0.045;
    g.gain.setValueAtTime(0,tt); g.gain.linearRampToValueAtTime(0.05,tt+0.01); g.gain.exponentialRampToValueAtTime(0.0001,tt+0.6); o.start(tt); o.stop(tt+0.65); }); }
  else if(kind==="talk"){ const o=AC.createOscillator(),g=AC.createGain(); o.type="triangle"; o.frequency.value=320;
    o.connect(g); g.connect(master); g.gain.setValueAtTime(0.03,tm); g.gain.exponentialRampToValueAtTime(0.0001,tm+0.16); o.start(tm); o.stop(tm+0.18); }
  else if(kind==="wind"){ const buf=AC.createBuffer(1,AC.sampleRate*1.6,AC.sampleRate),d=buf.getChannelData(0);
    for(let i=0;i<d.length;i++) d[i]=(Math.random()*2-1); const n=AC.createBufferSource(); n.buffer=buf;
    const bp=AC.createBiquadFilter(); bp.type="bandpass"; bp.frequency.value=600; bp.Q.value=0.5;
    const g=AC.createGain(); g.gain.setValueAtTime(0,tm); g.gain.linearRampToValueAtTime(0.12,tm+0.5); g.gain.exponentialRampToValueAtTime(0.0001,tm+1.5);
    n.connect(bp); bp.connect(g); g.connect(master); n.start(tm); n.stop(tm+1.6); }
  else if(kind==="bell"){ [0,7].forEach((s,i)=>{ const o=AC.createOscillator(),g=AC.createGain(); o.type="sine";
    o.frequency.value=660*Math.pow(2,s/12); o.connect(g); g.connect(master); const tt=tm+i*0.14;
    g.gain.setValueAtTime(0,tt); g.gain.linearRampToValueAtTime(0.05,tt+0.01); g.gain.exponentialRampToValueAtTime(0.0001,tt+1.4); o.start(tt); o.stop(tt+1.5); }); }
  else if(kind==="chirp"){ const o=AC.createOscillator(),g=AC.createGain(); o.type="sine";
    o.frequency.setValueAtTime(1800,tm); o.frequency.exponentialRampToValueAtTime(2600,tm+0.08); o.frequency.exponentialRampToValueAtTime(1600,tm+0.16);
    o.connect(g); g.connect(master); g.gain.setValueAtTime(0.03,tm); g.gain.exponentialRampToValueAtTime(0.0001,tm+0.2); o.start(tm); o.stop(tm+0.22); }
  else if(kind==="crack"){ const buf=AC.createBuffer(1,AC.sampleRate*0.3,AC.sampleRate),d=buf.getChannelData(0);
    for(let i=0;i<d.length;i++) d[i]=(Math.random()*2-1)*Math.pow(1-i/d.length,3); const n=AC.createBufferSource(); n.buffer=buf;
    const hp=AC.createBiquadFilter(); hp.type="highpass"; hp.frequency.value=1200; const g=AC.createGain(); g.gain.value=0.09;
    n.connect(hp); hp.connect(g); g.connect(master); n.start(tm); n.stop(tm+0.3); }
  else if(kind==="fire"){ const o=AC.createOscillator(),g=AC.createGain(); o.type="sawtooth"; o.frequency.value=70+Math.random()*40;
    const lp=AC.createBiquadFilter(); lp.type="lowpass"; lp.frequency.value=300; o.connect(lp); lp.connect(g); g.connect(master);
    g.gain.setValueAtTime(0.04,tm); g.gain.exponentialRampToValueAtTime(0.0001,tm+0.14); o.start(tm); o.stop(tm+0.16); }
  else if(kind==="sheep"){ const o=AC.createOscillator(),g=AC.createGain(); o.type="sawtooth";
    o.frequency.setValueAtTime(280,tm); o.frequency.setValueAtTime(250,tm+0.08); o.frequency.setValueAtTime(300,tm+0.16);
    const lp=AC.createBiquadFilter(); lp.type="lowpass"; lp.frequency.value=900; o.connect(lp); lp.connect(g); g.connect(master);
    g.gain.setValueAtTime(0.035,tm); g.gain.setValueAtTime(0.01,tm+0.12); g.gain.exponentialRampToValueAtTime(0.0001,tm+0.4); o.start(tm); o.stop(tm+0.42); }
  else if(kind==="dombra"){ [0,7,12,9].forEach((s,i)=>{ const o=AC.createOscillator(),g=AC.createGain(); o.type="triangle";
    o.frequency.value=196*Math.pow(2,s/12); o.connect(g); g.connect(master); const tt=tm+i*0.11;
    g.gain.setValueAtTime(0,tt); g.gain.linearRampToValueAtTime(0.05,tt+0.01); g.gain.exponentialRampToValueAtTime(0.0001,tt+0.5); o.start(tt); o.stop(tt+0.55); }); } }
/* per-scene living soundscape */
let flavorTimer=null;
const SNOW_SCENE_FLAVOR={ village:["bell","chirp"], attic:["chirp"], forest:["chirp"], camp:["fire"],
  palace:["crack","wind"], clockwork_chapel:["crack"], mountains:["wind"], lapland:["wind","crack"], palacehall:["bell"] };
function startFlavor(scene){ stopFlavor(); const kinds=SCENE_FLAVOR[scene]; if(!kinds) return;
  const tick=()=>{ if(current==="world"&&S&&S.sound) sfx(kinds[Math.floor(Math.random()*kinds.length)]);
    flavorTimer=setTimeout(tick, 2600+Math.random()*4200); };
  flavorTimer=setTimeout(tick, 1800+Math.random()*2000); }
function stopFlavor(){ if(flavorTimer) clearTimeout(flavorTimer); flavorTimer=null; }

