/* emotion shading: p pitch mult, r rate mult, v volume */
const EM = {
  warm:{p:1.05,r:1.02,v:1}, gentle:{p:0.99,r:0.9,v:.95}, kind:{p:1.0,r:0.95,v:1}, calm:{p:0.96,r:0.9,v:.95},
  bold:{p:1.06,r:1.08,v:1.05}, fierce:{p:1.02,r:1.14,v:1.1}, urgent:{p:1.06,r:1.2,v:1.05}, gossip:{p:1.08,r:1.14,v:1},
  hope:{p:1.1,r:1.05,v:1}, grateful:{p:1.05,r:0.97,v:1}, waking:{p:1.1,r:1.0,v:1}, hurt:{p:1.07,r:1.0,v:1},
  worried:{p:1.06,r:1.06,v:.95}, pleading:{p:1.09,r:1.0,v:1}, sad:{p:0.93,r:0.9,v:.9},
  tears:{p:1.13,r:0.86,v:1}, resolve:{p:1.0,r:1.0,v:1}, wise:{p:0.94,r:0.9,v:.95},
  cold:{p:0.9,r:0.9,v:.9}, cool:{p:0.9,r:0.92,v:.95}, empty:{p:0.82,r:0.8,v:.85}, dazed:{p:0.86,r:0.82,v:.85},
  alluring:{p:0.92,r:0.86,v:.95}, soft:{p:0.96,r:0.88,v:.8}, narr:{p:1.0,r:1.0,v:1}
};

let VOICES=[], voiceAssign={};
function classifyVoice(v){ const n=(v.name||"").toLowerCase();
  if(/female|woman|samantha|victoria|karen|tessa|fiona|moira|serena|zira|milena|katya|alena|yelena|amelie|joana|paulina|female/.test(n)) return "f";
  if(/\bmale\b|man|daniel|alex|fred|david|george|rishi|yuri|pavel|maxim|thomas|male/.test(n)) return "m";
  return "u"; }
/* rank the device's voices so the most natural-sounding ones are cast first */
function voiceQuality(v){ const n=(v.name||"").toLowerCase(); let s=0;
  if(/natural|neural|premium|enhanced/.test(n)) s+=6;
  if(/google/.test(n)) s+=5; if(/microsoft/.test(n)) s+=3;
  if(v.localService===false) s+=2; if(/compact|espeak|robot/.test(n)) s-=6; return s; }
function refreshVoices(){ try{ VOICES=window.speechSynthesis?speechSynthesis.getVoices()||[]:[]; }catch(e){ VOICES=[]; } assignVoices(); }
/* Give every character a STABLE, DISTINCT device voice. We hand out unique
   voices greedily (gender-matched first) so the narrator and the main cast each
   sound like a different person; only once the device runs out of voices do we
   reuse, and even then pitch/rate/emotion keep them apart. Characters are cast
   in VOICE_PROFILE declaration order (narrator + leads first) so the best,
   most-distinct voices go to the roles that carry the story. */
function assignVoices(){
  voiceAssign={}; if(!VOICES.length || !VOICE_PROFILE) return;
  const want=langTag().slice(0,2);
  let pool=VOICES.filter(v=>v.lang&&v.lang.toLowerCase().indexOf(want)===0);
  if(!pool.length) pool=VOICES.filter(v=>/en/i.test(v.lang));
  if(!pool.length) pool=VOICES.slice();
  pool=pool.slice().sort((a,b)=>voiceQuality(b)-voiceQuality(a));   // prefer the most natural voices the device offers
  const female=[],male=[],other=[];
  pool.forEach(v=>{ const c=classifyVoice(v); if(c==="f")female.push(v); else if(c==="m")male.push(v); else other.push(v); });
  const used=new Set(), reuse={};
  const takeUnique=arr=>{ for(const v of arr){ if(!used.has(v)){ used.add(v); return v; } } return null; };
  const pick=g=>{
    let v = g==="f" ? (takeUnique(female)||takeUnique(other)||takeUnique(male))
          : g==="m" ? (takeUnique(male)||takeUnique(other)||takeUnique(female))
          :           (takeUnique(other)||takeUnique(male)||takeUnique(female));
    if(v) return v;                                   // still a fresh, unused voice
    const gp = g==="f"?(female.length?female:pool) : g==="m"?(male.length?male:pool) : (other.length?other:pool);
    reuse[g]=(reuse[g]||0); const src=gp.length?gp:pool;   // pool exhausted → deterministic round-robin reuse
    return src.length? src[(reuse[g]++)%src.length] : (pool[0]||null);
  };
  Object.keys(VOICE_PROFILE).forEach(k=>{ voiceAssign[k]=pick(VOICE_PROFILE[k].g); });
}
let ttsBusy=false;
/* ---- audiobook clip playback (pre-recorded per-character narration) ---- */
let abAudio=null; const abCache={};
/* warm a clip so playback starts instantly (seamless line-to-line transitions) */
function warmClip(url){ if(!url||abCache[url]) return; try{ const a=new Audio(); a.preload="auto"; a.src=url; abCache[url]=a; }catch(e){} }
/* preload the clips for the current and next beat, so there is no fetch gap */
function preloadBeatAudio(ci,bi){
  if(!NARRATION||!S) return; let chs; try{ chs=curStory().chapters; }catch(e){ return; } if(!chs) return;
  [[ci,bi],[ci,bi+1]].forEach(([c,b])=>{ const ch=chs[c]; if(!ch) return; const beat=ch.beats[b]; if(!beat) return;
    const pp=storyPath();
    const nk=pp+":"+c+":"+b+":narr"; if(NARRATION[nk]) warmClip(NARRATION[nk]);
    if(beat.dialog) beat.dialog.forEach((d,li)=>{ const dk=pp+":"+c+":"+b+":d"+li; if(NARRATION[dk]) warmClip(NARRATION[dk]); }); });
}
/* short volume fade so clips never click on start or cut abruptly when interrupted */
function fadeAudio(a,from,to,ms,guard){ if(!a) return; try{ a.volume=Math.max(0,Math.min(1,from)); }catch(e){ return; }
  const t0=performance.now(); const iv=setInterval(()=>{ if(guard&&!guard()){ clearInterval(iv); return; }
    const k=Math.min(1,(performance.now()-t0)/ms);
    try{ a.volume=Math.max(0,Math.min(1, from+(to-from)*k)); }catch(e){ clearInterval(iv); return; }
    if(k>=1){ clearInterval(iv); if(to<=0){ try{a.pause();}catch(e){} } } }, 16); }
function stopClip(){ if(abAudio){ const a=abAudio; abAudio=null; try{ a.onended=null; a.onerror=null; }catch(e){}
    fadeAudio(a,a.volume,0,140); duckAudio(false); } }
function playClip(url, fbText, fbWho, fbEm){
  try{ if(window.speechSynthesis) speechSynthesis.cancel(); }catch(e){}
  stopClip();
  // if the recorded clip can't load/decode/play, SPEAK the line instead of going silent
  const fallback=()=>{ ttsBusy=false; abAudio=null; duckAudio(false);
    if(fbText!=null && fbWho!=null && window.speechSynthesis) speakTTS(fbText, fbWho, fbEm); else { endTalking(); signalSpoken(); } };
  try{
    abAudio = abCache[url] || new Audio(url);
    try{ abAudio.currentTime=0; }catch(e){}
    ttsBusy=true; duckAudio(true);
    const cur=abAudio;
    abAudio.onended=()=>{ if(cur!==abAudio) return; ttsBusy=false; abAudio=null; duckAudio(false); endTalking(); signalSpoken(); };
    abAudio.onerror=()=>{ if(cur!==abAudio) return; fallback(); };
    const p=abAudio.play(); if(p&&p.catch) p.catch(()=>{ if(cur===abAudio) fallback(); });
    fadeAudio(cur,0.05,1,90,()=>cur===abAudio);     // gentle fade-in, aborts if the clip is replaced
  }catch(e){ fallback(); }
}
/* deterministic index so a character always maps to the same fallback voice */
function voiceIndexFor(who){ let h=0; for(let i=0;i<who.length;i++) h=(h*31+who.charCodeAt(i))>>>0; return h; }
function speak(text, who, em, key){
  // Any path that will NOT actually start audio must release the talking-mouth now.
  if(!S||!S.voice){ endTalking(); return; }
  // The hero (e.g. Gerda) is now voiced too, in their own character voice, so the
  // tale plays as a film. The mic lets the user optionally perform instead.
  const en = (lang==="en");
  const narrClip  = (key && NARRATION && NARRATION[key] && en) ? NARRATION[key] : null;
  const bakedClip = (key && en && BAKED && BAKED[key]) ? BAKED[key] : null;
  // The NARRATOR keeps the recorded audiobook voice. EVERY OTHER character has a
  // baked, distinct recorded voice (generated per character) so each one sounds
  // unique on every device — never "just the narrator". RU/KK, or a clip that
  // fails, fall back to the per-character synthesized voice, then to silence.
  if(who==="narrator"){
    // self-contained mastered storyteller first (identical on every device),
    // then any legacy recorded clip as a backup.
    const nb=(key && en && BAKED_NARR && BAKED_NARR[key]) ? BAKED_NARR[key] : null;
    if(nb){ playClip(nb, text, who, em); return; }
    if(narrClip){ playClip(narrClip, text, who, em); return; }
  } else if(bakedClip){
    playClip(bakedClip, text, who, em); return;      // this character's own recorded voice
  } else if(narrClip && T && T.urlVoices){
    playClip(narrClip, text, who, em); return;       // hosted per-character clip (opt-in tales, e.g. Ayaz Bi)
  }
  if(window.speechSynthesis){ speakTTS(text, who, em); return; }
  if(narrClip){ playClip(narrClip, text, who, em); return; }
  endTalking();
}
function speakTTS(text, who, em){
  if(!window.speechSynthesis){ endTalking(); return; }
  try{
    stopClip();
    try{ speechSynthesis.cancel(); }catch(e){}
    try{ speechSynthesis.resume(); }catch(e){}                 // Chrome / WebView can leave the queue paused
    if(!VOICES.length){ try{ VOICES=speechSynthesis.getVoices()||[]; if(VOICES.length) assignVoices(); }catch(e){} }
    const prof=VOICE_PROFILE[who]||{p:1,r:1,g:"u"};
    const e=EM[em]||EM.resolve;
    const clean=text.replace(/\*/g,"").trim(); if(!clean){ endTalking(); return; }
    const u=new SpeechSynthesisUtterance(clean);
    u.lang=langTag();
    // this character's assigned voice; if none was assigned yet, fan characters
    // deterministically across whatever voices exist so they still sound distinct
    let v=voiceAssign[who];
    if(!v && VOICES.length){ const want=langTag().slice(0,2);
      const pref=VOICES.filter(x=>x.lang&&x.lang.toLowerCase().indexOf(want)===0);
      const src=pref.length?pref:VOICES; v=src[voiceIndexFor(who)%src.length]; }
    if(v) u.voice=v;
    const jit=0.98+Math.random()*0.04;          // slight natural jitter
    const pace=who==="narrator"?0.93:0.98;      // audiobook pacing — a touch slower and calmer
    u.pitch=Math.max(0.1,Math.min(2, prof.p*e.p*jit));
    u.rate =Math.max(0.5,Math.min(1.6, prof.r*e.r*pace*jit));
    u.volume=Math.max(0.15,Math.min(1, e.v!=null?e.v:1));
    u.onstart=()=>{ ttsBusy=true; duckAudio(true); };
    u.onend=()=>{ ttsBusy=false; duckAudio(false); endTalking(); signalSpoken(); };
    u.onerror=()=>{ ttsBusy=false; duckAudio(false); endTalking(); signalSpoken(); };
    ttsBusy=true; speechSynthesis.speak(u);
    setTimeout(()=>{ try{ if(window.speechSynthesis && speechSynthesis.paused) speechSynthesis.resume(); }catch(e){} }, 90);
  }catch(e){ ttsBusy=false; endTalking(); signalSpoken(); }
}
/* generic recognizer factory (used by free-chat mic AND the player-turn mic) */
function makeRecog(onFinal,onState){
  const SR=window.SpeechRecognition||window.webkitSpeechRecognition; if(!SR) return null;
  const r=new SR(); r.lang=langTag(); r.interimResults=true; r.continuous=false;
  r.onstart=()=>onState&&onState(true); r.onend=()=>onState&&onState(false);
  r.onresult=(e)=>{ let s=""; for(const res of e.results) s+=res[0].transcript;
    onState&&onState(true,s); if(e.results[e.results.length-1].isFinal) onFinal&&onFinal(s.trim()); };
  return r;
}
let recog=null, listening=false;
function toggleMic(){
  if(!(window.SpeechRecognition||window.webkitSpeechRecognition)){
    toast(t(UI.narrator), t(L("Voice input isn't available here.","Голосовой ввод недоступен.","Дауыспен енгізу қолжетімсіз."))); return; }
  if(listening){ if(recog) recog.stop(); return; }
  recog=makeRecog((final)=>submitPrompt(final), (on,partial)=>{ listening=on; $("#btnMic").classList.toggle("live",on);
    if(partial!=null) $("#promptInput").value=partial; });
  try{ recog&&recog.start(); }catch(e){}
}

/* ================= ACTORS ================= */
const stageOuter=$("#stage"), stage=$("#cam"), bg=$("#bg"), camEl=$("#cam"), envEl=$("#env");
let actors={}, playerActor=null, playerX=50;
function nowMs(){ return Date.now(); }
function clearActors(){ Object.values(actors).forEach(a=>a.el.remove()); actors={}; playerActor=null; }
function slotFor(i,total){ if(total<=1) return 66; const arr=total===2?[32,72]:total===3?[22,50,78]:null;
  if(arr) return arr[i]; return 16+68*i/(total-1); }
/* principals = the player + the named cast (never the background extras) */
function principalKeys(){ return Object.keys(actors).filter(k=> !(actors[k]&&actors[k].extra)); }
const MIN_GAP=15;                 // minimum spacing (%) between two actors' centres
/* Pick an on-stage slot near `preferred` that does not collide with anyone
   already standing — the PLAYER included. This is what stops NPCs spawning on
   top of the player (who sits at x=50) or on top of each other. */
function freeSlot(preferred, exceptKey){
  const taken=principalKeys().filter(k=>k!==exceptKey).map(k=>actors[k].x);
  const clamp=x=>Math.max(12,Math.min(88,x));
  const clear=x=>taken.every(o=>Math.abs(o-x)>=MIN_GAP);
  if(preferred!=null && clear(clamp(preferred))) return clamp(preferred);
  const order=[66,34,78,22,84,16,60,40,72,28,50];
  for(const c of order){ if(clear(c)) return c; }
  const avg=taken.length? taken.reduce((a,b)=>a+b,0)/taken.length : 50;   // last resort: emptiest side
  return clamp(avg<50?86:14);
}
/* Take an AUTHORED position as a preference but guarantee no two characters
   overlap: if the preferred spot is within MIN_GAP of someone, nudge outward to
   the nearest clear spot. Used for every spawn/move so the cast never stacks. */
function resolveSlot(preferred, exceptKey){
  const clamp=x=>Math.max(12,Math.min(88,x));
  if(preferred==null) return freeSlot(null,exceptKey);
  const x=clamp(preferred);
  const taken=principalKeys().filter(k=>k!==exceptKey && actors[k]).map(k=>actors[k].x);
  const clear=c=>taken.every(o=>Math.abs(o-c)>=MIN_GAP);
  if(clear(x)) return x;
  for(let d=2; d<=84; d+=2){ for(const cand of [x+d, x-d]){ const c=clamp(cand); if(clear(c)) return c; } }
  return x;   // stage genuinely full — fall back to the ask
}
/* Safety net for crowded scenes: if any two characters would still overlap
   (more actors than MIN_GAP slots), redistribute the whole cast evenly across
   the stage, preserving their left-to-right order so no one is ever stacked. */
let _spreadT=null;
function scheduleSpread(){ if(_spreadT) clearTimeout(_spreadT); _spreadT=setTimeout(spreadActors, 80); }
function spreadActors(){
  const recs=principalKeys().map(k=>actors[k]).filter(r=>r&&r.el).sort((a,b)=>a.x-b.x);
  if(recs.length<2) return;
  let overlap=false; for(let i=1;i<recs.length;i++){ if(recs[i].x-recs[i-1].x < 12){ overlap=true; break; } }
  if(!overlap) return;                                  // only intervene when actually crowded
  const LO=14, HI=86, gap=Math.min(MIN_GAP, (HI-LO)/(recs.length-1));
  const orig=recs.map(r=>r.x);
  // minimal-displacement de-overlap: push crowded neighbours apart, keep everyone
  // as near their authored mark as possible (no cross-stage relocation).
  for(let i=1;i<recs.length;i++){ if(recs[i].x < recs[i-1].x+gap) recs[i].x=recs[i-1].x+gap; }
  if(recs[recs.length-1].x>HI){                          // overflowed right → settle from the right edge
    recs[recs.length-1].x=HI;
    for(let i=recs.length-2;i>=0;i--){ if(recs[i].x > recs[i+1].x-gap) recs[i].x=recs[i+1].x-gap; }
    if(recs[0].x<LO){ recs[0].x=LO; for(let i=1;i<recs.length;i++){ if(recs[i].x<recs[i-1].x+gap) recs[i].x=recs[i-1].x+gap; } }
  }
  recs.forEach((r,i)=>{ const nx=Math.max(LO,Math.min(HI,+r.x.toFixed(2)));
    if(Math.abs(nx-orig[i])>0.1){ r.x=nx; if(r.el) r.el.style.left=nx+"%"; } });
}
function addActor(key,xPct,isPlayer,entering){
  const el=document.createElement("div"); el.className="actor"+(isPlayer?" player":""); el.dataset.key=key; el.style.left=xPct+"%";
  // desync each character's breathing/weight-shift so the cast never moves in lock-step
  const slow=(PERSONA[key]&&PERSONA[key].slow);
  el.style.setProperty("--bd",(slow?5.6:3.9)+Math.random()*(slow?2.2:1.8)+"s");
  el.style.setProperty("--bdelay",(-Math.random()*4).toFixed(2)+"s");
  const shadow=document.createElement("div"); shadow.className="shadow"; el.appendChild(shadow);
  const body=document.createElement("div"); body.className="body";
  const breathe=document.createElement("div"); breathe.className="breathe"; breathe.appendChild(charImgEl(key));
  body.appendChild(breathe); el.appendChild(body);
  const halo=document.createElement("div"); halo.className="halo"; el.appendChild(halo);
  const tag=document.createElement("div"); tag.className="tag"; tag.textContent=nameOf(key); el.appendChild(tag);
  if(isPlayer) playerActor=el;
  el.addEventListener("click",(e)=>{ e.stopPropagation(); if(isPlayer) return;
    if(!S.met[key]){S.met[key]=1; award("met",nameOf(key)); save();}
    npcAside(key); });
  stage.appendChild(el);
  const rec={el,body,breathe,x:xPct,key,busyUntil:0,activity:(PERSONA[key]&&PERSONA[key].activity)||null,facing:1};
  actors[isPlayer?"__player":key]=rec;
  if(rec.activity) body.classList.add(rec.activity);
  if(entering){ el.classList.add("enter"); setTimeout(()=>el.classList.remove("enter"),1000); }
  return el;
}
function ensureActor(key, targetX){
  if(key==="narrator") return null;
  if(key===S.player) return playerActor;
  if(actors[key]){ if(targetX!=null) moveActor(actors[key], resolveSlot(targetX,key)); return actors[key].el; }  // already here → never a duplicate
  const finalX = resolveSlot(targetX, key);   // authored slot, nudged clear of anyone already on stage
  const crowded = principalKeys().filter(k=>actors[k]).length >= 2;   // is the stage already populated?
  if(crowded){
    // populated stage: materialise IN PLACE at the slot (soft fade/rise), so a new
    // character never walks across the stage through the others already standing there.
    const el=addActor(key, finalX, false, true);
    return el;
  }
  // near-empty stage: keep the cinematic walk-in from the nearest edge
  const fromLeft=finalX<50; const startX=fromLeft?-8:108;
  const el=addActor(key,startX,false,true);
  const rec=actors[key];
  rec.x=finalX; rec.facing=fromLeft?1:-1;   // register the FINAL slot NOW so co-spawning actors don't pick it too
  requestAnimationFrame(()=>{ el.classList.add("walking"); el.classList.toggle("face-left",!fromLeft);
    el.style.left=finalX+"%";
    setTimeout(()=>el.classList.remove("walking"),1300); });
  return el;
}
/* a named character walks off the nearest edge and is fully removed from the
   cast (so within a scene the stage never just accumulates bodies) */
function removeActor(key){ const rec=actors[key]; if(!rec||rec.key===S.player) return;
  const el=rec.el, off=(rec.x<50)?-20:120;
  faceToward(rec, off); el.classList.add("walking"); el.style.opacity="0"; el.style.left=off+"%";
  delete actors[key];                                   // drop from cast immediately so relayout ignores it
  setTimeout(()=>{ try{ el.remove(); }catch(e){} }, 1200); }
function setSpeaking(key){ Object.values(actors).forEach(a=>a.el.classList.remove("speaking"));
  const a=(key===S.player)?actors["__player"]:actors[key]; if(a) a.el.classList.add("speaking"); }

/* ================= PERSONALITY & AUTONOMOUS BEHAVIOR ================= */
const SNOW_PERSONA = {
  gerda:{acts:["look","sway","wave","hop"],move:0.35},
  kay:{acts:["look","sway","shiver","back"],move:0.2},
  queen:{acts:["sway","look","sky"],move:0.12,slow:true},
  robber:{acts:["hop","cheer","wave","point"],move:0.6},
  robber_mother:{acts:["point","nod","shake"],move:0.3,activity:"act-cook"},
  grandmother:{acts:["nod","sway","look"],move:0.12,activity:"act-sweep"},
  raven:{acts:["hop","look","wave","point"],move:0.55},
  crow:{acts:["hop","nod","look"],move:0.45},
  reindeer:{acts:["nod","shiver","shake"],move:0.3},
  prince:{acts:["nod","sway","bow"],move:0.2},
  princess:{acts:["wave","sway","nod"],move:0.22},
  flower_witch:{acts:["sway","look","sky"],move:0.18,activity:"act-work"},
  lapland_woman:{acts:["nod","look","work"],move:0.18},
  finland_woman:{acts:["nod","sway","read"],move:0.12,activity:"act-read"}
};
const SNOW_COLD_SCENES={palace:1,mountains:1,lapland:1,clockwork_chapel:1,finland:0};
function playBehavior(rec,cls,dur){
  if(!rec||!rec.body) return;
  rec.body.className="body "+cls;
  rec.busyUntil=nowMs()+dur;
  setTimeout(()=>{ if(rec.body) rec.body.className="body "+(rec.activity||""); }, dur);
}
function faceToward(rec,targetX){ if(!rec) return; const left=targetX<rec.x;
  rec.el.classList.toggle("face-left",left); rec.facing=left?-1:1; }
function moveActor(rec,toX,run,cb){
  if(!rec) return; toX=Math.max(12,Math.min(88,toX));
  faceToward(rec,toX);
  rec.el.classList.add(run?"running":"walking");
  rec.el.style.left=toX+"%"; rec.x=toX; rec.busyUntil=nowMs()+(run?900:1400);
  let steps=0; const iv=setInterval(()=>{ sfx("step"); if(++steps>3) clearInterval(iv); },160);
  setTimeout(()=>{ clearInterval(iv); rec.el.classList.remove("walking","running"); if(cb)cb(); }, run?900:1400);
}
let behaviorTimer=null;
function startBehavior(){ stopBehavior(); behaviorTimer=setInterval(behaviorStep, 1300); }
function stopBehavior(){ if(behaviorTimer) clearInterval(behaviorTimer); behaviorTimer=null; }
function behaviorStep(){
  if(current!=="world") return;
  if($("#chaptercard").classList.contains("show")||$("#puzzle").classList.contains("show")) return;
  const now=nowMs();
  const children=Object.values(actors).filter(a=>a.kind==="child");
  Object.values(actors).forEach(rec=>{
    if(now<rec.busyUntil) return;
    if(rec.el.classList.contains("walking")||rec.el.classList.contains("running")||rec.el.classList.contains("speaking")) return;
    const isPlayer=(rec.key===S.player);
    const per=PERSONA[rec.key]||rec.persona||{acts:["look","sway"],move:0.2};
    const r=Math.random();
    // children play: chase & throw snowballs
    if(rec.kind==="child" && children.length>1 && r<0.35){
      const other=children.find(c=>c!==rec);
      if(other && Math.random()<0.5){ throwSnowball(rec,other); rec.body.className="body b-cheer"; rec.busyUntil=now+900;
        setTimeout(()=>{ if(rec.body) rec.body.className="body "+(rec.activity||""); },900); return; }
    }
    // NPCs & extras wander; then look around when they arrive (a small routine)
    if(!isPlayer && r<per.move*0.4){
      const range=per.slow?10:(rec.kind==="child"?30:22); let nx=rec.x+(Math.random()*range*2-range);
      nx=Math.max(12,Math.min(88,nx));
      // never wander into another character — keep clean spacing on stage
      const others=principalKeys().filter(k=>actors[k]!==rec).map(k=>actors[k].x);
      if(others.some(o=>Math.abs(o-nx)<MIN_GAP)) return;   // would crowd someone → stay put this tick
      moveActor(rec,nx,(per.move>0.5&&Math.random()<0.45), ()=>{
        setTimeout(()=>{ if(rec.body && now===now) playBehavior(rec,"b-look",2200); }, 200);
      });
      return;
    }
    if(r<0.64){
      let act=per.acts[Math.floor(Math.random()*per.acts.length)];
      if(COLD_SCENES[curScene] && rec.key!=="queen" && rec.kind!=="child" && Math.random()<0.4) act="shiver";
      const dur = act==="sway"||act==="look"?2600 : act==="bow"?1400 : 1000;
      playBehavior(rec,"b-"+act,dur);
    } else if(rec.activity){ if(!rec.body.classList.contains(rec.activity)) rec.body.className="body "+rec.activity; }
  });
}

/* ================= CINEMATIC CAMERA ================= */
let cam={x:0,y:0,s:1};
function applyCam(){ camEl.style.transform="translate("+cam.x+"%,"+cam.y+"%) scale("+cam.s+")";
  // subtle background parallax opposite the camera pan (depth)
  if(bg) bg.style.backgroundPosition=(50-cam.x*1.1)+"% "+(50-cam.y*0.7)+"%"; }
/* gentle continuous "handheld" breath + brief shakes on big moments (smooth camera life) */
let shakeAmt=0, idleRAF=0;
const reduceMotion=(window.matchMedia&&matchMedia("(prefers-reduced-motion:reduce)").matches);
function camShake(a){ shakeAmt=Math.max(shakeAmt,a||0.4); }
function idleCam(){ idleRAF=requestAnimationFrame(idleCam);
  if(current!=="world"||reduceMotion){ if(stageOuter) stageOuter.style.transform=""; return; }
  const t=performance.now()*0.001;
  const bx=Math.sin(t*0.5)*0.32, by=Math.cos(t*0.37)*0.2;
  shakeAmt*=0.9; const sx=(Math.random()-0.5)*shakeAmt, sy=(Math.random()-0.5)*shakeAmt;
  stageOuter.style.transform="translate("+(bx+sx)+"%,"+(by+sy)+"%)"; }
idleCam();
function cameraTo(x,y,s,dur){ cam.x=x;cam.y=y;cam.s=s;
  camEl.style.transitionDuration=(dur||1.7)+"s"; applyCam(); }
function cameraEstablish(){ cameraTo(0,0,1.0,2.0); }             // wide shot
function cameraPushTo(xPct){ // gentle push-in centered on a speaker
  const dx=(50-xPct)*0.28; cameraTo(dx,-1.5,1.14,1.6); }
function cameraDrama(){ cameraTo(0,-2,1.22,1.2); }               // strong zoom for big moments
/* ---- extended cinematic vocabulary: sequenced moves for film-like framing ---- */
function _seq(x,y,s,dur){ requestAnimationFrame(()=>cameraTo(x,y,s,dur)); }   // start next frame so the snap-set transitions
function cameraCrane(dir){                                        // vertical crane
  if(dir==="down"){ cameraTo(0,-9,1.02,0.01); _seq(0,-1,1.12,3.4); }          // descend from on-high into the scene
  else { cameraTo(0,4,1.22,0.01); _seq(0,-7,1.06,3.6); }                       // rise: low & tight → high & wide reveal
}
function cameraOrbit(xPct,dir){                                   // lateral arc around a subject (parallax "orbit")
  const d=(dir==="l"?-1:1), cx=(50-(xPct==null?50:xPct))*0.26;
  cameraTo(cx - d*7, -1.5, 1.26, 0.01); _seq(cx + d*7, -3, 1.24, 3.6); }
function cameraPushIn(xPct){ const dx=(50-(xPct==null?50:xPct))*0.3; cameraTo(dx,-2.5,1.34,2.8); } // slow deliberate push
function cameraPullOut(){ cameraTo(0,-2.5,1.32,0.01); _seq(0,0,1.0,3.2); }     // from close → wide reveal
function cameraOTS(xPct){ const x=(xPct==null?50:xPct), side=x<50?1:-1;        // over-the-shoulder: subject off to one side
  cameraTo((50-x)*0.34 + side*8, -2.5, 1.3, 1.9); }

