/* per-scene cinematic lighting: colour grade + optional god-ray shafts */
const LIGHT={
  attic:{grade:"warm",rays:"on"}, village:{grade:"cold",rays:""}, river:{grade:"cold",rays:"cool"},
  garden:{grade:"bright",rays:"on"}, palacehall:{grade:"bright",rays:"on"}, camp:{grade:"warm",rays:""},
  mountains:{grade:"cold",rays:"cool"}, lapland:{grade:"cold",rays:"cool"}, finland:{grade:"warm",rays:""},
  palace:{grade:"mystic",rays:"cool"}, clockwork_chapel:{grade:"mystic",rays:"cool"}, forest:{grade:"cold",rays:"cool"},
  wishing_well:{grade:"mystic",rays:"cool"}, aurora_tent:{grade:"mystic",rays:"cool"},
  // Aldar steppe scenes fall back warm/bright
  aul:{grade:"warm",rays:"on"}, market:{grade:"bright",rays:"on"}, steppe:{grade:"bright",rays:"on"},
  // Sleeping Beauty — per-scene cinematic grade + god-ray shafts
  great_hall:{grade:"warm",rays:"on"}, throne_room:{grade:"mystic",rays:"cool"}, tower:{grade:"warm",rays:"on"},
  sleeping_castle:{grade:"cold",rays:"cool"}, thorn_wood:{grade:"mystic",rays:"cool"}, chamber:{grade:"bright",rays:"on"},
  // Er-Töstik — per-scene cinematic grade + god-ray shafts
  aul_famine:{grade:"cold",rays:"cool"}, horse_herd:{grade:"warm",rays:"on"}, wedding_aul:{grade:"warm",rays:"on"},
  sorqudyq:{grade:"cold",rays:"cool"}, snake_court:{grade:"mystic",rays:"cool"}, underworld:{grade:"mystic",rays:"cool"},
  temir_aul:{grade:"cold",rays:"cool"}, iron_palace:{grade:"warm",rays:"on"}, world_tree:{grade:"mystic",rays:"on"},
  sky_upper:{grade:"bright",rays:"on"}, deer_spring:{grade:"bright",rays:"on"}, reunion_aul:{grade:"warm",rays:"on"}
};
const RIM={warm:"rgba(255,214,150,.62)",cold:"rgba(150,205,255,.6)",mystic:"rgba(150,240,220,.55)",bright:"rgba(255,240,205,.6)"};
function applyGrade(scene){
  const g=$("#grade"), r=$("#rays"); if(!g||!r) return;
  const cold=(COLD_SCENES&&COLD_SCENES[scene]);
  const lp=LIGHT[scene]||{grade:cold?"cold":"warm",rays:cold?"cool":""};
  const grade=lp.grade||"warm";
  g.className=grade;
  r.className=lp.rays?("on"+(lp.rays==="cool"?" cool":"")):"";
  if(stageOuter) stageOuter.dataset.light=grade;                 // tints the cast to match the scene light
  if(stage) stage.style.setProperty("--rim",RIM[grade]||RIM.warm); // mood-coloured rim on whoever speaks
}

/* ================= INTERACTIVE DISCOVERIES (tap hidden things for lore + memories) ================= */
const findsEl=$("#finds"); let sceneFinds=[], curFindCard=null;
function sceneFindList(scene){ return (DISCOVER&&DISCOVER[scene])||[]; }
function totalFinds(){ let n=0; for(const k in (DISCOVER||{})) n+=DISCOVER[k].length; return n; }
function foundCount(){ return (S&&S.found)?Object.keys(S.found).length:0; }
function spawnDiscoveries(scene){
  if(!findsEl) return; findsEl.innerHTML=""; sceneFinds=sceneFindList(scene);
  if(!S.found) S.found={};
  sceneFinds.forEach(d=>{
    const el=document.createElement("div"); el.className="find"+(S.found[d.id]?" found":"");
    el.style.left=d.x+"%"; el.style.top=d.y+"%"; el.title=t(d.name);
    el.innerHTML='<span class="ring"></span><span class="glyph">'+d.ic+'</span>';
    el.addEventListener("click",(e)=>{ e.stopPropagation(); collectFind(d,el); });
    findsEl.appendChild(el);
  });
  updateFindChip();
}
function collectFind(d,el){
  const fresh=!S.found[d.id];
  if(fresh){ S.found[d.id]=1; save(); if(el) el.classList.add("found"); sfx("sparkle"); if(d) findParticles(d);
    dingChip(); award("memory", t(d.name));
    if(sceneFinds.length && sceneFinds.every(x=>S.found[x.id])) setTimeout(()=>award("scenememories", t(SCENES[curScene].label)),900);
    if(totalFinds()>0 && foundCount()>=totalFinds()) setTimeout(()=>award("allmemories", t(UI.memAll)),1400);
  } else { sfx("chime"); }
  showFindCard(d); updateFindChip();
}
function showFindCard(d){ $("#fcIc").textContent=d.ic; $("#fcName").textContent=t(d.name); $("#fcText").textContent=t(d.text);
  $("#fcFoot").textContent=t(UI.findClose); $("#findcard").classList.add("show"); curFindCard=d; }
function closeFindCard(){ $("#findcard").classList.remove("show"); curFindCard=null; }
function findParticles(d){ if(!findsEl) return;
  for(let i=0;i<12;i++){ const s=document.createElement("div"); s.className="spark"; s.style.left=d.x+"%"; s.style.top=d.y+"%"; findsEl.appendChild(s);
    const a=Math.random()*6.28, dist=18+Math.random()*42, dur=520+Math.random()*380;
    if(s.animate){ s.animate([{transform:"translate(-50%,-50%)",opacity:1},
        {transform:"translate(-50%,-50%) translate("+(Math.cos(a)*dist).toFixed(1)+"px,"+(Math.sin(a)*dist).toFixed(1)+"px)",opacity:0}],
        {duration:dur,easing:"cubic-bezier(.2,.6,.3,1)"}); }
    setTimeout(()=>s.remove(),dur+40); }
}
function updateFindChip(){ const chip=$("#findchip"); if(!chip) return; const tot=totalFinds();
  if(!tot){ chip.classList.remove("on","show"); return; }
  $("#findNum").textContent=foundCount()+"/"+tot; chip.classList.add("on"); requestAnimationFrame(()=>chip.classList.add("show")); }
function dingChip(){ const chip=$("#findchip"); if(chip){ chip.classList.remove("ding"); void chip.offsetWidth; chip.classList.add("ding"); } }
/* a small sparkle where you touch the living world (idle feedback) */
function touchSparkle(px,py){ if(!findsEl||current!=="world") return; const R=stageOuter.getBoundingClientRect();
  const x=((px-R.left)/R.width*100), y=((py-R.top)/R.height*100); if(y>82) return;   // keep clear of the caption area
  for(let i=0;i<6;i++){ const s=document.createElement("div"); s.className="spark"; s.style.left=x+"%"; s.style.top=y+"%"; findsEl.appendChild(s);
    const a=Math.random()*6.28, dist=10+Math.random()*22, dur=420+Math.random()*260;
    if(s.animate){ s.animate([{transform:"translate(-50%,-50%)",opacity:.9},{transform:"translate(-50%,-50%) translate("+(Math.cos(a)*dist).toFixed(1)+"px,"+(Math.sin(a)*dist).toFixed(1)+"px)",opacity:0}],{duration:dur,easing:"ease-out"}); }
    setTimeout(()=>s.remove(),dur+40); } }
function spawnBird(){
  const b=document.createElement("div"); b.className="bird";
  const y=8+Math.random()*22, ltr=Math.random()<0.5, dur=7+Math.random()*5;
  b.innerHTML="<i>ᨑ</i>"; b.style.top=y+"%"; b.style.left=ltr?"-6%":"106%";
  b.style.transition="left "+dur+"s linear, top "+dur+"s ease-in-out";
  envEl.appendChild(b);
  requestAnimationFrame(()=>{ b.style.left=ltr?"106%":"-6%"; b.style.top=(y+ (Math.random()*8-4))+"%"; });
  setTimeout(()=>b.remove(), dur*1000+200);
}

/* ================= BACKGROUND EXTRAS (crowd life) ================= */
function silhouetteKind(kind){
  const col={child:["#6ea0e0","#33517f"],villager:["#b98a5a","#5c4326"],guard:["#8aa0b8","#3a4a5c"],
    lady:["#d08faa","#7a3f56"],woodsman:["#9a7a52","#4a3720"]}[kind]||["#3a5591","#22345f"];
  return "data:image/svg+xml;utf8,"+encodeURIComponent(
    "<svg xmlns='http://www.w3.org/2000/svg' width='200' height='460'>"+
    "<defs><radialGradient id='g' cx='50%' cy='28%'><stop offset='0%' stop-color='"+col[0]+"'/>"+
    "<stop offset='100%' stop-color='"+col[1]+"'/></radialGradient></defs>"+
    "<ellipse cx='100' cy='96' rx='46' ry='50' fill='url(#g)'/>"+
    "<path d='M100 150 C50 150 40 230 46 400 C48 452 152 452 154 400 C160 230 150 150 100 150 Z' fill='url(#g)'/></svg>");
}
const SNOW_EXTRAS = {
  village:[{k:"child",act:"act-play",x:14,far:0},{k:"child",act:"act-play",x:26,far:0},
    {k:"villager",act:"act-carry",x:86,far:1},{k:"woodsman",act:"act-chop",x:74,far:1},{k:"lady",act:"act-carry",x:8,far:1}],
  attic:[{k:"child",act:"act-play",x:16,far:1}],
  camp:[{k:"villager",act:"act-work",x:16,far:1},{k:"villager",act:"act-carry",x:90,far:1}],
  palacehall:[{k:"guard",act:"act-work",x:8,far:1},{k:"guard",act:"act-work",x:92,far:1},{k:"lady",act:"act-carry",x:20,far:1}],
  garden:[{k:"lady",act:"act-work",x:84,far:1}],
  forest:[{k:"woodsman",act:"act-chop",x:82,far:1}],
  lapland:[{k:"villager",act:"act-work",x:20,far:1}],
  mountains:[{k:"woodsman",act:"act-carry",x:80,far:1}]
};
let extraId=0;
function crowdImg(kind){ const c=(T&&T.crowd)||null; if(!c) return null;
  return (kind==="child") ? (c.child||c.villager) : (c.villager||c.child); }
function spawnExtras(scene){
  return;   // background crowd figures removed — only named story characters appear on screen now
  /* eslint-disable no-unreachable */
  const list=EXTRAS[scene]||[];
  list.forEach(e=>{
    const url=crowdImg(e.k); if(!url) return;   // no real crowd art → skip (never show mannequin placeholders)
    const key="__x"+(extraId++);
    const el=document.createElement("div"); el.className="actor extra"+(e.far?" far":""); el.style.left=e.x+"%";
    const body=document.createElement("div"); body.className="body "+e.act;
    const img=new Image(); img.style.height="100%"; img.style.display="block";
    img.onerror=()=>{ el.remove(); delete actors[key]; }; img.src=url; body.appendChild(img);
    el.appendChild(body);
    stage.appendChild(el);
    actors[key]={el,body,x:e.x,key,extra:true,kind:e.k,activity:e.act,busyUntil:0,
      persona:{acts:e.k==="child"?["hop","cheer","look"]:["look","sway","nod"], move:e.k==="child"?0.7:0.3}};
  });
}
function throwSnowball(fromRec,toRec){
  if(!fromRec||!toRec) return;
  const s=document.createElement("div"); s.className="snowball";
  s.style.left=fromRec.x+"%"; s.style.bottom="20%"; s.style.transition="left .5s linear, bottom .5s ease-out";
  stage.appendChild(s);
  requestAnimationFrame(()=>{ s.style.left=toRec.x+"%"; s.style.bottom="16%"; });
  setTimeout(()=>{ s.remove(); if(toRec.body){ toRec.body.className="body b-back"; toRec.busyUntil=nowMs()+800;
    setTimeout(()=>{ if(toRec.body) toRec.body.className="body "+(toRec.activity||""); },800); } }, 520);
}

/* ================= CINEMATIC SEQUENCES ================= */
function runCine(steps, done){
  const nb=$("#narration"); nb.classList.add("cine");
  let i=0;
  const next=()=>{
    if(i>=steps.length){ nb.classList.remove("cine","show"); curNarrObj=null; clearLine(); clearAdvance(); cameraEstablish(); if(done) done(); return; }
    const si=i; const st=steps[i++]; applyCineStep(st, si);
    // A cine step with narration holds until its recorded line has been heard (never
    // shorter than its authored camera beat), so the montage voice is never cut off
    // or overrun by the next step. Pure staging steps keep their fixed dwell.
    if(st.narr){ setAdvance(()=>next());
      armLine(autoAfter(300), Math.max(st.wait||2400, estReadMs(t(st.narr)))); }
    else setTimeout(next, st.wait||2400);
  };
  next();
}
/* the shared camera vocabulary, usable from cine steps and beat `stage:` cues */
function applyCamCue(cam){
  if(cam==null) return;
  if(cam==="wide") cameraEstablish();
  else if(cam==="drama") cameraDrama();
  else if(cam==="up") cameraTo(0,-7,1.16,2.4);
  else if(cam==="skypan") cameraTo(0,6,1.05,2.6);
  else if(cam==="hold") cameraTo(0,-1.5,1.08,3.2);        // slow, held breath
  else if(cam==="craneup") cameraCrane("up");
  else if(cam==="cranedown") cameraCrane("down");
  else if(cam==="pushin") cameraPushIn(null);
  else if(cam==="pullout") cameraPullOut();
  else if(cam==="orbit") cameraOrbit(null,"r");
  else if(Array.isArray(cam)) cameraTo(cam[0],cam[1],cam[2],cam[3]);
  else if(cam&&cam.push!=null) cameraPushTo(cam.push);
  else if(cam&&cam.on!=null){ const rec=actorRec(cam.on); if(rec) cameraPushTo(rec.x); }  // frame a character
  else if(cam&&cam.pushOn!=null){ const rec=actorRec(cam.pushOn); cameraPushIn(rec?rec.x:50); }   // deliberate push onto a character
  else if(cam&&cam.orbit!=null){ const rec=actorRec(cam.orbit); cameraOrbit(rec?rec.x:50, cam.dir||"r"); }
  else if(cam&&cam.ots!=null){ const rec=actorRec(cam.ots); cameraOTS(rec?rec.x:50); }             // over-the-shoulder
  else if(cam&&cam.crane!=null) cameraCrane(cam.crane);
}
function applyCineStep(st, si){
  applyStaging(st);   // fx / wind / cam / grade / cast are all handled here now
  if(st.narr){ vwRender($("#narrText"),t(st.narr)); $("#narration").classList.add("show");
    // cine narration has its own recorded clip, keyed  <path>:<ci>:<bi>:c<stepIndex>
    const ck=(S!=null && si!=null) ? (storyPath()+":"+S.ci+":"+S.bi+":c"+si) : null;
    lastPlayed={type:"narr",obj:st.narr,who:"narrator",key:ck};
    speak(t(st.narr),"narrator","narr",ck); curNarrObj=st.narr; }
}
/* Shared staging directives — usable from a cine step OR from a beat's `stage:`
   field, so a plain narration/dialogue beat can direct the cast (walk to a mark,
   turn away, embrace, leave) AND the camera/weather/light without being turned
   into a cinematic (which would drop its recorded audiobook clip).
     cam:<cue>  fx:<type>  wind:true  grade:<scene>
     spawn:[keys]  move:[{who,x,run}]  exit:[keys]  back:[keys]  face:[{who,x}]
     gesture:[{who,act,dur}]  (act = a b-* behaviour: hop, wave, point, nod, hug…) */
function actorRec(k){ return (k===S.player)?actors["__player"]:actors[k]; }
function applyStaging(st){
  if(!st) return;
  if(st.fx) seedFx(st.fx);
  if(st.wind){ sfx("wind"); windGust(1.4); camShake(0.5); }
  if(st.camShake) camShake(0.7);
  if(st.grade) applyGrade(st.grade);
  // spawn + move together: a spawned actor walks straight to its authored move
  // target, so the entrance rAF can never clobber the move (old teleport bug).
  if(st.spawn||st.move){
    const mv={}; (st.move||[]).forEach(m=>{ mv[m.who]=m; });
    (st.spawn||[]).forEach(k=> ensureActor(k, mv[k]?mv[k].x:null));
    (st.move||[]).forEach(m=>{ if((st.spawn||[]).indexOf(m.who)>=0) return;   // already handled at spawn
      const rec=actorRec(m.who); if(rec) moveActor(rec, resolveSlot(m.x, m.who===S.player?"__player":m.who), m.run); });
  }
  if(st.spawn||st.move) scheduleSpread();   // de-overlap crowded casts once entrances settle
  // camera AFTER cast placement, so character-framing cues (on/ots/orbit/pushOn) frame real positions
  if(st.cam!=null) applyCamCue(st.cam);
  if(st.face) st.face.forEach(f=>{ const rec=actorRec(f.who); if(rec) faceToward(rec,f.x); });
  if(st.gesture) st.gesture.forEach(g=>{ const rec=actorRec(g.who); if(rec) playBehavior(rec,"b-"+g.act, g.dur||1200); });
  if(st.exit) st.exit.forEach(k=> removeActor(k===S.player?"__player":k));
  if(st.back) st.back.forEach(k=>{ const rec=actorRec(k);
    if(rec&&rec.body){ rec.body.className="body b-back"; rec.busyUntil=nowMs()+1100;
      setTimeout(()=>{ if(rec.body) rec.body.className="body "+(rec.activity||""); },1100); } });
}

/* ================= BUBBLES / NARRATION ================= */
let pendingAdvance=null, curBubble=null, curBubbleObj=null, curNarrObj=null, lastPlayed=null;
let lastAdvanceAt=0;
function setAdvance(fn){ pendingAdvance=fn; }
function clearAdvance(){ pendingAdvance=null; }
/* Advance the story one step. There is no Continue button any more: the story
   plays itself. A tap is still accepted as an OPTIONAL "skip ahead". */
function doAdvance(){
  if(!pendingAdvance) return;
  const now=nowMs();
  if(now-lastAdvanceAt<260) return;      // debounce accidental double-taps
  lastAdvanceAt=now;
  clearLine();                            // cancel this line's pending auto-advance
  const f=pendingAdvance; pendingAdvance=null;
  try{ f(); }catch(e){ /* never let a bad step wedge navigation */ }
}
/* ---- AUTO-PLAY: each line advances itself when its voice finishes (plus a
   natural pause), so the tale flows like a film with no button to press. If no
   audio 'end' fires (muted / synthesis dropped), a reading-time fallback keeps
   it moving. A tap still skips ahead. ---- */
let lineDoneCb=null, lineFallback=null, lineMinUntil=0, lineMinTimer=null;
/* how long a line stays on screen AT MINIMUM — a generous audiobook reading pace
   (~155 wpm) so every character has time to deliver its whole line, never rushed. */
function estReadMs(txt){ const w=((txt||"").trim().split(/\s+/).length)||1; return Math.max(2200, 750+w*385); }
/* Arm a line. It may NOT advance before its full reading time has elapsed, even
   if the audio 'end' (or a failed/empty TTS utterance) fires early — this is what
   stops non-narrator lines from being skipped or rushed. If audio runs LONGER
   than the reading time, it drives the advance instead (real recorded voices). */
function armLine(cb, est){ lineDoneCb=cb;
  const minHold=Math.max(1200, est||3000);
  lineMinUntil=nowMs()+minHold;
  if(lineFallback) clearTimeout(lineFallback);
  if(lineMinTimer){ clearTimeout(lineMinTimer); lineMinTimer=null; }
  lineFallback=setTimeout(()=>signalSpoken(), minHold+3500); }   // hard cap if no 'end' ever arrives
function signalSpoken(){ if(!lineDoneCb) return;
  const remain=lineMinUntil-nowMs();
  if(remain>60){                                   // audio ended early → hold until the line is fully "read"
    if(lineMinTimer) clearTimeout(lineMinTimer);
    lineMinTimer=setTimeout(signalSpoken, remain); return; }
  const cb=lineDoneCb; lineDoneCb=null;
  if(lineFallback){ clearTimeout(lineFallback); lineFallback=null; }
  if(lineMinTimer){ clearTimeout(lineMinTimer); lineMinTimer=null; } cb(); }
function clearLine(){ lineDoneCb=null;
  if(lineFallback){ clearTimeout(lineFallback); lineFallback=null; }
  if(lineMinTimer){ clearTimeout(lineMinTimer); lineMinTimer=null; } }
/* the pause after a line, then auto-advance (a tap can still pre-empt it) */
function autoAfter(pauseMs){ return ()=>{ if(pendingAdvance) setTimeout(()=>doAdvance(), pauseMs); }; }

/* audiobook line keys — match the SNOW_NARRATION manifest */
function narrKey(){ return S? (storyPath()+":"+S.ci+":"+S.bi+":narr") : null; }
function dlgKey(li){ return S? (storyPath()+":"+S.ci+":"+S.bi+":d"+li) : null; }
function showNarration(obj,next){
  hideBubble(); curNarrObj=obj; curBubbleObj=null;
  vwRender($("#narrText"),t(obj));
  $("#narration").classList.add("show"); $("#dlgadv").classList.remove("show");
  lastPlayed={type:"narr",obj:obj,who:"narrator",key:narrKey()};
  cameraEstablish();                 // wide establishing shot while the narrator speaks
  setAdvance(()=>{ $("#narration").classList.remove("show"); if(next) next(); });
  armLine(autoAfter(800), estReadMs(t(obj)));   // hold a beat after the narration, then advance
  speak(t(obj),"narrator","narr",narrKey());
}
function hideNarration(){ $("#narration").classList.remove("show"); curNarrObj=null; stopClip(); }

let lastSpeakerKey=null;
/* the mouth/talking motion runs for exactly as long as the audio does: it is
   cleared by endTalking() from the clip's / TTS's 'end' event, so the acting
   matches the audiobook instead of a length guess. A generous fallback covers
   the muted case where no audio 'end' fires. */
let curTalkRec=null, talkFallback=null, talkMinUntil=0;
/* Stop the speaker's mouth. Unless forced (a new speaker is taking over), keep it
   animating until the line's reading time is up — so an early/empty audio 'end'
   never freezes a character mid-line while their words are still on screen. */
function endTalking(force){
  if(!force){ const remain=talkMinUntil-nowMs();
    if(remain>60){ if(talkFallback) clearTimeout(talkFallback); talkFallback=setTimeout(()=>endTalking(),remain); return; } }
  if(talkFallback){ clearTimeout(talkFallback); talkFallback=null; }
  const rec=curTalkRec; curTalkRec=null;
  if(rec&&rec.body){ if(rec.body.classList.contains("talking")) rec.body.className="body "+(rec.activity||""); rec.busyUntil=nowMs(); } }
const CLOSEUP_EM={tears:1,pleading:1,empty:1,dazed:1,alluring:1,waking:1,hurt:1,soft:1};
function choreographSpeak(who, textLen, em){
  const rec=(who===S.player)?actors["__player"]:actors[who]; if(!rec) return rec;
  const dur=Math.min(6000, 1500+textLen*45);
  // speaker turns toward the previous speaker (or centre) and "talks" with body motion
  const other=lastSpeakerKey&&actors[lastSpeakerKey]?actors[lastSpeakerKey]:null;
  faceToward(rec, other?other.x:50);
  endTalking(true);                          // a NEW speaker takes over: force-stop the previous mouth NOW
  // The mouth must keep animating for at least the line's full reading time, so a
  // character visibly performs every word even when audio ends early (or never plays).
  const minTalk=Math.max(2400, 750+(textLen/5.2)*385);
  talkMinUntil=nowMs()+minTalk;
  const hold = S.voice ? Math.max(16000, minTalk) : minTalk;   // real audio may run long; fallback only caps it
  rec.busyUntil=nowMs()+hold; curTalkRec=rec;
  // OPENING PHYSICAL ACTION keyed to the emotion, THEN settle into the talking
  // motion — so a character visibly performs the line, never just stands and talks.
  const g=SPEAK_GESTURE[em];
  const beginTalk=()=>{ if(curTalkRec===rec && rec.body) rec.body.className="body talking"; };
  if(g && rec.body){ rec.body.className="body b-"+g; setTimeout(beginTalk, 600); } else beginTalk();
  talkFallback=setTimeout(()=>{ endTalking(true); }, hold);
  // the listener turns to the speaker and reacts in a way that fits the line
  if(other && other!==rec){ faceToward(other, rec.x);
    if(Math.random()<0.72){ const react=LISTEN_REACT[em]||"nod"; other.body.className="body b-"+react; other.busyUntil=nowMs()+900;
      setTimeout(()=>{ if(other.body) other.body.className="body "+(other.activity||""); },900); } }
  // emotional lines get a tighter close-up + a small musical swell under the voice
  if(CLOSEUP_EM[em]){ cameraTo((50-rec.x)*0.34,-2.5,1.26,1.5); swellBeds(1.3,600,4200); } else cameraPushTo(rec.x);
  lastSpeakerKey=who;
  return rec;
}
/* emotion → an opening gesture the speaker performs as they begin the line */
const SPEAK_GESTURE={
  bold:"point", fierce:"shake", urgent:"point", resolve:"point",
  gossip:"wave", pleading:"wave", hope:"hop", waking:"hop", grateful:"bow",
  warm:"nod", kind:"nod", calm:"nod", wise:"nod", soft:"sway", gentle:"nod",
  worried:"back", hurt:"back", sad:"back", cold:"shake", cool:"sway",
  empty:"sway", dazed:"sway", alluring:"sway", tears:"kneel" };
/* emotion → how the LISTENER reacts to hearing it */
const LISTEN_REACT={ fierce:"back", cold:"back", alluring:"back", bold:"nod",
  tears:"nod", pleading:"nod", hope:"hop", warm:"nod", worried:"back" };
/* posture held on the speaker's body for the length of the line, keyed to emotion */
const POSTURE={sad:"sad",tears:"sad",hurt:"sad",
  bold:"bold",fierce:"bold",resolve:"bold",urgent:"bold",
  cold:"cold",cool:"cold",empty:"cold",dazed:"cold",
  worried:"worried",pleading:"worried",wise:"worried",calm:"worried",
  warm:"tender",kind:"tender",hope:"tender",grateful:"tender",gentle:"tender",soft:"tender",alluring:"tender",waking:"tender"};
const POS_ALL=["pos-sad","pos-bold","pos-cold","pos-worried","pos-tender"];
function setPosture(rec,em){ if(!rec||!rec.breathe) return; rec.breathe.classList.remove(...POS_ALL);
  const g=POSTURE[em]; if(g) rec.breathe.classList.add("pos-"+g); }
function clearPostures(){ Object.values(actors).forEach(a=>{ if(a&&a.breathe) a.breathe.classList.remove(...POS_ALL); }); }
function showBubble(who,obj,em,next,key,perform){
  hideNarration(); hideBubble();
  const el=ensureActor(who);
  const rec=(who===S.player)?actors["__player"]:actors[who];
  const x= rec? rec.x : 50;
  setSpeaking(who);
  setPosture(rec,em);
  choreographSpeak(who, t(obj).length, em);
  const b=document.createElement("div"); b.className="bubble"+(/^\s*\*/.test(t(obj))?" think":"");
  b.style.left=x+"%"; b.style.bottom="44%";
  b.innerHTML='<div class="box"><span class="who">'+nameOf(who)+'</span><span class="btx"></span></div>'; vwRender(b.querySelector(".btx"),t(obj));
  stage.appendChild(b); requestAnimationFrame(()=>b.classList.add("show"));
  curBubble=b; curBubbleObj=obj; curNarrObj=null;
  lastPlayed={type:"dlg",obj:obj,who:who,em:em,key:key};
  if(who!=="narrator" && who!==S.player && !S.met[who]){ S.met[who]=1; save(); }
  if(!(key && NARRATION && NARRATION[key] && lang==="en") && !perform) sfx("talk");   // no UI blip under a full clip
  setAdvance(()=>{ next&&next(); });
  armLine(autoAfter(950), estReadMs(t(obj)));   // a natural pause between speakers before the next line
  if(perform && perform.takeUrl){ ttsBusy=true; duckAudio(true); playClip(perform.takeUrl, null, null, null); }  // the user's own recorded voice, lip-synced
  else if(perform && perform.silent){ /* typed line: no audio — the reading-time fallback advances it */ }
  else speak(t(obj),who,em,key);
  breathPuff(rec);                       // frosty breath in the cold
}
/* a puff of frosty breath drifting from a speaker in a cold scene */
function breathPuff(rec){
  if(!rec||!(COLD_SCENES&&COLD_SCENES[curScene])) return;
  const p=document.createElement("div"); p.className="breath";
  const flip=rec.el&&rec.el.classList.contains("face-left");
  p.style.left=(rec.x + (flip?-4:4))+"%"; p.style.bottom="46%";
  if(flip) p.style.transform="scaleX(-1)";
  stage.appendChild(p); setTimeout(()=>p.remove(),1600);
}
function hideBubble(){ if(curBubble){ curBubble.classList.remove("show"); const b=curBubble; setTimeout(()=>b.remove(),300); curBubble=null; }
  $("#dlgadv").classList.remove("show"); Object.values(actors).forEach(a=>a.el.classList.remove("speaking")); clearPostures(); stopClip(); endTalking(); }
function replayLast(){ if(!lastPlayed) return;
  // only re-voice a line that is still on screen (replay button, or a mid-line language switch)
  if(!curNarrObj && !curBubble) return;
  try{ if(window.speechSynthesis) speechSynthesis.cancel(); }catch(e){} stopClip();
  speak(t(lastPlayed.obj), lastPlayed.who, lastPlayed.em||"narr", lastPlayed.key); }

/* re-render visible localized text on language change */
function relocalizeLive(){
  if(!S || current!=="world") return;
  if(lang!=="en") stopClip();   // recorded clips are English; RU/KK fall back to per-character TTS
  if(curNarrObj) vwRender($("#narrText"),t(curNarrObj));
  if(curBubble&&curBubbleObj){ const el=curBubble.querySelector(".btx"); if(el) el.textContent=t(curBubbleObj);
    const wh=curBubble.querySelector(".who"); if(wh&&lastPlayed) wh.textContent=nameOf(lastPlayed.who); }
  Object.values(actors).forEach(a=>{ const tg=a.el.querySelector(".tag"); if(tg) tg.textContent=nameOf(a.key); });
  if($("#playerturn").classList.contains("show")){ $("#ptWho").textContent=nameOf(S.player);
    if(ptLineObj) $("#ptSug").textContent="“"+t(ptLineObj)+"”"; }
  updateObjective(); if(curScene&&SCENES[curScene]) $("#hudLoc").textContent=t(SCENES[curScene].label);
}

/* ================= LIVING WORLD (ambient NPC life) ================= */
/* Short idle lines so characters talk to each other and move on their own,
   even when the player only watches. Each speaks in their own voice. */
const SNOW_AMBIENT = {
  grandmother:[{line:L("Mind the cold, little ones.","Берегитесь холода, малыши.","Суықтан сақ болыңдар, кішкентайлар."),em:"gentle"},
    {line:L("I'll put the kettle on.","Поставлю чайник.","Шәйнекті қоямын."),em:"kind"}],
  kay:[{line:L("Look — no two snowflakes are alike.","Смотри — нет двух одинаковых снежинок.","Қара — бірдей екі үлпек жоқ."),em:"cold"}],
  raven:[{line:L("Kraa! News, news from the palace!","Кар! Новости, новости из дворца!","Қарқ! Сарайдан жаңалық!"),em:"gossip"},
    {line:L("A clever match, they say.","Говорят, удачная пара.","Тамаша жұп, дейді."),em:"gossip"}],
  crow:[{line:L("My betrothed serves inside those walls.","Моя невеста служит за этими стенами.","Қалыңдығым сол қабырға ішінде қызмет етеді."),em:"warm"}],
  robber:[{line:L("Ha! Hold still, you silly beast.","Ха! Стой смирно, глупый зверь.","Ха! Тыныш тұр, ақымақ аң."),em:"bold"}],
  robber_mother:[{line:L("More wood on the fire!","Ещё дров в костёр!","Отқа тағы отын сал!"),em:"fierce"}],
  reindeer:[{line:L("*snorts and stamps toward the north*","*фыркает и бьёт копытом на север*","*пысқырып, солтүстікке тебеді*"),em:"gentle"}],
  prince:[{line:L("A fine, clear evening, my love.","Чудный ясный вечер, любовь моя.","Ашық әдемі кеш, сүйіктім."),em:"calm"}],
  princess:[{line:L("Let the traveler rest a while.","Пусть путница отдохнёт.","Жолаушы аздап демалсын."),em:"kind"}],
  flower_witch:[{line:L("It is always summer here.","Здесь всегда лето.","Мұнда әрдайым жаз."),em:"soft"}],
  lapland_woman:[{line:L("Two hundred miles yet to go.","Ещё двести миль пути.","Тағы екі жүз шақырым бар."),em:"calm"}],
  finland_woman:[{line:L("Her own heart is her power.","Её сила — в её сердце.","Оның күші — жүрегінде."),em:"wise"}],
  queen:[{line:L("How beautifully still it is.","Как прекрасна эта тишина.","Бұл тыныштық қандай әдемі."),em:"cool"}]
};
let ambientTimer=null;
let coldTimer=null;
function coldTick(){ coldTimer=setTimeout(coldTick, 4200+Math.random()*4600);
  if(current!=="world"||!(COLD_SCENES&&COLD_SCENES[curScene])) return;
  if(ttsBusy||pendingAdvance||$("#playerturn").classList.contains("show")) return;
  const all=Object.values(actors).filter(a=>a&&a.body&&a.busyUntil<=nowMs()&&!a.el.classList.contains("speaking"));
  if(!all.length) return; const a=all[Math.floor(Math.random()*all.length)];
  playBehavior(a,"b-shiver",1000); }                 // the cold makes them shiver
let windTimer=null;
function sceneBreezy(){ const fl=(SCENE_FLAVOR&&SCENE_FLAVOR[curScene])||[]; return fl.indexOf("wind")>=0||fl.indexOf("chirp")>=0; }
function windTick(){ windTimer=setTimeout(windTick, 7000+Math.random()*6000);
  if(current!=="world"||!sceneBreezy()) return;
  if(ttsBusy||$("#playerturn").classList.contains("show")) return;   // don't jostle a spoken close-up
  windGust(0.45+Math.random()*0.5); }                                // a breeze stirs capes, cloth and foliage
function startWorldLife(){ stopWorldLife();
  ambientTimer=setTimeout(ambientTick, 5000+Math.random()*5000);
  coldTimer=setTimeout(coldTick, 3000+Math.random()*3000);
  windTimer=setTimeout(windTick, 4000+Math.random()*4000);
  startBehavior(); }                 // continuous autonomous character behavior
function stopWorldLife(){ if(ambientTimer)clearTimeout(ambientTimer); ambientTimer=null;
  if(coldTimer)clearTimeout(coldTimer); coldTimer=null;
  if(windTimer)clearTimeout(windTimer); windTimer=null; stopBehavior(); }
function presentNpcs(){ return Object.keys(actors).filter(k=>k!=="__player" && !(actors[k]&&actors[k].extra)); }
function ambientBubble(who,obj,em){
  const a=actors[who]; if(!a) return;
  const b=document.createElement("div"); b.className="bubble ambient"+(/^\s*\*/.test(t(obj))?" think":"");
  b.style.left=a.x+"%"; b.style.bottom="46%";
  b.innerHTML='<div class="box"><span class="who">'+nameOf(who)+'</span>'+t(obj)+'</div>';
  stage.appendChild(b); requestAnimationFrame(()=>b.classList.add("show"));
  // acted out: the speaker turns to a nearby character and talks with body motion
  const others=presentNpcs().filter(k=>k!==who); if(others.length){ const o=actors[others[0]]; if(o){ faceToward(a,o.x); faceToward(o,a.x); } }
  a.body.className="body talking"; a.busyUntil=nowMs()+3200;
  speak(t(obj),who,em);
  setTimeout(()=>{ b.classList.remove("show"); setTimeout(()=>b.remove(),300);
    if(a.body) a.body.className="body "+(a.activity||""); }, 3600);
}
/* tap a character in the idle world for an optional aside in their own voice */
function npcAside(key){
  if(!AMBIENT||!AMBIENT[key]||!AMBIENT[key].length) return;
  if(ttsBusy||pendingAdvance||$("#playerturn").classList.contains("show")) return;
  if(curBubble||curNarrObj||(typeof cinActive!=="undefined"&&cinActive)) return;   // don't talk over a scripted line
  if(!actors[key]) return;
  const pool=AMBIENT[key], la=pool[Math.floor(Math.random()*pool.length)];
  ambientBubble(key, la.line, la.em);
}
function ambientTick(){
  ambientTimer=setTimeout(ambientTick, 8000+Math.random()*7000);
  if(current!=="world" || ttsBusy || pendingAdvance) return;   // never chatter over a waiting story beat
  // never speak over a visible scripted line (narration or a dialogue bubble), and
  // never during a cinematic master track — this is what used to make an on-stage
  // Snow Queen repeat her idle line on a loop underneath the narration.
  if(curBubble || curNarrObj || (typeof cinActive!=="undefined" && cinActive)) return;
  if($("#playerturn").classList.contains("show")||$("#puzzle").classList.contains("show")||$("#chaptercard").classList.contains("show")) return;
  const npcs=presentNpcs().filter(k=>AMBIENT[k]); if(!npcs.length) return;
  const a=npcs[Math.floor(Math.random()*npcs.length)];
  const la=AMBIENT[a][Math.floor(Math.random()*AMBIENT[a].length)];
  ambientBubble(a, la.line, la.em);
  const others=npcs.filter(k=>k!==a);
  if(others.length && Math.random()<0.6){
    const b=others[Math.floor(Math.random()*others.length)];
    const lb=AMBIENT[b][Math.floor(Math.random()*AMBIENT[b].length)];
    setTimeout(()=>{ if(current==="world"&&!$("#playerturn").classList.contains("show")) ambientBubble(b, lb.line, lb.em); }, 2600+Math.random()*800);
  }
}
/* ================= STORY ENGINE ================= */
let curScene=null, chapterActive=false;
function storyPath(){ return (S&&(S.path||S.player))||null; }
function curStory(){ return STORY[storyPath()]; }
function curChapter(){ return curStory().chapters[S.ci]; }

function buildStoryScene(scene){
  curScene=scene; const sc=SCENES[scene];
  if(!S.seen[scene]){ S.seen[scene]=true; award("discover",t(sc.label)); }
  seedFx(sc.fx); loadSceneBg(bg,scene); clearActors(); applyEnv(scene); applyGrade(scene); spawnDiscoveries(scene);
  lastSpeakerKey=null; cameraEstablish();
  addActor(S.player, 50, true); playerX=50; spawnExtras(scene);
  $("#hudLoc").textContent=t(sc.label);
  if(S.sound) startAmbient(scene);
  save(); startWorldLife();
}
function updateObjective(){
  if(!S) return; const ch=curChapter(); if(!ch) return;
  $("#objChapter").textContent=t(UI.chapterWord)+" "+(S.ci+1)+" · "+t(ch.title);
  $("#objGoal").textContent=t(ch.obj);
  $("#objective").classList.add("show");
}
function enterChapter(){
  const ch=curChapter(); if(!ch){ finishStory(); return; }
  buildStoryScene(ch.scene); S.bi=0; save();
  award("chapter", t(ch.title));
  // chapter card
  $("#ccNo").textContent=t(UI.chapterWord)+" "+(S.ci+1);
  $("#ccTitle").textContent=t(ch.title);
  const cc=$("#chaptercard"); cc.classList.add("show");
  updateObjective();
  const startBeats=()=>{ cc.classList.remove("show"); cc.onclick=null; playBeat(); };
  cc.onclick=startBeats;
  setTimeout(()=>{ if(cc.classList.contains("show")) startBeats(); }, 3600);
}
function playBeat(){
  const ch=curChapter(); if(!ch){ finishStory(); return; }
  const beat=ch.beats[S.bi];
  if(!beat){ nextChapter(); return; }
  preloadBeatAudio(S.ci, S.bi);            // warm this + the next beat's clips for gap-free playback
  if(beat.place && beat.place!==curScene){ transitionScene(beat.place, ()=>runBeat(beat)); return; }
  runBeat(beat);
}
function runBeat(beat){
  if(beat.obj){ curChapter().obj=beat.obj; } // rare per-beat objective override
  updateObjective();
  const proceed=()=>{
    if(beat.stage) applyStaging(beat.stage);   // direct the cast on a plain narr/dialog beat (keeps its clip)
    // pre-spawn dialog speakers
    if(beat.dialog){ beat.dialog.forEach(d=>{ if(d.who!=="narrator"&&d.who!==S.player) ensureActor(d.who); }); scheduleSpread(); }
    const afterNarr=()=>{ if(beat.dialog){ runDialog(beat.dialog, ()=> afterBeat(beat)); } else afterBeat(beat); };
    if(beat.narr){ showNarration(beat.narr, afterNarr); }
    else if(beat.dialog){ runDialog(beat.dialog, ()=> afterBeat(beat)); }
    else afterBeat(beat);
  };
  if(beat.cine){ runCine(beat.cine, proceed); } else proceed();
}
function runDialog(list, done){
  let i=0;
  const step=()=>{ if(i>=list.length){ hideBubble(); clearAdvance(); clearLine(); done(); return; }
    const li=i; const d=list[i++];
    if(d.who===S.player) playerTurn(d, li, step);          // the user performs their hero's line (records/speaks)
    else showBubble(d.who, d.line, d.em, step, dlgKey(li)); // other characters auto-play in their own voice
  };
  step();
}

/* ---- the player speaks their own line (voice/type); never AI-voiced ----
   The player's own voice is RECORDED (MediaRecorder), saved, and replayable —
   they perform inside the tale. Their words are never spoken by a synthetic voice. */
let ptRecog=null, ptResolveFn=null, ptLineObj=null;
let mediaRec=null, recChunks=[], ptStream=null, takes={}, curLineKey=null;
/* live recording feedback: analyser-driven waveform, elapsed timer, level meter */
let recCtx=null, recAnalyser=null, recData=null, recRaf=null, recT0=0, recTimerId=null;
function lineKey(){ return S.player+":"+S.ci+":"+S.bi; }
function fmtTime(ms){ const s=Math.floor(ms/1000); return Math.floor(s/60)+":"+String(s%60).padStart(2,"0"); }
function startRecMeter(){
  const cv=$("#ptWave"), rec=$("#ptRec"), tm=$("#ptTimer"); if(!cv) return;
  cv.classList.add("show"); if(rec) rec.classList.add("show");
  recT0=nowMs(); if(tm) tm.textContent="0:00";
  if(recTimerId) clearInterval(recTimerId);
  recTimerId=setInterval(()=>{ if(tm) tm.textContent=fmtTime(nowMs()-recT0); }, 250);
  try{
    const AC=window.AudioContext||window.webkitAudioContext;
    if(AC && ptStream){ recCtx=new AC(); const src=recCtx.createMediaStreamSource(ptStream);
      recAnalyser=recCtx.createAnalyser(); recAnalyser.fftSize=1024; recData=new Uint8Array(recAnalyser.fftSize);
      src.connect(recAnalyser); drawWave(); }
  }catch(e){}
}
function drawWave(){
  const cv=$("#ptWave"); if(!cv||!recAnalyser){ return; }
  const ctx=cv.getContext("2d"), W=cv.width, H=cv.height;
  recAnalyser.getByteTimeDomainData(recData);
  ctx.clearRect(0,0,W,H);
  // mirrored amplitude bars
  const bars=48, step=Math.floor(recData.length/bars); ctx.fillStyle="#e5399b";
  for(let i=0;i<bars;i++){ let peak=0; for(let j=0;j<step;j++){ const v=Math.abs(recData[i*step+j]-128)/128; if(v>peak)peak=v; }
    const bh=Math.max(2, peak*H*0.92), x=i*(W/bars)+2, w=(W/bars)-4, y=(H-bh)/2;
    ctx.globalAlpha=0.55+peak*0.45; ctx.fillRect(x,y,w,bh); }
  ctx.globalAlpha=1;
  recRaf=requestAnimationFrame(drawWave);
}
function stopRecMeter(){
  if(recRaf) cancelAnimationFrame(recRaf); recRaf=null;
  if(recTimerId){ clearInterval(recTimerId); recTimerId=null; }
  if(recCtx){ try{ recCtx.close(); }catch(e){} recCtx=null; } recAnalyser=null;
  const cv=$("#ptWave"), rec=$("#ptRec"); if(cv) cv.classList.remove("show"); if(rec) rec.classList.remove("show");
}
async function startRecording(){
  if(!navigator.mediaDevices||!navigator.mediaDevices.getUserMedia||typeof MediaRecorder==="undefined"){
    $("#ptHint").textContent=t(UI.ptNoMic); return; }
  try{
    if(!ptStream) ptStream=await navigator.mediaDevices.getUserMedia({
      audio:{ echoCancellation:true, noiseSuppression:true, autoGainControl:true } });
    if(mediaRec&&mediaRec.state!=="inactive"){ try{mediaRec.stop();}catch(e){} }
    recChunks=[]; mediaRec=new MediaRecorder(ptStream);
    mediaRec.ondataavailable=e=>{ if(e.data&&e.data.size) recChunks.push(e.data); };
    mediaRec.onstop=()=>{ stopRecMeter();
      if(recChunks.length){ const blob=new Blob(recChunks,{type:mediaRec.mimeType||"audio/webm"});
        const key=curLineKey; if(takes[key]&&takes[key].url){ try{URL.revokeObjectURL(takes[key].url);}catch(e){} }
        takes[key]={url:URL.createObjectURL(blob), dur:nowMs()-recT0}; if(curLineKey===key) showTake(); }
      // if this recording was for the player's turn, continue the story with their take
      if(recForTurn){ recForTurn=false; resolvePlayer(ptLastFinal, !!(takes[curLineKey])); } };
    mediaRec.start(); $("#ptMic").classList.add("rec"); $("#ptHint").textContent=t(UI.ptRecording);
    startRecMeter();
  }catch(e){
    $("#ptHint").textContent=t(UI.ptMicDenied);   // permission refused or no device
  }
}
function stopRecording(){ $("#ptMic").classList.remove("rec"); stopRecMeter();
  if(mediaRec&&mediaRec.state!=="inactive"){ try{mediaRec.stop();}catch(e){} } }
function showTake(){ $("#ptTake").classList.toggle("show", !!(takes[curLineKey])); }
let takeAudio=null;
function playTake(){ const tk=takes[curLineKey]; if(!tk) return; try{ if(takeAudio){takeAudio.pause();} takeAudio=new Audio(tk.url); takeAudio.play(); }catch(e){} }
/* ---- the user performs their chosen hero's line, then the story auto-continues ----
   They can just speak (mic auto-listens) or tap "Say this line". Their own recorded
   voice is played back in sync with the character; a viewer who does nothing is
   never stuck — after a pause the hero's own voice speaks the line. */
let ptDitem=null, ptLi=null, ptNext=null, ptTimeout=null, recForTurn=false, ptLastFinal="", ptDone=false;
function playerTurn(d, li, next){
  hideNarration(); hideBubble();
  ptDitem=d; ptLi=li; ptNext=next; ptDone=false; ptLastFinal="";
  ptLineObj=d.line; curLineKey=lineKey();
  const suggestion=t(d.line);
  $("#ptWho").textContent=nameOf(S.player);
  $("#ptSug").textContent="“"+suggestion+"”";
  $("#ptInput").value=""; $("#ptHint").textContent=t(UI.ptHint);
  $("#playerturn").classList.add("show");
  showTake(); setSpeaking(S.player);
  if(ptTimeout) clearTimeout(ptTimeout);
  // Safety net: a viewer who never engages (or whose mic is denied/unavailable)
  // is never stuck — the turn auto-resolves. But if they are actively recording
  // or speaking when the timer fires, we DON'T cut them off mid-line: we wait and
  // check again, so a slow or thoughtful speaker always gets to finish their line.
  const armPassiveTimeout=()=>{ if(ptTimeout) clearTimeout(ptTimeout);
    ptTimeout=setTimeout(()=>{
      if(ptDone) return;
      const recording=(mediaRec&&mediaRec.state==="recording");
      const speaking=$("#ptMic")&&$("#ptMic").classList.contains("live");
      if(recording||speaking){ armPassiveTimeout(); return; }   // still performing → keep waiting
      resolvePlayer(null,false);                                // truly idle → continue the story
    }, 15000);
  };
  armPassiveTimeout();
  recForTurn=true; startPlayerMic(); startRecording();           // let them just speak their line
}
/* finish the player's turn and continue the story automatically */
function resolvePlayer(spokenText, usedTake){
  if(ptDone) return; ptDone=true;
  if(ptTimeout){ clearTimeout(ptTimeout); ptTimeout=null; }
  recForTurn=false;
  if(ptRecog){ try{ptRecog.stop();}catch(e){} ptRecog=null; }
  if(mediaRec&&mediaRec.state!=="inactive"){ try{mediaRec.stop();}catch(e){} }
  $("#ptMic").classList.remove("live","rec");
  $("#playerturn").classList.remove("show");
  const d=ptDitem, li=ptLi, next=ptNext; ptDitem=null; ptNext=null;
  if(!d){ if(next) next(); return; }
  const tk=takes[curLineKey], typed=(spokenText&&spokenText.trim());
  if(usedTake && tk && tk.url){
    const said = typed ? spokenText.trim() : t(d.line);
    showBubble(S.player, {en:said,ru:said,kk:said}, d.em, next, null, {takeUrl:tk.url});  // the user's own voice
  } else if(typed){
    showBubble(S.player, {en:spokenText.trim(),ru:spokenText.trim(),kk:spokenText.trim()}, d.em, next, null, {silent:true});
  } else {
    // The selected character is NEVER voiced by their own prerecorded/baked voice —
    // every one of their lines belongs to the player's microphone. If the player
    // doesn't record or type (mic denied, or they just watch), we show the assigned
    // line as silent text and let the story continue; we never speak it for them.
    showBubble(S.player, d.line, d.em, next, null, {silent:true});
  }
}
function startPlayerMic(){
  if(!(window.SpeechRecognition||window.webkitSpeechRecognition)){
    $("#ptHint").textContent=t(UI.ptNoMic); return; }
  if(ptRecog){ try{ptRecog.stop();}catch(e){} ptRecog=null; }
  ptRecog=makeRecog(
    (final)=>{ ptLastFinal=final;                     // they finished speaking → stop & continue with their take
      if(mediaRec&&mediaRec.state!=="inactive"){ try{mediaRec.stop();}catch(e){} } else resolvePlayer(final,false); },
    (on,partial)=>{ $("#ptMic").classList.toggle("live",on);
      $("#ptHint").textContent = on? t(UI.ptListening) : t(UI.ptHint);
      if(partial!=null) $("#ptInput").value=partial; });
  try{ ptRecog&&ptRecog.start(); }catch(e){}
}
function togglePlayerMic(){
  if($("#ptMic").classList.contains("rec")||$("#ptMic").classList.contains("live")){
    if(mediaRec&&mediaRec.state!=="inactive"){ try{mediaRec.stop();}catch(e){} } else resolvePlayer(ptLastFinal,false);
  } else { recForTurn=true; startPlayerMic(); startRecording(); } }
function afterBeat(beat){
  hideBubble(); hideNarration();
  logBeat(beat);
  if(beat.act==="shoes"){ effectShoes(()=>advanceBeat()); return; }
  if(beat.act==="depart"){ effectDepart(()=>advanceBeat()); return; }
  if(beat.act==="ride"){ effectRide(()=>advanceBeat()); return; }
  if(beat.act==="gift"){ effectGift(()=>advanceBeat()); return; }
  if(beat.act==="ram"){ effectRam(()=>advanceBeat()); return; }
  if(beat.act==="coat"){ effectCoat(()=>advanceBeat()); return; }
  if(beat.act==="puzzle"){ openPuzzle(()=>advanceBeat()); return; }
  if(beat.act==="riddle"){ openRiddle(beat.riddle,()=>advanceBeat()); return; }
  advanceBeat();
}
function advanceBeat(){ S.bi++; save(); playBeat(); }
function nextChapter(){ S.ci++; S.bi=0; save(); if(S.ci>=curStory().chapters.length){ finishStory(); } else enterChapter(); }

function logBeat(beat){
  // keep a short recap for the Story tab
  let line=null;
  if(beat.narr) line=beat.narr;
  else if(beat.dialog&&beat.dialog.length){ line=beat.dialog[beat.dialog.length-1].line; }
  if(line){ const ch=curChapter(); S.log.push({ch:ch.title, line:line}); if(S.log.length>40) S.log.shift(); save(); }
}

function transitionScene(scene, cb){
  stopWorldLife();
  swellBeds(1.3, 450, 2600);        // music blooms through the transition, then settles
  // cinematic dip: fade audio + a themed wash, rebuild behind it, then reveal
  const dip=$("#dip"); const warm=!(COLD_SCENES&&COLD_SCENES[scene]);
  if(dip){ dip.classList.toggle("warmdip",warm); dip.classList.add("show"); }
  if(master&&S&&S.sound) fadeMaster(0.12,0.45);
  bg.style.opacity="0"; if(findsEl) findsEl.innerHTML="";
  stage.querySelectorAll(".actor,.bubble.ambient").forEach(e=>{ e.style.transition="opacity .5s ease, transform .5s ease"; e.style.opacity="0"; e.style.transform=(e.className.indexOf("actor")>=0?"translateX(-50%) translateY(4%) scale(.97)":"translateY(6px)"); });
  setTimeout(()=>{ buildStoryScene(scene); bg.style.opacity="1";
    if(dip) setTimeout(()=>dip.classList.remove("show"),120);
    if(master&&S&&S.sound) fadeMaster(0.9,1.4);
    if(cb) cb(); }, 640);
}

/* ================= SPECIAL EFFECTS ================= */
function effectShoes(done){ // toss red shoes into the river
  const shoe=document.createElement("div"); shoe.textContent="👟";
  shoe.style.cssText="position:absolute;left:48%;bottom:30%;font-size:34px;z-index:30;transition:all 1.6s ease;";
  stage.appendChild(shoe);
  requestAnimationFrame(()=>{ shoe.style.left="78%"; shoe.style.bottom="24%"; shoe.style.opacity="0"; shoe.style.transform="rotate(60deg)"; });
  sfx("chime"); setTimeout(()=>{ shoe.remove(); done(); }, 1700);
}
function effectDepart(done){ // fly away with the sleigh
  cameraTo(0,-4,1.12,1.8);
  const target = S.player==="queen"?"__player":(actors["kay"]?"kay":"__player");
  const el = actors[target]? actors[target].el : playerActor;
  if(el){ el.style.transition="all 1.8s cubic-bezier(.4,0,.2,1)"; el.style.left="130%"; el.style.bottom="60%"; el.style.opacity="0"; }
  sfx("chime"); setTimeout(()=>{ cameraEstablish(); done(); }, 1900);
}
function effectRide(done){ // ride the reindeer across, then north
  cameraTo(6,0,1.08,1.6);
  const r=actors["reindeer"], p=actors["__player"];
  if(r&&p){ r.el.style.transition=p.el.style.transition="all 1.8s ease"; r.el.style.left="120%"; p.el.style.left="118%"; p.el.style.bottom="30%"; }
  sfx("chime"); setTimeout(()=>{ cameraEstablish(); done(); },1900);
}
function effectGift(done){ // receive a relic-like keepsake: crow_key
  if(S.relics.indexOf("crow_key")<0){ S.relics.push("crow_key"); award("relic", t(RELICS.crow_key.name)); save(); }
  sfx("chime"); setTimeout(done,500);
}
function grantRelic(id){ if(RELICS[id] && S.relics.indexOf(id)<0){ S.relics.push(id); award("relic", t(RELICS[id].name)); save(); } }
function effectRam(done){ // Aldar hoists the fat ram and strolls off
  grantRelic("fat_ram"); cameraTo(6,0,1.1,1.5);
  const p=actors["__player"]; if(p){ p.el.style.transition="all 1.8s ease"; p.el.classList.add("walking"); p.el.style.left="118%"; }
  sfx("dombra"); setTimeout(()=>{ cameraEstablish(); if(p) p.el.classList.remove("walking"); done(); },1700);
}
function effectCoat(done){ // trade coats
  grantRelic("holey_coat"); cameraDrama(); sfx("chime"); setTimeout(()=>{ cameraEstablish(); done(); },900);
}

/* ice puzzle */
let pzWord="", pzIdx=0, pzDone=null;
function openPuzzle(done){
  pzDone=done; cameraDrama();
  pzWord = (t(PUZZLE.word)||"ETERNITY").toUpperCase();
  pzIdx=0;
  $("#pzTitle").textContent = t(PUZZLE.title);
  $("#pzHint").textContent = t(PUZZLE.hint);
  const tgt=$("#pzTarget"); tgt.innerHTML="";
  for(let i=0;i<pzWord.length;i++){ const s=document.createElement("div"); s.className="pz-slot"; s.dataset.i=i; tgt.appendChild(s); }
  const pool=$("#pzPool"); pool.innerHTML="";
  const letters=pzWord.split(""); shuffle(letters);
  letters.forEach((ch,k)=>{ const d=document.createElement("div"); d.className="pz-shard"; d.textContent=ch; d.dataset.ch=ch;
    d.addEventListener("click",()=>tapShard(d,ch)); pool.appendChild(d); });
  $("#puzzle").classList.add("show");
  // "the shards of ice rose up and spelled the word themselves" — if the reader
  // doesn't, the ice completes the word on its own so the film flows to its end.
  if(pzAutoTimer) clearTimeout(pzAutoTimer);
  pzAutoTimer=setTimeout(pzAutoStep, 4200);
}
let pzAutoTimer=null;
function pzAutoStep(){
  if(!$("#puzzle").classList.contains("show") || pzIdx>=pzWord.length) return;
  const need=pzWord[pzIdx];
  const shard=[...document.querySelectorAll('#pzPool .pz-shard:not(.used)')].find(d=>d.dataset.ch===need);
  if(shard) tapShard(shard, need);
  if(pzIdx<pzWord.length) pzAutoTimer=setTimeout(pzAutoStep, 620);
}
function shuffle(a){ for(let i=a.length-1;i>0;i--){ const j=Math.floor((i+1)*fakeRand(i)); const tmp=a[i];a[i]=a[j];a[j]=tmp; } return a; }
let _seed=7; function fakeRand(i){ _seed=(_seed*9301+49297+i)%233280; return _seed/233280; }
function tapShard(el,ch){
  const need=pzWord[pzIdx];
  if(ch===need){ el.classList.add("used"); const slot=$('#pzTarget .pz-slot[data-i="'+pzIdx+'"]');
    if(slot){ slot.textContent=ch; slot.classList.add("filled"); } pzIdx++; sfx("chime");
    if(pzIdx>=pzWord.length){ award("puzzle", pzWord); setTimeout(closePuzzle, 900); } }
  else { el.animate([{transform:"translateX(-4px)"},{transform:"translateX(4px)"},{transform:"translateX(0)"}],{duration:220}); }
}
function closePuzzle(){ if(pzAutoTimer){ clearTimeout(pzAutoTimer); pzAutoTimer=null; } $("#puzzle").classList.remove("show"); cameraEstablish(); const d=pzDone; pzDone=null; if(d) d(); }

/* wit-riddle mechanic (multiple choice) — the Aldar-flavoured "puzzle" */
let rdDone=null;
function openRiddle(riddle, done){
  rdDone=done; cameraDrama();
  const rd=riddle||{q:PUZZLE.title,opts:[{t:PUZZLE.word,ok:true}]};
  $("#rdTag").textContent=t(PUZZLE.title);
  $("#rdQ").textContent=t(rd.q);
  const box=$("#rdOpts"); box.innerHTML="";
  const opts=rd.opts.slice(); shuffle(opts);
  opts.forEach(o=>{ const b=document.createElement("div"); b.className="rd-opt"; b.textContent=t(o.t);
    b.addEventListener("click",()=>{ if(o.ok){ b.classList.add("right"); award("puzzle", t(PUZZLE.word));
        sfx("chime"); setTimeout(closeRiddle,850); }
      else { b.classList.add("wrong"); sfx("talk"); setTimeout(()=>b.classList.remove("wrong"),450); } });
    box.appendChild(b); });
  $("#riddle").classList.add("show");
}
function closeRiddle(){ $("#riddle").classList.remove("show"); cameraEstablish(); const d=rdDone; rdDone=null; if(d) d(); }

/* ================= FREE INPUT ================= */
function submitPrompt(text){ text=(text||$("#promptInput").value||"").trim(); if(!text) return;
  $("#promptInput").value=""; closePrompt();
  // player line as a bubble
  showBubble(S.player, {en:text,ru:text,kk:text}, "resolve", ()=>{});
  const npc=Object.keys(actors).find(k=>k!=="__player");
  if(npc){ if(!S.met[npc]){S.met[npc]=1; save();}
    const host=window.claude&&typeof window.claude.complete==="function";
    if(host) aiReply(npc,text); else setTimeout(()=>{ /* stay quiet, characters lead the story */ }, 300);
  } else { toast(t(UI.narrator), t(UI.noOneNear)); }
}
async function aiReply(key,userText){
  const host=window.claude&&typeof window.claude.complete==="function"; if(!host) return;
  try{ const ch=curChapter();
    const prompt="You are "+nameOf(key)+" in Hans Christian Andersen's The Snow Queen. The player is "+nameOf(S.player)+
      ". Current chapter: "+t(ch.title)+". The player said: \""+userText+"\". Reply with ONE short in-character line (max 16 words) in "+
      (lang==="ru"?"Russian":lang==="kk"?"Kazakh":"English")+". No narration, no quotes.";
    const out=await window.claude.complete(prompt);
    let line=(out||"").trim().replace(/^["']|["']$/g,"").split("\n")[0].slice(0,140);
    if(line){ setTimeout(()=> showBubble(key,{en:line,ru:line,kk:line},"warm",()=>{}), 700); }
  }catch(e){}
}
function openPrompt(){ $("#promptbar").classList.add("show"); $("#promptInput").focus(); }
function closePrompt(){ $("#promptbar").classList.remove("show"); }

/* ================= ACHIEVEMENTS ================= */
function award(kind,label){ let head;
  if(kind==="discover") head=UI.achDiscover; else if(kind==="met") head=UI.achMet; else if(kind==="chapter") head=UI.achChapter;
  else if(kind==="relic") head=UI.relicsHead; else if(kind==="puzzle") head=UI.achPuzzle; else if(kind==="end") head=UI.achEnd;
  else if(kind==="memory") head=UI.achMemory; else if(kind==="scenememories") head=UI.memScene; else if(kind==="allmemories") head=UI.memAll;
  else head=UI.narrator;
  toast(t(head), label); sfx(kind==="memory"||kind==="scenememories"||kind==="allmemories"?"sparkle":"chime"); }
function toast(head,label){ const el=document.createElement("div"); el.className="toast";
  const ic=head===t(UI.relicsHead)?"🌟":head===t(UI.achDiscover)?"🗺":head===t(UI.achMet)?"🤝":head===t(UI.achPuzzle)?"❄":head===t(UI.achChapter)?"📖"
    :head===t(UI.achMemory)?"💠":head===t(UI.memScene)?"❄":head===t(UI.memAll)?"👑":"✦";
  el.innerHTML='<div class="ic">'+ic+'</div><div class="tx"><b>'+head+'</b><span>'+label+'</span></div>';
  $("#toasts").appendChild(el); requestAnimationFrame(()=>el.classList.add("show"));
  setTimeout(()=>{ el.classList.remove("show"); setTimeout(()=>el.remove(),600); },3000); }

/* ================= MENU SHEET ================= */
const sheet=$("#sheet"); let sheetTab="story";   /* Journal feature removed */
function openSheet(){ /* Journal removed */ }
function closeSheet(){ if(sheet) sheet.classList.remove("on"); }
function renderSheet(){ const body=$("#parchBody");
  if(sheetTab==="story"){ let h="<h4>"+t(UI.storySoFar)+"</h4>";
    if(!S.log.length){ h+='<div class="empty">…</div>'; }
    else { const recent=S.log.slice(-8); recent.forEach(e=> h+='<div class="entry"><div class="h">'+t(e.ch)+'</div><div class="d">'+t(e.line)+'</div></div>'); }
    const names=Object.keys(S.met).map(k=>nameOf(k));
    h+='<div class="entry"><div class="h">'+t(UI.soulsMet)+' — '+names.length+'</div><div class="d">'+(names.join(", ")||t(UI.none))+'</div></div>';
    body.innerHTML=h;
  } else if(sheetTab==="memories"){ const tot=totalFinds(); const got=foundCount();
    let h="<h4>"+t(UI.memHead)+" — "+got+"/"+tot+"</h4>";
    const items=[]; for(const sc in (DISCOVER||{})) DISCOVER[sc].forEach(d=>{ if(S.found&&S.found[d.id]) items.push(d); });
    if(!items.length){ h+='<div class="empty">'+t(UI.memEmpty)+'</div>'; }
    else { items.forEach(d=> h+='<div class="entry"><div class="h">'+d.ic+' '+t(d.name)+'</div><div class="d">'+t(d.text)+'</div></div>');
      if(got<tot) h+='<div class="entry"><div class="d" style="opacity:.7;font-style:italic">'+t(UI.memHint)+'</div></div>'; }
    body.innerHTML=h;
  } else if(sheetTab==="relics"){ let h="<h4>"+t(UI.relicsHead)+" — "+S.relics.length+"</h4>";
    if(!S.relics.length){ h+='<div class="empty">'+t(UI.relicsEmpty)+'</div>'; }
    else { h+='<div class="relics">'; S.relics.forEach(r=>{ const a=loadArt(r), rl=RELICS[r];
      h+='<div class="relic"><img data-remote="'+(a.remote||"")+'" src="'+a.local+'" onerror="artFallback(this)"/><div class="rn">'+t(rl.name)+'</div><div class="rd">'+t(rl.lore)+'</div></div>'; });
      h+='</div>'; }
    body.innerHTML=h;
  } else { body.innerHTML='<h4>'+t(UI.mapHead)+'</h4><canvas id="mapCanvas"></canvas><div class="map-hint">'+t(UI.mapHint)+'</div>'; drawMap(); }
}
function artFallback(img){ if(img.dataset.stage==="remote"||!img.dataset.remote){ img.style.background="#c9b184"; img.removeAttribute("src"); return; }
  img.dataset.stage="remote"; img.src=img.dataset.remote; }
window.artFallback=artFallback;

const SNOW_MAP_POS={ attic:[20,16],village:[28,30],river:[42,44],garden:[58,58],palacehall:[74,50],camp:[40,64],
  mountains:[58,34],lapland:[72,24],finland:[80,14],palace:[64,8],clockwork_chapel:[50,6],forest:[34,48],wishing_well:[16,44],aurora_tent:[86,30] };

/* interactive discoveries: hidden things to tap in each scene for extra Andersen lore + a collected "memory" */
const SNOW_DISCOVERIES={
  attic:[
    {id:"a_roses",x:26,y:26,ic:"🌹",name:L("The Rose Boxes","Ящики с розами","Раушан жәшіктері"),text:L("Gerda and Kai's window boxes reached across the gutter, and their roses grew into one blooming arch. In summer the children stepped across and sat among the flowers.","Ящики Герды и Кая тянулись через жёлоб, и розы срослись в единую цветущую арку. Летом дети переходили друг к другу и сидели среди цветов.","Герда мен Кайдың терезе жәшіктері науа арқылы жалғасып, раушандары бір гүлді доғаға айналды. Жазда балалар бір-біріне өтіп, гүл арасында отыратын.")},
    {id:"a_frost",x:71,y:30,ic:"❄️",name:L("Frost Flowers","Морозные цветы","Аяз гүлдері"),text:L("Grandmother said the frost painted flowers on the glass. Kai would warm a copper coin on the stove and press it to the ice to peer through the little thaw-hole.","Бабушка говорила, что мороз рисует на стекле цветы. Кай грел медную монету на печке и прикладывал ко льду, чтобы взглянуть в проталинку.","Әже аяз әйнекке гүл салады дейтін. Кай мыс тиынды пеште жылытып, мұзға басып, кішкене тесіктен қарайтын.")},
    {id:"a_stove",x:16,y:50,ic:"🔥",name:L("Grandmother's Stove","Печка бабушки","Әженің пеші"),text:L("By the warm stove Grandmother told the tale of the Snow Queen, who rules the swarming snowflakes and flies where they crowd most thickly.","У тёплой печки бабушка рассказывала о Снежной королеве, что правит роем снежинок и летит там, где их гуще всего.","Жылы пеш жанында әже Қар ханшайымы туралы айтатын — ол қар үлпегін билеп, олар қалың жерде ұшады.")}],
  village:[
    {id:"v_sled",x:22,y:48,ic:"🛷",name:L("The Little Sleds","Санки","Шаналар"),text:L("Bold boys tied their sleds to farmers' carts to be pulled across the square. Kai tied his to a great white sleigh — and it carried him away into the storm.","Смелые мальчишки привязывали санки к возам, чтобы прокатиться по площади. Кай привязал свои к большим белым саням — и они унесли его в метель.","Батыл балалар шаналарын арбаға байлап, алаңмен тартылатын. Кай шанасын үлкен ақ шанаға байлады — ол оны боранға алып кетті.")},
    {id:"v_mirror",x:74,y:26,ic:"🪞",name:L("The Goblin's Mirror","Зеркало тролля","Тролль айнасы"),text:L("An evil goblin forged a mirror that shrank all that was good and swelled all that was vile. It shattered into millions of splinters: one in the eye makes the world look ugly, one in the heart turns it to ice.","Злой тролль выковал зеркало, что уменьшало доброе и увеличивало злое. Оно разбилось на миллионы осколков: в глазу — и мир кажется уродливым, в сердце — и оно леденеет.","Зұлым тролль жақсыны кішірейтіп, жаманды үлкейтетін айна жасады. Ол миллион сыныққа шашырады: көзге түссе — әлем ұсқынсыз, жүрекке түссе — ол мұздай қатады.")},
    {id:"v_square",x:50,y:21,ic:"🌨️",name:L("The Frozen Square","Замёрзшая площадь","Қатқан алаң"),text:L("Snow whirled through the market square until the people stood as still as statues. The Snow Queen's silent sleigh circled twice before it stopped beside Kai.","Снег кружил по площади, пока люди не застыли, как статуи. Безмолвные сани королевы дважды объехали площадь и встали возле Кая.","Қар алаңды айналып, адамдар мүсіндей қатып қалды. Ханшайымның үнсіз шанасы екі айналып, Кайдың қасына тоқтады.")}],
  river:[
    {id:"r_boat",x:24,y:52,ic:"🛶",name:L("The Little Boat","Лодочка","Кішкентай қайық"),text:L("A boat lay loose at the bank. Gerda climbed in to ask the river for Kai, and the current carried her gently downstream, past green banks she had never seen.","У берега стояла незакреплённая лодка. Герда села в неё, чтобы спросить у реки о Кае, и течение понесло её мимо невиданных зелёных берегов.","Жағада босаған қайық тұрды. Герда Кайды сұрауға оған отырды, ағын оны бұрын көрмеген жасыл жағалаулардан алып жүрді.")},
    {id:"r_shoes",x:68,y:44,ic:"👟",name:L("The Red Shoes","Красные башмачки","Қызыл башмақ"),text:L("Gerda offered the river her most precious things — her new red shoes — if only it would bring Kai back. Love gives away what it treasures most.","Герда предложила реке самое дорогое — новые красные башмачки — лишь бы вернуть Кая. Любовь отдаёт то, что ей всего дороже.","Герда Кайды қайтарса, ең қымбатын — жаңа қызыл башмағын — өзенге ұсынды. Махаббат ең асылын қиып береді.")},
    {id:"r_roses",x:45,y:30,ic:"🌹",name:L("The Buried Roses","Спрятанные розы","Жасырын раушандар"),text:L("The magic gardener sank every rose beneath the earth so Gerda would forget Kai. But her tears woke them, and the roses whispered that he was not among the dead.","Волшебница спрятала все розы под землю, чтобы Герда забыла Кая. Но её слёзы разбудили их, и розы шепнули, что его нет среди мёртвых.","Сиқыршы Герда Кайды ұмытсын деп раушандарды жер астына жасырды. Бірақ жасы оларды оятты, раушандар оның өлілер арасында жоқ екенін сыбырлады.")}],
  garden:[
    {id:"g_hat",x:72,y:34,ic:"🎩",name:L("The Flower Hat","Шляпа с цветами","Гүлді қалпақ"),text:L("The old woman's straw hat was painted with flowers — and among them a single rose, the one bloom she forgot to hide. It broke the whole enchantment.","Соломенная шляпа старушки была расписана цветами, и среди них — одна роза, единственная, что она забыла спрятать. Она разрушила всё колдовство.","Кемпірдің сабан қалпағы гүлмен боялған — арасында жасыруды ұмытқан жалғыз раушан. Ол бүкіл сиқырды бұзды.")},
    {id:"g_flowers",x:26,y:46,ic:"🌷",name:L("What the Flowers Say","О чём говорят цветы","Гүлдер не дейді"),text:L("Each flower in the garden told Gerda its own small dream, but none had seen Kai. Only the roses, risen from the dark earth, still remembered him.","Каждый цветок рассказывал Герде свою мечту, но никто не видел Кая. Лишь розы, поднявшись из тёмной земли, помнили о нём.","Бақтағы әр гүл Гердаға өз арманын айтты, бірақ ешбірі Кайды көрмепті. Тек қара жерден көтерілген раушандар оны есінде сақтаған.")}],
  palacehall:[
    {id:"p_crown",x:70,y:26,ic:"👑",name:L("The Clever Suitor","Умный жених","Ақылды күйеу"),text:L("A princess longed for a husband who could truly speak for himself. Of a hundred fine talkers, only a bright-eyed boy was not afraid — but he was not Kai.","Принцесса мечтала о муже, что умеет говорить сам за себя. Из сотни краснобаев не робел лишь один смышлёный юноша — но это был не Кай.","Ханшайым өзі сөйлей алатын күйеу аңсады. Жүз шешеннің ішінде тек көзі оттай бір жігіт именбеді — бірақ ол Кай емес еді.")},
    {id:"p_coach",x:28,y:44,ic:"🐴",name:L("The Golden Coach","Золотая карета","Алтын күйме"),text:L("The prince and princess gave Gerda a coach of pure gold, warm boots and a fur muff, and sent her onward toward the frozen north.","Принц и принцесса подарили Герде карету из чистого золота, тёплые сапожки и муфту и отправили её дальше на мёрзлый север.","Ханзада мен ханшайым Гердаға таза алтын күйме, жылы етік пен тон қолғап сыйлап, оны мұзды солтүстікке аттандырды.")}],
  camp:[
    {id:"c_knife",x:24,y:44,ic:"🗡️",name:L("The Robber Girl","Разбойница","Қарақшы қыз"),text:L("Wild and lonely, the little robber girl kept a whole menagerie and a knife at her belt. She spared Gerda because she was brave — then gave her the reindeer.","Дикая и одинокая, маленькая разбойница держала целый зверинец и нож за поясом. Она пощадила Герду за храбрость — и отдала ей оленя.","Асау әрі жалғыз кішкентай қарақшы қыз тұтас хайуанат пен белінде пышақ ұстайтын. Батылдығы үшін Герданы аяп, оған бұғысын берді.")},
    {id:"c_doves",x:72,y:28,ic:"🕊️",name:L("The Wood-Pigeons","Лесные голуби","Орман көгершіндері"),text:L("High in the robbers' loft the wood-pigeons cooed a secret: they had seen Kai in the Snow Queen's sleigh, borne north over the treetops toward Lapland.","Под кровлей разбойников голуби проворковали тайну: они видели Кая в санях королевы, летящих на север над лесом, к Лапландии.","Қарақшылар шатырында көгершіндер құпия сыбырлады: олар Кайды ханшайым шанасында, орман үстімен солтүстікке, Лапландияға ұшып бара жатқанын көрген.")}],
  lapland:[
    {id:"l_cod",x:26,y:42,ic:"🐟",name:L("The Cod-Letter","Письмо на треске","Балықтағы хат"),text:L("The Lapland woman had no paper, so she wrote to the wise Finland woman on a dried cod — who read the letter three times until she knew it by heart, then boiled it for soup.","У лапландки не было бумаги, и она написала финке на сушёной треске — та трижды прочла письмо, выучила наизусть, а потом сварила из рыбы суп.","Лапландиялық әйелде қағаз болмай, ол ақылды финляндиялық әйелге кептірілген балыққа хат жазды — ол хатты жатқа білгенше үш рет оқып, сосын одан сорпа қайнатты.")},
    {id:"l_deer",x:72,y:34,ic:"🦌",name:L("The Reindeer","Северный олень","Бұғы"),text:L("Born in the far north, the reindeer knew every mile of snow. He ran with Gerda on his back to the very edge of the Snow Queen's land.","Рождённый на дальнем севере, олень знал каждую версту снегов. Он мчал Герду на спине до самого края владений королевы.","Алыс солтүстікте туған бұғы қардың әр шақырымын білетін. Ол Герданы арқасына салып, ханшайым жерінің шетіне дейін шапты.")}],
  finland:[
    {id:"f_heart",x:50,y:36,ic:"💗",name:L("Her Only Power","Её единственная сила","Оның жалғыз күші"),text:L("The Finland woman refused to give Gerda any charm. Her power was already the greatest in the world, she said — the innocence and love of a child's own heart.","Финка отказалась дать Герде волшебство. Её сила и так величайшая на свете, сказала она, — невинность и любовь детского сердца.","Финляндиялық әйел Гердаға сиқыр беруден бас тартты. Оның күші әлемдегі ең зоры — бала жүрегінің пәктігі мен махаббаты, деді ол.")}],
  palace:[
    {id:"q_lake",x:30,y:40,ic:"🧊",name:L("The Mirror of Reason","Зеркало разума","Ақыл айнасы"),text:L("In the middle of the frozen lake Kai pushed flat shards of ice, trying to spell one word — 'eternity'. The Snow Queen had promised him the whole world if he could, but the cold could never complete it.","Посреди замёрзшего озера Кай двигал плоские льдинки, силясь сложить одно слово — «вечность». Королева обещала ему весь мир, но холод не мог его сложить.","Қатқан көлдің ортасында Кай жалпақ мұз бөлшектерін жылжытып, бір сөз құрамақ болды — «мәңгілік». Ханшайым оған бүкіл әлемді уәде еткен, бірақ суық оны бітіре алмады.")},
    {id:"q_tear",x:68,y:44,ic:"💧",name:L("The Melting","Оттепель","Еру"),text:L("Gerda's warm tears fell on Kai's breast and sank to his heart, melting the ice and washing away the splinter. He wept too, and the glass ran from his eye — and he knew her at last.","Тёплые слёзы Герды упали Каю на грудь и проникли в сердце, растопив лёд и смыв осколок. Он тоже заплакал, стёклышко вышло из глаза — и он наконец узнал её.","Герданың ыстық жасы Кайдың кеудесіне тамып, жүрегіне жетті, мұзды еріткен ол сынықты жуып тастады. Кай да жылап, шыны көзінен шықты — ол ақыры оны таныды.")}]
};

/* ================= FAIRYTALE LIBRARY: content packs ================= */
/* Each tale is a self-contained package on the same reusable engine. */
const SNOW = { id:"snow_queen",
  meta:{ title:L("The Snow Queen","Снежная королева","Қар ханшайымы"),
    desc:L("Andersen's winter epic — a girl crosses the frozen world to melt the ice in her dearest friend's heart.","Зимний эпос Андерсена — девочка идёт через мёрзлый мир, чтобы растопить лёд в сердце друга.","Андерсеннің қысқы дастаны — қыз досының жүрегіндегі мұзды еріту үшін мұзды әлемді кезеді."),
    len:L("25–40 min","25–40 мин","25–40 мин"), diff:L("Gentle","Спокойная","Жеңіл"), chars:3,
    coverGrad:["#2a3f6b","#0a1024"], coverArt:"title", fx:"snow" },
  puzzle:{ word:L("ETERNITY","ВЕЧНОСТЬ","МӘҢГІЛІК"),
    title:L("The Ice Puzzle","Ледяная загадка","Мұз жұмбағы"),
    hint:L("Arrange the ice shards to spell the word.","Сложите осколки льда, чтобы получилось слово.","Сөзді құрау үшін мұз сынықтарын орналастырыңыз.") },
  scenes:SNOW_SCENES, names:SNOW_NAME, relics:SNOW_RELICS, story:SNOW_STORY, playable:SNOW_PLAYABLE,
  narration:SNOW_NARRATION, discoveries:SNOW_DISCOVERIES, baked:SNOW_BAKED, bakedNarr:SNOW_BAKED_NARR,
  assets:SNOW_ASSETS, voices:SNOW_VOICE_PROFILE, persona:SNOW_PERSONA, ambient:SNOW_AMBIENT, extras:SNOW_EXTRAS,
  env:SNOW_ENV, mood:SNOW_SCENE_MOOD, flavor:SNOW_SCENE_FLAVOR, cold:SNOW_COLD_SCENES, map:SNOW_MAP_POS,
  crowd:{ villager:"https://d8j0ntlcm91z4.cloudfront.net/user_2xUTZyOrgpbyqY4CQUTF1CKWnQy/hf_20260702_131610_62711659-2857-4620-8897-1934010abcd4.png",
          child:"https://d8j0ntlcm91z4.cloudfront.net/user_2xUTZyOrgpbyqY4CQUTF1CKWnQy/hf_20260702_131619_ecad6a44-d971-4eba-b225-8da33b65d7ae.png" } };

/* engine reads these mutable bindings; useTale() points them at the chosen pack */
let SCENES,NAME,RELICS,STORY,PLAYABLE,ASSETS,VOICE_PROFILE,PERSONA,AMBIENT,EXTRAS,ENV,SCENE_MOOD,SCENE_FLAVOR,COLD_SCENES,MAP_POS,PUZZLE,NARRATION,DISCOVER,BAKED,BAKED_NARR,T=null;
function useTale(p){ T=p; SCENES=p.scenes;NAME=p.names;RELICS=p.relics;STORY=p.story;PLAYABLE=p.playable;ASSETS=p.assets;
  VOICE_PROFILE=p.voices;PERSONA=p.persona;AMBIENT=p.ambient;EXTRAS=p.extras;ENV=p.env;SCENE_MOOD=p.mood;
  SCENE_FLAVOR=p.flavor;COLD_SCENES=p.cold;MAP_POS=p.map;PUZZLE=p.puzzle;NARRATION=p.narration||null;DISCOVER=p.discoveries||{};
  BAKED=p.baked||null; BAKED_NARR=p.bakedNarr||null;   // per-tale offline voice packs
  try{ document.getElementById("app").setAttribute("data-tale", p.id); }catch(e){}
  try{ const th=(p.theme||{}); const r=document.documentElement.style;
    ["--frost","--frost-dim","--amber","--amber-deep","--midnight","--deep"].forEach(k=>{ if(th[k]) r.setProperty(k,th[k]); else r.removeProperty(k); }); }catch(e){}
  try{assignVoices();}catch(e){} }
