const ALDAR_DISCOVERIES={
  aul:[
    {id:"al_yurt",x:26,y:40,ic:"⛺",name:L("The Yurt","Юрта","Киіз үй"),text:L("A yurt can be raised or struck in an hour and carried on a single camel. Its round felt walls hold off the steppe's summer heat and its winter cold alike.","Юрту можно собрать или разобрать за час и увезти на одном верблюде. Круглые войлочные стены хранят и от летнего зноя, и от зимней стужи.","Киіз үйді бір сағатта тігіп не жығып, бір түйеге артуға болады. Дөңгелек киіз қабырғасы жаздың ыстығынан да, қыстың суығынан да қорғайды.")},
    {id:"al_dombra",x:70,y:34,ic:"🪕",name:L("The Dombra","Домбра","Домбыра"),text:L("Two strings and a hollow wooden body — the dombra carries the whole voice of the steppe. A good küy can say what a hundred words cannot.","Две струны и полый деревянный корпус — домбра несёт весь голос степи. Хороший кюй скажет то, чего не выразить и сотней слов.","Екі ішек пен қуыс ағаш шанақ — домбыра даланың бүкіл үнін жеткізеді. Жақсы күй жүз сөз айта алмағанды айтады.")}],
  market:[
    {id:"al_melon",x:30,y:44,ic:"🍈",name:L("Steppe Melons","Степные дыни","Дала қауыны"),text:L("The bazaar's melons are sweeter than honey. A clever trader weighs with one hand and flatters with the other — but Aldar can out-talk any of them.","Дыни на базаре слаще мёда. Ловкий торговец одной рукой взвешивает, другой льстит — но Алдара не переговоришь.","Базардың қауыны балдан тәтті. Айлакер саудагер бір қолымен таразылап, екіншісімен мақтайды — бірақ Алдарды сөзден жеңе алмайсың.")},
    {id:"al_carpet",x:72,y:40,ic:"🧶",name:L("The Carpet","Ковёр","Кілем"),text:L("Every woven pattern has a name and a meaning — ram's horns for plenty, running water for life. A dowry carpet can take a girl a whole year to weave.","У каждого узора есть имя и смысл — бараньи рога к достатку, бегущая вода к жизни. Ковёр-приданое девушка ткёт целый год.","Әр өрнектің аты мен мәні бар — қошқар мүйіз молшылыққа, аққан су өмірге. Жасау кілемін қыз бір жыл тоқиды.")}],
  steppe:[
    {id:"al_eagle",x:60,y:24,ic:"🦅",name:L("The Golden Eagle","Беркут","Бүркіт"),text:L("Steppe hunters raise golden eagles from chicks, then free them after years of service. The trust between hunter and bird is a matter of honour.","Степные охотники растят беркутов с птенцов и через годы отпускают на волю. Доверие между охотником и птицей — дело чести.","Дала аңшылары бүркітті балапанынан өсіріп, жылдар өткен соң бостандыққа жібереді. Аңшы мен құстың сенімі — ар ісі.")},
    {id:"al_horse",x:34,y:48,ic:"🐎",name:L("The Horse","Конь","Жылқы"),text:L("On the steppe a man without a horse is a man without legs. The finest racer is called a 'tulpar' — one that seems to fly above the grass.","В степи человек без коня — человек без ног. Лучшего скакуна зовут «тулпар» — тот, что будто летит над травой.","Далада атсыз адам — аяқсыз адам. Ең жүйрікті «тұлпар» дейді — шөп үстінен ұшып бара жатқандай.")}]
};
const ALDAR_PLAYABLE = [
  {key:"aldar", name:ALDAR_NAME.aldar, role:L("The Beardless Trickster","Безбородый хитрец","Сақалсыз айлакер"),
   power:L("Your wit is sharper than any knife. You see the greed in others — and turn it gently against them until the fattest ram walks home on your shoulders.","Твой ум острее любого ножа. Ты видишь жадность в других — и мягко обращаешь её против них, пока самый жирный баран не окажется у тебя на плечах.","Ақылың кез келген пышақтан өткір. Өзгенің сараңдығын көресің — оны жайлап оларға қарсы бұрып, ең семіз қой иығыңда үйге қайтады.")},
  {key:"shepherd", name:ALDAR_NAME.shepherd, role:L("The Apprentice","Ученик","Шәкірт"),
   power:L("You are poor in sheep but quick to learn. Follow Aldar across the steppe, and his cleverness will slowly become your own.","Ты беден овцами, но быстро учишься. Иди за Алдаром по степи, и его смекалка постепенно станет твоей.","Қойың аз, бірақ тез үйренесің. Алдардың соңынан ерсең, оның айласы бірте-бірте сенікі болады.")},
  {key:"bai", name:ALDAR_NAME.bai, role:L("The Greedy Bai","Жадный бай","Сараң бай"),
   power:L("You have flocks, gold and a fine fox-fur coat — and a bottomless greed that Aldar Köse knows far too well.","У тебя стада, золото и роскошная лисья шуба — и бездонная жадность, которую Алдар Косе знает слишком хорошо.","Малың, алтының, әдемі түлкі тоның бар — және Алдар Көсе тым жақсы білетін түпсіз сараңдық.")}
];
const ALDAR_STORY = {
 aldar:{
  ending:{ title:L("The Poorest, Happiest Man on the Steppe","Беднейший и счастливейший человек в степи","Даладағы ең кедей әрі ең бақытты жан"),
    text:L("Aldar shared the ram, the coat and the shaitans' gold among the poor of the aul, and kept for himself only the laughter. That night the dombra played until dawn. And so the beardless trickster stayed the poorest and the happiest man on the whole steppe — while the misers, one after another, never did learn.",
      "Алдар раздал барана, шубу и золото шайтанов беднякам аула, а себе оставил лишь смех. В ту ночь домбра играла до рассвета. Так безбородый хитрец и остался беднейшим и счастливейшим человеком во всей степи — а скряги, один за другим, так ничему и не научились.",
      "Алдар қой мен тон, шайтандардың алтынын ауылдың кедейлеріне таратып, өзіне тек күлкіні қалдырды. Сол түні домбыра таң атқанша ойнады. Сөйтіп сақалсыз айлакер бүкіл даладағы ең кедей әрі ең бақытты адам болып қала берді — ал сараңдар бірінен соң бірі еш нәрсеге үйренбеді.") },
  chapters:[
   { title:L("The Beardless Trickster","Безбородый хитрец","Сақалсыз айлакер"), scene:"aul",
     obj:L("Meet Aldar Köse and the people of the aul","Познакомьтесь с Алдаром Косе и людьми аула","Алдар Көсе мен ауыл жұртымен таныс"),
     beats:[
      {narr:L("In a certain aul on the wide steppe there lived a beardless trickster named Aldar Köse. His eyes were sharp, his feet were quick, his hands were nimble — and his wit was nimbler still.",
        "В одном ауле на широкой степи жил безбородый хитрец по имени Алдар Косе. Глаза у него были острые, ноги быстрые, руки проворные — а ум ещё проворнее.",
        "Кең даладағы бір ауылда Алдар Көсе атты сақалсыз айлакер өмір сүрді. Көзі өткір, аяғы жүйрік, қолы ұғырлы — ал ақылы одан да ұғырлы еді.")},
      {narr:L("He owned no riches at all. Yet he loved nothing better than to tease and outwit the fools and the misers — and by his cunning alone he never once went without a fat ram for his supper.",
        "Богатства у него не было вовсе. Но больше всего он любил подшучивать над глупцами и скрягами и обводить их вокруг пальца — и одной лишь хитростью никогда не оставался без жирного барана на ужин.",
        "Байлығы мүлде жоқ-ты. Бірақ ол ақымақтар мен сараңдарды мазақтап, алдап кетуді бәрінен жақсы көретін — тек айласымен ешқашан кешкі асқа семіз қойсыз қалмайтын.")},
      {dialog:[
        {who:"shepherd",em:"warm",line:L("Aldar! You are smiling again. Whose sheep will be yours by sundown this time?","Алдар! Ты снова улыбаешься. Чьи овцы станут твоими к закату на этот раз?","Алдар! Тағы жымиып тұрсың. Бұл жолы кімнің қойы кешке сенікі болады?")},
        {who:"aldar",em:"warm",line:L("Only the ones a greedy man is too greedy to keep, little brother. Watch and learn.","Только те, что жадный слишком жаден, чтобы удержать, братишка. Смотри и учись.","Тек сараң адам сараңдығынан ұстай алмайтындары ғана, бауырым. Қарап үйрен.")},
        {who:"granny",em:"gentle",line:L("Leave old Zhatyrbai a sheep or two, you rascal — though heaven knows he would not do the same for you.","Оставь старому Жатырбаю овцу-другую, проказник, хоть он-то для тебя и пальцем не шевельнёт.","Кәрі Жатырбайға бір-екі қой қалдыр, шумақ, ол саған қолын да қимылдатпайтынын құдай біледі.")}
      ]}
     ]},
   { title:L("Two Rubles and a Fat Ram","Два рубля и жирный баран","Екі сом мен семіз қой"), scene:"bai_yurt",
     obj:L("Watch how Aldar turns two rubles into the fattest ram","Посмотрите, как Алдар превращает два рубля в жирного барана","Алдар екі сомды семіз қойға қалай айналдыратынын көр"),
     beats:[
      {narr:L("One day Aldar came to the great tent of the greedy Bai Zhatyrbai, holding two silver rubles tight in his fist.",
        "Однажды Алдар пришёл к большой юрте жадного бая Жатырбая, крепко зажав в кулаке два серебряных рубля.",
        "Бірде Алдар сараң Жатырбай байдың үлкен киіз үйіне екі күміс сомды жұдырығына қатты қысып келді.")},
      {dialog:[
        {who:"aldar",em:"warm",line:L("Honoured bai, I have two rubles but no purse. My hand is tired of holding them. Help me be rid of them — sell me some poor little goat-kid for two rubles.","Почтенный бай, у меня два рубля, а кошелька нет. Рука устала их держать. Помоги мне от них избавиться — продай мне за два рубля какого-нибудь плохонького козлёнка.","Құрметті бай, екі сомым бар, әмиянім жоқ. Ұстай-ұстай қолым талды. Одан құтылуға көмектес — екі сомға бір нашар лақ сатшы.")},
        {who:"bai",em:"bold",line:L("Ha! Gladly, gladly! Two rubles for a kid — a fine bargain. Here, take this one.","Ха! С радостью, с радостью! Два рубля за козлёнка — славная сделка. Вот, бери этого.","Ха! Қуана-қуана! Лаққа екі сом — жақсы сауда. Мә, мынаны ал.")}
      ]},
      {narr:L("The bai caught a scrawny, limping little kid — one that had two days of life left in it at most — and handed it over for the two rubles. But Aldar kept the coins in his fist.",
        "Бай поймал тощего хроменького козлёнка, которому оставалось жить дня два, и отдал за два рубля. Но Алдар денег из кулака не выпустил.",
        "Бай екі-ақ күн өмірі қалған арық, ақсақ лақты ұстап, екі сомға берді. Бірақ Алдар ақшаны жұдырығынан шығармады.")},
      {dialog:[
        {who:"aldar",em:"warm",line:L("You know what, honoured bai — I have changed my mind. Take the two rubles AND the kid, and give me a lamb instead.","Знаешь что, почтенный бай, — я передумал. Бери два рубля И козлёнка, а мне дай ягнёнка.","Білесің бе, құрметті бай — ойымды өзгерттім. Екі сом МЕН лақты ал, маған қозы бер.")},
        {who:"bai",em:"bold",line:L("Two rubles and a kid for a lamb? Ha, not a bad trade at all! Take the smallest one.","Два рубля и козлёнок за ягнёнка? Ха, совсем неплохо! Бери вон того, поменьше.","Қозыға екі сом мен лақ па? Ха, жаман емес! Анау кішкенесін ал.")}
      ]},
      {dialog:[
        {who:"aldar",em:"warm",line:L("Wait — I have changed my mind again. Take the rubles, the kid AND the lamb, and give me a she-goat.","Постой — я снова передумал. Бери рубли, козлёнка И ягнёнка, а мне дай козу.","Тоқта — тағы ойымды өзгерттім. Сомды, лақты МЕН қозыны ал, маған ешкі бер.")},
        {who:"bai",em:"bold",line:L("Rubles, kid AND lamb, all for one thin goat! Heh — take her!","Рубли, козлёнок И ягнёнок за одну тощую козу! Хе — бери!","Сом, лақ МЕН қозы — бір арық ешкіге! Хе — ал!")},
        {who:"aldar",em:"warm",line:L("One last change, honoured bai. Take the rubles, the kid, the lamb and the goat — and give me a single ram. But let me choose it myself.","Последний раз, почтенный бай. Бери рубли, козлёнка, ягнёнка и козу — а мне дай одного барана. Только выбрать позволь самому.","Соңғы рет, құрметті бай. Сом, лақ, қозы мен ешкіні ал — маған бір қой бер. Тек өзім таңдайын.")}
      ]},
      {narr:L("The bai could hardly believe his luck — two rubles, a kid, a lamb AND a goat, all for a single ram! So Aldar walked into the flock and chose the very biggest, fattest ram, hoisted it onto his shoulders, and strolled away whistling.",
        "Бай своему счастью поверить не мог — два рубля, козлёнок, ягнёнок И коза за одного барана! И Алдар вошёл в стадо, выбрал самого большого, жирного барана, взвалил на плечи и пошёл, посвистывая.",
        "Бай бақытына сене алмады — екі сом, лақ, қозы МЕН ешкі, бәрі бір қойға! Алдар отарға еніп, ең үлкен, семіз қойды таңдап, иығына салып, ысқырып жүре берді.")},
      {dialog:[
        {who:"bai",em:"bold",line:L("Ha-ha! What a fool that Aldar is — all that, given away for one single ram!","Ха-ха! Ну и глупец же этот Алдар — столько добра отдал за одного барана!","Ха-ха! Мына Алдар нағыз ақымақ — сонша дүниені бір қойға берді!")},
        {who:"aldar",em:"warm",line:L("Sleep well, honoured bai. One of us is a fool — and it will take you a while to work out which.","Спи спокойно, почтенный бай. Один из нас глупец — и ты не скоро поймёшь, который.","Тыныш ұйықта, құрметті бай. Біреуіміз ақымақпыз — қайсымыз екенін көп ұзамай білесің.")}
      ], act:"ram"}
     ]},
   { title:L("The Magic Fur Coat","Волшебная шуба","Сиқырлы тон"), scene:"winter_steppe",
     obj:L("Trade your way into the bai's fine coat","Выменяйте себе роскошную шубу бая","Байдың әдемі тонын айырбастап ал"),
     beats:[
      {cine:[
        {narr:L("That winter was so bitter the birds froze in the very air. The wind howled across the white steppe, and the snow blew sideways.","Та зима была так люта, что птицы замерзали прямо в воздухе. Ветер выл над белой степью, и снег летел вбок.","Ол қыс сонша қатты болды, құстар аспанда қатып қалды. Ақ дала үстінде жел ұлып, қар қиғаш ұшты."), cam:"up", fx:"snow", wind:true, wait:2600},
        {narr:L("Along the road came Bai Zhatyrbai, wrapped in a magnificent fox-fur coat — and yet shivering. And there rode Aldar, in a coat more hole than cloth, whistling as though it were spring.","По дороге ехал бай Жатырбай, укутанный в роскошную лисью шубу, — и всё равно дрожал. А навстречу ехал Алдар, в шубе, где дыр больше, чем сукна, и насвистывал, будто на дворе весна.","Жолмен түлкі тонға оранған Жатырбай бай келе жатты — сонда да қалтырайды. Ал матадан гөрі тесігі көп тонмен Алдар көктемдей ысқырып келеді."), cam:[0,-3,1.12,2.2], fx:"snow", spawn:["bai"], move:[{who:"bai",x:66}], wind:true, wait:3000}
      ],
      dialog:[
        {who:"bai",em:"worried",line:L("Aldar! How can you whistle? Your coat is more hole than cloth — you must be frozen through!","Алдар! Как ты можешь свистеть? В твоей шубе дыр больше, чем сукна — ты же насквозь промёрз!","Алдар! Қалай ысқырасың? Тоныңда матадан тесік көп — мұзша қатқан боларсың!")},
        {who:"aldar",em:"warm",line:L("Ah, honoured bai, that is the whole secret. My coat is warm BECAUSE of the holes. The wind blows in through this one, and straight out through that one, and never has time to chill me.","Ах, почтенный бай, в этом-то весь секрет. Моя шуба тепла ИЗ-ЗА дыр. Ветер влетает в одну и тут же вылетает в другую и не успевает меня остудить.","Ах, құрметті бай, бүкіл сыр сонда. Менің тоным тесіктің АРҚАСЫНДА жылы. Жел мына тесіктен кіріп, ана тесіктен шығып, мені суытуға үлгермейді.")},
        {who:"aldar",em:"warm",line:L("But your coat is closed all round, so the cold creeps in and stays, with nowhere to escape. That is why you shiver.","А твоя шуба закрыта со всех сторон, вот холод и заползает внутрь да там и остаётся — деться-то ему некуда. Оттого ты и дрожишь.","Ал сенің тоның жан-жағы жабық, суық еніп алып, шығатын жері болмай, ішінде қалады. Сондықтан қалтырайсың.")}
      ]},
      {dialog:[
        {who:"bai",em:"pleading",line:L("Of course! What a fool I have been! Aldar — trade with me! My fox-fur for your magic coat, quickly!","Ну конечно! Каким же я был глупцом! Алдар — меняемся! Моя лисья шуба на твою волшебную, скорей!","Әрине! Мен қандай ақымақ болдым! Алдар — айырбастайық! Түлкі тонымды сенің сиқырлы тоныңа, тез!")},
        {who:"aldar",em:"warm",line:L("This coat? Oh, I could never part with it... but for you, honoured bai — since you ask so kindly.","Эту шубу? Ах, я бы ни за что с ней не расстался... но для тебя, почтенный бай, — раз уж ты так просишь.","Мына тонды ма? Ах, ешқашан айырылмас едім... бірақ сен үшін, құрметті бай — сұрағаннан кейін.")}
      ]},
      {narr:L("They swapped coats on the spot. Aldar rode home snug in the fine fox-fur — while Bai Zhatyrbai, colder now than ever, sat in a coat full of holes and understood, at last, that he had been tricked again.",
        "Они тут же обменялись шубами. Алдар поехал домой, уютно закутавшись в лисий мех, — а бай Жатырбай, замёрзший теперь пуще прежнего, сидел в дырявой шубе и наконец понял, что его снова провели.",
        "Олар сол жерде тон айырбастады. Алдар түлкі тонға оранып, жылы үйге қайтты — ал Жатырбай бай бұрынғыдан бетер тоңып, тесік тонмен отырып, тағы алданғанын ақыры түсінді.", ), act:"coat"}
     ]},
   { title:L("Aldar and the Shaitans","Алдар и шайтаны","Алдар мен шайтандар"), scene:"shaitan_hollow",
     obj:L("Outwit the shaitans with nothing but your wits","Перехитрите шайтанов одной лишь смекалкой","Тек айламен шайтандарды алда"),
     beats:[
      {narr:L("In a dark hollow at the edge of the steppe lived shaitans, who robbed every traveler by daring them to contests of strength. Aldar walked in armed with nothing but his wits.",
        "В тёмном логове на краю степи жили шайтаны, что грабили каждого путника, вызывая его на состязания в силе. Алдар вошёл туда, вооружённый одной лишь смекалкой.",
        "Даланың шетіндегі қараңғы сайда шайтандар тұратын; олар әр жолаушыны күш сынасуға шақырып тонайтын. Алдар оларға тек айламен қаруланып кірді.")},
      {dialog:[
        {who:"shaitan",em:"cool",line:L("Squeeze water from this stone, little man — or we shall have your bones!","Выжми воду из этого камня, человечек, — или мы заберём твои кости!","Мына тастан су сыққ, кішкене адам — әйтпесе сүйегіңді аламыз!")},
        {who:"aldar",em:"bold",line:L("Water from a stone? Child's play. Watch closely.","Воду из камня? Пустяки. Смотри внимательно.","Тастан су ма? Балалық іс. Мұқият қара.")}
      ]},
      {narr:L("Aldar palmed a soft white curd cheese in place of the stone, squeezed — and whey ran dripping through his fingers. The shaitans gasped.",
        "Алдар незаметно подменил камень мягким белым сыром, сжал — и сыворотка потекла у него меж пальцев. Шайтаны ахнули.",
        "Алдар тастың орнына жұмсақ ақ ірімшікті алақанына жасырып, қысып еді — саусақтарынан сарысу тамшылады. Шайтандар аңырды.")},
      {dialog:[
        {who:"shaitan",em:"worried",line:L("Then race my swiftest brother across the steppe!","Тогда обгони моего быстрейшего брата по степи!","Ендеше даладағы ең жүйрік ағамнан оза шап!")},
        {who:"aldar",em:"warm",line:L("I am far too grand to run myself. I will send my baby brother — he naps in the grass over there.","Я слишком важен, чтобы бегать самому. Пошлю братишку — он вон там спит в траве.","Өзім жүгіретіндей маңызды емеспін. Кішкентай бауырымды жіберемін — ол анау шөпте ұйықтап жатыр.")}
      ]},
      {narr:L("The 'baby brother' was a hedgehog. Each time the shaitan raced past a bush, another spiny little brother was already there ahead of him. Beaten at every turn, the shaitans fled in terror — and left all their gold behind. But first, one set Aldar a final riddle.",
        "«Братишкой» был ёжик. Всякий раз, обегая куст, шайтан находил там колючего братца уже впереди себя. Проигранные всюду, шайтаны в ужасе бежали, бросив всё золото. Но напоследок один загадал Алдару загадку.",
        "«Кішкентай бауыр» — кірпі еді. Шайтан бұтадан өткен сайын, тікенді бауыр одан озып тұратын. Жеңіліп біткен шайтандар үрейленіп қашты, барлық алтынын тастап. Бірақ соңында біреуі Алдарға жұмбақ айтты.")},
      {dialog:[
        {who:"shaitan",em:"cool",line:L("One question, trickster: what beats us every time, though it carries no club and no knife? Answer, and the gold is yours.","Один вопрос, хитрец: что бьёт нас всякий раз, хоть и без дубины и ножа? Ответь — и золото твоё.","Бір сұрақ, айлакер: шоқпар да, пышақ та жоқ бола тұра бізді әр жолы жеңетін не? Жауап бер — алтын сенікі.")}
      ], act:"riddle",
        riddle:{ q:L("What beats a shaitan every time, though it carries no weapon at all?","Что побеждает шайтана всякий раз, хотя и вовсе без оружия?","Ешқандай қаруы жоқ бола тұра шайтанды әр жолы жеңетін не?"),
          opts:[ {t:L("A sharp wit","Острый ум","Өткір ақыл"),ok:true},
                 {t:L("A strong arm","Сильная рука","Күшті білек"),ok:false},
                 {t:L("A heavy club","Тяжёлая дубина","Ауыр шоқпар"),ok:false},
                 {t:L("A bag of gold","Мешок золота","Алтын қап"),ok:false} ] }}
     ]},
   { title:L("The Trick That Fed the Aul","Хитрость, что накормила аул","Ауылды асыраған айла"), scene:"aul",
     obj:L("Bring your winnings home to the aul","Принесите добычу домой, в аул","Олжаңды ауылға алып қайт"),
     beats:[
      {narr:L("Aldar carried the ram, the fine coat and the shaitans' gold home across the steppe — and shared nearly all of it among the poorest families of the aul.",
        "Алдар принёс барана, роскошную шубу и золото шайтанов домой через степь — и раздал почти всё это беднейшим семьям аула.",
        "Алдар қой мен әдемі тонды, шайтандардың алтынын дала арқылы үйге әкелді — оның барлығын дерлік ауылдың ең кедей отбасыларына таратты.")},
      {dialog:[
        {who:"shepherd",em:"hope",line:L("Teach me, Aldar — how is it you always win, with nothing in your hands?","Научи меня, Алдар, — как это ты всегда выигрываешь с пустыми руками?","Үйрет, Алдар — қолыңда ештеңе жоқ, қалай әрдайым ұтасың?")},
        {who:"aldar",em:"warm",line:L("It is the simplest thing, little brother. A greedy heart always cheats itself. I only hold the door open and let it walk through.","Проще простого, братишка. Жадное сердце всегда обманывает само себя. Я лишь придерживаю дверь и даю ему пройти.","Бұл өте оңай, бауырым. Сараң жүрек әрдайым өзін-өзі алдайды. Мен тек есікті ұстап тұрып, оны өткіземін.")},
        {who:"granny",em:"gentle",line:L("Bless your beardless chin, you rascal. The aul eats well tonight because of it.","Благослови твой безбородый подбородок, проказник. Аул сегодня сыт благодаря ему.","Сақалсыз иегіңе бақ берсін, шумақ. Бүгін ауыл соның арқасында тоқ.")}
      ]}
     ]}
  ]},

 shepherd:{
  ending:{ title:L("No Longer Poor in Wit","Больше не беден умом","Ақылға енді кедей емес"),
    text:L("You came to Aldar with an empty purse and empty hands, and you leave with neither gold nor sheep — but with something the greedy bai will never buy: the quick, kind cleverness of Aldar Köse himself. On the steppe, that is the only wealth that never runs out.",
      "Ты пришёл к Алдару с пустым кошельком и пустыми руками, а уходишь без золота и без овец — но с тем, что жадному баю вовек не купить: с быстрой, доброй смекалкой самого Алдара Косе. В степи это единственное богатство, что не кончается.",
      "Алдарға бос әмиянмен, бос қолмен келдің, ал алтынсыз да, қойсыз да кетіп барасың — бірақ сараң бай ешқашан сатып ала алмайтын нәрсемен: Алдар Көсенің жылдам да мейірімді айласымен. Далада бұл — таусылмайтын жалғыз байлық.") },
  chapters:[
   { title:L("Following the Trickster","За хитрецом","Айлакердің соңынан"), scene:"aul",
     obj:L("Follow Aldar and see how the world really works","Идите за Алдаром и посмотрите, как устроен мир","Алдардың соңынан еріп, әлемнің шын жүйесін көр"),
     beats:[
      {narr:L("You are a young shepherd, poor in everything but hope. When Aldar Köse offers to show you how the clever survive on the steppe, you drop your crook and follow.",
        "Ты молодой пастух, бедный всем, кроме надежды. Когда Алдар Косе предлагает показать, как ловкие выживают в степи, ты бросаешь свой посох и идёшь за ним.",
        "Сен жас шопансың, үміттен басқа бәріне кедейсің. Алдар Көсе даладағы айлакерлер қалай күн көретінін көрсетем дегенде, таяғыңды тастап, соңынан ересің.")},
      {dialog:[
        {who:"aldar",em:"warm",line:L("Keep your eyes open and your mouth shut, and you will learn more in one day than in ten years of herding.","Держи глаза открытыми, а рот закрытым — и за один день узнаешь больше, чем за десять лет пастьбы.","Көзіңді ашық, аузыңды жабық ұста — бір күнде он жыл қой бағудан көп үйренесің.")},
        {who:"shepherd",em:"hope",line:L("I have nothing to trade, Aldar. How can a poor man ever win?","Мне нечего менять, Алдар. Как бедняку выиграть?","Айырбастайтын ештеңем жоқ, Алдар. Кедей адам қалай ұтады?")}
      ]}
     ]},
   { title:L("The Lesson of the Ram","Урок с бараном","Қой сабағы"), scene:"bai_yurt",
     obj:L("Learn Aldar's trick with the greedy bai","Усвойте хитрость Алдара с жадным баем","Алдардың сараң баймен айласын үйрен"),
     beats:[
      {narr:L("You crouch by the tent-flap and watch Aldar hand the bai two rubles, then change his mind again and again — kid for lamb, lamb for goat, goat for one ram of his own choosing.",
        "Ты притаился у входа в юрту и смотришь, как Алдар отдаёт баю два рубля, а потом снова и снова передумывает — козлёнок на ягнёнка, ягнёнок на козу, коза на одного барана по своему выбору.",
        "Киіз үй есігінің қасында бүгіліп, Алдардың байға екі сом беріп, сосын қайта-қайта ойын өзгерткенін бақылайсың — лақты қозыға, қозыны ешкіге, ешкіні өзі таңдаған бір қойға.")},
      {dialog:[
        {who:"aldar",em:"warm",line:L("You see, little brother? I never once raised my voice. The bai's own greed did all the work.","Видишь, братишка? Я ни разу не повысил голоса. Всю работу сделала жадность самого бая.","Көрдің бе, бауырым? Бір рет те дауысымды көтермедім. Бүкіл жұмысты байдың өз сараңдығы істеді.")},
        {who:"shepherd",em:"waking",line:L("So the trick is not to take — it is to let him give. I think I begin to understand.","Значит, хитрость не в том, чтобы взять, а в том, чтобы он сам отдал. Кажется, я начинаю понимать.","Демек айла — алу емес, оны өзі берсін деу екен. Түсіне бастаған сияқтымын.")}
      ]}
     ]},
   { title:L("Your Own First Trick","Твоя первая хитрость","Алғашқы айлаң"), scene:"market",
     obj:L("Try your new-found cleverness in the bazaar","Испытайте новообретённую смекалку на базаре","Жаңа тапқан айлаңды базарда сына"),
     beats:[
      {dialog:[
        {who:"merchant",em:"gossip",line:L("Only a fool pays full price at my stall, boy. What have you got to offer?","Только глупец платит у меня полную цену, парень. Что предложишь?","Менің дүкенімде тек ақымақ толық баға төлейді, бала. Не ұсынасың?")},
        {who:"shepherd",em:"bold",line:L("A pouch of the finest gold-dust, merchant — though for a friend of Aldar's, perhaps we can come to terms.","Мешочек тончайшего золотого песка, купец, — но для друга Алдара, пожалуй, сговоримся.","Ең майда алтын құмы бар қалта, саудагер — бірақ Алдардың досына, келісуге болар.")},
        {who:"aldar",em:"warm",line:L("Ha! Now you have it, little brother. Careful — a good trick fed with kindness, or it turns to poison.","Ха! Вот теперь ты понял, братишка. Только осторожно: добрую хитрость корми добротой, не то станет ядом.","Ха! Міне енді түсіндің, бауырым. Абайла — жақсы айланы мейіріммен асыра, әйтпесе уға айналады.")}
      ]}
     ]}
  ]},

 bai:{
  ending:{ title:L("The Bai Who Learned to Laugh","Бай, что научился смеяться","Күлуді үйренген бай"),
    text:L("A ram, a fine fox-fur coat, a purse of gold — all of it walked away on the back of a beardless man with two rubles and a smile. You raged, you plotted, you were fooled again. And then, one evening by the fire, you did the last thing anyone expected of a greedy bai: you threw back your head and laughed. And the whole aul, Aldar loudest of all, laughed warmly with you.",
      "Баран, роскошная лисья шуба, кошель золота — всё ушло на спине безбородого с двумя рублями и улыбкой. Ты злился, ты строил козни, тебя провели снова. А потом, вечером у огня, ты сделал то, чего от жадного бая никто не ждал: запрокинул голову и рассмеялся. И весь аул, а громче всех Алдар, тепло смеялся вместе с тобой.",
      "Қой, әдемі түлкі тон, алтын қалта — бәрі екі сом мен күлкісі бар сақалсыздың арқасында кетті. Ашуландың, айла құрдың, тағы алдандың. Сосын бір кеште от басында сараң байдан ешкім күтпеген нәрсені істедің: басыңды шалқайтып күлдің. Бүкіл ауыл, ең қатты Алдар, сенімен жылы күлді.") },
  chapters:[
   { title:L("A Bai's Fine Morning","Прекрасное утро бая","Байдың жақсы таңы"), scene:"bai_yurt",
     obj:L("Enjoy your wealth — before Aldar arrives","Насладитесь богатством — пока не явился Алдар","Байлығыңды тат — Алдар келгенше"),
     beats:[
      {narr:L("You are Bai Zhatyrbai, the richest man for three days' ride: flocks past counting, chests of silver, and a fox-fur coat that is the envy of the steppe. Life is good — until a beardless man appears at your tent with two rubles and a smile.",
        "Ты бай Жатырбай, богатейший на три дня пути: стад не счесть, сундуки серебра и лисья шуба на зависть всей степи. Жизнь хороша — пока у твоей юрты не появляется безбородый с двумя рублями и улыбкой.",
        "Сен Жатырбай байсың, үш күндік жердегі ең бай адам: санауға болмас мал, күміс сандықтар, бүкіл дала қызығатын түлкі тон. Өмір жақсы — киіз үйіңе екі сом мен күлкісі бар сақалсыз келгенше.")},
      {dialog:[
        {who:"baibishe",em:"worried",line:L("Husband, that Aldar is at the door again. Whatever he offers — say no!","Муж, этот Алдар снова у порога. Что бы он ни предлагал — откажи!","Байым, ана Алдар тағы есік алдында. Не ұсынса да — жоқ де!")},
        {who:"bai",em:"bold",line:L("Peace, wife! Do you take me for a fool? No trickster gets the better of Zhatyrbai.","Тише, жена! За глупца меня держишь? Ни один хитрец не проведёт Жатырбая.","Тыныш, әйел! Мені ақымақ деп пе ең? Бірде-бір айлакер Жатырбайды алдай алмайды.")}
      ]}
     ]},
   { title:L("How the Ram Slipped Away","Как ушёл баран","Қой қалай кетті"), scene:"bai_yurt",
     obj:L("Make a shrewd bargain with Aldar — you are sure you can","Заключите с Алдаром выгодную сделку — вы уверены в себе","Алдармен тиімді сауда жаса — сенімдісің"),
     beats:[
      {narr:L("He offers you two rubles to take a worthless kid off his hands. Then he changes his mind — again, and again — and each time the bargain looks even better for you.",
        "Он предлагает тебе два рубля, лишь бы сбыть никудышного козлёнка. Потом передумывает — снова и снова — и всякий раз сделка кажется тебе всё выгоднее.",
        "Ол түкке тұрғысыз лақты өткізу үшін саған екі сом ұсынады. Сосын ойын өзгертеді — қайта-қайта — әр жолы сауда саған тиімдірек көрінеді.")},
      {dialog:[
        {who:"bai",em:"bold",line:L("Two rubles, a kid, a lamb AND a goat — all for one ram? The man is a born fool! Choose your ram, Aldar, choose!","Два рубля, козлёнок, ягнёнок И коза — всё за одного барана? Прирождённый дурак! Выбирай барана, Алдар, выбирай!","Екі сом, лақ, қозы МЕН ешкі — бәрі бір қойға? Туа біткен ақымақ! Қойыңды таңда, Алдар, таңда!")},
        {who:"bai",em:"worried",line:L("...Wait. He took the FATTEST ram. And left me the kid, the lamb, the goat... and my own two rubles back. How...?","...Постой. Он взял самого ЖИРНОГО барана. А мне оставил козлёнка, ягнёнка, козу... и мои же два рубля. Как...?","...Тоқта. Ол ең СЕМІЗ қойды алды. Маған лақ, қозы, ешкі... және өз екі сомымды қалдырды. Қалай...?")}
      ], act:"ram"}
     ]},
   { title:L("The Coat, and the Last Laugh","Шуба и последний смех","Тон және соңғы күлкі"), scene:"winter_steppe",
     obj:L("Guard your fox-fur coat against the trickster","Уберегите лисью шубу от хитреца","Түлкі тоныңды айлакерден сақта"),
     beats:[
      {narr:L("Winter comes, and with it Aldar, whistling in a coat full of holes. He swears the holes make it warmer than any fox-fur. Freezing in your fine closed coat, you feel the old greed stir once more...",
        "Приходит зима, а с ней Алдар, насвистывающий в дырявой шубе. Он клянётся, что дыры делают её теплее любой лисьей. Замерзая в своей роскошной закрытой шубе, ты снова чувствуешь, как шевелится старая жадность...",
        "Қыс келеді, онымен бірге тесік тонмен ысқырған Алдар. Тесіктер оны кез келген түлкі тоннан жылы етеді деп ант етеді. Әдемі жабық тоныңда тоңып, ескі сараңдықтың қайта қозғалғанын сезесің...")},
      {dialog:[
        {who:"aldar",em:"warm",line:L("The wind blows in one hole and out the next, honoured bai. A closed coat only traps the cold. But of course, you are far too wise to be fooled...","Ветер входит в одну дыру и выходит в другую, почтенный бай. Закрытая шуба лишь держит холод. Но ты, конечно, слишком мудр, чтобы попасться...","Жел бір тесіктен кіріп, екіншісінен шығады, құрметті бай. Жабық тон суықты ұстап қалады. Әрине, сен алданбайтындай дана адамсың...")},
        {who:"bai",em:"pleading",line:L("Give me that coat, Aldar! Here, take my fox-fur — quickly, before I freeze!","Дай мне ту шубу, Алдар! Вот, бери мою лисью — скорей, пока не замёрз!","Ол тонды бер, Алдар! Мә, түлкі тонымды ал — тез, тоңып өлместен бұрын!")}
      ]},
      {narr:L("And so you froze twice over — in body, then in pride. But that night, warmed by the aul's fire and the aul's laughter, you finally laughed too. Perhaps a little wit is worth more than a great deal of gold.",
        "Так ты замёрз дважды — телом, а потом гордостью. Но в ту ночь, согретый огнём аула и его смехом, ты наконец рассмеялся и сам. Быть может, немного ума дороже, чем куча золота.",
        "Сөйтіп екі рет тоңдың — денеңмен, сосын тәкаппарлығыңмен. Бірақ сол түні ауылдың оты мен күлкісіне жылынып, ақыры өзің де күлдің. Бәлкім, аздаған ақыл көп алтыннан қымбат шығар.", ), act:"coat"}
     ]}
  ]}
};
