const SB_AMBIENT = {
  king:[{line:L("Let the feast never end tonight!","Пусть нынче пир не кончается!","Бүгін той бітпесін!"),em:"warm"},
    {line:L("Burn every spindle in the realm — every last one!","Сжечь все веретёна в королевстве — до единого!","Патшалықтағы барлық ұршықты өртеңдер — соңғысына дейін!"),em:"bold"},
    {line:L("My daughter shall never know a moment's fear.","Моя дочь не узнает ни мгновения страха.","Қызым бір сәт те қорқыныш білмейді."),em:"warm"}],
  queen:[{line:L("How peacefully she sleeps.","Как мирно она спит.","Қандай тыныш ұйықтап жатыр."),em:"gentle"},
    {line:L("Sixteen years... and still I count each one.","Шестнадцать лет... а я всё считаю их.","Он алты жыл... әлі әрқайсысын санаймын."),em:"worried"},
    {line:L("Look how the whole court loves her.","Смотри, как весь двор её любит.","Қара, бүкіл сарай оны жақсы көреді."),em:"tender"}],
  rosalind:[{line:L("A little more beauty never hurt anyone.","Немного красоты ещё никому не вредило.","Аздап сұлулық ешкімге зиян еткен емес."),em:"warm"},
    {line:L("All who look on her shall love her — that was my gift.","Всякий, кто взглянет на неё, полюбит её — таков мой дар.","Оны көрген әркім сүйеді — менің сыйым осы."),em:"warm"}],
  marigold:[{line:L("Shall we give her a song as well?","Подарим ей ещё и песню?","Оған ән де сыйлайық па?"),em:"warm"},
    {line:L("Her voice will be sweeter than any lark's.","Голос её будет слаще любого жаворонка.","Дауысы кез келген бозторғайдан тәтті болады."),em:"warm"}],
  wren:[{line:L("Kindness outlasts any curse.","Доброта переживёт любое проклятие.","Мейірім кез келген қарғыстан ұзақ."),em:"gentle"},
    {line:L("Sleep, not death. I could give her that much.","Сон, а не смерть. Хоть это я могла ей дать.","Өлім емес, ұйқы. Оған сонша болса да бере алдым."),em:"gentle"},
    {line:L("I dare not leave her side until the prince comes.","Не смею отойти от неё, пока не придёт принц.","Ханзада келгенше қасынан кетуге батпаймын."),em:"worried"}],
  carabosse:[{line:L("They will remember me now.","Теперь-то меня запомнят.","Енді мені есте сақтайды."),em:"cool"},
    {line:L("No invitation for me? A pity — for them.","Меня не позвали? Жаль — их же.","Мені шақырмады ма? Өкінішті — өздеріне."),em:"cold"},
    {line:L("Sixteen years is such a little while to wait.","Шестнадцать лет — такой малый срок для ожидания.","Он алты жыл — күтуге сондай аз мерзім."),em:"cool"}],
  prince:[{line:L("No hedge of thorns will turn me back.","Никакая чаща не повернёт меня вспять.","Ешбір тікенек орман мені кері қайтармайды."),em:"resolve"},
    {line:L("A hundred years... and yet I feel I have always known her.","Сто лет... а мне чудится, будто я всегда её знал.","Жүз жыл... бірақ оны әрдайым білгендей сезінемін."),em:"tender"}],
  spinner:[{line:L("Come closer, child. Just take the spindle — so.","Подойди ближе, дитя. Возьми веретено — вот так.","Жақынырақ кел, балам. Ұршықты ал — былай."),em:"soft"}]
};
