const SB_DISCOVERIES = {
  great_hall:[
    {id:"sb_cradle",x:30,y:44,ic:"👑",name:L("The Golden Cradle","Золотая колыбель","Алтын бесік"),text:L("A cradle of gold awaited the long-desired child, and three good fairies stood as her godmothers.","Золотая колыбель ждала долгожданное дитя, и три добрые феи стали её крёстными.","Күткен балаға алтын бесік дайын тұрды, үш мейірімді пері оның шомылдыру анасы болды.")},
    {id:"sb_banners",x:70,y:26,ic:"🎏",name:L("The Rose Banners","Розовые стяги","Раушан тулары"),text:L("Banners of rose and gold hung from every arch. The rose was the old sign of the royal house — beauty that guards a hidden thorn.","С каждой арки свисали стяги розовые и золотые. Роза была древним знаком королевского дома — красота, что хранит скрытый шип.","Әр аркадан раушан мен алтын тулар салбырап тұрды. Раушан — патша әулетінің көне белгісі: жасырын тікенді қорғайтын сұлулық.")},
    {id:"sb_bells",x:16,y:34,ic:"🔔",name:L("The Kingdom's Bells","Колокола королевства","Патшалық қоңыраулары"),text:L("When Aurora was born the king had every bell in the land rung at once, and the sound carried three days' ride in every direction.","Когда родилась Аврора, король велел разом ударить во все колокола страны, и звон разнёсся на три дня пути во все стороны.","Аврора туғанда патша елдегі барлық қоңырауды бірден соқтырды, дыбыс төрт тарапқа үш күндік жолға жетті.")}],
  throne_room:[
    {id:"sb_gifts",x:32,y:40,ic:"🎁",name:L("The Fairies' Gifts","Дары фей","Перілер сыйы"),text:L("Beauty, a voice of song, a kind and merry heart — the good fairies' gifts could never be unmade, not even by the darkest curse.","Красота, голос певучий, сердце доброе и весёлое — дары добрых фей нельзя было отнять, даже самым тёмным проклятием.","Сұлулық, әнші дауыс, мейірімді, көңілді жүрек — мейірімді перілердің сыйын ең қара қарғыс та жоя алмайтын.")},
    {id:"sb_candles",x:60,y:30,ic:"🕯️",name:L("The Guttered Candles","Погасшие свечи","Сөнген шамдар"),text:L("Half the candles in the hall went out in a single cold gust — the whole court knew, before she spoke, that Carabosse had come.","Половина свечей в зале погасла от одного холодного порыва — весь двор понял, ещё до её слов, что явилась Карабос.","Залдағы шамдардың жартысы бір суық лептен өшті — Қарабос келгенін сарай ол сөйлемей жатып түсінді.")},
    {id:"sb_thrones",x:50,y:52,ic:"🪑",name:L("The Twin Thrones","Два трона","Егіз тақ"),text:L("Two carved thrones stood side by side. For sixteen years the king and queen ruled in joy — and in a quiet, unspoken fear.","Два резных трона стояли рядом. Шестнадцать лет король с королевой правили в радости — и в тихом, невысказанном страхе.","Екі ойма тақ қатар тұрды. Он алты жыл патша мен патшайым қуанышпен — әрі үнсіз, айтылмаған қорқынышпен билік етті.")}],
  garden:[
    {id:"sb_roses",x:26,y:40,ic:"🌹",name:L("The Castle Roses","Замковые розы","Сарай раушандары"),text:L("Roses climbed every wall of the garden. They say a rose bloomed the hour Aurora was born, and never once wilted while she lived.","Розы вились по каждой стене сада. Говорят, роза распустилась в час рождения Авроры и ни разу не увяла, пока та жила.","Раушан бақтың әр қабырғасын шырмады. Аврора туған сағатта раушан ашылып, ол тірі кезде бір рет те солмаған дейді.")},
    {id:"sb_fountain",x:54,y:48,ic:"⛲",name:L("The Wishing Fountain","Фонтан желаний","Тілек бұрқағы"),text:L("As a girl Aurora dropped a copper coin into this fountain each morning, and wished — she never told for what. Every wish but one came true.","Девочкой Аврора каждое утро роняла в этот фонтан медную монетку и загадывала — о чём, не говорила. Все желания, кроме одного, сбылись.","Қыз кезінде Аврора әр таң сайын осы бұрқаққа мыс тиын тастап, тілек тілейтін — нені екенін айтпайтын. Біреуінен басқа бәрі орындалды.")},
    {id:"sb_sundial",x:76,y:34,ic:"🕰️",name:L("The Garden Sundial","Садовые солнечные часы","Бақ күн сағаты"),text:L("A sundial counted the bright years away. The gardeners never guessed why the queen watched its slow shadow with such tender dread.","Солнечные часы отсчитывали светлые годы. Садовники не догадывались, отчего королева следила за их медленной тенью с такой нежной тревогой.","Күн сағаты жарық жылдарды санады. Патшайымның оның баяу көлеңкесіне неге сондай нәзік үреймен қарайтынын бақташылар білмеді.")}],
  tower:[
    {id:"sb_wheel",x:64,y:42,ic:"🧵",name:L("The Last Spinning Wheel","Последняя прялка","Соңғы шығыр"),text:L("One spinning wheel escaped the king's fires, hidden in the tower — and upon it the whole prophecy turned.","Одна прялка ускользнула от королевских костров, укрытая в башне, — и на ней-то и сбылось всё пророчество.","Бір шығыр патша отынан құтылып, мұнарада жасырынды — бүкіл болжам соған байланды.")},
    {id:"sb_stair",x:28,y:56,ic:"🌀",name:L("The Winding Stair","Винтовая лестница","Айналма баспалдақ"),text:L("A narrow stair Aurora had never climbed spiralled up to the little door. Some say her feet knew the way as if a dream had walked it first.","Узкая лестница, по которой Аврора не поднималась, вилась к дверце. Говорят, ноги её знали путь, будто сон прошёл по нему раньше.","Аврора баспаған тар баспалдақ кішкене есікке дейін оралып барды. Аяғы жолды түс бұрын жүргендей білді дейді.")},
    {id:"sb_window",x:44,y:22,ic:"🪟",name:L("The Narrow Window","Узкое окно","Тар терезе"),text:L("Through this one slit of a window fell the only light in the tower — falling, that morning, on an old woman and her wheel.","В эту щель-окно падал единственный свет башни — в то утро он лёг на старуху и её прялку.","Осы тар терезеден мұнараның жалғыз сәулесі түсті — сол таңда ол кемпір мен оның шығырына түсті.")}],
  sleeping_castle:[
    {id:"sb_hearth",x:24,y:52,ic:"🔥",name:L("The Frozen Hearth","Застывший очаг","Қатқан ошақ"),text:L("The fire on the hearth stood without moving, its flames caught mid-flicker — neither burning down nor going out, for a hundred years.","Огонь в очаге застыл, языки пламени замерли на полувзмахе — сто лет не догорая и не гаснув.","Ошақтағы от қозғалмай тұрды, жалыны жарты лепте қатып қалды — жүз жыл жанбай да, сөнбей де.")},
    {id:"sb_clock",x:58,y:30,ic:"⏳",name:L("The Stopped Hour","Остановившийся час","Тоқтаған сағат"),text:L("Every clock in the castle stopped at the same minute. Dust rose and hung in the air, and even that did not fall until she woke.","Все часы в замке остановились на одной минуте. Пыль поднялась и повисла в воздухе — и даже она не осела, пока принцесса не проснулась.","Сарайдағы барлық сағат бір минутта тоқтады. Шаң көтеріліп, ауада ілініп қалды — ол ханшайым оянғанша түскен жоқ.")},
    {id:"sb_banner_top",x:74,y:18,ic:"🚩",name:L("The Highest Banner","Высочайший стяг","Ең биік ту"),text:L("Only the topmost banner rose above the thorns. For a hundred years it was all a traveller could see of a whole sleeping kingdom.","Лишь самый верхний стяг поднимался над терновником. Сто лет только его и мог разглядеть путник от целого спящего королевства.","Тікенектен тек ең жоғарғы ту ғана көрінді. Жүз жыл бойы жолаушы бүкіл ұйықтаған патшалықтан тек соны көре алды.")}],
  thorn_wood:[
    {id:"sb_thorns",x:72,y:50,ic:"🌹",name:L("The Hedge of Thorns","Терновая чаща","Тікенді орман"),text:L("For a hundred years the thorns kept the castle — cruel to the hasty, but opening into roses for love that came in its true hour.","Сто лет терновник хранил замок — жестокий к спешащим, но раскрывавшийся розами для любви, пришедшей в свой срок.","Жүз жыл тікенек сарайды қорғады — асыққанға қатыгез, бірақ өз сағатында келген махаббатқа раушан болып ашылды.")},
    {id:"sb_briar",x:30,y:44,ic:"🥀",name:L("The Oldest Briar","Самый старый терн","Ең кәрі тікен"),text:L("The thickest briar was as old as the curse itself, its thorns long as a finger. Yet in its heart a single bud waited, closed, for a hundred years.","Самый толстый терновник был стар, как само проклятие, шипы — с палец длиной. Но в сердце его сто лет ждал закрытый бутон.","Ең жуан тікен қарғыстың өзіндей кәрі, тікені саусақтай ұзын еді. Бірақ жүрегінде жабық бүршік жүз жыл күтті.")},
    {id:"sb_lost",x:52,y:62,ic:"⚔️",name:L("The Bold Ones Before","Смельчаки до него","Оған дейінгі батырлар"),text:L("Many a bold prince had ridden here to cut through and win her — and the hedge closed about them like cruel hands. Not one came out again.","Не один дерзкий принц приезжал прорубиться и добыть её — и чаща смыкалась вокруг них, точно жестокие руки. Никто не вышел назад.","Талай батыл ханзада оны алмаққа тікенекті кесуге келді — орман оларды қатыгез қолдай қымқырды. Ешқайсысы қайтпады.")}],
  forest:[
    {id:"sb_oldman",x:30,y:40,ic:"🧓",name:L("The Old Man's Tale","Рассказ старика","Қарттың әңгімесі"),text:L("An old woodcutter kept the whole story alive: of the castle behind the thorns, and the fairest princess in the world asleep within.","Старый дровосек хранил всю повесть: о замке за терновником и о прекраснейшей принцессе на свете, спящей в нём.","Кәрі отыншы бар әңгімені сақтады: тікенек артындағы сарай мен ішінде ұйықтаған әлемдегі ең сұлу ханшайым туралы.")},
    {id:"sb_steed",x:70,y:46,ic:"🐴",name:L("The Prince's Steed","Конь принца","Ханзада аты"),text:L("Florimund's horse would go no nearer the thorns and stood trembling at the wood's edge — so the prince went on alone, on foot.","Конь Флоримунда не шёл ближе к терновнику и дрожал на краю леса — и принц пошёл дальше один, пешком.","Флоримундтың аты тікенекке жақындамай, орман шетінде дірілдеп тұрды — ханзада жаяу, жалғыз жүріп кетті.")},
    {id:"sb_ring",x:50,y:60,ic:"🍄",name:L("The Fairy Ring","Ведьмино кольцо","Пері шеңбері"),text:L("A perfect ring of mushrooms marked where the good fairies were said to meet. Step inside at dusk, the old man warned, and a hundred years might pass.","Ровное кольцо грибов отмечало место встреч добрых фей. Ступи в него в сумерках, предупреждал старик, и может пройти сто лет.","Саңырауқұлақтың дөңгелек шеңбері мейірімді перілер жиналатын жерді белгіледі. Іңірде ішіне кірсең, жүз жыл өтуі мүмкін деп ескертті қарт.")}],
  chamber:[
    {id:"sb_canopy",x:34,y:44,ic:"🛏️",name:L("The Canopy Bed","Кровать под балдахином","Балдахинді төсек"),text:L("Under a canopy of rose silk Aurora lay as fair as the day she fell, the faint colour of a rose still in her cheek.","Под балдахином из розового шёлка Аврора лежала прекрасна, как в день, когда уснула, и слабый румянец розы держался на щеке.","Раушан жібек шатыр астында Аврора құлаған күнгідей сұлу жатты, бетінде раушанның болмашы қызылы бар еді.")},
    {id:"sb_doves",x:68,y:30,ic:"🕊️",name:L("The Sleeping Doves","Спящие голуби","Ұйықтаған көгершіндер"),text:L("Even the doves on the sill slept, heads tucked beneath their wings — and woke with a sudden clap of feathers the moment she opened her eyes.","Даже голуби на карнизе спали, спрятав головы под крыло, — и вспорхнули разом, лишь она открыла глаза.","Терезедегі көгершіндер де басын қанат астына тығып ұйықтады — ол көзін ашқан сәтте бірден қанат қағып ұшты.")},
    {id:"sb_rosecheek",x:52,y:56,ic:"🌸",name:L("The Rose in Her Cheek","Румянец на щеке","Беттегі қызғылт"),text:L("A hundred years of sleep had not stolen the warmth from her face. That single rose of colour was how Florimund knew she still lived.","Сто лет сна не отняли тепла у её лица. По этому единственному румянцу Флоримунд и понял, что она жива.","Жүз жылдық ұйқы оның бетінен жылуды алмады. Осы жалғыз қызғылттан Флоримунд оның тірі екенін білді.")}]
};
