const ERT_RELICS = {
  hero_bow:{name:L("Töstik's Bow","Лук Тёстика","Төстіктің садағы"),lore:L("A bow whose drawn arrow passes clean through nine layers of iron — the weapon of a hero born of a single meal of meat.","Лук, чья стрела пробивает девять слоёв железа насквозь, — оружие богатыря, рождённого от одного лишь куска мяса.","Тартқан жебесі тоғыз қабат темірден өтетін садақ — бір үзім еттен туған батырдың қаруы.")},
  iron_file:{name:L("The Bowman's File","Напильник лучника","Ұста егеуі"),lore:L("The humble iron file Töstik could not travel without — the very lure by which the ogress meant to trap him.","Простой железный напильник, без которого Тёстик не мог в путь, — та самая приманка, которой ведьма хотела его заманить.","Төстік онсыз жүре алмайтын қарапайым темір егеу — жалмауыз оны аулаймын деген дәл сол жем.")},
  gold_feather:{name:L("Samuryk's Feather","Перо Самрука","Самұрық қауырсыны"),lore:L("A single feather of the great two-headed bird; set alight in a hopeless hour, it summons her from across the world.","Единственное перо великой двуглавой птицы; зажжённое в безнадёжный час, оно призывает её через весь мир.","Ұлы қос басты құстың жалғыз қауырсыны; ең қиын сәтте тұтатсаң, ол әлемнің арғы шетінен ұшып жетеді.")},
  soul_casket:{name:L("The Casket of the Soul","Ларец души","Жан сандығы"),lore:L("Deep in a deer, deep in a chest, nine small birds — and in them the hidden life of a monster who kept his soul outside his body.","Глубоко в олене, глубоко в ларце, девять птенцов — и в них скрытая жизнь чудовища, что держал душу вне тела.","Еліктің ішінде, сандықтың ішінде тоғыз балапан — жанын денесінен тыс сақтаған жауыздың жасырын өмірі соларда.")}
};
const ERT_PLAYABLE = [
  {key:"tostik", name:ERT_NAME.tostik, role:L("The Miraculous Hero","Чудесный богатырь","Кереметтен туған батыр"), path:"tostik",
   power:L("Born of a single meal in a starving aul, you grew a year in a month. Live the whole epic — find your lost brothers, win Kenzhekei, ride Shalkuiryk into the underworld, out-dare khans and monsters, and come home.","Рождённый от одного куска в голодном ауле, ты рос за месяц на год. Проживи весь эпос — найди пропавших братьев, добудь Кенжекей, спустись на Шалкуйрыке в подземный мир, одолей ханов и чудовищ и вернись домой.","Аш ауылда бір үзім еттен туып, айына бір жас өстің. Бүкіл дастанды өмір сүр — жоғалған ағаларыңды тап, Кенжекейді ал, Шалқұйрықпен жер астына түс, хандар мен жауыздарды жеңіп, елге орал.")},
  {key:"kenzhekei", name:ERT_NAME.kenzhekei, role:L("The Wise Bride","Мудрая невеста","Ақылды келіншек"), path:"kenzhekei",
   power:L("Youngest and cleverest of nine sisters. See the epic through the eyes of the bride whose wisdom chooses the magic horse, sees through the ogress's trap, and waits a lifetime with unbroken faith.","Младшая и умнейшая из девяти сестёр. Взгляни на эпос глазами невесты, чья мудрость выбирает волшебного коня, разгадывает ловушку ведьмы и ждёт всю жизнь с несломленной верой.","Тоғыз қыздың кенжесі әрі ақылдысы. Дастанды сиқырлы атты таңдаған, жалмауыздың торын танып, өмір бойы сенімін жоғалтпай күткен келіншектің көзімен көр.")},
  {key:"shalkuiryk", name:ERT_NAME.shalkuiryk, role:L("The Magic Horse","Волшебный конь","Сиқырлы тұлпар"), path:"shalkuiryk",
   power:L("A tulpar who speaks, who splits the earth at a gallop and dives to the bottom of lakes. Carry your batyr through the underworld, win his races, and never once leave his side.","Тулпар, что говорит, раскалывает землю на скаку и ныряет на дно озёр. Пронеси своего батыра сквозь подземный мир, выиграй его скачки и ни разу не оставь его.","Сөйлейтін тұлпар — шапқанда жер жарады, көл түбіне сүңгиді. Батырыңды жер астынан алып өт, бәйгесін ұт, оны бір сәт те тастама.")}
];
