const ERT_AMBIENT = {
  ernazar:[{line:L("Eight sons gone into the snow, and not one word since.","Восемь сыновей ушли в снега, и с тех пор ни слова.","Сегіз ұл қарға кетті, содан бері бір хабар жоқ."),em:"sad"},
    {line:L("The meat in the shanyrak — quick, boil it, wife!","Мясо в шаныраке — скорей, свари его, жена!","Шаңырақтағы ет — тез, асып жібер, кемпір!"),em:"warm"}],
  mother:[{line:L("Eat, my son. A batyr must keep his strength.","Ешь, сынок. Батыру нужны силы.","Же, балам. Батырға күш керек."),em:"gentle"}],
  kenzhekei:[{line:L("A quick tongue is worth more than a fast horse — but a wise one keeps both.","Быстрый язык дороже быстрого коня — но мудрый бережёт и то, и другое.","Жүйрік тіл жүйрік аттан қымбат — бірақ ақылды екеуін де сақтайды."),em:"wise"},
    {line:L("Ask your father for the file, Töstik. Then you will see.","Спроси у отца напильник, Тёстик. Тогда увидишь.","Әкеңнен егеуді сұра, Төстік. Сонда көресің."),em:"worried"}],
  shalkuiryk:[{line:L("Whatever befalls us now, batyr, we bear it as one soul.","Что бы ни случилось, батыр, мы — одна душа.","Не болса да, батыр, біз бір жанбыз."),em:"resolve"}],
  bektory:[{line:L("Such a hero should not be wasted on a mortal girl...","Такому герою не место рядом со смертной...","Мұндай батыр пенде қызға лайық емес..."),em:"cool"}],
  jalmauyz:[{line:L("Heh... I have waited long for you, little batyr.","Хе... долго же я тебя ждала, батырчик.","Хе... сені көптен күттім, батыр."),em:"cool"}],
  bapy:[{line:L("Fear nothing in my court, and my court will honour you.","Ничего не бойся в моём дворе, и он почтит тебя.","Ордамда ештеңеден қорықпа, орда сені құрметтейді."),em:"wise"}],
  temir:[{line:L("No man takes my daughter without out-daring my whole realm.","Никто не возьмёт мою дочь, не превзойдя всё моё царство.","Бүкіл елімді жеңбей ешкім қызымды алмайды."),em:"bold"}]
};
