const ERT_DISCOVERIES = {
  aul_famine:[
    {id:"ert_tostik_meat",x:52,y:34,ic:"🍖",name:L("The Breast-Meat","Грудинка кобылы","Бие төстігі"),text:L("A strip of mare's breast-meat, left drying in the smoke-hole and forgotten. Eaten by the starving old couple, it gave them a son — and the son his name: Töstik.","Полоска грудинки кобылы, забытая в дымоходе. Съеденная голодными стариками, она подарила им сына — и сыну имя: Тёстик.","Түтіндікте кеуіп, ұмыт қалған бие төстігі. Аш шал мен кемпір жеп, ұл тапты — ұлға есім де берді: Төстік.")},
    {id:"ert_shanyrak",x:74,y:26,ic:"☀",name:L("The Shanyrak","Шанырак","Шаңырақ"),text:L("The round crown of the yurt, open to the sky. Through its wheel of light the old man spied the meat that would change everything.","Круглая корона юрты, открытая небу. Сквозь её светлое колесо старик приметил мясо, что всё переменило.","Аспанға ашық киіз үйдің дөңгелек тәжі. Оның жарық шеңберінен шал бәрін өзгерткен етті көрді.")}],
  steppe:[
    {id:"ert_sadak",x:30,y:40,ic:"🏹",name:L("The Nine-Iron Bow","Лук на девять железа","Тоғыз темір садақ"),text:L("By two years old Töstik could send an arrow clean through nine layers of iron. No creature of the steppe was beyond his aim.","В два года Тёстик пробивал стрелой девять слоёв железа. Ни один зверь степи не уходил от него.","Екі жасында Төстік жебесін тоғыз қабат темірден өткізетін. Даладағы аңның бірі одан құтылмайтын.")},
    {id:"ert_ormek",x:70,y:46,ic:"🧶",name:L("The Broken Loom","Порванный станок","Үзілген өрмек"),text:L("An old woman's weaving, torn by Töstik's heel as he chased a bird. Her bitter taunt about 'eight lost brothers' set the whole epic in motion.","Ткацкий станок старухи, порванный пяткой Тёстика в погоне за птицей. Её злая насмешка о «восьми пропавших братьях» и завела весь эпос.","Құс қуған Төстіктің өкшесі жыртқан кемпірдің өрмегі. Оның «жоғалған сегіз ағаң» деген ащы мысқылы бүкіл дастанды қозғады.")}],
  wedding_aul:[
    {id:"ert_saukele",x:34,y:40,ic:"👰",name:L("The Saukele","Саукеле","Сәукеле"),text:L("The towering silver-and-coral bridal crown of Kenzhekei — the tallest, dearest headdress a Kazakh bride can wear, worth a whole herd.","Высокий убор невесты из серебра и кораллов — самый высокий и дорогой венец казашки, ценою в целый табун.","Кенжекейдің күміс пен маржаннан жасалған биік бас киімі — қазақ қызының ең биік, ең қымбат тәжі, бір табын жылқыға тұрады.")},
    {id:"ert_sausage",x:66,y:36,ic:"💍",name:L("The Nine Earrings","Девять серёг","Тоғыз сырға"),text:L("Nine earrings hung on the lattice — nine sisters of one mother, whom Ernazar sought for his nine sons. The ninth was Kenzhekei, marked apart.","Девять серёг на кереге — девять сестёр одной матери, которых Ерназар сватал за девятерых сыновей. Девятая — Кенжекей, особая.","Керегедегі тоғыз сырға — бір анадан туған тоғыз қыз, Ерназар тоғыз ұлына айттырған. Тоғызыншысы — ерекше Кенжекей.")}],
  sorqudyq:[
    {id:"ert_well",x:40,y:48,ic:"🕳",name:L("The Ill-Omened Well","Дурной колодец","Сорқұдық"),text:L("Kenzhekei begged the caravan not to camp at Sorqudyq. They did — and by its bitter water the ogress first laid her hands on the family.","Кенжекей молила не вставать у Сорқудыка. Встали — и у его горькой воды ведьма впервые дотянулась до семьи.","Кенжекей Сорқұдыққа қонбауды өтінді. Қонды — ащы суының басында жалмауыз алғаш отбасына қол салды.")},
    {id:"ert_ingen",x:70,y:44,ic:"🐫",name:L("The Grey She-Camel","Куба-инген","Құба інген"),text:L("Kenzhekei's own dowry camel, whose calving would one day be the sign of Töstik's return. Its wandering led Ernazar into the ogress's grip.","Приданая верблюдица Кенжекей, чей отёл однажды станет знаком возвращения Тёстика. Её пропажа привела Ерназара в лапы ведьмы.","Кенжекейдің жасау түйесі, ботасы бір күні Төстіктің оралуының белгісі болмақ. Оны іздеу Ерназарды жалмауыздың қолына апарды.")}],
  snake_court:[
    {id:"ert_snakes",x:36,y:44,ic:"🐍",name:L("The Guardian Serpents","Змеи-стражи","Күзетші жыландар"),text:L("Two black serpents at the door, two grey at the threshold, two golden on the throne — the doorkeepers, the children, and the very selves of Bapy Khan. To flinch was to fail.","Две чёрные змеи у двери, две серые у порога, две золотые на троне — стражи, дети и сам Бапы-хан с женой. Дрогнуть — значило проиграть.","Есікте екі қара жылан, табалдырықта екі сұр, тақта екі алтын — күзетшілер, балалар, Бапы ханның өзі мен әйелі. Именсең — жеңілдің.")}],
  temir_aul:[
    {id:"ert_companions",x:64,y:40,ic:"🤝",name:L("The Six Wonders","Шесть чудо-спутников","Алты ғажайып жолдас"),text:L("Mountain-Mover, Lake-Drinker, Swift-Foot, Keen-Ear, Sharp-Eye and the Deft One — six marvels of the underworld who joined Töstik, each mightier than an army in his own strange gift.","Таусогар, Колтауысар, Желаяк, Саккулак, Зоркий и Ловкач — шесть чудес подземья, что примкнули к Тёстику, каждый сильнее войска в своём даре.","Таусоғар, Көлтауысар, Желаяқ, Саққұлақ, Қырағы және Епті — Төстікке қосылған жер астының алты кереметі, әрқайсысы өз өнерінде әскерден күшті.")}],
  world_tree:[
    {id:"ert_bayterek",x:50,y:24,ic:"🌳",name:L("The Bayterek","Бәйтерек","Бәйтерек"),text:L("The world-tree at the spring of the underworld, so vast a single branch could shade a day's ride. In its crown the great bird Samuryk built her nest.","Мировое древо у подземного родника, столь огромное, что одна ветвь укрывала дневной переход. В его кроне вила гнездо Самрук.","Жер асты бұлағының басындағы бәйтерек, бір бұтағы бір күндік жерді көлеңкелейтін. Ұясын ұлы Самұрық құс сонда салған.")},
    {id:"ert_aydahar",x:74,y:52,ic:"🐉",name:L("The Dragon of the Tree","Дракон древа","Ағаш айдаһары"),text:L("Every year a dragon climbed the Bayterek to devour Samuryk's chicks. Töstik's single arrow, loosed between its eyes, made him the great bird's friend forever.","Каждый год дракон полз по Бәйтереку пожрать птенцов Самрук. Одна стрела Тёстика между глаз сделала его другом птицы навек.","Жыл сайын айдаһар балапандарды жеуге бәйтерекке өрмелейтін. Төстіктің көзінің арасына тиген жалғыз жебесі оны құстың мәңгі досы қылды.")}],
  deer_spring:[
    {id:"ert_deer",x:44,y:44,ic:"🦌",name:L("The Forty Deer","Сорок оленей","Қырық елік"),text:L("Forty deer that come to Boryqty spring at noon; among them the bent brown doe whose belly hid nine chests — and in the smallest, the soul of a monster.","Сорок оленей приходят к роднику Борыкты в полдень; средь них бурая олениха, чьё чрево скрывало девять ларцов — и в меньшем душа чудовища.","Түсте Борықты бұлаққа келетін қырық елік; арасында ішінде тоғыз сандық жасырған қайқы қаракер елік — ең кішісінде жауыздың жаны.")}]
};

