const FROG_RELICS = {
  golden_ball:{name:L("The Golden Ball","Золотой мяч","Алтын доп"),lore:L("The princess's best-loved toy — a ball of pure gold she would toss into the air and catch beside the cool spring. The one careless throw that changed everything.","Самая любимая игрушка принцессы — мяч из чистого золота, что она подбрасывала и ловила у прохладного родника. Тот один небрежный бросок, что переменил всё.","Ханшайымның ең сүйікті ойыншығы — салқын бұлақ жанында аспанға лақтырып, қағып алатын саф алтыннан жасалған доп. Бәрін өзгерткен сол бір ұқыпсыз лақтырыс.")},
  golden_plate:{name:L("The Golden Plate","Золотое блюдо","Алтын табақ"),lore:L("From this plate the princess ate at the king's table — and, by her own promise, so too did a cold little frog, mouthful for mouthful beside her.","С этого блюда принцесса ела за столом короля — и, по её же обещанию, ела с него и холодная лягушка, кусок за куском рядом с ней.","Осы табақтан ханшайым патшаның дастарханында тамақтанды — өз уәдесі бойынша, қасында суық бақа да лұқпа-лұқпадан жеді.")},
  iron_bands:{name:L("The Three Iron Bands","Три железных обруча","Үш темір шеңбер"),lore:L("Faithful Henry had three iron bands forged around his heart, lest it burst with grief when his master became a frog. Joy, at last, would snap them one by one.","Верный Генрих велел сковать три железных обруча вокруг сердца, чтоб оно не разорвалось от горя, когда господин стал лягушкой. Радость наконец разбила их один за другим.","Адал Генрих қожайыны бақаға айналғанда жүрегі қайғыдан жарылмасын деп, оның айналасына үш темір шеңбер соқтырған. Ақыры қуаныш оларды бірінен соң бірін үзді.")},
  gold_crown:{name:L("The Golden Crown","Золотая корона","Алтын тәж"),lore:L("The crown the princess offered the frog, and all her pearls and jewels besides — none of which he wanted. He asked only for a friend.","Корона, что принцесса предлагала лягушке, и все её жемчуга и самоцветы впридачу — ничего из этого он не желал. Он просил лишь друга.","Ханшайым бақаға ұсынған тәж, оған қоса барлық меруерті мен асыл тастары — оның ешқайсысы бақаға керегі жоқ еді. Ол тек дос сұрады.")}
};

