const FROG_DISCOVERIES={
  spring:[
    {id:"fp_lime",x:28,y:32,ic:"🌳",name:L("The Old Lime Tree","Старая липа","Кәрі жөке ағашы"),text:L("For a hundred years the great lime has shaded this spring. Its heart-shaped leaves whisper over the water, and bees hum in its blossom every midsummer.","Сто лет большая липа укрывает этот родник. Её сердцевидные листья шепчут над водой, а в её цвету каждое лето гудят пчёлы.","Жүз жыл бойы алып жөке осы бұлақты көлеңкелеп тұр. Жүрек пішінді жапырақтары су үстінде сыбырлайды, гүлдеген шағында әр жазда аралар ызыңдайды.")},
    {id:"fp_ball",x:66,y:52,ic:"🟡",name:L("The Golden Ball","Золотой мяч","Алтын доп"),text:L("Solid gold, warm from the sun, light enough to toss to the clouds. The princess loved it above every other treasure — until it slipped from her hands into the deep.","Из чистого золота, тёплый от солнца, лёгкий, чтоб подбросить до облаков. Принцесса любила его больше всех сокровищ — пока он не выскользнул из рук в глубину.","Саф алтыннан, күннен жылынған, бұлтқа дейін лақтыруға жеңіл. Ханшайым оны барлық қазынадан артық көрді — қолынан сусып тереңге кеткенше.")}
  ],
  forest:[
    {id:"fp_path",x:34,y:44,ic:"🍃",name:L("The Forest Path","Лесная тропа","Орман соқпағы"),text:L("A narrow path winds between the old trees to the spring. Not far from the palace, yet the deeper you go, the older and quieter the world becomes.","Узкая тропа вьётся меж старых деревьев к роднику. Недалеко от дворца, но чем глубже идёшь, тем древнее и тише становится мир.","Тар соқпақ кәрі ағаштардың арасымен бұлаққа қарай ирелеңдейді. Сарайдан алыс емес, бірақ тереңдеген сайын әлем көне әрі тыныш бола түседі.")},
    {id:"fp_reeds",x:72,y:60,ic:"🌾",name:L("The Whispering Reeds","Шепчущий камыш","Сыбырлаған қамыс"),text:L("Tall reeds crowd the water's edge. They say an enchanted thing may hide among them for years, waiting for the one heart brave enough to keep a promise.","Высокий камыш теснится у кромки воды. Говорят, зачарованное существо может годами таиться в нём, ожидая единственное сердце, что сдержит обещание.","Биік қамыс су жиегіне үймелеп өседі. Айтуларынша, сиқырланған жан онда жылдар бойы тығылып, уәдені орындауға батылы жететін жалғыз жүректі күте алады.")}
  ],
  palace_hall:[
    {id:"fp_plate",x:30,y:52,ic:"🍽️",name:L("The Golden Plate","Золотое блюдо","Алтын табақ"),text:L("Every dish at the king's table is served on gold. The princess never once thought she might share hers — least of all with a frog.","Всякое блюдо за столом короля подают на золоте. Принцесса и помыслить не могла, что придётся делить своё — да ещё с лягушкой.","Патшаның дастарханындағы әр тағам алтын табаққа тартылады. Ханшайым өз табағын біреумен бөлісемін деп ойламаған да еді — оның үстіне бақамен.")},
    {id:"fp_steps",x:70,y:40,ic:"🪜",name:L("The Marble Steps","Мраморные ступени","Мәрмәр саты"),text:L("Wide steps of pale marble climb to the great doors. Up them, splish-splash, one wet step at a time, came a visitor no one had invited.","Широкие ступени бледного мрамора ведут к большим дверям. По ним, плюх-шлёп, ступень за мокрой ступенью, поднимался незваный гость.","Ақ мәрмәрдан қаланған кең саты үлкен есікке қарай көтеріледі. Солармен, былш-былш, бір-бірлеп дымқыл сатымен, ешкім шақырмаған қонақ көтерілді.")}
  ],
  princes_kingdom:[
    {id:"fp_carriage",x:26,y:56,ic:"🐎",name:L("The Eight White Horses","Восемь белых коней","Сегіз ақ ат"),text:L("A carriage came drawn by eight white horses in golden harness, with ostrich plumes nodding at their brows — sent to carry the prince home at last.","Прибыла карета, запряжённая восемью белыми конями в золотой сбруе, со страусиными перьями на лбах — присланная увезти принца наконец домой.","Алтын әбзелді сегіз ақ ат жеккен күйме келді, маңдайларында түйеқұс қауырсындары желбіреген — ханзаданы ақыры үйіне алып қайтуға жіберілген.")},
    {id:"fp_towers",x:68,y:30,ic:"🏰",name:L("The Golden Spires","Золотые шпили","Алтын мұнаралар"),text:L("The prince's kingdom rises white and gold on a green hill. For long years its towers waited empty for a master lost to a witch's spell.","Королевство принца встаёт бело-золотым на зелёном холме. Долгие годы его башни пустовали, ожидая господина, потерянного из-за чар колдуньи.","Ханзаданың патшалығы жасыл төбеде аппақ, алтын болып көтеріледі. Ұзақ жылдар оның мұнаралары мыстанның сиқырынан айырылған қожайынын күтіп бос тұрды.")}
  ]
};

const FROG_PLAYABLE = [
  {key:"princess", name:FROG_NAME.princess, role:L("The Youngest Princess","Младшая принцесса","Кенже ханшайым"), path:"princess",
   power:L("Loveliest of the king's daughters, and the most spoiled. A careless promise by a forest spring will teach you what a given word is truly worth — and what a cold little friend may become.","Прекраснейшая из дочерей короля и самая избалованная. Небрежное обещание у лесного родника научит тебя, чего на деле стоит данное слово — и кем может стать холодный маленький друг.","Патшаның қыздарының ішіндегі ең сұлуы әрі ең еркесі. Орман бұлағының жанындағы ұқыпсыз уәде саған берген сөздің шын бағасын үйретеді — әрі суық кішкентай досың кімге айналатынын.")},
  {key:"prince", name:FROG_NAME.prince, role:L("The Enchanted Frog","Заколдованный принц","Сиқырланған ханзада"), path:"prince",
   power:L("A witch's spell has bound you into the shape of a frog, chained to a lonely spring. Only a princess who keeps her promise can break it. Live the long wait, the bargain, and the moment the spell shatters.","Чары колдуньи заключили тебя в облик лягушки, прикованной к одинокому роднику. Разрушить их может лишь принцесса, что сдержит слово. Проживи долгое ожидание, сделку и миг, когда чары спадут.","Мыстанның сиқыры сені жалғыз бұлаққа шынжырланған бақаның кейпіне түсірді. Оны тек уәдесін орындаған ханшайым бұза алады. Ұзақ күтуді, келісімді және сиқыр сынған сәтті бастан кешір.")},
  {key:"henry", name:FROG_NAME.henry, role:L("The Faithful Servant","Верный слуга","Адал қызметші"), path:"henry",
   power:L("You served the prince before the curse, and grieved so hard when he was lost that you had three iron bands forged round your heart. Keep your long, loyal watch — and feel the bands break with joy.","Ты служил принцу до проклятия и так горевал, когда он пропал, что велел сковать три железных обруча вокруг сердца. Неси свою долгую, верную стражу — и почувствуй, как обручи лопнут от радости.","Сен ханзадаға қарғыстан бұрын қызмет еттің, ол жоғалғанда сонша қайғырғаныңнан жүрегіңе үш темір шеңбер соқтырдың. Ұзақ, адал күзетіңді жалғастыр — де шеңберлердің қуаныштан үзілгенін сез.")}
];

const FROG_STORY = {
 princess:{
  ending:{ title:L("The Word That Became a Crown","Слово, ставшее короной","Тәжге айналған сөз"),
    text:L("A golden ball, a careless promise, and a cold little frog you could hardly bear to touch — and from all of it, a prince, a kingdom, and a love you never expected. You learned the hardest and the sweetest lesson a princess can learn: a promise given must be a promise kept, and the smallest, ugliest thing may hold the greatest heart of all. And so, keeping her word, the youngest princess became a queen.",
      "Золотой мяч, небрежное обещание и холодная лягушка, к которой ты едва могла притронуться, — и из всего этого принц, королевство и любовь, которой ты не ждала. Ты усвоила самый трудный и самый сладкий урок, какой может усвоить принцесса: данное обещание нужно держать, а в самом малом и невзрачном может биться самое большое сердце. И так, сдержав слово, младшая принцесса стала королевой.",
      "Алтын доп, ұқыпсыз уәде және әрең қол тигізетін суық кішкентай бақа — солардың бәрінен ханзада, патшалық және сен күтпеген махаббат туды. Ханшайым үйрене алатын ең қиын әрі ең тәтті сабақты меңгердің: берген уәдені орындау керек, ал ең кішкентай, ең көріксіз жанда бәрінен зор жүрек соғып тұруы мүмкін. Сөйтіп, сөзінде тұрған кенже ханшайым патшайым болды.") },
  chapters:[
   { title:L("The Golden Ball","Золотой мяч","Алтын доп"), scene:"spring",
     obj:L("Play by the spring — and lose what you love most","Поиграй у родника — и потеряй самое любимое","Бұлақ жанында ойна — де ең сүйгеніңнен айырыл"),
     beats:[
      {narr:L("In the old days, when wishing still helped, there lived a king whose daughters were all beautiful — but the youngest was so lovely that even the sun was amazed each time it shone upon her face.",
        "В старые дни, когда желания ещё сбывались, жил-был король, и все дочери его были прекрасны — но младшая была так хороша, что даже солнце дивилось всякий раз, освещая её лицо.",
        "Ерте заманда, тілек әлі де көмектесетін кезде, бір патша өмір сүріпті, оның қыздарының бәрі сұлу еді — бірақ кенжесі сондай әдемі болды, тіпті күн оның жүзіне сәуле түсірген сайын таңғалатын.")},
      {narr:L("Not far from the palace lay a great, dark forest, and under an old lime tree there was a spring. On hot days the youngest princess would sit beside the cool water and toss a golden ball into the air and catch it. It was her best-loved toy.",
        "Недалеко от дворца лежал большой тёмный лес, а под старой липой был родник. В жаркие дни младшая принцесса садилась у прохладной воды, подбрасывала золотой мяч и ловила его. То была её самая любимая игрушка.",
        "Сарайдан алыс емес жерде үлкен қара орман жатты, ал кәрі жөке ағашының астында бұлақ бар еді. Ыстық күндері кенже ханшайым салқын судың жанына отырып, алтын допты аспанға лақтырып, қағып алатын. Ол оның ең сүйікті ойыншығы болатын.")},
      {dialog:[
        {who:"princess",em:"warm",line:L("Up you go, little sun of gold — as high as the treetops! No one throws you higher than I.","Лети, золотое солнышко, — до самых верхушек! Никто не бросает тебя выше меня.","Ұш, алтын күнім — ағаш басына дейін! Сені менен биік лақтыратын ешкім жоқ.")},
        {who:"sister",em:"gossip",line:L("Careful, sister — one day that ball will fly where you cannot follow.","Осторожней, сестрица, — однажды мяч улетит туда, куда тебе не добраться.","Абайла, әпке — бір күні ол доп сен жете алмайтын жерге ұшып кетеді.")}
      ]},
      {narr:L("One day the ball did not fall back into her little hand. It slipped past her fingers, struck the ground, and rolled straight into the spring — and the water was so deep you could not see the bottom.",
        "Однажды мяч не вернулся в её ладошку. Он выскользнул меж пальцев, ударился оземь и покатился прямо в родник — а вода была так глубока, что дна не разглядеть.",
        "Бір күні доп оның алақанына қайтып түспеді. Саусақтарынан сусып, жерге тиіп, тура бұлаққа домалап кетті — ал су сондай терең еді, түбін көру мүмкін емес.")},
      {narr:L("The princess watched it sink and vanish, and she began to cry. Her sobs grew louder and louder, for she was in such distress.",
        "Принцесса смотрела, как он тонет и исчезает, и заплакала. Всхлипы её становились всё громче, так велико было её горе.",
        "Ханшайым оның батып, көзден ғайып болғанын көріп, жылай бастады. Қайғысы сонша ауыр болғандықтан, өксігі барған сайын қатая түсті.")},
      {dialog:[
        {who:"frog",em:"soft",line:L("What is the matter, king's daughter? You are crying so hard that even a stone would pity you.","Что случилось, дочь короля? Ты плачешь так, что и камень бы тебя пожалел.","Не болды, патшаның қызы? Тасты да аяр етіп, соншама қатты жылап тұрсың ғой.")},
        {who:"princess",em:"tears",line:L("Oh — it's you, is it, splish-splash? I am crying because my golden ball has fallen into the spring.","Ах — это ты, плюх-шлёп? Я плачу оттого, что мой золотой мяч упал в родник.","Ә — сен бе едің, былш-былш? Алтын допым бұлаққа түсіп кеткендіктен жылап тұрмын.")}
      ]},
      {dialog:[
        {who:"frog",em:"kind",line:L("Hush then, don't cry. I can help you. But what will you give me if I bring back your toy?","Полно, не плачь. Я помогу. Но что ты дашь мне, если я верну твою игрушку?","Қой, жылама. Мен көмектесе аламын. Бірақ ойыншығыңды әкеліп берсем, маған не бересің?")},
        {who:"princess",em:"pleading",line:L("Anything you like, you dear frog — my clothes, my pearls, my jewels, even my golden crown!","Всё, что захочешь, милая лягушка, — платья, жемчуга, самоцветы, даже мою золотую корону!","Не қаласаң да, қымбатты бақа — киімдерімді, меруерттерімді, асыл тастарымды, тіпті алтын тәжімді де!")}
      ]},
      {dialog:[
        {who:"frog",em:"soft",line:L("I care nothing for your clothes or pearls or crown. But let me be your friend — sit with you at table, eat from your golden plate, drink from your cup, and sleep upon your bed — and I will dive for your ball.","Мне не нужны ни платья, ни жемчуга, ни корона. Но позволь мне стать твоим другом — сидеть с тобой за столом, есть с твоего золотого блюда, пить из твоей чаши и спать на твоей постели — и я нырну за мячом.","Маған киімің де, меруертің де, тәжің де керек емес. Бірақ досың болуыма рұқсат ет — дастарханда қасыңда отырып, алтын табағыңнан жеп, тостағаныңнан ішіп, төсегіңде ұйықтауыма — сонда допыңа сүңгимін.")},
        {who:"princess",em:"warm",line:L("Oh yes — I promise! (What nonsense this silly frog talks. All he does is sit and croak. How could he ever be my friend?)","О да — обещаю! (Что за вздор мелет глупая лягушка. Только и знает, что сидеть да квакать. Какой из неё друг?)","Иә, әрине — уәде етемін! (Мына ақымақ бақа не деп мылжыңдайды. Отырып бақылдаудан басқа не біледі? Қайдан дос болушы еді?)")}
      ]},
      {narr:L("Once she had promised, the frog dived under the water and soon came back with the golden ball in its mouth, and threw it onto the grass. The princess snatched up her toy and ran for home, joyful — and forgot the poor frog entirely.",
        "Как только она пообещала, лягушка нырнула и вскоре вернулась с золотым мячом во рту и бросила его на траву. Принцесса схватила игрушку и радостно побежала домой — и напрочь забыла о бедной лягушке.",
        "Уәде беруі мұң екен, бақа суға сүңгіп, көп ұзамай алтын допты аузына тістеп қайтып шықты да, шөпке лақтырды. Ханшайым ойыншығын іліп алып, қуана үйіне қарай жүгірді — де байғұс бақаны мүлдем ұмытты.")},
      {dialog:[
        {who:"frog",em:"hurt",line:L("Wait! Take me with you — I cannot run as you do!","Постой! Возьми меня с собой — я не умею бегать, как ты!","Тоқта! Мені де ал — сен сияқты жүгіре алмаймын ғой!")},
        {who:"princess",em:"cool",line:L("A promise to a frog is no promise at all. Farewell, splish-splash!","Обещание лягушке — вовсе не обещание. Прощай, плюх-шлёп!","Бақаға берген уәде — уәде емес. Қош бол, былш-былш!")}
      ], act:"ball"}
     ]},
   { title:L("The Uninvited Guest","Незваный гость","Шақырылмаған қонақ"), scene:"palace_hall",
     obj:L("Face the visitor who climbs the marble steps","Встреть гостя, что взбирается по мраморной лестнице","Мәрмәр сатымен өрлеп келе жатқан қонақты қарсы ал"),
     beats:[
      {narr:L("Next day, as the princess sat at table with the king and all his courtiers, eating from her golden plate, something came hopping — splish-splash — up the marble steps. It knocked at the great door and cried out.",
        "На другой день, когда принцесса сидела за столом с королём и всеми придворными и ела с золотого блюда, что-то заскакало — плюх-шлёп — вверх по мраморной лестнице. Оно постучало в большую дверь и позвало.",
        "Ертеңіне ханшайым патшамен және барлық сарай адамдарымен дастарханда отырып, алтын табағынан жеп жатқанда, әлдене секектеп — былш-былш — мәрмәр сатымен өрледі. Ол үлкен есікті қағып, айқайлады.")},
      {dialog:[
        {who:"frog",em:"soft",line:L("Princess, youngest princess, open and let me in.","Принцесса, младшая принцесса, отвори и впусти меня.","Ханшайым, кенже ханшайым, есікті аш, кіргіз мені.")}
      ]},
      {narr:L("She ran to see who was there, and when she opened the door and saw the frog, she slammed it shut as fast as she could and hurried back to her chair, her heart pounding.",
        "Она побежала посмотреть, кто там, а увидев лягушку, захлопнула дверь что было сил и поспешила назад к своему стулу, и сердце её колотилось.",
        "Ол кім екенін көрмекке жүгіріп барды, бақаны көрген бойда есікті бар күшімен сарт жауып, жүрегі дүрсілдеп, орнына қайта асықты.")},
      {dialog:[
        {who:"king",em:"wise",line:L("What frightens you so, child? Is there a giant at the door come to carry you off?","Что тебя так напугало, дитя? Уж не великан ли за дверью, что хочет тебя унести?","Сені сонша не қорқытты, балам? Есік алдында сені алып кетуге келген алып тұр ма әлде?")},
        {who:"princess",em:"worried",line:L("It is no giant, Father. It is a nasty, cold, slimy frog.","Не великан, батюшка. Это мерзкая, холодная, скользкая лягушка.","Алып емес, әке. Ол — жиренішті, суық, жылтыр бақа.")}
      ]},
      {dialog:[
        {who:"king",em:"gentle",line:L("And what does a frog want with a princess?","И что нужно лягушке от принцессы?","Ал бақаның ханшайымнан не алғысы келеді?")},
        {who:"princess",em:"soft",line:L("Yesterday, by the spring, my golden ball fell in. I cried so hard the frog fetched it for me — but first it made me promise it could live with me. I never thought it could leave the water... and now it is at the door.","Вчера у родника мой золотой мяч упал в воду. Я так плакала, что лягушка достала его — но сперва взяла с меня обещание, что будет жить со мной. Я и не думала, что она выберется из воды... а теперь она у дверей.","Кеше бұлақ жанында алтын допым суға түсті. Мен қатты жылағанда бақа оны алып берді — бірақ алдымен өзінің менімен бірге тұратынына уәде алды. Судан шыға алады деп ойламап едім... енді ол есік алдында тұр.")}
      ]}
     ]},
   { title:L("A Promise Is a Promise","Обещание есть обещание","Уәде — уәде"), scene:"throne_room",
     obj:L("Learn from the king what a given word is worth","Узнай у короля, чего стоит данное слово","Патшадан берген сөздің бағасын біл"),
     beats:[
      {narr:L("As they spoke, the frog knocked a second time, and this time it sang.",
        "Пока они говорили, лягушка постучала во второй раз и на сей раз запела.",
        "Олар сөйлесіп тұрғанда, бақа екінші рет қақты, бұл жолы ол ән салды.")},
      {dialog:[
        {who:"frog",em:"soft",line:L("Princess, youngest princess, let me in. You gave me your promise, down by the spring. Princess, youngest princess, let me in.","Принцесса, младшая принцесса, впусти. Ты дала мне обещание там, у родника. Принцесса, младшая принцесса, впусти.","Ханшайым, кенже ханшайым, кіргіз. Уәде бердің ғой маған бұлақтың жағасында. Ханшайым, кенже ханшайым, кіргіз.")}
      ]},
      {dialog:[
        {who:"king",em:"resolve",line:L("You made a promise, daughter, and a promise must be kept. Go and let the frog in.","Ты дала слово, дочь моя, а слово надо держать. Ступай и впусти лягушку.","Уәде бердің, қызым, ал уәдені орындау керек. Барып, бақаны кіргіз.")},
        {who:"princess",em:"worried",line:L("But Father — to a frog? Must I truly keep such a promise?","Но батюшка — лягушке? Неужели я должна сдержать такое обещание?","Бірақ әке — бақаға ма? Осындай уәдені шынымен орындауым керек пе?")},
        {who:"king",em:"wise",line:L("Especially such a promise. He who helps you in your need must not be despised after. Open the door.","Особенно такое. Кто помог тебе в нужде, того нельзя презирать после. Отвори дверь.","Әсіресе осындайды. Мұқтаж кезіңде көмектескенді кейін жек көруге болмайды. Есікті аш.")}
      ]},
      {narr:L("So she opened the door, and the frog hopped in and followed her, splish-splash, all the way to her chair. Then it called to be lifted up beside her, and the king nodded that she must.",
        "И она отворила дверь, и лягушка вскочила и поскакала за ней, плюх-шлёп, до самого стула. Потом велела посадить её рядом, и король кивнул, что так и надо.",
        "Сонымен ол есікті ашты, бақа секіріп кіріп, соңынан былш-былш орнына дейін ерді. Сосын қасына көтеріп қоюды сұрады, патша солай ету керек екенін басын изеп білдірді.")},
      {dialog:[
        {who:"frog",em:"soft",line:L("Now push your golden plate a little nearer, so that we may eat together.","А теперь придвинь золотое блюдо поближе, чтобы нам есть вместе.","Енді алтын табағыңды жақындат, бірге тамақтанайық.")},
        {who:"princess",em:"soft",line:L("...As you wish. (Every mouthful sticks in my throat.)","...Как пожелаешь. (Каждый кусок застревает у меня в горле.)","...Қалауыңша. (Әр лұқпа тамағыма тұрып қалады.)")}
      ], act:"puzzle"}
     ]},
   { title:L("The Frog in the Chamber","Лягушка в опочивальне","Бөлмедегі бақа"), scene:"bedchamber",
     obj:L("Face the frog one last time — and break the spell","Встреть лягушку в последний раз — и разрушь чары","Бақамен соңғы рет бетпе-бет кел — де сиқырды бұз"),
     beats:[
      {dialog:[
        {who:"frog",em:"soft",line:L("I have eaten enough, and now I am tired. Carry me to your room and make ready your silken bed, so that we may sleep.","Я наелся и теперь устал. Отнеси меня в свою комнату и постели шёлковую постель, чтобы нам уснуть.","Тойдым, енді шаршадым. Мені бөлменге апарып, жібек төсегіңді дайында, ұйықтайық.")},
        {who:"princess",em:"tears",line:L("Sleep in my clean, pretty bed? I cannot bear to touch a cold, damp frog!","Спать в моей чистой, красивой постели? Я не в силах притронуться к холодной, склизкой лягушке!","Менің таза, әдемі төсегімде ұйықтау ма? Суық, дымқыл бақаға қол тигізе алмаймын!")}
      ]},
      {dialog:[
        {who:"king",em:"fierce",line:L("He helped you when you were in trouble. You shall not scorn him now. Take him up.","Он помог тебе в беде. Не смей теперь его презирать. Возьми его.","Ол сен қиналғанда көмектесті. Енді оны жек көруге болмайды. Көтеріп ал.")}
      ]},
      {narr:L("So she picked the frog up between two fingertips, carried it upstairs and set it down in a corner. But when she lay in bed, it came hopping across the floor.",
        "И она подняла лягушку двумя пальцами, отнесла наверх и посадила в угол. Но когда она легла, лягушка запрыгала по полу к ней.",
        "Сонымен ол бақаны екі саусағының ұшымен ұстап, жоғары апарып, бұрышқа қойды. Бірақ ол төсекке жатқанда, бақа еденмен секіріп келе бастады.")},
      {dialog:[
        {who:"frog",em:"pleading",line:L("I am tired, and I want to sleep as well as you. Lift me up, or I shall tell your father.","Я устал и хочу спать не хуже тебя. Подними меня, не то я скажу твоему отцу.","Мен де шаршадым, сен сияқты ұйықтағым келеді. Мені көтер, әйтпесе әкеңе айтамын.")},
        {who:"princess",em:"fierce",line:L("Then take THAT, you horrible frog — and be still at last!","Так вот тебе, мерзкая лягушка, — и умолкни наконец!","Ендеше, мынаны ал, жексұрын бақа — де ақыры тыныш бол!")}
      ]},
      {narr:L("In her anger she seized the frog in both hands and hurled it against the wall. But when it fell, it was no longer a frog. There stood a handsome prince with kind and sparkling eyes.",
        "В гневе она схватила лягушку обеими руками и швырнула о стену. Но, упав, она уже не была лягушкой. Пред нею стоял прекрасный принц с добрыми, сияющими глазами.",
        "Ашуланғанынан ол бақаны екі қолымен ұстап, қабырғаға сарт ұрды. Бірақ құлаған кезде ол енді бақа емес еді. Алдында мейірімді, жарқыраған көзді сұлу ханзада тұрды.")},
      {dialog:[
        {who:"prince",em:"tender",line:L("A wicked witch put a spell on me, and no one but you could break it. You kept your promise, and it has set me free.","Злая колдунья наложила на меня чары, и никто, кроме тебя, не мог их снять. Ты сдержала слово — и оно освободило меня.","Мыстан кемпір маған сиқыр салған еді, оны сенен басқа ешкім бұза алмайтын. Сен уәдеңде тұрдың — сол мені азат етті.")},
        {who:"princess",em:"dazed",line:L("Then... the cold little frog I could not bear to touch was a prince all along?","Так... холодная лягушка, к которой я боялась притронуться, всё время была принцем?","Демек... қол тигізуден қорыққан суық бақа әрдайым ханзада болған ба?")}
      ], act:"transform"}
     ]},
   { title:L("The Journey Home","Путь домой","Үйге қайту"), scene:"carriage_road",
     obj:L("Ride out to the prince's kingdom","Отправься в королевство принца","Ханзаданың патшалығына аттан"),
     beats:[
      {narr:L("In the morning a carriage arrived, drawn by eight white horses with golden harness and ostrich plumes at their brows. Behind it stood Faithful Henry, the prince's servant, come to carry his master home.",
        "Поутру прибыла карета, запряжённая восемью белыми конями в золотой сбруе, со страусиными перьями на лбах. Позади стоял Верный Генрих, слуга принца, приехавший увезти господина домой.",
        "Таңертең алтын әбзелді, маңдайларында түйеқұс қауырсыны бар сегіз ақ ат жеккен күйме келді. Артында ханзаданың қызметшісі Адал Генрих тұрды, ол қожайынын үйіне алып қайтуға келген еді.")},
      {dialog:[
        {who:"henry",em:"warm",line:L("Welcome back, my prince — and welcome to you, my princess. The whole kingdom has waited long for this day.","С возвращением, мой принц, — и добро пожаловать, моя принцесса. Всё королевство долго ждало этого дня.","Қайтып оралуыңмен, ханзадам — қош келдің, ханшайымым. Бүкіл патшалық осы күнді ұзақ күтті.")}
      ]},
      {narr:L("When they had driven a little way, the prince heard a loud crack behind him, as though the carriage were breaking.",
        "Когда они отъехали немного, принц услышал позади громкий треск, будто карета ломается.",
        "Аздап жол жүргенде, ханзада артынан күйме сынып жатқандай қатты сырт еткен дыбыс естіді.")},
      {dialog:[
        {who:"prince",em:"worried",line:L("Henry — the carriage is breaking!","Генрих — карета ломается!","Генрих — күйме сынып жатыр!")},
        {who:"henry",em:"tender",line:L("No, master — it is only an iron band about my heart. I had three forged there, lest it burst with grief while you were a frog beneath the spring. One has snapped now, for joy that you are free.","Нет, господин, — это лишь железный обруч на моём сердце. Я велел сковать три, чтоб оно не разорвалось от горя, пока ты был лягушкой под водой. Один лопнул — от радости, что ты свободен.","Жоқ, қожайын — бұл жүрегімдегі темір шеңбер ғана. Сен бұлақ түбінде бақа болғанда, жүрегім қайғыдан жарылмасын деп үшеу соқтырғам. Біреуі енді үзілді — сенің азат болғаныңа қуанғаннан.")}
      ]},
      {narr:L("Twice more upon the road the prince heard the great crack, and twice more he feared the carriage was breaking. But it was only Faithful Henry's heart, filling with happiness, snapping the iron bands of sorrow one by one.",
        "Ещё дважды в пути принц слышал громкий треск и дважды пугался, что карета ломается. Но то было лишь сердце Верного Генриха, наполняясь счастьем, разбивало один за другим железные обручи печали.",
        "Жолда тағы екі рет ханзада қатты сырт еткенді естіп, тағы екі рет күйме сынды деп қорықты. Бірақ бұл Адал Генрихтің жүрегі ғана болатын — бақытқа толып, қайғының темір шеңберлерін бірінен соң бірін үзіп жатты.")},
      {dialog:[
        {who:"prince",em:"warm",line:L("Then let them all break, faithful friend. Our sorrows are behind us, and my kingdom lies just over the hill.","Так пусть же лопнут все, верный друг. Печали наши позади, а королевство моё — вон за тем холмом.","Ендеше бәрі де үзілсін, адал досым. Қайғымыз артта қалды, ал патшалығым анау төбенің арғы жағында ғана.")}
      ], act:"carriage"}
     ]}
  ]},

 prince:{
  ending:{ title:L("The Prince Who Was Set Free","Принц, обретший свободу","Азаттыққа жеткен ханзада"),
    text:L("For long, lonely years you waited in the reeds of a forgotten spring, a prince in a frog's cold skin, while a witch's spell held your true shape prisoner. You could not force the spell — only a kept promise could break it. And when at last one was kept, you rose again, a prince, and rode home with the very princess whose word set you free. Patience, and the faith that a promise still means something, carried you out of the dark water and into the light.",
      "Долгие, одинокие годы ты ждал в камышах забытого родника — принц в холодной шкуре лягушки, покуда чары колдуньи держали в плену твой истинный облик. Ты не мог сломать чары силой — их могло разрушить лишь сдержанное обещание. И когда его наконец сдержали, ты вновь восстал принцем и уехал домой с той самой принцессой, чьё слово тебя освободило. Терпение и вера в то, что обещание ещё что-то значит, вывели тебя из тёмной воды к свету.",
      "Ұзақ, жалғыз жылдар бойы сен ұмыт болған бұлақтың қамысында күттің — бақаның суық терісіндегі ханзада, ал мыстанның сиқыры шынайы кейпіңді тұтқында ұстады. Сиқырды күшпен бұза алмадың — оны тек орындалған уәде ғана бұза алатын. Ақыры біреу уәдесін орындағанда, сен қайта ханзада болып тұрдың да, сені азат еткен сөздің иесі — сол ханшайыммен үйіңе аттандың. Шыдам мен уәденің әлі де мәні бар екеніне сенім сені қара судан жарыққа алып шықты.") },
  chapters:[
   { title:L("The Witch's Curse","Проклятие колдуньи","Мыстанның қарғысы"), scene:"forest",
     obj:L("Live the moment the spell falls upon you","Проживи миг, когда чары настигают тебя","Сиқыр саған түскен сәтті бастан кешір"),
     beats:[
      {cine:[
        {narr:L("You were a prince once, young and proud, with a kingdom of white towers and a servant, Faithful Henry, who loved you as a brother.","Ты был когда-то принцем, юным и гордым, с королевством белых башен и слугой, Верным Генрихом, что любил тебя, как брата.","Сен бір кездері ханзада едің — жас әрі паң, аппақ мұнаралы патшалығың және сені бауырындай жақсы көретін қызметшің Адал Генрих бар еді.")},
        {narr:L("But on a dark day in the forest you met a wicked witch, and gave her neither greeting nor kindness — and for that cold heart she laid a cold spell upon you.","Но в тёмный день в лесу ты встретил злую колдунью и не дал ей ни привета, ни доброты — и за холодное сердце она наложила на тебя холодные чары.","Бірақ орманда бір қараңғы күні мыстан кемпірді кездестіріп, оған не сәлем, не мейірім бермедің — сол суық жүрек үшін ол саған суық сиқыр салды.")}
      ]},
      {dialog:[
        {who:"witch",em:"cold",line:L("So proud, little prince, and so cold of heart. A cold heart deserves a cold shape. Be a frog, and sit in the spring, until one keeps a promise made to you.","Так горд, маленький принц, и так холоден сердцем. Холодному сердцу — холодный облик. Стань лягушкой и сиди в роднике, пока кто-нибудь не сдержит данного тебе слова.","Сонша паңсың, кішкентай ханзада, әрі жүрегің суық. Суық жүрекке суық кейіп лайық. Бақа бол да, біреу саған берген уәдесін орындағанша бұлақта отыр.")},
        {who:"prince",em:"worried",line:L("Wait — mercy! What must I do to be free?","Постой — пощади! Что мне сделать, чтоб освободиться?","Тоқта — рақым ет! Азат болу үшін не істеуім керек?")},
        {who:"witch",em:"cold",line:L("Nothing. That is the cruelty of it. Another must choose to keep faith with a frog. Croak, and wait.","Ничего. В том и жестокость. Кто-то другой должен сам сдержать слово, данное лягушке. Квакай и жди.","Ештеңе. Оның қаталдығы да сонда. Басқа біреу бақаға берген сөзінде тұруды өзі таңдауы керек. Бақылда да, күт.")}
      ], act:"transform"}
     ]},
   { title:L("Years in the Spring","Годы в роднике","Бұлақтағы жылдар"), scene:"spring",
     obj:L("Wait in the cold water — until a golden ball falls","Жди в холодной воде — пока не упадёт золотой мяч","Салқын суда күт — алтын доп түскенше"),
     beats:[
      {narr:L("Season after season you sat among the reeds, watching the surface of the spring, a prince's mind trapped behind a frog's wide eyes. Then, one hot day, a golden ball dropped through the water and sank to the bottom — and above, a princess wept.",
        "Время шло за временем, а ты сидел в камышах, глядя на гладь родника, — ум принца, запертый за широкими глазами лягушки. И вот, в жаркий день, золотой мяч упал сквозь воду и опустился на дно, а наверху плакала принцесса.",
        "Маусым артынан маусым өтіп, сен қамыс арасында отырып, бұлақтың бетіне қарадың — бақаның ірі көздерінің артында қамалған ханзаданың ойы. Сосын бір ыстық күні алтын доп судан өтіп, түбіне батты, ал жоғарыда ханшайым жылап тұрды.")},
      {dialog:[
        {who:"frog",em:"soft",line:L("A weeping princess — and a golden ball at the bottom of my spring. Perhaps, after all these years, here is my one chance.","Плачущая принцесса — и золотой мяч на дне моего родника. Быть может, после стольких лет вот он, мой единственный шанс.","Жылап тұрған ханшайым — де бұлағымның түбінде алтын доп. Бәлкім, сонша жылдан кейін, міне, менің жалғыз мүмкіндігім.")}
      ]},
      {dialog:[
        {who:"frog",em:"kind",line:L("Don't cry, king's daughter. I will fetch your ball — if you will promise to let me be your friend.","Не плачь, дочь короля. Я достану твой мяч — если пообещаешь, что позволишь мне стать твоим другом.","Жылама, патшаның қызы. Допыңды алып беремін — егер досың болуыма уәде берсең.")},
        {who:"princess",em:"pleading",line:L("Anything, dear frog — only bring it back to me!","Всё что угодно, милая лягушка, — только верни его!","Не болса да, қымбатты бақа — тек оны маған қайтарып бер!")}
      ]},
      {narr:L("You dived, as you had a hundred times in play, and this time carried up a princess's dearest treasure. She promised — and then she ran, and forgot you. But a spell does not care whether a promise is remembered. Only whether, in the end, it is kept.",
        "Ты нырнул, как нырял сотню раз играючи, и на сей раз вынес самое дорогое сокровище принцессы. Она пообещала — а потом убежала и забыла тебя. Но чарам всё равно, помнят ли обещание. Важно лишь, сдержат ли его в конце.",
        "Сен ойнап жүз рет сүңгігендей сүңгідің, бұл жолы ханшайымның ең қымбат қазынасын алып шықтың. Ол уәде берді — сосын жүгіріп кетіп, сені ұмытты. Бірақ сиқырға уәденің есте сақталуы бәрібір. Тек ақыр соңында орындала ма, жоқ па — маңыздысы сол.")}
     ]},
   { title:L("At the Princess's Table","За столом принцессы","Ханшайымның дастарханында"), scene:"palace_hall",
     obj:L("Follow the princess and hold her to her word","Иди за принцессой и напомни ей о слове","Ханшайымның соңынан еріп, сөзін еске сал"),
     beats:[
      {narr:L("You could not run as she ran, but a frog is patient. Splish-splash, step by wet step, you climbed the marble stairs of the palace and knocked upon the door.",
        "Ты не мог бежать, как она, но лягушка терпелива. Плюх-шлёп, мокрая ступень за ступенью, ты взобрался по мраморной лестнице дворца и постучал в дверь.",
        "Сен ол сияқты жүгіре алмадың, бірақ бақа шыдамды. Былш-былш, дымқыл сатыдан саты, сен сарайдың мәрмәр басқышымен көтеріліп, есікті қақтың.")},
      {dialog:[
        {who:"frog",em:"soft",line:L("Princess, youngest princess, let me in. You gave me your promise, down by the spring.","Принцесса, младшая принцесса, впусти. Ты дала мне обещание там, у родника.","Ханшайым, кенже ханшайым, кіргіз. Уәде бердің ғой маған бұлақтың жағасында.")},
        {who:"king",em:"resolve",line:L("The little one is right, daughter. A promise is a promise. Let the frog come in and sit by you.","Малыш прав, дочь моя. Обещание есть обещание. Впусти лягушку и посади рядом.","Кішкентайдың айтқаны дұрыс, қызым. Уәде — уәде. Бақаны кіргіз де, қасыңа отырғыз.")}
      ]},
      {narr:L("And so you ate from her golden plate, mouthful for mouthful, while she sat stiff with disgust — and all the while you thought: patience, patience. The spell is old, but a kept promise is stronger.",
        "И ты ел с её золотого блюда, кусок за куском, пока она сидела, застыв от отвращения, — а сам всё думал: терпение, терпение. Чары стары, но сдержанное обещание сильнее.",
        "Сөйтіп сен оның алтын табағынан лұқпа-лұқпадан жедің, ал ол жиіркеніштен қатып отырды — ал өзің: шыда, шыда, деп ойладың. Сиқыр көне, бірақ орындалған уәде одан күшті.")}
     ]},
   { title:L("The Spell Breaks","Чары спадают","Сиқыр сынады"), scene:"bedchamber",
     obj:L("Ask for the last thing — and be made whole","Попроси о последнем — и стань собою вновь","Соңғы нәрсені сұра — де қайта өзің бол"),
     beats:[
      {dialog:[
        {who:"frog",em:"pleading",line:L("Carry me to your room. I am tired, and by your promise I am to sleep beside you. Lift me up — or I shall tell your father.","Отнеси меня в комнату. Я устал, и по твоему обещанию мне спать подле тебя. Подними меня — не то скажу твоему отцу.","Мені бөлменге апар. Шаршадым, уәдең бойынша қасыңда ұйықтауым керек. Мені көтер — әйтпесе әкеңе айтамын.")},
        {who:"princess",em:"fierce",line:L("Then take THAT, you horrible frog!","Так вот тебе, мерзкая лягушка!","Ендеше, мынаны ал, жексұрын бақа!")}
      ]},
      {narr:L("She hurled you against the wall — and in that hard, angry moment the witch's spell shattered like ice. The frog's skin fell away, and you stood upright once more: a prince, whole, with your own two hands and your own sparkling eyes.",
        "Она швырнула тебя о стену — и в тот жёсткий, гневный миг чары колдуньи раскололись, как лёд. Лягушачья шкура спала, и ты вновь встал во весь рост: принц, целый, со своими руками и своими сияющими глазами.",
        "Ол сені қабырғаға сарт ұрды — сол қатал, ашулы сәтте мыстанның сиқыры мұздай шытынап сынды. Бақаның терісі түсіп, сен қайтадан тік тұрдың: бүтін ханзада, өз қолдарыңмен, өз жарқыраған көздеріңмен.")},
      {dialog:[
        {who:"prince",em:"tender",line:L("Do not be afraid. A wicked witch bound me, and only you could set me free. You kept your word — and so the spell is broken forever.","Не бойся. Злая колдунья сковала меня, и лишь ты могла освободить. Ты сдержала слово — и чары разрушены навсегда.","Қорықпа. Мыстан кемпір мені байлаған еді, тек сен ғана азат ете алатынсың. Сен сөзіңде тұрдың — сиқыр мәңгіге бұзылды.")}
      ], act:"transform"}
     ]},
   { title:L("Home at Last","Наконец-то домой","Ақыры үйге"), scene:"princes_kingdom",
     obj:L("Return to the kingdom that waited for you","Вернись в королевство, что ждало тебя","Сені күткен патшалыққа орал"),
     beats:[
      {narr:L("At dawn a carriage came for you, drawn by eight white horses in golden harness, and Faithful Henry stood behind it, weeping for joy. He had waited all these years with three iron bands about his heart.",
        "На рассвете за тобой прибыла карета, запряжённая восемью белыми конями в золотой сбруе, и позади стоял Верный Генрих, плача от радости. Все эти годы он ждал с тремя железными обручами вокруг сердца.",
        "Таң ата саған алтын әбзелді сегіз ақ ат жеккен күйме келді, артында Адал Генрих қуаныштан жылап тұрды. Осынша жыл ол жүрегіне үш темір шеңбер салып күткен еді.")},
      {dialog:[
        {who:"henry",em:"tears",line:L("My prince — you are yourself again! I hardly dared to hope. Come home; your kingdom has kept your throne warm.","Мой принц — ты снова стал собой! Я и надеяться не смел. Едем домой; королевство хранило твой трон.","Ханзадам — сен қайта өзің болдың! Үміт етуге де батпап едім. Үйге қайтайық; патшалығың тағыңды сақтап тұр.")},
        {who:"prince",em:"warm",line:L("Faithful Henry. Through all my froggish years, I never doubted you would be here. Take us home.","Верный Генрих. Все мои лягушачьи годы я ни разу не усомнился, что ты будешь здесь. Вези нас домой.","Адал Генрих. Бақа болған барлық жылдарымда сенің осында болатыныңа бір сәт те күмәнданбадым. Бізді үйге апар.")}
      ], act:"carriage"}
     ]}
  ]},

 henry:{
  ending:{ title:L("The Heart That Would Not Break","Сердце, что не разбилось","Сынбаған жүрек"),
    text:L("You are only a servant, the tale never even gives your deeds a chapter of their own — yet without your faith there would be no ending at all. You bound your grieving heart in iron so it would not burst while your master suffered, and you kept your watch through years of silence, never once believing him truly lost. When at last he rode home a prince again, joy broke the iron bands one by one, and your loyal heart beat free. Faithful Henry: the quietest hero of the tale, and its truest.",
      "Ты всего лишь слуга, сказка даже не отвела твоим делам отдельной главы, — но без твоей верности не было бы и конца. Ты сковал скорбящее сердце железом, чтоб оно не разорвалось, пока страдал господин, и нёс свою стражу сквозь годы молчания, ни разу не поверив, что он и вправду потерян. И когда он наконец вернулся домой снова принцем, радость разбила железные обручи один за другим, и верное сердце твоё забилось на воле. Верный Генрих — тишайший герой сказки и самый истинный.",
      "Сен бар болғаны қызметшісің, ертегі сенің істеріңе жеке тарау да арнамайды — бірақ сенің адалдығың болмаса, ешқандай ақыр да болмас еді. Қожайының азап шеккенде жүрегің жарылмасын деп, оны темірмен байладың, үнсіздік жылдарында күзетіңді жалғастырдың, оны шынымен жоғалды деп бір рет те сенбедің. Ол ақыры қайта ханзада болып үйге оралғанда, қуаныш темір шеңберлерді бірінен соң бірін үзді, адал жүрегің азат болып соқты. Адал Генрих — ертегінің ең үнсіз, әрі ең шынайы қаһарманы.") },
  chapters:[
   { title:L("The Master Lost","Потерянный господин","Жоғалған қожайын"), scene:"princes_kingdom",
     obj:L("Grieve for the prince — and bind your heart in iron","Оплачь принца — и скуй сердце железом","Ханзадаға қайғыр — де жүрегіңді темірмен байла"),
     beats:[
      {narr:L("You are Faithful Henry, servant and friend to the young prince. One dark day he rode into the forest and never came back — and word crept home that a witch had turned him into a frog and bound him to a forest spring.",
        "Ты Верный Генрих, слуга и друг молодого принца. В один тёмный день он уехал в лес и не вернулся — а домой прокралась весть, что колдунья обратила его в лягушку и приковала к лесному роднику.",
        "Сен Адал Генрихсің — жас ханзаданың қызметшісі әрі досы. Бір қараңғы күні ол орманға аттанып, қайтып оралмады — ал үйге мыстан оны бақаға айналдырып, орман бұлағына байлап қойды деген хабар жетті.")},
      {dialog:[
        {who:"henry",em:"tears",line:L("My prince, a frog in the cold water... My heart will surely break in two. I cannot bear this grief.","Мой принц — лягушка в холодной воде... Сердце моё вот-вот разорвётся надвое. Мне не снести этой скорби.","Ханзадам — суық судағы бақа... Жүрегім екіге жарылатын шығар. Бұл қайғыны көтере алмаймын.")}
      ]},
      {narr:L("So that your heart would not burst with sorrow, you went to the smith and had three strong iron bands forged and set about it — grief bound in iron, to be borne until your master should come home.",
        "И чтоб сердце не разорвалось от горя, ты пошёл к кузнецу и велел сковать три крепких железных обруча и надеть их на сердце — скорбь, закованная в железо, чтобы нести её, пока господин не вернётся.",
        "Жүрегің қайғыдан жарылмасын деп, ұстаға барып, үш мықты темір шеңбер соқтырып, оны жүрегіңе орнаттың — қожайының үйге қайтқанша көтеретін, темірге қамалған қайғы.")},
      {dialog:[
        {who:"henry",em:"resolve",line:L("Hold now, iron. Hold my heart together until the day he is free. However long the years, I will wait.","Держи, железо. Скрепи моё сердце до дня, когда он освободится. Сколько бы ни было лет, я буду ждать.","Ұста, темір. Ол азат болатын күнге дейін жүрегімді бүтін сақта. Жылдар қанша созылса да, күтемін.")}
      ], act:"bands"}
     ]},
   { title:L("The Long Watch","Долгая стража","Ұзақ күзет"), scene:"carriage_road",
     obj:L("Keep faith through the silent years","Храни верность сквозь безмолвные годы","Үнсіз жылдарда адалдықты сақта"),
     beats:[
      {narr:L("The years passed and no word came. Others called the prince lost for good and told you to grieve and move on. But you readied his kingdom as if he might return any morning, and never let the dust settle on his empty throne.",
        "Годы шли, и вестей не было. Другие звали принца потерянным навек и велели тебе смириться и жить дальше. Но ты держал королевство наготове, будто он мог вернуться любым утром, и не давал пыли осесть на пустом троне.",
        "Жылдар өтті, ешбір хабар келмеді. Өзгелер ханзаданы біржола жоғалды деп, саған қайғырып, күнелте бер деді. Бірақ сен оның патшалығын кез келген таңда орала қалғандай дайын ұстадың, бос тағына шаң қондырмадың.")},
      {dialog:[
        {who:"sister",em:"gossip",line:L("Henry, it has been years. No man comes back from a witch's spell. Why do you still keep his lamps lit?","Генрих, прошло столько лет. Никто не возвращается от колдовских чар. Зачем ты всё ещё жжёшь его светильники?","Генрих, қанша жыл өтті. Мыстанның сиқырынан ешкім қайтпайды. Неге әлі оның шамдарын жағып қоясың?")},
        {who:"henry",em:"resolve",line:L("Because a servant's faith does not run out like a candle. He helped others when he could; I will keep faith with him now. He will come home.","Оттого что верность слуги не тает, как свеча. Он помогал другим, когда мог; и я сохраню верность ему. Он вернётся домой.","Себебі қызметшінің адалдығы шам сияқты таусылмайды. Ол қолынан келгенде өзгелерге көмектесті; мен де оған адал болып қаламын. Ол үйге қайтады.")}
      ]},
      {narr:L("And every night you touched the three iron bands about your heart and felt them cold and unbroken — a sign, you told yourself, that somewhere your master lived on, waiting as patiently as you.",
        "И каждую ночь ты касался трёх железных обручей на сердце и чувствовал их холодными и целыми — знак, говорил ты себе, что где-то господин твой жив и ждёт так же терпеливо, как ты.",
        "Әр түні жүрегіңдегі үш темір шеңберге қол тигізіп, олардың суық әрі бүтін екенін сездің — бұл, дедің өзіңе, қожайының бір жерде тірі жүр, ол да сен сияқты шыдаммен күтіп жатыр деген белгі.")}
     ]},
   { title:L("The Bands Break","Обручи лопаются","Шеңберлер үзіледі"), scene:"carriage_road",
     obj:L("Drive your master home — and let joy break the iron","Вези господина домой — и пусть радость разобьёт железо","Қожайыныңды үйге апар — де қуаныш темірді үзсін"),
     beats:[
      {narr:L("At last the summons came: the spell was broken, the prince was a man again. You harnessed eight white horses in gold, set ostrich plumes at their brows, and drove yourself to fetch him — and there he stood, whole, beside a princess.",
        "Наконец пришёл зов: чары разрушены, принц снова человек. Ты запряг восьмерых белых коней в золото, надел им на лбы страусиные перья и сам поехал за ним — и вот он стоял, целый, рядом с принцессой.",
        "Ақыры шақыру келді: сиқыр бұзылды, ханзада қайта адам болды. Сен сегіз ақ атты алтынға жегіп, маңдайларына түйеқұс қауырсынын тағып, оны алуға өзің аттандың — де, міне, ол бүтін күйінде ханшайымның қасында тұрды.")},
      {dialog:[
        {who:"henry",em:"tears",line:L("My prince — it is truly you. Climb in, both of you; I will carry you home myself, as I always swore I would.","Мой принц — это и вправду ты. Садитесь оба; я сам отвезу вас домой, как и клялся.","Ханзадам — бұл шынымен сен екенсің. Екеуің де мініңдер; ант еткенімдей, өздеріңді үйге өзім апарамын.")}
      ]},
      {narr:L("As you drove, a great crack rang out, and then another, and another. Not the carriage — the three iron bands about your heart, bursting one after another, for the sorrow that had bound them was gone, and only joy was left.",
        "Пока вы ехали, раздался громкий треск, потом ещё и ещё. То не карета — три железных обруча на твоём сердце лопались один за другим, ибо скорбь, что их сковала, ушла, и осталась только радость.",
        "Жол жүріп келе жатқанда қатты сырт еткен дыбыс шықты, сосын тағы, тағы. Ол күйме емес — жүрегіңдегі үш темір шеңбер бірінен соң бірі үзілді, өйткені оларды байлаған қайғы кетіп, тек қуаныш қалды.")},
      {dialog:[
        {who:"prince",em:"warm",line:L("Henry — the carriage!","Генрих — карета!","Генрих — күйме!")},
        {who:"henry",em:"warm",line:L("No, master. It is only my heart, throwing off its iron at last. I told you it would hold — and it did, until this happy day.","Нет, господин. Это лишь моё сердце наконец сбрасывает своё железо. Я говорил, что оно выдержит, — и оно выдержало, до этого счастливого дня.","Жоқ, қожайын. Бұл жүрегім ғана — ақыры темірін лақтырып тастап жатыр. Айтқам ғой шыдайды деп — шыдады да, осы бақытты күнге дейін.")}
      ], act:"carriage"}
     ]}
  ]}
};

