const QANBAK_DISCOVERIES = {
  "shore":[{id:"qb_net",x:30,y:62,ic:"\ud83c\udfa3",name:L("The Fishing Net","\u0420\u044b\u0431\u0430\u0446\u043a\u0430\u044f \u0441\u0435\u0442\u044c","\u0411\u0430\u043b\u044b\u049b \u0430\u0443\u043b\u0430\u0439\u0442\u044b\u043d \u0430\u0443"),text:L("A single net was a poor man's whole livelihood on the steppe rivers.","\u041e\u0434\u043d\u0430 \u0441\u0435\u0442\u044c \u0431\u044b\u043b\u0430 \u0434\u043b\u044f \u0431\u0435\u0434\u043d\u044f\u043a\u0430 \u0432\u0441\u0435\u043c \u043f\u0440\u043e\u043f\u0438\u0442\u0430\u043d\u0438\u0435\u043c \u043d\u0430 \u0441\u0442\u0435\u043f\u043d\u044b\u0445 \u0440\u0435\u043a\u0430\u0445.","\u0414\u0430\u043b\u0430 \u04e9\u0437\u0435\u043d\u0434\u0435\u0440\u0456\u043d\u0434\u0435 \u0431\u0456\u0440 \u0430\u0443 \u043a\u0435\u0434\u0435\u0439\u0434\u0456\u04a3 \u0431\u04af\u043a\u0456\u043b \u043d\u04d9\u043f\u0430\u049b\u0430\u0441\u044b \u0435\u0434\u0456.")}],
  "mountains":[{id:"qb_flint",x:60,y:38,ic:"\ud83e\udea8",name:L("Flint","\u041a\u0440\u0435\u043c\u0435\u043d\u044c","\u0428\u0430\u049b\u043f\u0430\u049b \u0442\u0430\u0441"),text:L("Nomads struck flint (shaqpaq) to make fire \u2014 this giant strikes whole mountains for sparks.","\u041a\u043e\u0447\u0435\u0432\u043d\u0438\u043a\u0438 \u0432\u044b\u0441\u0435\u043a\u0430\u043b\u0438 \u043e\u0433\u043e\u043d\u044c \u043a\u0440\u0435\u043c\u043d\u0451\u043c (\u0448\u0430\u043a\u043f\u0430\u043a) \u2014 \u044d\u0442\u043e\u0442 \u0436\u0435 \u0432\u0435\u043b\u0438\u043a\u0430\u043d \u0431\u044c\u0451\u0442 \u0446\u0435\u043b\u044b\u043c\u0438 \u0433\u043e\u0440\u0430\u043c\u0438.","\u041a\u04e9\u0448\u043f\u0435\u043d\u0434\u0456\u043b\u0435\u0440 \u0448\u0430\u049b\u043f\u0430\u049b \u0442\u0430\u0441\u044b\u043c\u0435\u043d \u043e\u0442 \u0436\u0430\u0493\u0430\u0442\u044b\u043d \u2014 \u0431\u04b1\u043b \u0434\u04d9\u0443 \u04b1\u0448\u049b\u044b\u043d \u04af\u0448\u0456\u043d \u0431\u04af\u0442\u0456\u043d \u0442\u0430\u0443\u043b\u0430\u0440\u0434\u044b \u0441\u043e\u0493\u0430\u0434\u044b.")}],
  "home":[{id:"qb_hearth",x:68,y:52,ic:"\u26fa",name:L("The Hearth","\u041e\u0447\u0430\u0433","\u041e\u0448\u0430\u049b"),text:L("Even the poorest kept a warm hearth for a guest \u2014 hospitality is sacred on the steppe.","\u0414\u0430\u0436\u0435 \u0431\u0435\u0434\u043d\u0435\u0439\u0448\u0438\u0439 \u0434\u0435\u0440\u0436\u0430\u043b \u0442\u0451\u043f\u043b\u044b\u0439 \u043e\u0447\u0430\u0433 \u0434\u043b\u044f \u0433\u043e\u0441\u0442\u044f \u2014 \u0433\u043e\u0441\u0442\u0435\u043f\u0440\u0438\u0438\u043c\u0441\u0442\u0432\u043e \u0432 \u0441\u0442\u0435\u043f\u0438 \u0441\u0432\u044f\u0442\u043e.","\u0415\u04a3 \u043a\u0435\u0434\u0435\u0439 \u0434\u0435 \u049b\u043e\u043d\u0430\u049b\u049b\u0430 \u0436\u044b\u043b\u044b \u043e\u0448\u0430\u049b \u0441\u0430\u049b\u0442\u0430\u0493\u0430\u043d \u2014 \u049b\u043e\u043d\u0430\u049b\u0436\u0430\u0439\u043b\u044b\u043b\u044b\u049b \u0434\u0430\u043b\u0430 \u04af\u0448\u0456\u043d \u049b\u0430\u0441\u0438\u0435\u0442\u0442\u0456.")}]
};

const QANBAK_PLAYABLE = [
  {key:"qanbaq", name:QANBAK_NAME.qanbaq, role:L("The Tumbleweed Old Man","\u0421\u0442\u0430\u0440\u0438\u043a \u041f\u0435\u0440\u0435\u043a\u0430\u0442\u0438-\u043f\u043e\u043b\u0435","\u049a\u0430\u04a3\u0431\u0430\u049b \u0448\u0430\u043b"), power:L("You own nothing but your wits \u2014 and on the steppe, a sharp wit outweighs any mountain.","\u0423 \u0442\u0435\u0431\u044f \u043d\u0435\u0442 \u043d\u0438\u0447\u0435\u0433\u043e, \u043a\u0440\u043e\u043c\u0435 \u0443\u043c\u0430 \u2014 \u0430 \u0432 \u0441\u0442\u0435\u043f\u0438 \u043e\u0441\u0442\u0440\u044b\u0439 \u0443\u043c \u043f\u0435\u0440\u0435\u0432\u0435\u0441\u0438\u0442 \u043b\u044e\u0431\u0443\u044e \u0433\u043e\u0440\u0443.","\u0410\u049b\u044b\u043b\u044b\u04a3\u043d\u0430\u043d \u0431\u0430\u0441\u049b\u0430 \u0435\u0448\u0442\u0435\u04a3\u0435\u04a3 \u0436\u043e\u049b \u2014 \u0430\u043b \u0434\u0430\u043b\u0430\u0434\u0430 \u04e9\u0442\u043a\u0456\u0440 \u0430\u049b\u044b\u043b \u043a\u0435\u0437 \u043a\u0435\u043b\u0433\u0435\u043d \u0442\u0430\u0443\u0434\u0430\u043d \u0430\u0443\u044b\u0440.")},
  {key:"dau", name:QANBAK_NAME.dau, role:L("The Mountain-Smashing Giant","\u0412\u0435\u043b\u0438\u043a\u0430\u043d, \u0447\u0442\u043e \u0431\u044c\u0451\u0442 \u0433\u043e\u0440\u0430\u043c\u0438","\u0422\u0430\u0443 \u0441\u043e\u0493\u044b\u0441\u0442\u044b\u0440\u0493\u0430\u043d \u0434\u04d9\u0443"), power:L("You can shatter mountains with your bare hands \u2014 if only you could out-think a wisp of an old man.","\u0422\u044b \u043a\u0440\u0443\u0448\u0438\u0448\u044c \u0433\u043e\u0440\u044b \u0433\u043e\u043b\u044b\u043c\u0438 \u0440\u0443\u043a\u0430\u043c\u0438 \u2014 \u0435\u0441\u043b\u0438 \u0431\u044b \u0442\u043e\u043b\u044c\u043a\u043e \u043c\u043e\u0433 \u043f\u0435\u0440\u0435\u0445\u0438\u0442\u0440\u0438\u0442\u044c \u0431\u044b\u043b\u0438\u043d\u043a\u0443-\u0441\u0442\u0430\u0440\u0438\u043a\u0430.","\u0422\u0430\u0443\u043b\u0430\u0440\u0434\u044b \u0436\u0430\u043b\u0430\u04a3 \u049b\u043e\u043b\u043c\u0435\u043d \u049b\u0438\u0440\u0430\u0442\u0430\u0441\u044b\u04a3 \u2014 \u0431\u0456\u0440 \u0443\u044b\u0441 \u0448\u0430\u043b\u0434\u0430\u043d \u0430\u049b\u044b\u043b\u043c\u0435\u043d \u043e\u0437\u0430 \u0430\u043b\u0441\u0430\u04a3 \u0493\u043e\u0439.")},
  {key:"tulki", name:QANBAK_NAME.tulki, role:L("The Sly Fox","\u0425\u0438\u0442\u0440\u0430\u044f \u043b\u0438\u0441\u0430","\u049a\u0443 \u0442\u04af\u043b\u043a\u0456"), power:L("The cleverest thief on the whole riverbank \u2014 or so you have always believed.","\u0425\u0438\u0442\u0440\u0435\u0439\u0448\u0430\u044f \u0432\u043e\u0440\u043e\u0432\u043a\u0430 \u043d\u0430 \u0432\u0441\u0451\u043c \u0431\u0435\u0440\u0435\u0433\u0443 \u2014 \u0438\u043b\u0438 \u0442\u0430\u043a \u0442\u044b \u0432\u0441\u0435\u0433\u0434\u0430 \u0441\u0447\u0438\u0442\u0430\u043b\u0430.","\u0411\u04af\u043a\u0456\u043b \u0436\u0430\u0493\u0430\u0434\u0430\u0493\u044b \u0435\u04a3 \u049b\u0443 \u04b1\u0440\u044b \u2014 \u04e9\u0437\u0456\u04a3 \u04d9\u0440\u049b\u0430\u0448\u0430\u043d \u0441\u043e\u043b\u0430\u0439 \u0441\u0435\u043d\u0433\u0435\u043d\u0441\u0456\u04a3.")}
];

const QANBAK_STORY = {
 "qanbaq":{ ending:{title:L("The Wind's Own Trickster","\u0425\u0438\u0442\u0440\u0435\u0446, \u0447\u0442\u043e \u043b\u0435\u0433\u0447\u0435 \u0432\u0435\u0442\u0440\u0430","\u0416\u0435\u043b\u0434\u0435\u043d \u0436\u0435\u04a3\u0456\u043b \u0430\u0439\u043b\u0430\u043a\u0435\u0440"),text:L("Qa\u00f1baq Shal outwitted a fox, a valley of giants and the black middle of the night \u2014 with nothing but his wits \u2014 and came home rich. Brain over brawn; the kind and clever heart carries the day.","\u041a\u0430\u0144\u0431\u0430\u043a-\u0448\u0430\u043b \u043f\u0435\u0440\u0435\u0445\u0438\u0442\u0440\u0438\u043b \u043b\u0438\u0441\u0443, \u0434\u043e\u043b\u0438\u043d\u0443 \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u043e\u0432 \u0438 \u0433\u043b\u0443\u0445\u0443\u044e \u043f\u043e\u043b\u043d\u043e\u0447\u044c \u2014 \u043e\u0434\u043d\u0438\u043c \u043b\u0438\u0448\u044c \u0443\u043c\u043e\u043c \u2014 \u0438 \u0432\u0435\u0440\u043d\u0443\u043b\u0441\u044f \u0434\u043e\u043c\u043e\u0439 \u0431\u043e\u0433\u0430\u0447\u043e\u043c. \u0423\u043c \u0441\u0438\u043b\u044c\u043d\u0435\u0435 \u0441\u0438\u043b\u044b; \u0434\u043e\u0431\u0440\u044b\u0439 \u0438 \u0445\u0438\u0442\u0440\u044b\u0439 \u0440\u0430\u0437\u0443\u043c \u043f\u043e\u0431\u0435\u0436\u0434\u0430\u0435\u0442.","\u049a\u0430\u04a3\u0431\u0430\u049b \u0448\u0430\u043b \u0442\u04af\u043b\u043a\u0456\u043d\u0456 \u0434\u0435, \u0434\u04d9\u0443\u043b\u0435\u0440 \u0430\u04a3\u0493\u0430\u0440\u044b\u043d \u0434\u0430, \u0442\u04af\u043d \u043e\u0440\u0442\u0430\u0441\u044b\u043d \u0434\u0430 \u2014 \u0442\u0435\u043a \u0430\u049b\u044b\u043b\u044b\u043c\u0435\u043d \u2014 \u0430\u043b\u0434\u0430\u043f, \u04af\u0439\u0456\u043d\u0435 \u0431\u0430\u0439 \u0431\u043e\u043b\u044b\u043f \u043e\u0440\u0430\u043b\u0434\u044b. \u0410\u049b\u044b\u043b \u043a\u04af\u0448\u0442\u0435\u043d \u043e\u0437\u0430\u0434\u044b; \u043c\u0435\u0439\u0456\u0440\u0456\u043c\u0434\u0456 \u0434\u0435 \u0430\u0439\u043b\u0430\u043a\u0435\u0440 \u0436\u04af\u0440\u0435\u043a \u0436\u0435\u04a3\u0435\u0434\u0456.")},
  chapters:[
  {title:L("The Tumbleweed Old Man","\u0421\u0442\u0430\u0440\u0438\u043a \u041f\u0435\u0440\u0435\u043a\u0430\u0442\u0438-\u043f\u043e\u043b\u0435","\u049a\u0430\u04a3\u0431\u0430\u049b \u0448\u0430\u043b"), scene:"shore", obj:L("Meet Qa\u00f1baq Shal and the fox who robs him","\u041f\u043e\u0437\u043d\u0430\u043a\u043e\u043c\u044c\u0442\u0435\u0441\u044c \u0441 \u041a\u0430\u0144\u0431\u0430\u043a-\u0448\u0430\u043b\u043e\u043c \u0438 \u043b\u0438\u0441\u043e\u0439, \u0447\u0442\u043e \u0435\u0433\u043e \u043e\u0431\u0438\u0440\u0430\u0435\u0442","\u049a\u0430\u04a3\u0431\u0430\u049b \u0448\u0430\u043b\u043c\u0435\u043d \u0436\u04d9\u043d\u0435 \u043e\u043d\u044b \u0442\u043e\u043d\u0430\u0439\u0442\u044b\u043d \u0442\u04af\u043b\u043a\u0456\u043c\u0435\u043d \u0442\u0430\u043d\u044b\u0441"),
   beats:[
     {narr:L("Long, long ago it was \u2014 when the goats were dappled grey and the pheasants were red \u2014 there lived an old man named Qa\u00f1baq Shal.","\u0414\u0430\u0432\u043d\u044b\u043c-\u0434\u0430\u0432\u043d\u043e \u044d\u0442\u043e \u0431\u044b\u043b\u043e \u2014 \u043a\u043e\u0433\u0434\u0430 \u043a\u043e\u0437\u044b \u0431\u044b\u043b\u0438 \u043f\u0451\u0441\u0442\u0440\u043e-\u0441\u0435\u0440\u044b\u043c\u0438, \u0430 \u0444\u0430\u0437\u0430\u043d\u044b \u043a\u0440\u0430\u0441\u043d\u044b\u043c\u0438 \u2014 \u0436\u0438\u043b-\u0431\u044b\u043b \u0441\u0442\u0430\u0440\u0438\u043a \u043f\u043e \u0438\u043c\u0435\u043d\u0438 \u041a\u0430\u0144\u0431\u0430\u043a-\u0448\u0430\u043b.","\u0415\u0440\u0442\u0435-\u0435\u0440\u0442\u0435, \u0435\u0440\u0442\u0435 \u0435\u043a\u0435\u043d, \u0435\u0448\u043a\u0456\u043b\u0435\u0440\u0456 \u0431\u04e9\u0440\u0442\u0435 \u0435\u043a\u0435\u043d, \u049b\u044b\u0440\u0493\u0430\u0443\u044b\u043b\u044b \u049b\u044b\u0437\u044b\u043b \u0435\u043a\u0435\u043d \u2014 \u0441\u043e\u043b \u0437\u0430\u043c\u0430\u043d\u0434\u0430 \u049a\u0430\u04a3\u0431\u0430\u049b \u0448\u0430\u043b \u0434\u0435\u0433\u0435\u043d \u0448\u0430\u043b \u0431\u043e\u043b\u044b\u043f\u0442\u044b.")},
     {narr:L("He was poor as a bare reed, and alone. He owned nothing but a fishing net, and lived on what the river gave him. He was so thin and light that when the wind rose it rolled him across the steppe like a ball of tumbleweed \u2014 and so the people named him Qa\u00f1baq.","\u0411\u0435\u0434\u0435\u043d \u043e\u043d \u0431\u044b\u043b, \u043a\u0430\u043a \u0433\u043e\u043b\u044b\u0439 \u043a\u0430\u043c\u044b\u0448, \u0438 \u043e\u0434\u0438\u043d\u043e\u043a. \u041d\u0435 \u0431\u044b\u043b\u043e \u0443 \u043d\u0435\u0433\u043e \u043d\u0438\u0447\u0435\u0433\u043e, \u043a\u0440\u043e\u043c\u0435 \u0440\u044b\u0431\u0430\u0446\u043a\u043e\u0439 \u0441\u0435\u0442\u0438, \u0438 \u043a\u043e\u0440\u043c\u0438\u043b\u0441\u044f \u043e\u043d \u0442\u0435\u043c, \u0447\u0442\u043e \u0434\u0430\u0432\u0430\u043b\u0430 \u0440\u0435\u043a\u0430. \u0411\u044b\u043b \u043e\u043d \u0442\u0430\u043a \u0445\u0443\u0434 \u0438 \u043b\u0451\u0433\u043e\u043a, \u0447\u0442\u043e \u0441\u0442\u043e\u0438\u043b\u043e \u043f\u043e\u0434\u043d\u044f\u0442\u044c\u0441\u044f \u0432\u0435\u0442\u0440\u0443 \u2014 \u0438 \u043a\u0430\u0442\u0438\u043b\u043e \u0435\u0433\u043e \u043f\u043e \u0441\u0442\u0435\u043f\u0438, \u043a\u0430\u043a \u043f\u0435\u0440\u0435\u043a\u0430\u0442\u0438-\u043f\u043e\u043b\u0435. \u041e\u0442\u0442\u043e\u0433\u043e \u0438 \u043f\u0440\u043e\u0437\u0432\u0430\u043b\u0438 \u0435\u0433\u043e \u041a\u0430\u0144\u0431\u0430\u043a\u043e\u043c.","\u041e\u043b \u0436\u0430\u043b\u0493\u044b\u0437, \u043a\u0435\u0434\u0435\u0439\u043b\u0456\u043a\u0442\u0435\u043d \u0448\u044b\u049b\u043f\u0430\u0493\u0430\u043d \u0448\u0430\u043b \u0435\u043a\u0435\u043d. \u0410\u0443 \u0441\u0430\u043b\u044b\u043f, \u0431\u0430\u043b\u044b\u049b \u04b1\u0441\u0442\u0430\u043f \u043a\u04af\u043d \u043a\u04e9\u0440\u0456\u043f\u0442\u0456. \u0421\u043e\u043d\u0448\u0430 \u0436\u0435\u04a3\u0456\u043b \u0435\u043a\u0435\u043d, \u0436\u0435\u043b \u0441\u043e\u049b\u0441\u0430, \u0434\u043e\u043c\u0430\u043b\u0430\u0439 \u0436\u04e9\u043d\u0435\u043b\u0435\u0434\u0456 \u0435\u043a\u0435\u043d. \u0421\u043e\u0434\u0430\u043d \u043e\u043d\u044b \u049a\u0430\u04a3\u0431\u0430\u049b \u0448\u0430\u043b \u0434\u0435\u043f \u0430\u0442\u0430\u043f \u043a\u0435\u0442\u0456\u043f\u0442\u0456.")},
     {narr:L("Each morning his net brought up two little fish. And each morning a sly fox slunk down to the water and took one for herself.","\u041a\u0430\u0436\u0434\u043e\u0435 \u0443\u0442\u0440\u043e \u0435\u0433\u043e \u0441\u0435\u0442\u044c \u043f\u0440\u0438\u043d\u043e\u0441\u0438\u043b\u0430 \u0434\u0432\u0435 \u0440\u044b\u0431\u0451\u0448\u043a\u0438. \u0418 \u043a\u0430\u0436\u0434\u043e\u0435 \u0443\u0442\u0440\u043e \u0445\u0438\u0442\u0440\u0430\u044f \u043b\u0438\u0441\u0430 \u043a\u0440\u0430\u043b\u0430\u0441\u044c \u043a \u0432\u043e\u0434\u0435 \u0438 \u0431\u0440\u0430\u043b\u0430 \u043e\u0434\u043d\u0443 \u0441\u0435\u0431\u0435.","\u041a\u04af\u043d \u0441\u0430\u0439\u044b\u043d \u0448\u0430\u043b\u0434\u044b\u04a3 \u0430\u0443\u044b\u043d\u0430 \u0435\u043a\u0456 \u0431\u0430\u043b\u044b\u049b \u0456\u043b\u0456\u043d\u0435\u0434\u0456 \u0435\u043a\u0435\u043d. \u041a\u04af\u043d \u0441\u0430\u0439\u044b\u043d \u0431\u0456\u0440 \u049b\u0443 \u0442\u04af\u043b\u043a\u0456 \u043a\u0435\u043b\u0456\u043f, \u0441\u043e\u043d\u044b\u04a3 \u0431\u0456\u0440\u0456\u043d \u0442\u0430\u0440\u0442\u044b\u043f \u0430\u043b\u044b\u043f \u043a\u0435\u0442\u0435\u0434\u0456 \u0435\u043a\u0435\u043d.")},
     {dialog:[{who:"tulki",em:"sly",line:L("Good morning, Grandfather. Two fish again? How generous. One for you\u2026 and one for me. That is only fair \u2014 I am so much cleverer than you.","\u0414\u043e\u0431\u0440\u043e\u0435 \u0443\u0442\u0440\u043e, \u0434\u0435\u0434\u0443\u0448\u043a\u0430. \u041e\u043f\u044f\u0442\u044c \u0434\u0432\u0435 \u0440\u044b\u0431\u043a\u0438? \u041a\u0430\u043a \u0449\u0435\u0434\u0440\u043e. \u041e\u0434\u043d\u0430 \u0442\u0435\u0431\u0435\u2026 \u0438 \u043e\u0434\u043d\u0430 \u043c\u043d\u0435. \u042d\u0442\u043e \u0441\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e \u2014 \u0432\u0435\u0434\u044c \u044f \u043a\u0443\u0434\u0430 \u0443\u043c\u043d\u0435\u0435 \u0442\u0435\u0431\u044f.","\u049a\u0430\u0439\u044b\u0440\u043b\u044b \u0442\u0430\u04a3, \u0430\u0442\u0430. \u0422\u0430\u0493\u044b \u0435\u043a\u0456 \u0431\u0430\u043b\u044b\u049b \u043f\u0430? \u049a\u0430\u043d\u0434\u0430\u0439 \u0436\u043e\u043c\u0430\u0440\u0442\u0441\u044b\u04a3. \u0411\u0456\u0440\u0435\u0443\u0456 \u0441\u0430\u0493\u0430\u043d\u2026 \u0431\u0456\u0440\u0435\u0443\u0456 \u043c\u0430\u0493\u0430\u043d. \u04d8\u0434\u0456\u043b \u0493\u043e\u0439 \u2014 \u043c\u0435\u043d \u0441\u0435\u043d\u0435\u043d \u04d9\u043b\u0434\u0435\u049b\u0430\u0439\u0434\u0430 \u0430\u049b\u044b\u043b\u0434\u044b\u043c\u044b\u043d.")},{who:"qanbaq",em:"sad",line:L("Take it, then, and choke on your fairness. A poor man cannot argue with sharp teeth.","\u0411\u0435\u0440\u0438, \u0438 \u043f\u043e\u0434\u0430\u0432\u0438\u0441\u044c \u0441\u0432\u043e\u0435\u0439 \u0441\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e\u0441\u0442\u044c\u044e. \u0411\u0435\u0434\u043d\u044f\u043a\u0443 \u043d\u0435 \u0441\u043f\u043e\u0440\u0438\u0442\u044c \u0441 \u043e\u0441\u0442\u0440\u044b\u043c\u0438 \u0437\u0443\u0431\u0430\u043c\u0438.","\u0410\u043b\u0430 \u0493\u043e\u0439, \u04d9\u0434\u0456\u043b\u0434\u0456\u0433\u0456\u04a3\u0435 \u0448\u0430\u0448\u0430\u043b\u044b\u043f \u049b\u0430\u043b. \u041a\u0435\u0434\u0435\u0439 \u0430\u0434\u0430\u043c \u04e9\u0442\u043a\u0456\u0440 \u0442\u0456\u0441\u043a\u0435 \u0434\u0430\u0443 \u0430\u0439\u0442\u0430 \u0430\u043b\u043c\u0430\u0439\u0434\u044b.")}]}
   ]},
  {title:L("The Long Road","\u0414\u043e\u043b\u0433\u0430\u044f \u0434\u043e\u0440\u043e\u0433\u0430","\u04b0\u0437\u0430\u049b \u0436\u043e\u043b"), scene:"road", obj:L("Leave the fox behind \u2014 bury your goods and set out","\u041e\u0441\u0442\u0430\u0432\u044c \u043b\u0438\u0441\u0443 \u043f\u043e\u0437\u0430\u0434\u0438 \u2014 \u0437\u0430\u043a\u043e\u043f\u0430\u0439 \u043f\u043e\u0436\u0438\u0442\u043a\u0438 \u0438 \u043e\u0442\u043f\u0440\u0430\u0432\u043b\u044f\u0439\u0441\u044f \u0432 \u043f\u0443\u0442\u044c","\u0422\u04af\u043b\u043a\u0456\u0434\u0435\u043d \u043a\u0435\u0442 \u2014 \u043c\u04af\u043b\u043a\u0456\u04a3\u0434\u0456 \u043a\u04e9\u043c\u0456\u043f, \u0436\u043e\u043b\u0493\u0430 \u0448\u044b\u049b"),
   beats:[
     {dialog:[{who:"qanbaq",em:"bold",line:L("I cannot bear that fox's mockery another day. I will move on \u2014 find another river, another shore, where no thieving fox knows my name.","\u041d\u0435 \u0432\u044b\u043d\u0435\u0441\u0443 \u0431\u043e\u043b\u044c\u0448\u0435 \u043d\u0430\u0441\u043c\u0435\u0448\u0435\u043a \u044d\u0442\u043e\u0439 \u043b\u0438\u0441\u044b. \u0423\u0439\u0434\u0443 \u2014 \u043d\u0430\u0439\u0434\u0443 \u0434\u0440\u0443\u0433\u0443\u044e \u0440\u0435\u043a\u0443, \u0434\u0440\u0443\u0433\u043e\u0439 \u0431\u0435\u0440\u0435\u0433, \u0433\u0434\u0435 \u043d\u0438 \u043e\u0434\u043d\u0430 \u0432\u043e\u0440\u043e\u0432\u043a\u0430-\u043b\u0438\u0441\u0430 \u043d\u0435 \u0437\u043d\u0430\u0435\u0442 \u043c\u043e\u0435\u0433\u043e \u0438\u043c\u0435\u043d\u0438.","\u0411\u04b1\u043b \u0442\u04af\u043b\u043a\u0456\u043d\u0456\u04a3 \u049b\u043e\u0440\u043b\u044b\u0493\u044b\u043d\u0430 \u0435\u043d\u0434\u0456 \u0448\u044b\u0434\u0430\u0439 \u0430\u043b\u043c\u0430\u0439\u043c\u044b\u043d. \u0411\u0430\u0441\u049b\u0430 \u0436\u0435\u0440\u0433\u0435 \u043a\u04e9\u0448\u0435\u043c\u0456\u043d \u2014 \u0442\u04af\u043b\u043a\u0456 \u0430\u0442\u044b\u043c\u0434\u044b \u0431\u0456\u043b\u043c\u0435\u0439\u0442\u0456\u043d \u04e9\u0437\u0433\u0435 \u04e9\u0437\u0435\u043d, \u04e9\u0437\u0433\u0435 \u0436\u0430\u0493\u0430 \u0442\u0430\u0431\u0430\u043c\u044b\u043d.")}]},
     {narr:L("He rolled up all he owned, hoisted it onto his thin old back, and set off across the steppe. But the load was heavy and the day was hot, and soon he tired.","\u041e\u043d \u0441\u043e\u0431\u0440\u0430\u043b \u0432\u0441\u0451 \u0441\u0432\u043e\u0451 \u0434\u043e\u0431\u0440\u043e, \u0432\u0437\u0432\u0430\u043b\u0438\u043b \u043d\u0430 \u0445\u0443\u0434\u0443\u044e \u0441\u0442\u0430\u0440\u0443\u044e \u0441\u043f\u0438\u043d\u0443 \u0438 \u043f\u043e\u0448\u0451\u043b \u0447\u0435\u0440\u0435\u0437 \u0441\u0442\u0435\u043f\u044c. \u041d\u043e \u043d\u043e\u0448\u0430 \u0431\u044b\u043b\u0430 \u0442\u044f\u0436\u0435\u043b\u0430, \u0430 \u0434\u0435\u043d\u044c \u0437\u043d\u043e\u0435\u043d, \u0438 \u0432\u0441\u043a\u043e\u0440\u0435 \u043e\u043d \u0443\u0442\u043e\u043c\u0438\u043b\u0441\u044f.","\u041e\u043b \u0431\u0430\u0440 \u043c\u04af\u043b\u043a\u0456\u043d \u0436\u0438\u043d\u0430\u043f, \u0430\u0440\u049b\u0430\u0441\u044b\u043d\u0430 \u0441\u0430\u043b\u044b\u043f, \u0436\u043e\u043b\u0493\u0430 \u0448\u044b\u049b\u0442\u044b. \u0411\u0456\u0440\u0430\u049b \u0436\u04af\u043a \u0430\u0443\u044b\u0440, \u043a\u04af\u043d \u044b\u0441\u0442\u044b\u049b \u0435\u0434\u0456, \u043a\u04e9\u043f \u04b1\u0437\u0430\u043c\u0430\u0439 \u0448\u0430\u0440\u0448\u0430\u0434\u044b.")},
     {narr:L("So, a little at a time, he hid his things along the way. In one place he buried his bundle of goods. In another he buried the tripe and guts he had gathered from the herders' slaughtered sheep. And in a third he buried a skin of sour ayran, white as snow.","\u0418 \u043f\u043e\u043d\u0435\u043c\u043d\u043e\u0433\u0443 \u043e\u043d \u043f\u0440\u044f\u0442\u0430\u043b \u0432\u0435\u0449\u0438 \u043f\u043e \u0434\u043e\u0440\u043e\u0433\u0435. \u0412 \u043e\u0434\u043d\u043e\u043c \u043c\u0435\u0441\u0442\u0435 \u0437\u0430\u043a\u043e\u043f\u0430\u043b \u0443\u0437\u0435\u043b \u0441 \u0434\u043e\u0431\u0440\u043e\u043c. \u0412 \u0434\u0440\u0443\u0433\u043e\u043c \u2014 \u043f\u043e\u0442\u0440\u043e\u0445\u0430 \u0438 \u0442\u0440\u0435\u0431\u0443\u0445\u0443, \u0447\u0442\u043e \u0441\u043e\u0431\u0440\u0430\u043b \u043e\u0442 \u0437\u0430\u0440\u0435\u0437\u0430\u043d\u043d\u044b\u0445 \u0447\u0430\u0431\u0430\u043d\u0430\u043c\u0438 \u043e\u0432\u0435\u0446. \u0410 \u0432 \u0442\u0440\u0435\u0442\u044c\u0435\u043c \u2014 \u0431\u0443\u0440\u0434\u044e\u043a \u043a\u0438\u0441\u043b\u043e\u0433\u043e \u0430\u0439\u0440\u0430\u043d\u0430, \u0431\u0435\u043b\u043e\u0433\u043e \u043a\u0430\u043a \u0441\u043d\u0435\u0433.","\u0421\u04e9\u0439\u0442\u0456\u043f \u043e\u043b \u043c\u04af\u043b\u043a\u0456\u043d \u0436\u043e\u043b \u0431\u043e\u0439\u044b\u043d\u0430 \u0431\u0456\u0440-\u0431\u0456\u0440\u043b\u0435\u043f \u043a\u04e9\u043c\u0434\u0456. \u0411\u0456\u0440 \u0436\u0435\u0440\u0433\u0435 \u0431\u0443\u043c\u0430-\u043c\u04af\u043b\u043a\u0456\u043d \u043a\u04e9\u043c\u0434\u0456. \u0422\u0430\u0493\u044b \u0431\u0456\u0440 \u0436\u0435\u0440\u0433\u0435 \u0435\u043b\u0434\u0456\u04a3 \u0441\u043e\u0439\u0493\u0430\u043d \u043c\u0430\u043b\u044b\u043d\u0430\u043d \u0436\u0438\u043d\u0430\u0493\u0430\u043d \u0456\u0448\u0435\u043a-\u049b\u0430\u0440\u043d\u044b\u043d \u043a\u04e9\u043c\u0434\u0456. \u0422\u0430\u0493\u044b \u0431\u0456\u0440 \u0436\u0435\u0440\u0433\u0435 \u049b\u0430\u0440\u0434\u0430\u0439 \u0430\u049b \u0430\u0439\u0440\u0430\u043d\u044b\u043d \u043a\u04e9\u043c\u0434\u0456.")},
     {narr:L("Now \u2014 while the load had weighed him down, the wind could not touch him. But the moment the last of it was buried and his back was light again, a great gust swept under him and bowled him over the hills \u2014 and set him down in a strange valley.","\u0418 \u0432\u043e\u0442 \u2014 \u043f\u043e\u043a\u0430 \u043d\u043e\u0448\u0430 \u0442\u044f\u043d\u0443\u043b\u0430 \u0435\u0433\u043e \u043a \u0437\u0435\u043c\u043b\u0435, \u0432\u0435\u0442\u0435\u0440 \u043d\u0435 \u043c\u043e\u0433 \u0435\u0433\u043e \u0442\u0440\u043e\u043d\u0443\u0442\u044c. \u041d\u043e \u0435\u0434\u0432\u0430 \u0437\u0430\u043a\u043e\u043f\u0430\u043b \u043e\u043d \u043f\u043e\u0441\u043b\u0435\u0434\u043d\u0435\u0435 \u0438 \u0441\u043f\u0438\u043d\u0430 \u0441\u0442\u0430\u043b\u0430 \u043b\u0451\u0433\u043a\u043e\u0439, \u043d\u0430\u043b\u0435\u0442\u0435\u043b \u043c\u043e\u0433\u0443\u0447\u0438\u0439 \u043f\u043e\u0440\u044b\u0432, \u043f\u043e\u043a\u0430\u0442\u0438\u043b \u0435\u0433\u043e \u0447\u0435\u0440\u0435\u0437 \u0445\u043e\u043b\u043c\u044b \u0438 \u043e\u043f\u0443\u0441\u0442\u0438\u043b \u0432 \u0447\u0443\u0436\u043e\u0439 \u0434\u043e\u043b\u0438\u043d\u0435.","\u0415\u043d\u0434\u0456 \u2014 \u0436\u04af\u043a \u0441\u0430\u043b\u043c\u0430\u049b \u0441\u0430\u043b\u044b\u043f \u0442\u04b1\u0440\u0493\u0430\u043d\u0434\u0430, \u0436\u0435\u043b \u043e\u0493\u0430\u043d \u0442\u0438\u043c\u0435\u0433\u0435\u043d \u0435\u0434\u0456. \u0410\u043b \u0441\u043e\u04a3\u0493\u044b \u043c\u04af\u043b\u043a\u0456\u043d \u043a\u04e9\u043c\u0456\u043f, \u0430\u0440\u049b\u0430\u0441\u044b \u0436\u0435\u04a3\u0456\u043b\u0434\u0435\u0439 \u0441\u0430\u043b\u044b\u0441\u044b\u043c\u0435\u043d, \u0431\u0456\u0440 \u049b\u0430\u0442\u0442\u044b \u0436\u0435\u043b \u0441\u043e\u0493\u044b\u043f, \u043e\u043d\u044b \u0430\u0441\u044b\u043f-\u0442\u04e9\u0433\u0456\u043f \u0434\u043e\u043c\u0430\u043b\u0430\u0442\u044b\u043f, \u0431\u0456\u0440 \u0431\u04e9\u0442\u0435\u043d \u0430\u04a3\u0493\u0430\u0440\u0493\u0430 \u0442\u04af\u0441\u0456\u0440\u0434\u0456.")},
     {dialog:[{who:"qanbaq",em:"worried",line:L("Oh \u2014 oh! Here I go \u2014 rolling, rolling, like a tumbleweed once more!","\u041e\u0439 \u2014 \u043e\u0439! \u0412\u043e\u0442 \u0438 \u043f\u043e\u043a\u0430\u0442\u0438\u043b\u0441\u044f \u044f \u2014 \u043e\u043f\u044f\u0442\u044c \u043a\u0430\u043a \u043f\u0435\u0440\u0435\u043a\u0430\u0442\u0438-\u043f\u043e\u043b\u0435!","\u041e\u0439 \u2014 \u043e\u0439! \u041a\u0435\u0442\u0442\u0456\u043c-\u0430\u0443 \u2014 \u0442\u0430\u0493\u044b \u0434\u0430 \u049b\u0430\u04a3\u0431\u0430\u049b\u0442\u0430\u0439 \u0434\u043e\u043c\u0430\u043b\u0430\u043f!")}]}
   ]},
  {title:L("The Valley of the Giant","\u0414\u043e\u043b\u0438\u043d\u0430 \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u0430","\u0414\u04d9\u0443\u0434\u0456\u04a3 \u0430\u04a3\u0493\u0430\u0440\u044b"), scene:"mountains", obj:L("Face the mountain-smashing giant","\u0412\u0441\u0442\u0440\u0435\u0442\u044c\u0441\u044f \u0441 \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u043e\u043c, \u0447\u0442\u043e \u0431\u044c\u0451\u0442 \u0433\u043e\u0440\u0430\u043c\u0438","\u0422\u0430\u0443 \u0441\u043e\u0493\u044b\u0441\u0442\u044b\u0440\u0493\u0430\u043d \u0434\u04d9\u0443\u043c\u0435\u043d \u0431\u0435\u0442\u043f\u0435-\u0431\u0435\u0442 \u043a\u0435\u043b"),
   beats:[
     {narr:L("He picked himself up, brushed off the dust, and looked around \u2014 and his heart nearly stopped. For there stood a GIANT, taking two whole mountains in his hands and striking them together like flint for fire.","\u041e\u043d \u043f\u043e\u0434\u043d\u044f\u043b\u0441\u044f, \u043e\u0442\u0440\u044f\u0445\u043d\u0443\u043b \u043f\u044b\u043b\u044c, \u043e\u0433\u043b\u044f\u0434\u0435\u043b\u0441\u044f \u2014 \u0438 \u0441\u0435\u0440\u0434\u0446\u0435 \u0435\u0434\u0432\u0430 \u043d\u0435 \u043e\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u043b\u043e\u0441\u044c. \u0418\u0431\u043e \u0441\u0442\u043e\u044f\u043b \u0442\u0430\u043c \u0412\u0415\u041b\u0418\u041a\u0410\u041d \u0438, \u0432\u0437\u044f\u0432 \u0432 \u0440\u0443\u043a\u0438 \u0434\u0432\u0435 \u0446\u0435\u043b\u044b\u0435 \u0433\u043e\u0440\u044b, \u0432\u044b\u0441\u0435\u043a\u0430\u043b \u0438\u043c\u0438 \u0438\u0441\u043a\u0440\u044b, \u043a\u0430\u043a \u043a\u0440\u0435\u043c\u043d\u0451\u043c.","\u041e\u043b \u043e\u0440\u043d\u044b\u043d\u0430\u043d \u0442\u04b1\u0440\u044b\u043f, \u0448\u0430\u04a3\u044b\u043d \u049b\u0430\u0493\u044b\u043f, \u0430\u0439\u043d\u0430\u043b\u0430\u0441\u044b\u043d\u0430 \u049b\u0430\u0440\u0430\u0441\u0430 \u2014 \u0436\u04af\u0440\u0435\u0433\u0456 \u0442\u0430\u0441 \u0442\u04e9\u0431\u0435\u0441\u0456\u043d\u0435 \u0448\u044b\u049b\u0442\u044b. \u0410\u043b\u0434\u044b\u043d\u0434\u0430 \u0431\u0456\u0440 \u0414\u04d8\u0423 \u0442\u04b1\u0440 \u0435\u043a\u0435\u043d, \u0435\u043a\u0456 \u0442\u0430\u0443\u0434\u044b \u049b\u043e\u043b\u044b\u043d\u0430 \u0430\u043b\u044b\u043f, \u0448\u0430\u049b\u043f\u0430\u049b\u0442\u0430\u0439 \u0431\u0456\u0440-\u0431\u0456\u0440\u0456\u043d\u0435 \u04b1\u0440\u044b\u043f \u0442\u04b1\u0440 \u0435\u043a\u0435\u043d.")},
     {dialog:[{who:"dau",em:"boast",line:L("Ho! Where are you bound, little old man? Come \u2014 let the two of us test our strength!","\u0425\u043e! \u041a\u0443\u0434\u0430 \u043f\u0443\u0442\u044c \u0434\u0435\u0440\u0436\u0438\u0448\u044c, \u0441\u0442\u0430\u0440\u0438\u0447\u043e\u043a? \u0410 \u043d\u0443 \u2014 \u043f\u043e\u043c\u0435\u0440\u0438\u043c\u0441\u044f \u0441\u0438\u043b\u043e\u0439!","\u04ba\u0435! \u049a\u0430\u0439\u0434\u0430 \u0431\u0430\u0440\u0430 \u0436\u0430\u0442\u049b\u0430\u043d \u0448\u0430\u043b\u0441\u044b\u04a3? \u041a\u0435\u043b, \u0435\u043a\u0435\u0443\u0456\u043c\u0456\u0437 \u043a\u04af\u0448 \u0441\u044b\u043d\u0430\u0441\u0430\u0439\u044b\u049b!")},{who:"qanbaq",em:"worried",line:L("(to himself) One breath from that fist would scatter me like chaff\u2026 I must fight with the only thing I own \u2014 my wits.","(\u043f\u0440\u043e \u0441\u0435\u0431\u044f) \u041e\u0434\u0438\u043d \u0432\u0434\u043e\u0445 \u044d\u0442\u043e\u0433\u043e \u043a\u0443\u043b\u0430\u043a\u0430 \u0440\u0430\u0437\u0432\u0435\u0435\u0442 \u043c\u0435\u043d\u044f, \u043a\u0430\u043a \u043c\u044f\u043a\u0438\u043d\u0443\u2026 \u0414\u0440\u0430\u0442\u044c\u0441\u044f \u043f\u0440\u0438\u0434\u0451\u0442\u0441\u044f \u0435\u0434\u0438\u043d\u0441\u0442\u0432\u0435\u043d\u043d\u044b\u043c, \u0447\u0442\u043e \u0435\u0441\u0442\u044c, \u2014 \u0443\u043c\u043e\u043c.","(\u0456\u0448\u0456\u043d\u0435\u043d) \u0410\u043d\u0430 \u0436\u04b1\u0434\u044b\u0440\u044b\u049b\u0442\u044b\u04a3 \u0431\u0456\u0440 \u043b\u0435\u0431\u0456-\u0430\u049b \u043c\u0435\u043d\u0456 \u0442\u043e\u043f\u0430\u043d\u0434\u0430\u0439 \u04b1\u0448\u044b\u0440\u0430\u0440\u2026 \u0411\u0430\u0440 \u0431\u0430\u0439\u043b\u044b\u0493\u044b\u043c\u043c\u0435\u043d \u2014 \u0430\u049b\u044b\u043b\u044b\u043c\u043c\u0435\u043d \u0493\u0430\u043d\u0430 \u043a\u04af\u0440\u0435\u0441\u0443\u0456\u043c \u043a\u0435\u0440\u0435\u043a.")}]},
     {narr:L("The giant lifted a black boulder as big as a cauldron, hurled it high into the sky, caught it in one hand as it fell, and held it out.","\u0412\u0435\u043b\u0438\u043a\u0430\u043d \u043f\u043e\u0434\u043d\u044f\u043b \u0447\u0451\u0440\u043d\u044b\u0439 \u0432\u0430\u043b\u0443\u043d \u0432\u0435\u043b\u0438\u0447\u0438\u043d\u043e\u0439 \u0441 \u043a\u043e\u0442\u0451\u043b, \u043f\u043e\u0434\u0431\u0440\u043e\u0441\u0438\u043b \u0435\u0433\u043e \u0432\u044b\u0441\u043e\u043a\u043e \u0432 \u043d\u0435\u0431\u043e, \u043f\u043e\u0439\u043c\u0430\u043b \u043e\u0434\u043d\u043e\u0439 \u0440\u0443\u043a\u043e\u0439 \u0438 \u043f\u0440\u043e\u0442\u044f\u043d\u0443\u043b \u0441\u0442\u0430\u0440\u0438\u043a\u0443.","\u0414\u04d9\u0443 \u049b\u0430\u0437\u0430\u043d\u0434\u0430\u0439 \u0431\u0456\u0440 \u049b\u0430\u0440\u0430 \u0442\u0430\u0441\u0442\u044b \u043a\u04e9\u0442\u0435\u0440\u0456\u043f, \u0430\u0441\u043f\u0430\u043d\u0493\u0430 \u043b\u0430\u049b\u0442\u044b\u0440\u044b\u043f \u0436\u0456\u0431\u0435\u0440\u0434\u0456 \u0434\u0435, \u0442\u04af\u0441\u0456\u043f \u043a\u0435\u043b\u0435 \u0436\u0430\u0442\u049b\u0430\u043d\u0434\u0430 \u049b\u0430\u0493\u044b\u043f \u0430\u043b\u044b\u043f, \u0448\u0430\u043b\u0493\u0430 \u04b1\u0441\u044b\u043d\u0434\u044b.")},
     {dialog:[{who:"dau",em:"boast",line:L("There! Now you, old man. Toss it up and catch it \u2014 just like that.","\u0412\u043e\u0442! \u0422\u0435\u043f\u0435\u0440\u044c \u0442\u044b, \u0441\u0442\u0430\u0440\u0438\u043a. \u041f\u043e\u0434\u0431\u0440\u043e\u0441\u044c \u0434\u0430 \u043f\u043e\u0439\u043c\u0430\u0439 \u2014 \u0432\u043e\u0442 \u0442\u0430\u043a.","\u041c\u0456\u043d\u0435\u043a\u0438! \u0415\u043d\u0434\u0456 \u0441\u0435\u043d, \u0448\u0430\u043b. \u041e\u0441\u044b\u043d\u044b \u043e\u0441\u044b\u043b\u0430\u0439 \u049b\u0430\u049b\u043f\u0430\u049b\u044b\u043b \u0435\u0442 \u2014 \u043a\u04e9\u0440\u0441\u0435\u0442\u0448\u0456.")}]}
   ]},
  {title:L("The Sky and the Earth","\u041d\u0435\u0431\u043e \u0438 \u0437\u0435\u043c\u043b\u044f","\u0410\u0441\u043f\u0430\u043d \u043c\u0435\u043d \u0436\u0435\u0440"), scene:"earthtrick", obj:L("Out-bluff the giant with the sky, the guts and the brains","\u041f\u0435\u0440\u0435\u0445\u0438\u0442\u0440\u0438 \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u0430 \u043d\u0435\u0431\u043e\u043c, \u043f\u043e\u0442\u0440\u043e\u0445\u0430\u043c\u0438 \u0438 \u043c\u043e\u0437\u0433\u0430\u043c\u0438","\u0410\u0441\u043f\u0430\u043d\u043c\u0435\u043d, \u0456\u0448\u0435\u043a-\u049b\u0430\u0440\u044b\u043d\u043c\u0435\u043d, \u043c\u0438\u043c\u0435\u043d \u0434\u04d9\u0443\u0434\u0456 \u0430\u043b\u0434\u0430\u043f \u0441\u043e\u049b"),
   beats:[
     {narr:L("The old man wrapped both arms around the boulder. He could not have lifted it an inch. So he looked up at the sky, and down at the stone, and up at the sky again \u2014 and stood there frowning all the day long.","\u0421\u0442\u0430\u0440\u0438\u043a \u043e\u0431\u0445\u0432\u0430\u0442\u0438\u043b \u0432\u0430\u043b\u0443\u043d \u043e\u0431\u0435\u0438\u043c\u0438 \u0440\u0443\u043a\u0430\u043c\u0438. \u0415\u043c\u0443 \u0431\u044b\u043b\u043e \u043d\u0435 \u043f\u043e\u0434\u043d\u044f\u0442\u044c \u0435\u0433\u043e \u0438 \u043d\u0430 \u0432\u0435\u0440\u0448\u043e\u043a. \u041e\u043d \u0433\u043b\u044f\u0434\u0435\u043b \u0442\u043e \u043d\u0430 \u043d\u0435\u0431\u043e, \u0442\u043e \u043d\u0430 \u043a\u0430\u043c\u0435\u043d\u044c, \u0442\u043e \u0441\u043d\u043e\u0432\u0430 \u043d\u0430 \u043d\u0435\u0431\u043e \u2014 \u0438 \u043f\u0440\u043e\u0441\u0442\u043e\u044f\u043b \u0442\u0430\u043a, \u0445\u043c\u0443\u0440\u044f\u0441\u044c, \u0446\u0435\u043b\u044b\u0439 \u0434\u0435\u043d\u044c.","\u0428\u0430\u043b \u0442\u0430\u0441\u0442\u044b \u049b\u04b1\u0448\u0430\u049b\u0442\u0430\u043f \u0430\u043b\u0434\u044b. \u041e\u043d\u044b \u0431\u0456\u0440 \u0435\u043b\u0456 \u0434\u0435 \u043a\u04e9\u0442\u0435\u0440\u0435 \u0430\u043b\u043c\u0430\u0441 \u0435\u0434\u0456. \u0421\u04e9\u0439\u0442\u0456\u043f \u043e\u043b \u0430\u0441\u043f\u0430\u043d\u0493\u0430 \u0431\u0456\u0440, \u0442\u0430\u0441\u049b\u0430 \u0431\u0456\u0440, \u0442\u0430\u0493\u044b \u0430\u0441\u043f\u0430\u043d\u0493\u0430 \u0431\u0456\u0440 \u049b\u0430\u0440\u0430\u043f, \u043a\u04af\u043d\u0456 \u0431\u043e\u0439\u044b \u049b\u0430\u0431\u0430\u0493\u044b\u043d \u0442\u04af\u0439\u0456\u043f \u0442\u04b1\u0440\u044b\u043f \u0430\u043b\u0434\u044b.")},
     {dialog:[{who:"dau",em:"worried",line:L("Hey! Are you going to stand there forever? Throw it!","\u042d\u0439! \u0422\u044b \u0442\u0430\u043a \u0438 \u0431\u0443\u0434\u0435\u0448\u044c \u0441\u0442\u043e\u044f\u0442\u044c \u0434\u043e \u0441\u043a\u043e\u043d\u0447\u0430\u043d\u0438\u044f \u0432\u0435\u043a\u0430? \u0411\u0440\u043e\u0441\u0430\u0439!","\u04d8\u0439! \u041e\u0441\u044b\u043b\u0430\u0439 \u0442\u04b1\u0440\u0430 \u0431\u0435\u0440\u0435\u0441\u0456\u04a3 \u0431\u0435? \u041b\u0430\u049b\u0442\u044b\u0440!")},{who:"qanbaq",em:"wise",line:L("I dare not, and here is why. If I throw this stone with all my strength, the sky itself may crack and come tumbling down upon us. And if I fail to catch it, it will punch a hole clean through the middle of the earth. I am only trying to spare us both.","\u041d\u0435 \u0441\u043c\u0435\u044e, \u0438 \u0432\u043e\u0442 \u043f\u043e\u0447\u0435\u043c\u0443. \u0411\u0440\u043e\u0448\u0443 \u043a\u0430\u043c\u0435\u043d\u044c \u0441\u043e \u0432\u0441\u0435\u0439 \u0441\u0438\u043b\u044b \u2014 \u0440\u0430\u0441\u043a\u043e\u043b\u0435\u0442\u0441\u044f \u043d\u0435\u0431\u043e \u0438 \u0440\u0443\u0445\u043d\u0435\u0442 \u043d\u0430 \u043d\u0430\u0441. \u0410 \u043d\u0435 \u043f\u043e\u0439\u043c\u0430\u044e \u2014 \u043f\u0440\u043e\u0431\u044c\u0451\u0442 \u043e\u043d \u0437\u0435\u043c\u043b\u044e \u043d\u0430\u0441\u043a\u0432\u043e\u0437\u044c, \u0434\u043e \u0441\u0430\u043c\u043e\u0439 \u0441\u0435\u0440\u0435\u0434\u0438\u043d\u044b. \u042f \u043b\u0438\u0448\u044c \u0445\u043e\u0447\u0443 \u0443\u0431\u0435\u0440\u0435\u0447\u044c \u043d\u0430\u0441 \u043e\u0431\u043e\u0438\u0445.","\u0411\u0430\u0442\u044b\u043b\u044b\u043c \u0431\u0430\u0440\u043c\u0430\u0439\u0434\u044b, \u043c\u04b1\u043d\u044b\u04a3 \u043c\u04d9\u043d\u0456\u0441\u0456 \u043c\u044b\u043d\u0430\u0443. \u0411\u0430\u0440 \u043a\u04af\u0448\u0456\u043c\u043c\u0435\u043d \u043b\u0430\u049b\u0442\u044b\u0440\u0441\u0430\u043c, \u0430\u0441\u043f\u0430\u043d \u0430\u0439\u043d\u0430\u043b\u044b\u043f \u0436\u0435\u0440\u0433\u0435 \u0442\u04af\u0441\u0435\u0440. \u04b0\u0441\u0442\u0430\u0439 \u0430\u043b\u043c\u0430\u0439 \u049b\u0430\u043b\u0441\u0430\u043c, \u0436\u0435\u0440\u0434\u0456\u04a3 \u0434\u04d9\u043b \u043e\u0440\u0442\u0430\u0441\u044b\u043d\u0430\u043d \u043e\u0439\u044b\u043f \u04e9\u0442\u0435\u0440. \u041c\u0435\u043d \u0435\u043a\u0435\u0443\u043c\u0456\u0437\u0434\u0456 \u0430\u044f\u043f \u0442\u04b1\u0440\u043c\u044b\u043d.")}]},
     {narr:L("The giant went pale. He rushed forward and seized the old man's hands.","\u0412\u0435\u043b\u0438\u043a\u0430\u043d \u043f\u043e\u0431\u043b\u0435\u0434\u043d\u0435\u043b. \u041e\u043d \u043a\u0438\u043d\u0443\u043b\u0441\u044f \u0432\u043f\u0435\u0440\u0451\u0434 \u0438 \u0441\u0445\u0432\u0430\u0442\u0438\u043b \u0441\u0442\u0430\u0440\u0438\u043a\u0430 \u0437\u0430 \u0440\u0443\u043a\u0438.","\u0414\u04d9\u0443\u0434\u0456\u04a3 \u04e9\u04a3\u0456 \u049b\u0430\u0448\u0442\u044b. \u041e\u043b \u0436\u04af\u0433\u0456\u0440\u0456\u043f \u043a\u0435\u043b\u0456\u043f, \u0448\u0430\u043b\u0434\u044b\u04a3 \u049b\u043e\u043b\u044b\u043d\u0430\u043d \u04b1\u0441\u0442\u0430\u0439 \u0430\u043b\u0434\u044b.")},
     {dialog:[{who:"dau",em:"pleading",line:L("Grandfather \u2014 aksakal \u2014 put it down, put it down! Don't throw it! You'll destroy us all for nothing!","\u0414\u0435\u0434\u0443\u0448\u043a\u0430 \u2014 \u0430\u043a\u0441\u0430\u043a\u0430\u043b \u2014 \u043e\u043f\u0443\u0441\u0442\u0438, \u043e\u043f\u0443\u0441\u0442\u0438 \u0435\u0433\u043e! \u041d\u0435 \u0431\u0440\u043e\u0441\u0430\u0439! \u0422\u044b \u0432\u0441\u0435\u0445 \u043d\u0430\u0441 \u043f\u043e\u0433\u0443\u0431\u0438\u0448\u044c \u043d\u0438 \u0437\u0430 \u0447\u0442\u043e!","\u0410\u049b\u0441\u0430\u049b\u0430\u043b \u2014 \u0430\u0442\u0435\u043a\u0435 \u2014 \u049b\u043e\u0439, \u049b\u043e\u044f \u0493\u043e\u0439! \u041b\u0430\u049b\u0442\u044b\u0440\u043c\u0430! \u0422\u0435\u0433\u0456\u043d \u0431\u04d9\u0440\u0456\u043c\u0456\u0437\u0434\u0456 \u049b\u04b1\u0440\u0442\u0430\u0441\u044b\u04a3!")}]},
     {narr:L("And so the old man learned how shallow the giant's wits ran, and his courage rose. 'Very well,' he said. 'Let us try a gentler game. Let us see who can pull the guts straight out of the earth!'","\u0422\u0430\u043a \u0441\u0442\u0430\u0440\u0438\u043a \u043f\u043e\u043d\u044f\u043b, \u043a\u0430\u043a \u043c\u0435\u043b\u043e\u043a \u0443\u043c \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u0430, \u0438 \u043e\u0441\u043c\u0435\u043b\u0435\u043b. \u00ab\u041d\u0443 \u0447\u0442\u043e \u0436, \u2014 \u0441\u043a\u0430\u0437\u0430\u043b \u043e\u043d. \u2014 \u0421\u044b\u0433\u0440\u0430\u0435\u043c \u0432 \u0438\u0433\u0440\u0443 \u043f\u043e\u043c\u044f\u0433\u0447\u0435. \u041f\u043e\u0433\u043b\u044f\u0434\u0438\u043c, \u043a\u0442\u043e \u0432\u044b\u0442\u044f\u043d\u0435\u0442 \u0438\u0437 \u0437\u0435\u043c\u043b\u0438 \u043f\u043e\u0442\u0440\u043e\u0445\u0430!\u00bb","\u0421\u043e\u043d\u0434\u0430 \u0448\u0430\u043b \u0434\u04d9\u0443\u0434\u0456\u04a3 \u0430\u049b\u044b\u043b\u044b\u043d\u044b\u04a3 \u0442\u0430\u0439\u044b\u0437\u0434\u044b\u0493\u044b\u043d \u0431\u0456\u043b\u0434\u0456 \u0434\u0435, \u0435\u0440\u0436\u04af\u0440\u0435\u043a \u0442\u0430\u0440\u0442\u0442\u044b. \u00ab\u0416\u0430\u0440\u0430\u0439\u0434\u044b, \u2014 \u0434\u0435\u0434\u0456 \u043e\u043b. \u2014 \u0416\u04b1\u043c\u0441\u0430\u0493\u044b\u0440\u0430\u049b \u043e\u0439\u044b\u043d \u043e\u0439\u043d\u0430\u0439\u044b\u049b. \u041a\u04d9\u043d\u0435, \u0436\u0435\u0440\u0434\u0456\u04a3 \u0456\u0448\u0435\u043a-\u049b\u0430\u0440\u043d\u044b\u043d \u043a\u0456\u043c \u0448\u044b\u0493\u0430\u0440\u0430\u0440 \u0435\u043a\u0435\u043d!\u00bb")},
     {narr:L("The giant took a run and stamped with all his weight. The ground caved in to his knee \u2014 but nothing came out. Then the old man trotted to the spot where he had buried the sheep's guts, gave the ground a little kick \u2014 and with a wet squelch, ropes of steaming guts burst up out of the earth.","\u0412\u0435\u043b\u0438\u043a\u0430\u043d \u0440\u0430\u0437\u0431\u0435\u0436\u0430\u043b\u0441\u044f \u0438 \u0442\u043e\u043f\u043d\u0443\u043b \u0441\u043e \u0432\u0441\u0435\u0439 \u0441\u0438\u043b\u044b. \u0417\u0435\u043c\u043b\u044f \u043f\u0440\u043e\u0441\u0435\u043b\u0430 \u0435\u043c\u0443 \u043f\u043e \u043a\u043e\u043b\u0435\u043d\u043e \u2014 \u043d\u043e \u043d\u0438\u0447\u0435\u0433\u043e \u043d\u0435 \u0432\u044b\u0448\u043b\u043e. \u0422\u043e\u0433\u0434\u0430 \u0441\u0442\u0430\u0440\u0438\u043a \u043f\u043e\u0434\u0431\u0435\u0436\u0430\u043b \u043a \u043c\u0435\u0441\u0442\u0443, \u0433\u0434\u0435 \u0437\u0430\u043a\u043e\u043f\u0430\u043b \u043e\u0432\u0435\u0447\u044c\u0438 \u043f\u043e\u0442\u0440\u043e\u0445\u0430, \u043b\u0435\u0433\u043e\u043d\u044c\u043a\u043e \u043f\u043d\u0443\u043b \u0437\u0435\u043c\u043b\u044e \u2014 \u0438 \u0441 \u0432\u043b\u0430\u0436\u043d\u044b\u043c \u0445\u043b\u044e\u043f\u0430\u043d\u044c\u0435\u043c \u0438\u0437 \u043d\u0435\u0451 \u0432\u044b\u0432\u0430\u043b\u0438\u043b\u0438\u0441\u044c \u0434\u044b\u043c\u044f\u0449\u0438\u0435\u0441\u044f \u043a\u0438\u0448\u043a\u0438.","\u0414\u04d9\u0443 \u0436\u04af\u0433\u0456\u0440\u0456\u043f \u043a\u0435\u043b\u0456\u043f, \u0431\u0430\u0440 \u0441\u0430\u043b\u043c\u0430\u0493\u044b\u043c\u0435\u043d \u0442\u0435\u0443\u0456\u043f \u049b\u0430\u043b\u0434\u044b. \u0416\u0435\u0440 \u0442\u0456\u0437\u0435\u0434\u0435\u043d \u043e\u0439\u044b\u043b\u0434\u044b \u2014 \u0431\u0456\u0440\u0430\u049b \u0435\u0448\u0442\u0435\u04a3\u0435 \u0448\u044b\u049b\u043f\u0430\u0434\u044b. \u0421\u043e\u043d\u0434\u0430 \u0448\u0430\u043b \u04e9\u0437\u0456 \u043a\u04e9\u043c\u0456\u043f \u049b\u043e\u0439\u0493\u0430\u043d \u049b\u043e\u0439 \u0456\u0448\u0435\u043a-\u049b\u0430\u0440\u043d\u044b \u0436\u0430\u0442\u049b\u0430\u043d \u0436\u0435\u0440\u0433\u0435 \u0436\u04af\u0433\u0456\u0440\u0456\u043f \u0431\u0430\u0440\u044b\u043f, \u0436\u0435\u0440\u0434\u0456 \u0442\u0435\u0443\u0456\u043f \u049b\u0430\u043b\u0441\u0430 \u2014 \u0431\u044b\u0440\u049b \u0435\u0442\u0456\u043f, \u0431\u0443\u044b \u0431\u04b1\u0440\u049b\u044b\u0440\u0430\u0493\u0430\u043d \u0456\u0448\u0435\u043a-\u049b\u0430\u0440\u044b\u043d \u0430\u0442\u044b\u043f \u0448\u044b\u049b\u0442\u044b.")},
     {dialog:[{who:"dau",em:"afraid",line:L("You \u2014 you tore the guts from the very ground!","\u0422\u044b \u2014 \u0442\u044b \u0432\u044b\u0440\u0432\u0430\u043b \u043f\u043e\u0442\u0440\u043e\u0445\u0430 \u0438\u0437 \u0441\u0430\u043c\u043e\u0439 \u0437\u0435\u043c\u043b\u0438!","\u0421\u0435\u043d \u2014 \u0441\u0435\u043d \u0436\u0435\u0440\u0434\u0456\u04a3 \u04e9\u0437\u0456\u043d\u0435\u043d \u0456\u0448\u0435\u043a-\u049b\u0430\u0440\u044b\u043d\u044b\u043d \u0436\u04b1\u043b\u044b\u043f \u0430\u043b\u0434\u044b\u04a3!")},{who:"qanbaq",em:"bold",line:L("Guts are easy. Come \u2014 now let us pull out the BRAINS of the earth!","\u041f\u043e\u0442\u0440\u043e\u0445\u0430 \u2014 \u043f\u0443\u0441\u0442\u044f\u043a. \u0410 \u043d\u0443 \u2014 \u0442\u0435\u043f\u0435\u0440\u044c \u0432\u044b\u0442\u044f\u043d\u0435\u043c \u041c\u041e\u0417\u0413\u0418 \u0437\u0435\u043c\u043b\u0438!","\u0406\u0448\u0435\u043a-\u049b\u0430\u0440\u044b\u043d \u043e\u04a3\u0430\u0439. \u041a\u0435\u043b \u2014 \u0435\u043d\u0434\u0456 \u0436\u0435\u0440\u0434\u0456\u04a3 \u041c\u0418\u042b\u041d \u0448\u044b\u0493\u0430\u0440\u0430\u0439\u044b\u049b!")}]},
     {narr:L("Again the giant stamped, and again only dirt. But the old man walked to where he had buried the skin of white ayran, kicked once \u2014 and up welled a great splash of something white and soft, spilling like brains across the ground.","\u0421\u043d\u043e\u0432\u0430 \u0442\u043e\u043f\u043d\u0443\u043b \u0432\u0435\u043b\u0438\u043a\u0430\u043d \u2014 \u0438 \u0441\u043d\u043e\u0432\u0430 \u043b\u0438\u0448\u044c \u0437\u0435\u043c\u043b\u044f. \u0410 \u0441\u0442\u0430\u0440\u0438\u043a \u043f\u043e\u0434\u043e\u0448\u0451\u043b \u043a \u043c\u0435\u0441\u0442\u0443, \u0433\u0434\u0435 \u0437\u0430\u043a\u043e\u043f\u0430\u043b \u0431\u0443\u0440\u0434\u044e\u043a \u0431\u0435\u043b\u043e\u0433\u043e \u0430\u0439\u0440\u0430\u043d\u0430, \u043f\u043d\u0443\u043b \u0440\u0430\u0437 \u2014 \u0438 \u0445\u043b\u044b\u043d\u0443\u043b\u043e \u0447\u0442\u043e-\u0442\u043e \u0431\u0435\u043b\u043e\u0435 \u0438 \u043c\u044f\u0433\u043a\u043e\u0435, \u0440\u0430\u0441\u0442\u0435\u043a\u0430\u044f\u0441\u044c \u043f\u043e \u0437\u0435\u043c\u043b\u0435, \u0442\u043e\u0447\u043d\u043e \u043c\u043e\u0437\u0433\u0438.","\u0414\u04d9\u0443 \u0442\u0430\u0493\u044b \u0442\u0435\u0443\u0456\u043f \u049b\u0430\u043b\u0434\u044b \u2014 \u0442\u0430\u0493\u044b \u0434\u0430 \u0442\u043e\u043f\u044b\u0440\u0430\u049b \u049b\u0430\u043d\u0430. \u0410\u043b \u0448\u0430\u043b \u0430\u049b \u0430\u0439\u0440\u0430\u043d \u043a\u04e9\u043c\u0433\u0435\u043d \u0436\u0435\u0440\u0456\u043d\u0435 \u0431\u0430\u0440\u044b\u043f, \u0431\u0456\u0440 \u0442\u0435\u0443\u0456\u043f \u049b\u0430\u043b\u0441\u0430 \u2014 \u0430\u043f\u043f\u0430\u049b \u04d9\u0440\u0456 \u0436\u04b1\u043c\u0441\u0430\u049b \u0431\u0456\u0440\u0434\u0435\u04a3\u0435 \u0430\u0442\u049b\u044b\u043b\u0430\u043f, \u0436\u0435\u0440\u0433\u0435 \u043c\u0438 \u0431\u043e\u043f \u0436\u0430\u0439\u044b\u043b\u0434\u044b.")},
     {dialog:[{who:"dau",em:"afraid",line:L("He pulls the brains from the earth as easily as picking mushrooms\u2026 What manner of old man IS this? Aksakal \u2014 honoured one \u2014 come home with me. Be a guest in the camp of the giants!","\u041e\u043d \u0432\u044b\u043d\u0438\u043c\u0430\u0435\u0442 \u043c\u043e\u0437\u0433\u0438 \u0437\u0435\u043c\u043b\u0438 \u043b\u0435\u0433\u043a\u043e, \u043a\u0430\u043a \u0433\u0440\u0438\u0431\u044b \u0441\u043e\u0431\u0438\u0440\u0430\u0435\u0442\u2026 \u0427\u0442\u043e \u044d\u0442\u043e \u0437\u0430 \u0441\u0442\u0430\u0440\u0438\u043a \u0442\u0430\u043a\u043e\u0439? \u0410\u043a\u0441\u0430\u043a\u0430\u043b \u2014 \u043f\u043e\u0447\u0442\u0435\u043d\u043d\u044b\u0439 \u2014 \u0438\u0434\u0451\u043c \u043a\u043e \u043c\u043d\u0435. \u0411\u0443\u0434\u044c \u0433\u043e\u0441\u0442\u0435\u043c \u0432 \u0441\u0442\u0430\u043d\u0435 \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u043e\u0432!","\u0421\u0430\u04a3\u044b\u0440\u0430\u0443\u049b\u04b1\u043b\u0430\u049b \u0442\u0435\u0440\u0433\u0435\u043d\u0434\u0435\u0439 \u0436\u0435\u0440\u0434\u0456\u04a3 \u043c\u0438\u044b\u043d \u043e\u043f-\u043e\u04a3\u0430\u0439 \u0448\u044b\u0493\u0430\u0440\u0430\u0434\u044b\u2026 \u041c\u044b\u043d\u0430\u0443 \u049b\u0430\u043d\u0434\u0430\u0439 \u0448\u0430\u043b \u04e9\u0437\u0456? \u0410\u049b\u0441\u0430\u049b\u0430\u043b \u2014 \u049b\u0430\u0434\u0456\u0440\u043b\u0456\u043c \u2014 \u04af\u0439\u0456\u043c\u0435 \u0436\u04af\u0440. \u0414\u04d9\u0443\u043b\u0435\u0440\u0434\u0456\u04a3 \u0430\u0443\u044b\u043b\u044b\u043d\u0434\u0430 \u049b\u043e\u043d\u0430\u049b \u0431\u043e\u043b!")}],act:"riddle",riddle:{q:L("What beats a giant every time, though it carries no club and no knife?","\u0427\u0442\u043e \u0431\u044c\u0451\u0442 \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u0430 \u0432\u0441\u044f\u043a\u0438\u0439 \u0440\u0430\u0437, \u0445\u043e\u0442\u044c \u0438 \u0431\u0435\u0437 \u0434\u0443\u0431\u0438\u043d\u044b \u0438 \u043d\u043e\u0436\u0430?","\u0428\u043e\u049b\u043f\u0430\u0440\u044b \u0434\u0430, \u043f\u044b\u0448\u0430\u0493\u044b \u0434\u0430 \u0436\u043e\u049b \u0431\u043e\u043b\u0441\u0430 \u0434\u0430, \u0434\u04d9\u0443\u0434\u0456 \u04d9\u0440\u0434\u0430\u0439\u044b\u043c \u0436\u0435\u04a3\u0435\u0442\u0456\u043d \u043d\u0435?"),opts:[{t:L("A sharp wit","\u041e\u0441\u0442\u0440\u044b\u0439 \u0443\u043c","\u04e8\u0442\u043a\u0456\u0440 \u0430\u049b\u044b\u043b"),ok:true},{t:L("A strong arm","\u0421\u0438\u043b\u044c\u043d\u0430\u044f \u0440\u0443\u043a\u0430","\u041a\u04af\u0448\u0442\u0456 \u0431\u0456\u043b\u0435\u043a"),ok:false},{t:L("A heavy club","\u0422\u044f\u0436\u0451\u043b\u0430\u044f \u0434\u0443\u0431\u0438\u043d\u0430","\u0410\u0443\u044b\u0440 \u0448\u043e\u049b\u043f\u0430\u0440"),ok:false},{t:L("A sack of gold","\u041c\u0435\u0448\u043e\u043a \u0437\u043e\u043b\u043e\u0442\u0430","\u0410\u043b\u0442\u044b\u043d \u049b\u0430\u043f"),ok:false}]}}
   ]},
  {title:L("The Camp of the Giants","\u0421\u0442\u0430\u043d \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u043e\u0432","\u0414\u04d9\u0443\u043b\u0435\u0440\u0434\u0456\u04a3 \u0430\u0443\u044b\u043b\u044b"), scene:"camp", obj:L("Enter the giants' camp and sense their plot","\u0412\u043e\u0439\u0434\u0438 \u0432 \u0441\u0442\u0430\u043d \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u043e\u0432 \u0438 \u043f\u043e\u0447\u0443\u0439 \u0438\u0445 \u0437\u0430\u043c\u044b\u0441\u0435\u043b","\u0414\u04d9\u0443\u043b\u0435\u0440\u0434\u0456\u04a3 \u0430\u0443\u044b\u043b\u044b\u043d\u0430 \u043a\u0456\u0440\u0456\u043f, \u043e\u043b\u0430\u0440\u0434\u044b\u04a3 \u049b\u0430\u0441\u0442\u0430\u043d\u0434\u044b\u0493\u044b\u043d \u0430\u04a3\u0493\u0430\u0440"),
   beats:[
     {narr:L("So the giant carried the old man to the camp of his kin \u2014 a ring of black felt tents each as tall as a hill, where giants sat gnawing whole roasted horses. When the first giant whispered what the little old man had done, the giants drew close together, and their eldest, old Baba D\u00e4u, rumbled low.","\u0418 \u043f\u043e\u043d\u0451\u0441 \u0432\u0435\u043b\u0438\u043a\u0430\u043d \u0441\u0442\u0430\u0440\u0438\u043a\u0430 \u0432 \u0441\u0442\u0430\u043d \u0441\u0432\u043e\u0438\u0445 \u0441\u043e\u0440\u043e\u0434\u0438\u0447\u0435\u0439 \u2014 \u043a\u0440\u0443\u0433 \u0447\u0451\u0440\u043d\u044b\u0445 \u0432\u043e\u0439\u043b\u043e\u0447\u043d\u044b\u0445 \u0448\u0430\u0442\u0440\u043e\u0432, \u043a\u0430\u0436\u0434\u044b\u0439 \u0441 \u0445\u043e\u043b\u043c \u0432\u044b\u0441\u043e\u0442\u043e\u0439, \u0433\u0434\u0435 \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u044b \u0433\u0440\u044b\u0437\u043b\u0438 \u0446\u0435\u043b\u044b\u0445 \u0436\u0430\u0440\u0435\u043d\u044b\u0445 \u043a\u043e\u043d\u0435\u0439. \u041a\u043e\u0433\u0434\u0430 \u043f\u0435\u0440\u0432\u044b\u0439 \u0432\u0435\u043b\u0438\u043a\u0430\u043d \u0448\u0435\u043f\u043d\u0443\u043b, \u0447\u0442\u043e \u0441\u043e\u0442\u0432\u043e\u0440\u0438\u043b \u0441\u0442\u0430\u0440\u0438\u0447\u043e\u043a, \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u044b \u0441\u0434\u0432\u0438\u043d\u0443\u043b\u0438\u0441\u044c \u0442\u0435\u0441\u043d\u0435\u0435, \u0438 \u0441\u0442\u0430\u0440\u0435\u0439\u0448\u0438\u0439 \u0438\u0445, \u0411\u0430\u0431\u0430-\u0414\u044d\u0443, \u0433\u043b\u0443\u0445\u043e \u0437\u0430\u0432\u043e\u0440\u0447\u0430\u043b.","\u0421\u04e9\u0439\u0442\u0456\u043f \u0434\u04d9\u0443 \u0448\u0430\u043b\u0434\u044b \u04e9\u0437 \u0430\u0493\u0430\u0439\u044b\u043d\u0434\u0430\u0440\u044b\u043d\u044b\u04a3 \u0430\u0443\u044b\u043b\u044b\u043d\u0430 \u0430\u043f\u0430\u0440\u0434\u044b \u2014 \u04d9\u0440\u049b\u0430\u0439\u0441\u044b\u0441\u044b \u0442\u04e9\u0431\u0435\u0434\u0435\u0439 \u049b\u0430\u0440\u0430 \u043a\u0438\u0456\u0437 \u04af\u0439\u043b\u0435\u0440\u0434\u0456\u04a3 \u0448\u0435\u04a3\u0431\u0435\u0440\u0456, \u0434\u04d9\u0443\u043b\u0435\u0440 \u0431\u04af\u0442\u0456\u043d \u043f\u0456\u0441\u0456\u0440\u0433\u0435\u043d \u0436\u044b\u043b\u049b\u044b\u043d\u044b \u043c\u04af\u0436\u0456\u043f \u043e\u0442\u044b\u0440 \u0435\u043a\u0435\u043d. \u04d8\u043b\u0433\u0456 \u0434\u04d9\u0443 \u043a\u0456\u0448\u043a\u0435\u043d\u0442\u0430\u0439 \u0448\u0430\u043b\u0434\u044b\u04a3 \u043d\u0435 \u0456\u0441\u0442\u0435\u0433\u0435\u043d\u0456\u043d \u0441\u044b\u0431\u044b\u0440\u043b\u0430\u0493\u0430\u043d\u0434\u0430, \u0434\u04d9\u0443\u043b\u0435\u0440 \u0431\u0456\u0440-\u0431\u0456\u0440\u0456\u043d\u0435 \u0436\u0430\u049b\u044b\u043d\u0434\u0430\u0441\u044b\u043f, \u0435\u04a3 \u04af\u043b\u043a\u0435\u043d\u0456 \u2014 \u043a\u04d9\u0440\u0456 \u0411\u0430\u0431\u0430 \u0414\u04d9\u0443 \u2014 \u043a\u04af\u04a3\u0456\u0440\u0435\u043d\u0435 \u0441\u04e9\u0439\u043b\u0435\u0434\u0456.")},
     {dialog:[{who:"elder",em:"cool",line:L("If this shrivelled little man can gut the earth and spill its brains, one day he may do the same to us. We will set him tasks no man could do. And tonight, while he sleeps, we will be rid of him. Say nothing. Smile.","\u0415\u0441\u043b\u0438 \u044d\u0442\u043e\u0442 \u0441\u043c\u043e\u0440\u0449\u0435\u043d\u043d\u044b\u0439 \u0441\u0442\u0430\u0440\u0438\u0447\u043e\u043a \u043f\u043e\u0442\u0440\u043e\u0448\u0438\u0442 \u0437\u0435\u043c\u043b\u044e \u0438 \u0432\u044b\u043b\u0438\u0432\u0430\u0435\u0442 \u0435\u0451 \u043c\u043e\u0437\u0433\u0438, \u043e\u0434\u043d\u0430\u0436\u0434\u044b \u043e\u043d \u0441\u0434\u0435\u043b\u0430\u0435\u0442 \u0442\u043e \u0436\u0435 \u0441 \u043d\u0430\u043c\u0438. \u0417\u0430\u0434\u0430\u0434\u0438\u043c \u0435\u043c\u0443 \u0440\u0430\u0431\u043e\u0442\u0443, \u0447\u0442\u043e \u043d\u0435 \u043f\u043e\u0434 \u0441\u0438\u043b\u0443 \u043d\u0438\u043a\u043e\u043c\u0443. \u0410 \u043d\u043e\u0447\u044c\u044e, \u043f\u043e\u043a\u0430 \u0441\u043f\u0438\u0442, \u0438\u0437\u0431\u0430\u0432\u0438\u043c\u0441\u044f \u043e\u0442 \u043d\u0435\u0433\u043e. \u041c\u043e\u043b\u0447\u0438\u0442\u0435. \u0423\u043b\u044b\u0431\u0430\u0439\u0442\u0435\u0441\u044c.","\u0415\u0433\u0435\u0440 \u043c\u044b\u043d\u0430 \u0431\u04af\u043a\u0448\u0456\u043a \u0448\u0430\u043b \u0436\u0435\u0440\u0434\u0456 \u0456\u0448\u0435\u043a-\u049b\u0430\u0440\u043d\u044b\u043d \u0448\u044b\u0493\u0430\u0440\u044b\u043f, \u043c\u0438\u044b\u043d \u0442\u04e9\u043a\u0441\u0435, \u0431\u0456\u0440 \u043a\u04af\u043d\u0456 \u0431\u0456\u0437\u0433\u0435 \u0434\u0435 \u0441\u043e\u043b\u0430\u0439 \u0456\u0441\u0442\u0435\u0440. \u041e\u0493\u0430\u043d \u0430\u0434\u0430\u043c \u0431\u0430\u043b\u0430\u0441\u044b \u0456\u0441\u0442\u0435\u0439 \u0430\u043b\u043c\u0430\u0441 \u0436\u04b1\u043c\u044b\u0441\u0442\u0430\u0440 \u0442\u0430\u043f\u0441\u044b\u0440\u0430\u043c\u044b\u0437. \u0422\u04af\u043d\u0434\u0435, \u04b1\u0439\u044b\u049b\u0442\u0430\u043f \u0436\u0430\u0442\u049b\u0430\u043d\u0434\u0430, \u043e\u0434\u0430\u043d \u049b\u04b1\u0442\u044b\u043b\u0430\u043c\u044b\u0437. \u04ae\u043d\u0434\u0435\u043c\u0435\u04a3\u0434\u0435\u0440. \u0416\u044b\u043c\u0438\u044b\u04a3\u0434\u0430\u0440.")},{who:"qanbaq",em:"wise",line:L("(to himself) Smiles by day, and whispers by night. I have sharp ears, my big friends. I heard every word.","(\u043f\u0440\u043e \u0441\u0435\u0431\u044f) \u0423\u043b\u044b\u0431\u043a\u0438 \u0434\u043d\u0451\u043c, \u0430 \u043d\u043e\u0447\u044c\u044e \u0448\u0451\u043f\u043e\u0442. \u0423 \u043c\u0435\u043d\u044f \u0447\u0443\u0442\u043a\u0438\u0435 \u0443\u0448\u0438, \u0434\u0440\u0443\u0437\u044c\u044f-\u0433\u0440\u043e\u043c\u0430\u0434\u0438\u043d\u044b. \u042f \u0441\u043b\u044b\u0448\u0430\u043b \u043a\u0430\u0436\u0434\u043e\u0435 \u0441\u043b\u043e\u0432\u043e.","(\u0456\u0448\u0456\u043d\u0435\u043d) \u041a\u04af\u043d\u0434\u0456\u0437 \u0436\u044b\u043c\u0438\u044e, \u0442\u04af\u043d\u0434\u0435 \u0441\u044b\u0431\u044b\u0440. \u049a\u04b1\u043b\u0430\u0493\u044b\u043c \u0441\u0430\u049b, \u0430\u043b\u044b\u043f \u0434\u043e\u0441\u0442\u0430\u0440\u044b\u043c. \u04d8\u0440 \u0441\u04e9\u0437\u0434\u0456 \u0435\u0441\u0442\u0456\u043f \u049b\u043e\u0439\u0434\u044b\u043c.")}]}
   ]},
  {title:L("Carry Off the River","\u0423\u043d\u0435\u0441\u0442\u0438 \u0440\u0435\u043a\u0443","\u04e8\u0437\u0435\u043d\u0434\u0456 \u043a\u04e9\u0442\u0435\u0440\u0456\u043f \u043a\u0435\u0442\u0443"), scene:"river", obj:L("Beat the water-fetching task with a bigger bluff","\u041f\u043e\u0431\u0435\u0434\u0438 \u0437\u0430\u0434\u0430\u0447\u0443 \u0441 \u0432\u043e\u0434\u043e\u0439 \u0435\u0449\u0451 \u0431\u043e\u043b\u044c\u0448\u0438\u043c \u0431\u043b\u0435\u0444\u043e\u043c","\u0421\u0443 \u0442\u0430\u0441\u0443 \u0441\u044b\u043d\u044b\u043d \u043e\u0434\u0430\u043d \u0430\u0441\u049b\u0430\u043d \u0430\u043b\u0434\u0430\u0443\u043c\u0435\u043d \u0436\u0435\u04a3"),
   beats:[
     {dialog:[{who:"elder",em:"cool",line:L("Guest! Do us one small kindness. Take this water skin to the river and fill it, that we may make tea for our honoured visitor.","\u0413\u043e\u0441\u0442\u044c! \u041e\u043a\u0430\u0436\u0438 \u043d\u0430\u043c \u043c\u0430\u043b\u0443\u044e \u0443\u0441\u043b\u0443\u0433\u0443. \u041e\u0442\u043d\u0435\u0441\u0438 \u044d\u0442\u043e\u0442 \u0431\u0443\u0440\u0434\u044e\u043a \u043a \u0440\u0435\u043a\u0435 \u0438 \u043d\u0430\u043f\u043e\u043b\u043d\u0438, \u0447\u0442\u043e\u0431\u044b \u0437\u0430\u0432\u0430\u0440\u0438\u0442\u044c \u0447\u0430\u0439 \u0434\u043b\u044f \u0434\u043e\u0440\u043e\u0433\u043e\u0433\u043e \u0433\u043e\u0441\u0442\u044f.","\u049a\u043e\u043d\u0430\u049b! \u0411\u0456\u0437\u0433\u0435 \u0431\u0456\u0440 \u0448\u0430\u0493\u044b\u043d \u0436\u0430\u049b\u0441\u044b\u043b\u044b\u049b \u0436\u0430\u0441\u0430. \u041c\u044b\u043d\u0430 \u0441\u0430\u0431\u0430\u043d\u044b \u04e9\u0437\u0435\u043d\u0433\u0435 \u0430\u043f\u0430\u0440\u044b\u043f \u0442\u043e\u043b\u0442\u044b\u0440\u0448\u044b, \u049b\u0430\u0434\u0456\u0440\u043b\u0456 \u043c\u0435\u0439\u043c\u0430\u043d\u0493\u0430 \u0448\u0430\u0439 \u049b\u0430\u0439\u043d\u0430\u0442\u0430\u0439\u044b\u049b.")}]},
     {narr:L("The water skin was a giant's saba \u2014 a leather bag so vast the old man could not have dragged it empty, let alone full. So instead he took up a spade and began, slowly and deliberately, to dig a long trench in a great circle all the way around the river itself.","\u0411\u0443\u0440\u0434\u044e\u043a \u0431\u044b\u043b \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u044c\u0435\u0439 \u0441\u0430\u0431\u043e\u0439 \u2014 \u043a\u043e\u0436\u0430\u043d\u044b\u043c \u043c\u0435\u0445\u043e\u043c \u0441\u0442\u043e\u043b\u044c \u043e\u0433\u0440\u043e\u043c\u043d\u044b\u043c, \u0447\u0442\u043e \u0441\u0442\u0430\u0440\u0438\u043a\u0443 \u043d\u0435 \u0441\u0434\u0432\u0438\u043d\u0443\u0442\u044c \u0435\u0433\u043e \u0438 \u043f\u0443\u0441\u0442\u044b\u043c, \u043d\u0435 \u0442\u043e \u0447\u0442\u043e \u043f\u043e\u043b\u043d\u044b\u043c. \u0418 \u0432\u043e\u0442 \u043e\u043d \u0432\u0437\u044f\u043b \u043b\u043e\u043f\u0430\u0442\u0443 \u0438 \u043f\u0440\u0438\u043d\u044f\u043b\u0441\u044f \u043d\u0435\u0442\u043e\u0440\u043e\u043f\u043b\u0438\u0432\u043e \u043a\u043e\u043f\u0430\u0442\u044c \u0434\u043b\u0438\u043d\u043d\u044b\u0439 \u0440\u043e\u0432 \u0448\u0438\u0440\u043e\u043a\u0438\u043c \u043a\u0440\u0443\u0433\u043e\u043c \u0432\u043e\u043a\u0440\u0443\u0433 \u0441\u0430\u043c\u043e\u0439 \u0440\u0435\u043a\u0438.","\u0421\u0443 \u044b\u0434\u044b\u0441\u044b \u0434\u04d9\u0443\u0434\u0456\u04a3 \u0441\u0430\u0431\u0430\u0441\u044b \u0435\u043a\u0435\u043d \u2014 \u0448\u0430\u043b\u0434\u044b\u04a3 \u0431\u043e\u0441 \u043a\u04af\u0439\u0456\u043d\u0434\u0435 \u0434\u0435 \u0441\u04af\u0439\u0440\u0435\u0442\u0435 \u0430\u043b\u043c\u0430\u0441, \u0442\u043e\u043b\u044b \u0442\u04af\u0433\u0456\u043b, \u043e\u0440\u0430\u0441\u0430\u043d \u0431\u044b\u043b\u0493\u0430\u0440\u044b \u049b\u0430\u043f. \u0421\u043e\u043d\u0434\u0430 \u043e\u043b \u043a\u04af\u0440\u0435\u043a \u0430\u043b\u044b\u043f, \u0430\u0441\u044b\u049b\u043f\u0430\u0439, \u04e9\u0437\u0435\u043d\u043d\u0456\u04a3 \u0434\u04d9\u043b \u0430\u0439\u043d\u0430\u043b\u0430\u0441\u044b\u043d \u04af\u043b\u043a\u0435\u043d \u0448\u0435\u04a3\u0431\u0435\u0440 \u049b\u044b\u043f \u043e\u0440 \u049b\u0430\u0437\u0430 \u0431\u0430\u0441\u0442\u0430\u0434\u044b.")},
     {dialog:[{who:"dau",em:"worried",line:L("Old man \u2014 what ARE you doing? The water is right there!","\u0421\u0442\u0430\u0440\u0438\u043a \u2014 \u0447\u0442\u043e \u0442\u044b \u0414\u0415\u041b\u0410\u0415\u0428\u042c? \u0412\u043e\u0434\u0430 \u0436\u0435 \u0432\u043e\u0442 \u043e\u043d\u0430!","\u0428\u0430\u043b \u2014 \u043d\u0435 \u0456\u0441\u0442\u0435\u043f \u0436\u0430\u0442\u044b\u0440\u0441\u044b\u04a3 \u0441\u0435\u043d? \u0421\u0443 \u0430\u043d\u0430\u0443 \u0442\u04b1\u0440 \u0493\u043e\u0439!")},{who:"qanbaq",em:"sly",line:L("Fetch a skin today, fetch a skin tomorrow \u2014 what a tiresome way to live! No. I will dig the whole river loose and carry it home entire, so you need never fetch water again.","\u041d\u043e\u0441\u0438\u0442\u044c \u0431\u0443\u0440\u0434\u044e\u043a \u0441\u0435\u0433\u043e\u0434\u043d\u044f, \u043d\u043e\u0441\u0438\u0442\u044c \u0437\u0430\u0432\u0442\u0440\u0430 \u2014 \u0447\u0442\u043e \u0437\u0430 \u0434\u043e\u043a\u0443\u0447\u043d\u0430\u044f \u0436\u0438\u0437\u043d\u044c! \u041d\u0435\u0442. \u0412\u044b\u043a\u043e\u043f\u0430\u044e \u0432\u0441\u044e \u0440\u0435\u043a\u0443 \u0440\u0430\u0437\u043e\u043c \u0438 \u0443\u043d\u0435\u0441\u0443 \u0446\u0435\u043b\u0438\u043a\u043e\u043c, \u0447\u0442\u043e\u0431\u044b \u0432\u0430\u043c \u0431\u043e\u043b\u044c\u0448\u0435 \u043d\u0435 \u043d\u043e\u0441\u0438\u0442\u044c \u0432\u043e\u0434\u044b.","\u0411\u04af\u0433\u0456\u043d \u0441\u0430\u0431\u0430, \u0435\u0440\u0442\u0435\u04a3 \u0441\u0430\u0431\u0430 \u0442\u0430\u0441\u0443 \u2014 \u049b\u0430\u043d\u0434\u0430\u0439 \u0436\u0430\u043b\u044b\u049b\u0442\u044b\u0440\u0430\u0440 \u0442\u0456\u0440\u043b\u0456\u043a! \u0416\u043e\u049b. \u041c\u0435\u043d \u0431\u04af\u043a\u0456\u043b \u04e9\u0437\u0435\u043d\u0434\u0456 \u049b\u0430\u0437\u044b\u043f \u0431\u043e\u0441\u0430\u0442\u044b\u043f, \u0442\u04b1\u0442\u0430\u0441 \u043a\u04e9\u0442\u0435\u0440\u0456\u043f \u04af\u0439\u0433\u0435 \u0430\u043f\u0430\u0440\u0430\u043c\u044b\u043d, \u0441\u0435\u043d\u0434\u0435\u0440 \u049b\u0430\u0439\u0442\u044b\u043f \u0441\u0443 \u0442\u0430\u0441\u043f\u0430\u0439\u0442\u044b\u043d \u0431\u043e\u043b\u0430\u0441\u044b\u04a3\u0434\u0430\u0440.")}]},
     {dialog:[{who:"elder",em:"afraid",line:L("Carry off \u2014 our whole RIVER?! Stop! Stop, I beg you \u2014 you'll leave the camp a dry bone! Give me the skin \u2014 I'll fetch the water myself!","\u0423\u043d\u0435\u0441\u0442\u0438 \u2014 \u0432\u0441\u044e \u043d\u0430\u0448\u0443 \u0420\u0415\u041a\u0423?! \u0421\u0442\u043e\u0439! \u0421\u0442\u043e\u0439, \u0443\u043c\u043e\u043b\u044f\u044e \u2014 \u043e\u0441\u0442\u0430\u0432\u0438\u0448\u044c \u0441\u0442\u0430\u043d \u0441\u0443\u0445\u043e\u0439 \u043a\u043e\u0441\u0442\u044c\u044e! \u0414\u0430\u0439 \u0431\u0443\u0440\u0434\u044e\u043a \u2014 \u0441\u0430\u043c \u043f\u0440\u0438\u043d\u0435\u0441\u0443 \u0432\u043e\u0434\u044b!","\u041a\u04e9\u0442\u0435\u0440\u0456\u043f \u043a\u0435\u0442\u0443 \u2014 \u0431\u04af\u043a\u0456\u043b \u04e8\u0417\u0415\u041d\u0406\u041c\u0406\u0417\u0414\u0406 \u043c\u0435?! \u0422\u043e\u049b\u0442\u0430! \u0422\u043e\u049b\u0442\u0430, \u0436\u0430\u043b\u044b\u043d\u0430\u043c\u044b\u043d \u2014 \u0430\u0443\u044b\u043b\u0434\u044b \u049b\u04b1\u0440\u0493\u0430\u049b \u0441\u04af\u0439\u0435\u043a\u0442\u0435\u0439 \u049b\u044b\u043b\u044b\u043f \u043a\u0435\u0442\u0435\u0441\u0456\u04a3! \u0421\u0430\u0431\u0430\u043d\u044b \u0431\u0435\u0440 \u2014 \u0441\u0443\u0434\u044b \u04e9\u0437\u0456\u043c \u04d9\u043a\u0435\u043b\u0435\u043c!")}]},
     {narr:L("And the great giant snatched up the enormous saba and ran to fill it, sweating, while the old man leaned on his spade and smiled.","\u0418 \u0433\u0440\u043e\u043c\u0430\u0434\u043d\u044b\u0439 \u0432\u0435\u043b\u0438\u043a\u0430\u043d \u0441\u0445\u0432\u0430\u0442\u0438\u043b \u043e\u0433\u0440\u043e\u043c\u043d\u0443\u044e \u0441\u0430\u0431\u0443 \u0438, \u043e\u0431\u043b\u0438\u0432\u0430\u044f\u0441\u044c \u043f\u043e\u0442\u043e\u043c, \u043f\u043e\u0431\u0435\u0436\u0430\u043b \u0435\u0451 \u043d\u0430\u043f\u043e\u043b\u043d\u044f\u0442\u044c, \u0430 \u0441\u0442\u0430\u0440\u0438\u043a \u043e\u043f\u0435\u0440\u0441\u044f \u043d\u0430 \u043b\u043e\u043f\u0430\u0442\u0443 \u0438 \u0443\u043b\u044b\u0431\u043d\u0443\u043b\u0441\u044f.","\u0410\u043b\u044b\u043f \u0434\u04d9\u0443 \u043e\u0440\u0430\u0441\u0430\u043d \u0441\u0430\u0431\u0430\u043d\u044b \u0448\u0430\u043f \u0431\u0435\u0440\u0456\u043f \u04b1\u0441\u0442\u0430\u043f, \u0442\u0435\u0440\u043b\u0435\u043f-\u0442\u0435\u043f\u0448\u0456\u043f, \u043e\u043d\u044b \u0442\u043e\u043b\u0442\u044b\u0440\u0443\u0493\u0430 \u0436\u04af\u0433\u0456\u0440\u0434\u0456, \u0430\u043b \u0448\u0430\u043b \u043a\u04af\u0440\u0435\u0433\u0456\u043d\u0435 \u0441\u04af\u0439\u0435\u043d\u0456\u043f, \u043a\u04af\u043b\u0456\u043c\u0441\u0456\u0440\u0435\u043f \u0442\u04b1\u0440\u0434\u044b.")}
   ]},
  {title:L("Drag Home the Forest","\u0423\u0442\u0430\u0449\u0438\u0442\u044c \u0432\u0435\u0441\u044c \u043b\u0435\u0441","\u041e\u0440\u043c\u0430\u043d\u0434\u044b \u0441\u04af\u0439\u0440\u0435\u043f \u04d9\u043a\u0435\u0442\u0443"), scene:"forest", obj:L("Turn the firewood task into another trap","\u041e\u0431\u0440\u0430\u0442\u0438 \u0437\u0430\u0434\u0430\u0447\u0443 \u0441 \u0434\u0440\u043e\u0432\u0430\u043c\u0438 \u0432 \u043d\u043e\u0432\u0443\u044e \u043b\u043e\u0432\u0443\u0448\u043a\u0443","\u041e\u0442\u044b\u043d \u0441\u044b\u043d\u044b\u043d \u0442\u0430\u0493\u044b \u0431\u0456\u0440 \u049b\u0430\u049b\u043f\u0430\u043d\u0493\u0430 \u0430\u0439\u043d\u0430\u043b\u0434\u044b\u0440"),
   beats:[
     {dialog:[{who:"elder",em:"cool",line:L("Then fetch us firewood, guest, for the night grows cold.","\u0422\u043e\u0433\u0434\u0430 \u043f\u0440\u0438\u043d\u0435\u0441\u0438 \u043d\u0430\u043c \u0434\u0440\u043e\u0432, \u0433\u043e\u0441\u0442\u044c, \u0438\u0431\u043e \u043d\u043e\u0447\u044c \u0445\u043e\u043b\u043e\u0434\u0430\u0435\u0442.","\u0415\u043d\u0434\u0435\u0448\u0435 \u043e\u0442\u044b\u043d \u04d9\u043a\u0435\u043b, \u049b\u043e\u043d\u0430\u049b, \u0442\u04af\u043d \u0441\u0430\u043b\u049b\u044b\u043d\u0434\u0430\u043f \u0431\u0430\u0440\u0430\u0434\u044b.")}]},
     {narr:L("A young giant tore a whole pine from the earth, roots and all, and swung it onto his shoulder to show his strength. But the old man took a long coil of rope and began, tree by tree, to loop it around the entire forest.","\u041c\u043e\u043b\u043e\u0434\u043e\u0439 \u0432\u0435\u043b\u0438\u043a\u0430\u043d \u0432\u044b\u0440\u0432\u0430\u043b \u0446\u0435\u043b\u0443\u044e \u0441\u043e\u0441\u043d\u0443 \u0441 \u043a\u043e\u0440\u043d\u044f\u043c\u0438 \u0438 \u0432\u0441\u043a\u0438\u043d\u0443\u043b \u043d\u0430 \u043f\u043b\u0435\u0447\u043e, \u043a\u0440\u0430\u0441\u0443\u044f\u0441\u044c \u0441\u0438\u043b\u043e\u0439. \u0410 \u0441\u0442\u0430\u0440\u0438\u043a \u0432\u0437\u044f\u043b \u0434\u043b\u0438\u043d\u043d\u0443\u044e \u0432\u0435\u0440\u0451\u0432\u043a\u0443 \u0438 \u0441\u0442\u0430\u043b, \u0434\u0435\u0440\u0435\u0432\u043e \u0437\u0430 \u0434\u0435\u0440\u0435\u0432\u043e\u043c, \u043e\u0431\u0432\u044f\u0437\u044b\u0432\u0430\u0442\u044c \u0435\u044e \u0432\u0435\u0441\u044c \u043b\u0435\u0441.","\u0411\u0456\u0440 \u0436\u0430\u0441 \u0434\u04d9\u0443 \u0442\u04af\u043f-\u0442\u0430\u043c\u044b\u0440\u044b\u043c\u0435\u043d \u0431\u04af\u0442\u0456\u043d \u049b\u0430\u0440\u0430\u0493\u0430\u0439\u0434\u044b \u0436\u04b1\u043b\u044b\u043f \u0430\u043b\u044b\u043f, \u043a\u04af\u0448\u0456\u043d \u043a\u04e9\u0440\u0441\u0435\u0442\u043f\u0435\u043a \u0431\u043e\u043f \u0438\u044b\u0493\u044b\u043d\u0430 \u0441\u0430\u043b\u0434\u044b. \u0410\u043b \u0448\u0430\u043b \u04b1\u0437\u044b\u043d \u0430\u0440\u049b\u0430\u043d \u0430\u043b\u044b\u043f, \u0430\u0493\u0430\u0448-\u0430\u0493\u0430\u0448\u0442\u0430\u043d \u0431\u04af\u043a\u0456\u043b \u043e\u0440\u043c\u0430\u043d\u0434\u044b \u043e\u0440\u0430\u043f \u0431\u0430\u0439\u043b\u0430\u0439 \u0431\u0430\u0441\u0442\u0430\u0434\u044b.")},
     {dialog:[{who:"jasdau",em:"worried",line:L("Grandfather\u2026 why do you tie them all together?","\u0414\u0435\u0434\u0443\u0448\u043a\u0430\u2026 \u0437\u0430\u0447\u0435\u043c \u0442\u044b \u0432\u044f\u0436\u0435\u0448\u044c \u0438\u0445 \u0432\u0441\u0435 \u0432\u043c\u0435\u0441\u0442\u0435?","\u0410\u0442\u0430\u2026 \u043d\u0435\u0433\u0435 \u0431\u04d9\u0440\u0456\u043d \u0431\u0430\u0439\u043b\u0430\u043f \u0436\u0430\u0442\u044b\u0440\u0441\u044b\u04a3?")},{who:"qanbaq",em:"sly",line:L("One log at a time? What a waste of an afternoon. I'll drag the whole forest home in a single pull and be done with it.","\u041f\u043e \u043e\u0434\u043d\u043e\u043c\u0443 \u043f\u043e\u043b\u0435\u043d\u0443? \u041f\u0443\u0441\u0442\u0430\u044f \u0442\u0440\u0430\u0442\u0430 \u0434\u043d\u044f. \u0423\u0432\u043e\u043b\u043e\u043a\u0443 \u0432\u0435\u0441\u044c \u043b\u0435\u0441 \u0437\u0430\u0440\u0430\u0437 \u2014 \u0438 \u0434\u0435\u043b\u0443 \u043a\u043e\u043d\u0435\u0446.","\u0411\u0456\u0440-\u0431\u0456\u0440\u043b\u0435\u043f \u043e\u0442\u044b\u043d \u0431\u0430? \u0411\u0435\u043a\u0435\u0440 \u0443\u0430\u049b\u044b\u0442. \u0411\u04af\u043a\u0456\u043b \u043e\u0440\u043c\u0430\u043d\u0434\u044b \u0431\u0456\u0440-\u0430\u049b \u0441\u04af\u0439\u0440\u0435\u043f \u04af\u0439\u0433\u0435 \u0430\u043f\u0430\u0440\u0430\u043c \u0434\u0430, \u0442\u044b\u043d\u0430\u043c.")}]},
     {dialog:[{who:"jasdau",em:"afraid",line:L("No \u2014 no! Where will we shelter? Where will the birds nest?! Leave the forest be \u2014 I'll carry the wood, I'll carry all of it!","\u041d\u0435\u0442 \u2014 \u043d\u0435\u0442! \u0413\u0434\u0435 \u043d\u0430\u043c \u0443\u043a\u0440\u044b\u0442\u044c\u0441\u044f? \u0413\u0434\u0435 \u043f\u0442\u0438\u0446\u0430\u043c \u0433\u043d\u0435\u0437\u0434\u0438\u0442\u044c\u0441\u044f?! \u041e\u0441\u0442\u0430\u0432\u044c \u043b\u0435\u0441 \u2014 \u044f \u043f\u0440\u0438\u043d\u0435\u0441\u0443 \u0434\u0440\u043e\u0432\u0430, \u0432\u0441\u0451 \u043f\u0440\u0438\u043d\u0435\u0441\u0443!","\u0416\u043e\u049b \u2014 \u0436\u043e\u049b! \u049a\u0430\u0439\u0434\u0430 \u043f\u0430\u043d\u0430\u043b\u0430\u0439\u043c\u044b\u0437? \u049a\u04b1\u0441\u0442\u0430\u0440 \u049b\u0430\u0439\u0434\u0430 \u04b1\u044f \u0441\u0430\u043b\u0430\u0434\u044b?! \u041e\u0440\u043c\u0430\u043d\u0434\u044b \u049b\u0430\u043b\u0434\u044b\u0440 \u2014 \u043e\u0442\u044b\u043d\u0434\u044b \u04e9\u0437\u0456\u043c \u0442\u0430\u0441\u0438\u043c\u044b\u043d, \u0431\u04d9\u0440\u0456\u043d \u0442\u0430\u0441\u0438\u043c\u044b\u043d!")}]},
     {narr:L("And so the old man carried nothing, and the giants carried everything, and still they grew more afraid of him with every passing hour.","\u0422\u0430\u043a \u0441\u0442\u0430\u0440\u0438\u043a \u043d\u0435 \u043d\u0451\u0441 \u043d\u0438\u0447\u0435\u0433\u043e, \u0430 \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u044b \u043d\u0435\u0441\u043b\u0438 \u0432\u0441\u0451, \u0438 \u0441 \u043a\u0430\u0436\u0434\u044b\u043c \u0447\u0430\u0441\u043e\u043c \u0431\u043e\u044f\u043b\u0438\u0441\u044c \u0435\u0433\u043e \u0432\u0441\u0451 \u0441\u0438\u043b\u044c\u043d\u0435\u0435.","\u0421\u04e9\u0439\u0442\u0456\u043f \u0448\u0430\u043b \u0435\u0448\u0442\u0435\u04a3\u0435 \u043a\u04e9\u0442\u0435\u0440\u043c\u0435\u0434\u0456, \u0434\u04d9\u0443\u043b\u0435\u0440 \u0431\u04d9\u0440\u0456\u043d \u043a\u04e9\u0442\u0435\u0440\u0434\u0456, \u04d9\u0440 \u04e9\u0442\u043a\u0435\u043d \u0441\u0430\u0439\u044b\u043d \u043e\u0434\u0430\u043d \u04af\u0440\u0435\u0439\u043b\u0435\u0440\u0456 \u0430\u0440\u0442\u0430 \u0431\u0435\u0440\u0434\u0456.")}
   ]},
  {title:L("The Night Ambush","\u041d\u043e\u0447\u043d\u0430\u044f \u0437\u0430\u0441\u0430\u0434\u0430","\u0422\u04af\u043d\u0433\u0456 \u0442\u043e\u0440\u0443\u044b\u043b"), scene:"night", obj:L("Survive the night the giants mean to end you","\u041f\u0435\u0440\u0435\u0436\u0438\u0432\u0438 \u043d\u043e\u0447\u044c, \u0432 \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u0442\u0435\u0431\u044f \u0440\u0435\u0448\u0438\u043b\u0438 \u0438\u0437\u0432\u0435\u0441\u0442\u0438","\u0414\u04d9\u0443\u043b\u0435\u0440 \u0441\u0435\u043d\u0456 \u049b\u04b1\u0440\u0442\u043f\u0430\u049b \u0431\u043e\u043b\u0493\u0430\u043d \u0442\u04af\u043d\u0434\u0435 \u0430\u043c\u0430\u043d \u049b\u0430\u043b"),
   beats:[
     {narr:L("When darkness fell, the giants spread a soft bed for their guest in the largest tent and wished him a smiling good night. But the old man had heard their whispers.","\u041a\u043e\u0433\u0434\u0430 \u043f\u0430\u043b\u0430 \u0442\u044c\u043c\u0430, \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u044b \u043f\u043e\u0441\u0442\u0435\u043b\u0438\u043b\u0438 \u0433\u043e\u0441\u0442\u044e \u043c\u044f\u0433\u043a\u0443\u044e \u043f\u043e\u0441\u0442\u0435\u043b\u044c \u0432 \u0441\u0430\u043c\u043e\u043c \u0431\u043e\u043b\u044c\u0448\u043e\u043c \u0448\u0430\u0442\u0440\u0435 \u0438 \u0441 \u0443\u043b\u044b\u0431\u043a\u043e\u0439 \u043f\u043e\u0436\u0435\u043b\u0430\u043b\u0438 \u0434\u043e\u0431\u0440\u043e\u0439 \u043d\u043e\u0447\u0438. \u041d\u043e \u0441\u0442\u0430\u0440\u0438\u043a \u0441\u043b\u044b\u0448\u0430\u043b \u0438\u0445 \u0448\u0451\u043f\u043e\u0442.","\u049a\u0430\u0440\u0430\u04a3\u0493\u044b \u0442\u04af\u0441\u043a\u0435\u043d\u0434\u0435, \u0434\u04d9\u0443\u043b\u0435\u0440 \u049b\u043e\u043d\u0430\u0493\u044b\u043d\u0430 \u0435\u04a3 \u04af\u043b\u043a\u0435\u043d \u043a\u0438\u0456\u0437 \u04af\u0439\u0433\u0435 \u0436\u04b1\u043c\u0441\u0430\u049b \u0442\u04e9\u0441\u0435\u043a \u0441\u0430\u043b\u044b\u043f, \u0436\u044b\u043c\u0438\u044b\u043f \u049b\u043e\u0448\u0442\u0430\u0441\u0442\u044b. \u0411\u0456\u0440\u0430\u049b \u0448\u0430\u043b \u043e\u043b\u0430\u0440\u0434\u044b\u04a3 \u0441\u044b\u0431\u044b\u0440\u044b\u043d \u0435\u0441\u0442\u0456\u0433\u0435\u043d \u0435\u0434\u0456.")},
     {dialog:[{who:"qanbaq",em:"wise",line:L("I think, tonight, I had best not be where they expect me.","\u041f\u043e\u0436\u0430\u043b\u0443\u0439, \u044d\u0442\u043e\u0439 \u043d\u043e\u0447\u044c\u044e \u043c\u043d\u0435 \u043b\u0443\u0447\u0448\u0435 \u0431\u044b\u0442\u044c \u043d\u0435 \u0442\u0430\u043c, \u0433\u0434\u0435 \u043c\u0435\u043d\u044f \u0436\u0434\u0443\u0442.","\u0411\u04af\u0433\u0456\u043d \u0442\u04af\u043d\u0434\u0435 \u043e\u043b\u0430\u0440 \u043a\u04af\u0442\u043a\u0435\u043d \u0436\u0435\u0440\u0434\u0435 \u0431\u043e\u043b\u043c\u0430\u0493\u0430\u043d\u044b\u043c \u0436\u04e9\u043d \u0448\u044b\u0493\u0430\u0440.")}]},
     {narr:L("So he rolled a heavy log beneath the blanket where his body should have lain, tucked it in snug, and crept away to sleep behind the woodpile. At the black middle of the night the giants stole in on tiptoe, lifted a boulder the size of a yurt, and dashed it down upon the bed \u2014 crash, again and again \u2014 until the log was splinters.","\u0418 \u043e\u043d \u043f\u043e\u0434\u043b\u043e\u0436\u0438\u043b \u043f\u043e\u0434 \u043e\u0434\u0435\u044f\u043b\u043e \u0442\u044f\u0436\u0451\u043b\u043e\u0435 \u0431\u0440\u0435\u0432\u043d\u043e, \u0443\u043a\u0443\u0442\u0430\u043b \u043f\u043e\u0443\u044e\u0442\u043d\u0435\u0435, \u0430 \u0441\u0430\u043c \u043f\u0440\u043e\u043a\u0440\u0430\u043b\u0441\u044f \u0441\u043f\u0430\u0442\u044c \u0437\u0430 \u043f\u043e\u043b\u0435\u043d\u043d\u0438\u0446\u0435\u0439. \u0412 \u0433\u043b\u0443\u0445\u0443\u044e \u043f\u043e\u043b\u043d\u043e\u0447\u044c \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u044b \u043f\u0440\u043e\u043a\u0440\u0430\u043b\u0438\u0441\u044c \u043d\u0430 \u0446\u044b\u043f\u043e\u0447\u043a\u0430\u0445, \u043f\u043e\u0434\u043d\u044f\u043b\u0438 \u0432\u0430\u043b\u0443\u043d \u0440\u0430\u0437\u043c\u0435\u0440\u043e\u043c \u0441 \u044e\u0440\u0442\u0443 \u0438 \u043e\u0431\u0440\u0443\u0448\u0438\u043b\u0438 \u043d\u0430 \u043f\u043e\u0441\u0442\u0435\u043b\u044c \u2014 \u0440\u0430\u0437 \u0437\u0430 \u0440\u0430\u0437\u043e\u043c \u2014 \u043f\u043e\u043a\u0430 \u0431\u0440\u0435\u0432\u043d\u043e \u043d\u0435 \u0440\u0430\u0437\u043b\u0435\u0442\u0435\u043b\u043e\u0441\u044c \u0432 \u0449\u0435\u043f\u043a\u0438.","\u0421\u04e9\u0439\u0442\u0456\u043f \u043e\u043b \u0434\u0435\u043d\u0435\u0441\u0456 \u0436\u0430\u0442\u0443\u0493\u0430 \u0442\u0438\u0456\u0441 \u043a\u04e9\u0440\u043f\u0435\u043d\u0456\u04a3 \u0430\u0441\u0442\u044b\u043d\u0430 \u0430\u0443\u044b\u0440 \u0431\u04e9\u0440\u0435\u043d\u0435 \u0441\u0430\u043b\u044b\u043f, \u0436\u044b\u043b\u044b\u0442\u044b\u043f \u0431\u04af\u0440\u043a\u0435\u043f \u049b\u043e\u0439\u0434\u044b \u0434\u0430, \u04e9\u0437\u0456 \u043e\u0442\u044b\u043d \u04af\u0439\u0456\u043d\u0434\u0456\u0441\u0456\u043d\u0456\u04a3 \u0430\u0440\u0442\u044b\u043d\u0430 \u0431\u0430\u0440\u044b\u043f \u04b1\u0439\u044b\u049b\u0442\u0430\u0434\u044b. \u0422\u04af\u043d \u043e\u0440\u0442\u0430\u0441\u044b\u043d\u0434\u0430 \u0434\u04d9\u0443\u043b\u0435\u0440 \u0430\u044f\u0493\u044b\u043d\u044b\u04a3 \u04b1\u0448\u044b\u043c\u0435\u043d \u0436\u0430\u0441\u044b\u0440\u044b\u043d \u043a\u0456\u0440\u0456\u043f, \u043a\u0438\u0456\u0437 \u04af\u0439\u0434\u0435\u0439 \u0442\u0430\u0441\u0442\u044b \u043a\u04e9\u0442\u0435\u0440\u0456\u043f, \u0442\u04e9\u0441\u0435\u043a\u043a\u0435 \u04b1\u0440\u0434\u044b \u2014 \u049b\u0430\u0439\u0442\u0430-\u049b\u0430\u0439\u0442\u0430 \u2014 \u0431\u04e9\u0440\u0435\u043d\u0435 \u0436\u0430\u04a3\u049b\u0430-\u0436\u0430\u04a3\u049b\u0430 \u0431\u043e\u043b\u0493\u0430\u043d\u0448\u0430.")},
     {narr:L("But at dawn, out strolled the old man, stretching and yawning in the morning sun, alive and whole. The giants gaped as though they had seen a ghost.","\u0410 \u043d\u0430 \u0440\u0430\u0441\u0441\u0432\u0435\u0442\u0435 \u0432\u044b\u0448\u0435\u043b \u0441\u0442\u0430\u0440\u0438\u043a, \u043f\u043e\u0442\u044f\u0433\u0438\u0432\u0430\u044f\u0441\u044c \u0438 \u0437\u0435\u0432\u0430\u044f \u043d\u0430 \u0443\u0442\u0440\u0435\u043d\u043d\u0435\u043c \u0441\u043e\u043b\u043d\u0446\u0435, \u0436\u0438\u0432\u043e\u0439 \u0438 \u043d\u0435\u0432\u0440\u0435\u0434\u0438\u043c\u044b\u0439. \u0412\u0435\u043b\u0438\u043a\u0430\u043d\u044b \u0440\u0430\u0437\u0438\u043d\u0443\u043b\u0438 \u0440\u0442\u044b, \u0441\u043b\u043e\u0432\u043d\u043e \u0443\u0437\u0440\u0435\u043b\u0438 \u043f\u0440\u0438\u0437\u0440\u0430\u043a\u0430.","\u0410\u043b \u0442\u0430\u04a3 \u0430\u0442\u049b\u0430\u043d\u0434\u0430, \u0448\u0430\u043b \u043a\u0435\u0440\u0456\u043b\u0456\u043f-\u0441\u043e\u0437\u044b\u043b\u044b\u043f, \u0442\u0430\u04a3\u0493\u044b \u043a\u04af\u043d\u0433\u0435 \u0435\u0441\u0456\u043d\u0435\u043f, \u0430\u043c\u0430\u043d-\u0435\u0441\u0435\u043d \u0448\u044b\u0493\u0430 \u043a\u0435\u043b\u0434\u0456. \u0414\u04d9\u0443\u043b\u0435\u0440 \u0435\u043b\u0435\u0441 \u043a\u04e9\u0440\u0433\u0435\u043d\u0434\u0435\u0439 \u0430\u04a3\u044b\u0440\u044b\u043f \u049b\u0430\u043b\u0434\u044b.")},
     {dialog:[{who:"qanbaq",em:"gentle",line:L("Aah, I slept poorly, friends. In the night some little flea \u2014 or a falling leaf, perhaps \u2014 kept flicking at my cheek. A trifle. Otherwise, a fine night. My thanks for the soft bed.","\u042d\u0445, \u043f\u043b\u043e\u0445\u043e \u044f \u0441\u043f\u0430\u043b, \u0434\u0440\u0443\u0437\u044c\u044f. \u041d\u043e\u0447\u044c\u044e \u043a\u0430\u043a\u0430\u044f-\u0442\u043e \u0431\u043b\u043e\u0448\u043a\u0430 \u2014 \u0438\u043b\u0438, \u043c\u043e\u0436\u0435\u0442, \u043f\u0430\u043b\u044b\u0439 \u043b\u0438\u0441\u0442 \u2014 \u0432\u0441\u0451 \u0449\u0435\u043a\u043e\u0442\u0430\u043b\u0430 \u043c\u043d\u0435 \u0449\u0451\u043a\u0443. \u041f\u0443\u0441\u0442\u044f\u043a. \u0410 \u0432 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u043e\u043c \u2014 \u0441\u043b\u0430\u0432\u043d\u0430\u044f \u043d\u043e\u0447\u044c. \u0421\u043f\u0430\u0441\u0438\u0431\u043e \u0437\u0430 \u043c\u044f\u0433\u043a\u0443\u044e \u043f\u043e\u0441\u0442\u0435\u043b\u044c.","\u0410\u04bb, \u043d\u0430\u0448\u0430\u0440 \u04b1\u0439\u044b\u049b\u0442\u0430\u0434\u044b\u043c, \u0434\u043e\u0441\u0442\u0430\u0440. \u0422\u04af\u043d\u0434\u0435 \u0431\u0456\u0440 \u0431\u04af\u0440\u0433\u0435 \u043c\u0435 \u2014 \u04d9\u043b\u0434\u0435 \u0442\u04af\u0441\u043a\u0435\u043d \u0436\u0430\u043f\u044b\u0440\u0430\u049b \u043f\u0430 \u2014 \u0431\u0435\u0442\u0456\u043c\u0434\u0456 \u0448\u044b\u043c\u0448\u044b\u043b\u0430\u043f \u043c\u0430\u0437\u0430\u043b\u0430\u0434\u044b. \u0422\u04af\u043a\u043a\u0435 \u0442\u04b1\u0440\u043c\u0430\u0439\u0434\u044b. \u04d8\u0439\u0442\u043f\u0435\u0441\u0435, \u0442\u0430\u043c\u0430\u0448\u0430 \u0442\u04af\u043d \u0431\u043e\u043b\u0434\u044b. \u0416\u04b1\u043c\u0441\u0430\u049b \u0442\u04e9\u0441\u0435\u043a\u043a\u0435 \u0440\u0430\u0445\u043c\u0435\u0442.")},{who:"dau",em:"afraid",line:L("(whispering) A boulder the size of a yurt\u2026 and he felt only a flea\u2026","(\u0448\u0451\u043f\u043e\u0442\u043e\u043c) \u0412\u0430\u043b\u0443\u043d \u0440\u0430\u0437\u043c\u0435\u0440\u043e\u043c \u0441 \u044e\u0440\u0442\u0443\u2026 \u0430 \u043e\u043d \u043f\u043e\u0447\u0443\u044f\u043b \u043b\u0438\u0448\u044c \u0431\u043b\u043e\u0445\u0443\u2026","(\u0441\u044b\u0431\u044b\u0440\u043b\u0430\u043f) \u041a\u0438\u0456\u0437 \u04af\u0439\u0434\u0435\u0439 \u0442\u0430\u0441\u2026 \u0430\u043b \u043e\u043b \u0431\u0430\u0440 \u0431\u043e\u043b\u0493\u0430\u043d\u044b \u0431\u04af\u0440\u0433\u0435\u043d\u0456 \u0441\u0435\u0437\u0434\u0456\u2026")}]}
   ]},
  {title:L("Gold, and the Way Home","\u0417\u043e\u043b\u043e\u0442\u043e \u0438 \u0434\u043e\u0440\u043e\u0433\u0430 \u0434\u043e\u043c\u043e\u0439","\u0410\u043b\u0442\u044b\u043d \u0436\u04d9\u043d\u0435 \u04af\u0439\u0433\u0435 \u049b\u0430\u0439\u0442\u0443"), scene:"home", obj:L("Win the giants' gold and see them off for good","\u0414\u043e\u0431\u0443\u0434\u044c \u0437\u043e\u043b\u043e\u0442\u043e \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u043e\u0432 \u0438 \u0441\u043f\u0440\u043e\u0432\u0430\u0434\u044c \u0438\u0445 \u043d\u0430\u0432\u0441\u0435\u0433\u0434\u0430","\u0414\u04d9\u0443\u043b\u0435\u0440\u0434\u0456\u04a3 \u0430\u043b\u0442\u044b\u043d\u044b\u043d \u04b1\u0442\u044b\u043f \u0430\u043b \u0434\u0430, \u043e\u043b\u0430\u0440\u0434\u044b \u043c\u04d9\u04a3\u0433\u0456\u0433\u0435 \u049b\u0443\u044b\u043f \u0436\u0456\u0431\u0435\u0440"),
   beats:[
     {dialog:[{who:"elder",em:"pleading",line:L("Honoured guest \u2014 great one \u2014 we have kept you far too long from your home. Take this. Take all of it, with our blessing, and go in peace.","\u041f\u043e\u0447\u0442\u0435\u043d\u043d\u044b\u0439 \u0433\u043e\u0441\u0442\u044c \u2014 \u0432\u0435\u043b\u0438\u043a\u0438\u0439 \u2014 \u043c\u044b \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0434\u043e\u043b\u0433\u043e \u0434\u0435\u0440\u0436\u0430\u043b\u0438 \u0442\u0435\u0431\u044f \u0432\u0434\u0430\u043b\u0438 \u043e\u0442 \u0434\u043e\u043c\u0430. \u0412\u043e\u0437\u044c\u043c\u0438 \u044d\u0442\u043e. \u0412\u043e\u0437\u044c\u043c\u0438 \u0432\u0441\u0451, \u0441 \u043d\u0430\u0448\u0438\u043c \u0431\u043b\u0430\u0433\u043e\u0441\u043b\u043e\u0432\u0435\u043d\u0438\u0435\u043c, \u0438 \u0441\u0442\u0443\u043f\u0430\u0439 \u0441 \u043c\u0438\u0440\u043e\u043c.","\u049a\u0430\u0434\u0456\u0440\u043b\u0456 \u049b\u043e\u043d\u0430\u049b \u2014 \u04b1\u043b\u044b \u0436\u0430\u043d \u2014 \u0441\u0435\u043d\u0456 \u04af\u0439\u0456\u04a3\u043d\u0435\u043d \u0442\u044b\u043c \u04b1\u0437\u0430\u049b \u0430\u043b\u044b\u043f \u049b\u0430\u043b\u0434\u044b\u049b. \u041c\u044b\u043d\u0430\u043d\u044b \u0430\u043b. \u0411\u0430\u0442\u0430\u043c\u044b\u0437\u0431\u0435\u043d \u0431\u04d9\u0440\u0456\u043d \u0430\u043b \u0434\u0430, \u0430\u043c\u0430\u043d-\u0435\u0441\u0435\u043d \u049b\u0430\u0439\u0442.")}]},
     {narr:L("The giants heaped up a great sack of gold and silver \u2014 more treasure than the old man had seen in all his days \u2014 and, because he was 'too mighty to trouble with a load,' a young giant hoisted the sack himself and carried it all the long way back across the steppe to the old man's little hut.","\u0412\u0435\u043b\u0438\u043a\u0430\u043d\u044b \u043d\u0430\u0432\u0430\u043b\u0438\u043b\u0438 \u0431\u043e\u043b\u044c\u0448\u043e\u0439 \u043c\u0435\u0448\u043e\u043a \u0437\u043e\u043b\u043e\u0442\u0430 \u0438 \u0441\u0435\u0440\u0435\u0431\u0440\u0430 \u2014 \u0431\u043e\u043b\u044c\u0448\u0435 \u0441\u043e\u043a\u0440\u043e\u0432\u0438\u0449, \u0447\u0435\u043c \u0441\u0442\u0430\u0440\u0438\u043a \u0432\u0438\u0434\u0435\u043b \u0437\u0430 \u0432\u0441\u044e \u0436\u0438\u0437\u043d\u044c, \u2014 \u0438, \u043f\u043e\u0441\u043a\u043e\u043b\u044c\u043a\u0443 \u043e\u043d \u0431\u044b\u043b \u00ab\u0441\u043b\u0438\u0448\u043a\u043e\u043c \u043c\u043e\u0433\u0443\u0447, \u0447\u0442\u043e\u0431\u044b \u0432\u043e\u0437\u0438\u0442\u044c\u0441\u044f \u0441 \u043d\u043e\u0448\u0435\u0439\u00bb, \u043c\u043e\u043b\u043e\u0434\u043e\u0439 \u0432\u0435\u043b\u0438\u043a\u0430\u043d \u0441\u0430\u043c \u0432\u0437\u0432\u0430\u043b\u0438\u043b \u043c\u0435\u0448\u043e\u043a \u0438 \u043f\u043e\u043d\u0451\u0441 \u0447\u0435\u0440\u0435\u0437 \u0432\u0441\u044e \u0441\u0442\u0435\u043f\u044c \u043a \u0434\u043e\u043c\u0438\u0448\u043a\u0443 \u0441\u0442\u0430\u0440\u0438\u043a\u0430.","\u0414\u04d9\u0443\u043b\u0435\u0440 \u0431\u0456\u0440 \u049b\u0430\u043f \u0430\u043b\u0442\u044b\u043d-\u043a\u04af\u043c\u0456\u0441 \u04af\u0439\u0456\u043f \u049b\u043e\u0439\u0434\u044b \u2014 \u0448\u0430\u043b\u0434\u044b\u04a3 \u04e9\u043c\u0456\u0440\u0456\u043d\u0434\u0435 \u043a\u04e9\u0440\u043c\u0435\u0433\u0435\u043d \u049b\u0430\u0437\u044b\u043d\u0430\u0441\u044b, \u2014 \u00ab\u0436\u04af\u043a \u043a\u04e9\u0442\u0435\u0440\u0443\u0433\u0435 \u0442\u044b\u043c \u04b1\u043b\u044b\u00bb \u0431\u043e\u043b\u0493\u0430\u043d\u0434\u044b\u049b\u0442\u0430\u043d, \u0431\u0456\u0440 \u0436\u0430\u0441 \u0434\u04d9\u0443 \u049b\u0430\u043f\u0442\u044b \u04e9\u0437\u0456 \u0430\u0440\u049b\u0430\u043b\u0430\u043f, \u0434\u0430\u043b\u0430 \u0430\u0441\u044b\u043f, \u0448\u0430\u043b\u0434\u044b\u04a3 \u043a\u0456\u0448\u043a\u0435\u043d\u0442\u0430\u0439 \u0430\u043b\u0430\u0448\u044b\u0493\u044b\u043d\u0430 \u0434\u0435\u0439\u0456\u043d \u043a\u04e9\u0442\u0435\u0440\u0456\u043f \u0431\u0430\u0440\u0434\u044b.")},
     {narr:L("As they drew near, the old man's small grandchild spotted them from the doorway and came running, hungry and delighted at the sight of the enormous stranger.","\u041a\u043e\u0433\u0434\u0430 \u043e\u043d\u0438 \u043f\u043e\u0434\u043e\u0448\u043b\u0438, \u043c\u0430\u043b\u0435\u043d\u044c\u043a\u0438\u0439 \u0432\u043d\u0443\u0447\u0435\u043a \u0441\u0442\u0430\u0440\u0438\u043a\u0430 \u0437\u0430\u043c\u0435\u0442\u0438\u043b \u0438\u0445 \u0441 \u043f\u043e\u0440\u043e\u0433\u0430 \u0438 \u0432\u044b\u0431\u0435\u0436\u0430\u043b \u043d\u0430\u0432\u0441\u0442\u0440\u0435\u0447\u0443, \u0433\u043e\u043b\u043e\u0434\u043d\u044b\u0439 \u0438 \u043e\u0431\u0440\u0430\u0434\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u043f\u0440\u0438 \u0432\u0438\u0434\u0435 \u0433\u0440\u043e\u043c\u0430\u0434\u043d\u043e\u0433\u043e \u0447\u0443\u0436\u0430\u043a\u0430.","\u041e\u043b\u0430\u0440 \u0436\u0430\u049b\u044b\u043d\u0434\u0430\u0493\u0430\u043d\u0434\u0430, \u0448\u0430\u043b\u0434\u044b\u04a3 \u043a\u0456\u0448\u043a\u0435\u043d\u0442\u0430\u0439 \u043d\u0435\u043c\u0435\u0440\u0435\u0441\u0456 \u043e\u043b\u0430\u0440\u0434\u044b \u0435\u0441\u0456\u043a \u0430\u043b\u0434\u044b\u043d\u0430\u043d \u043a\u04e9\u0440\u0456\u043f, \u0430\u0448 \u04d9\u0440\u0456 \u0430\u043b\u044b\u043f \u0431\u0435\u0439\u0442\u0430\u043d\u044b\u0441\u0442\u0430\u043d \u049b\u0443\u0430\u043d\u044b\u043f, \u0436\u04af\u0433\u0456\u0440\u0456\u043f \u0448\u044b\u049b\u0442\u044b.")},
     {dialog:[{who:"bala",em:"warm",line:L("Grandfather! Grandfather! You've brought us a giant! Are we going to EAT him? I'm so hungry \u2014 is it giant-meat for supper tonight?","\u0414\u0435\u0434\u0443\u0448\u043a\u0430! \u0414\u0435\u0434\u0443\u0448\u043a\u0430! \u0422\u044b \u043f\u0440\u0438\u043d\u0451\u0441 \u043d\u0430\u043c \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u0430! \u041c\u044b \u0435\u0433\u043e \u0421\u042a\u0415\u0414\u0418\u041c? \u042f \u0442\u0430\u043a \u0433\u043e\u043b\u043e\u0434\u0435\u043d \u2014 \u043d\u0430 \u0443\u0436\u0438\u043d \u0441\u0435\u0433\u043e\u0434\u043d\u044f \u043c\u044f\u0441\u043e \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u0430?","\u0410\u0442\u0430! \u0410\u0442\u0430! \u0411\u0456\u0437\u0433\u0435 \u0434\u04d9\u0443 \u04d9\u043a\u0435\u043b\u0434\u0456\u04a3 \u0431\u0435?! \u041e\u043d\u044b \u0416\u0415\u0419\u041c\u0406\u0417 \u0431\u0435? \u049a\u0430\u0440\u043d\u044b\u043c \u0430\u0448\u044b\u043f \u0442\u04b1\u0440 \u2014 \u0431\u04af\u0433\u0456\u043d \u043a\u0435\u0448\u043a\u0456\u0433\u0435 \u0434\u04d9\u0443\u0434\u0456\u04a3 \u0435\u0442\u0456 \u043c\u0435?")},{who:"qanbaq",em:"sly",line:L("Patience, little one! Yes \u2014 this one looks plump and tender. Sharpen the big knife; we'll feast on giant tonight, and salt the rest for winter.","\u0422\u0435\u0440\u043f\u0435\u043d\u0438\u0435, \u043c\u0430\u043b\u044b\u0448! \u0414\u0430 \u2014 \u044d\u0442\u043e\u0442-\u0442\u043e \u0443\u043f\u0438\u0442\u0430\u043d\u043d\u044b\u0439 \u0434\u0430 \u043d\u0435\u0436\u043d\u044b\u0439. \u0422\u043e\u0447\u0438 \u0431\u043e\u043b\u044c\u0448\u043e\u0439 \u043d\u043e\u0436; \u043d\u044b\u043d\u0447\u0435 \u043f\u0438\u0440\u0443\u0435\u043c \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u043e\u043c, \u0430 \u043e\u0441\u0442\u0430\u043b\u044c\u043d\u043e\u0435 \u0437\u0430\u0441\u043e\u043b\u0438\u043c \u043d\u0430 \u0437\u0438\u043c\u0443.","\u0421\u0430\u0431\u044b\u0440, \u0431\u0430\u043b\u0430\u043c! \u0418\u04d9 \u2014 \u043c\u044b\u043d\u0430\u0443 \u0442\u043e\u043b\u044b\u049b \u04d9\u0440\u0456 \u0436\u04b1\u043c\u0441\u0430\u049b \u043a\u04e9\u0440\u0456\u043d\u0435\u0434\u0456. \u04ae\u043b\u043a\u0435\u043d \u043f\u044b\u0448\u0430\u049b\u0442\u044b \u049b\u0430\u0439\u0440\u0430; \u0431\u04af\u0433\u0456\u043d \u0434\u04d9\u0443\u0434\u0456\u04a3 \u0435\u0442\u0456\u043d\u0435 \u0442\u043e\u0439\u044b\u043f, \u049b\u0430\u043b\u0493\u0430\u043d\u044b\u043d \u049b\u044b\u0441\u049b\u0430 \u0442\u04b1\u0437\u0434\u0430\u0439\u043c\u044b\u0437.")}]},
     {dialog:[{who:"jasdau",em:"fierce",line:L("EAT me?! These little people EAT giants?!","\u0421\u042a\u0415\u0421\u0422\u042c \u043c\u0435\u043d\u044f?! \u042d\u0442\u0438 \u043c\u0430\u043b\u044f\u0432\u043a\u0438 \u0415\u0414\u042f\u0422 \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u043e\u0432?!","\u041c\u0435\u043d\u0456 \u0416\u0415\u0419 \u043c\u0435?! \u041c\u044b\u043d\u0430 \u043a\u0456\u0448\u043a\u0435\u043d\u0442\u0430\u0439\u043b\u0430\u0440 \u0434\u04d9\u0443\u0434\u0456 \u0416\u0415\u0419 \u043c\u0435?!")}]},
     {narr:L("The young giant flung down the sack of gold, spun on his heel, and fled howling over the hills \u2014 and neither he nor any of his kin was ever seen in that country again.","\u041c\u043e\u043b\u043e\u0434\u043e\u0439 \u0432\u0435\u043b\u0438\u043a\u0430\u043d \u0448\u0432\u044b\u0440\u043d\u0443\u043b \u043c\u0435\u0448\u043e\u043a \u0441 \u0437\u043e\u043b\u043e\u0442\u043e\u043c, \u0440\u0430\u0437\u0432\u0435\u0440\u043d\u0443\u043b\u0441\u044f \u0438 \u0441 \u0432\u043e\u0435\u043c \u0443\u043c\u0447\u0430\u043b\u0441\u044f \u0437\u0430 \u0445\u043e\u043b\u043c\u044b \u2014 \u0438 \u043d\u0438 \u0435\u0433\u043e, \u043d\u0438 \u0440\u043e\u0434\u043d\u0438 \u0435\u0433\u043e \u0431\u043e\u043b\u044c\u0448\u0435 \u0432 \u0442\u0435\u0445 \u043a\u0440\u0430\u044f\u0445 \u043d\u0435 \u0432\u0438\u0434\u0435\u043b\u0438.","\u0416\u0430\u0441 \u0434\u04d9\u0443 \u0430\u043b\u0442\u044b\u043d \u049b\u0430\u043f\u0442\u044b \u043b\u0430\u049b\u0442\u044b\u0440\u044b\u043f \u0442\u0430\u0441\u0442\u0430\u043f, \u043a\u0435\u0440\u0456 \u0431\u04b1\u0440\u044b\u043b\u044b\u043f, \u04b1\u043b\u0430\u0440\u0434\u0430\u0439 \u04b1\u043b\u044b\u043f, \u0442\u04e9\u0431\u0435\u043b\u0435\u0440\u0434\u0435\u043d \u0430\u0441\u044b\u043f \u049b\u0430\u0448\u0442\u044b \u2014 \u0441\u043e\u0434\u0430\u043d \u043e\u043d\u044b \u0434\u0430, \u043e\u043d\u044b\u04a3 \u0430\u0493\u0430\u0439\u044b\u043d\u0434\u0430\u0440\u044b\u043d \u0434\u0430 \u043e\u043b \u04e9\u043b\u043a\u0435\u0434\u0435 \u049b\u0430\u0439\u0442\u044b\u043f \u0435\u0448\u043a\u0456\u043c \u043a\u04e9\u0440\u043c\u0435\u043f\u0442\u0456.")},
     {narr:L("And so Qa\u00f1baq Shal \u2014 the poor old man so light the wind once rolled him away \u2014 carried his gold inside and lived out his long days rich, warm and merry, with his grandchild on his knee. For the strong may shake the mountains, but it is the clever heart, and the kind one, that carries the day.","\u0422\u0430\u043a \u041a\u0430\u0144\u0431\u0430\u043a-\u0448\u0430\u043b \u2014 \u0431\u0435\u0434\u043d\u044b\u0439 \u0441\u0442\u0430\u0440\u0438\u043a, \u0441\u0442\u043e\u043b\u044c \u043b\u0451\u0433\u043a\u0438\u0439, \u0447\u0442\u043e \u0432\u0435\u0442\u0435\u0440 \u043a\u043e\u0433\u0434\u0430-\u0442\u043e \u043a\u0430\u0442\u0438\u043b \u0435\u0433\u043e \u043f\u0440\u043e\u0447\u044c, \u2014 \u0432\u043d\u0451\u0441 \u0437\u043e\u043b\u043e\u0442\u043e \u0432 \u0434\u043e\u043c \u0438 \u0434\u043e\u0436\u0438\u043b \u0441\u0432\u043e\u0438 \u0434\u043e\u043b\u0433\u0438\u0435 \u0434\u043d\u0438 \u0432 \u0434\u043e\u0441\u0442\u0430\u0442\u043a\u0435, \u0442\u0435\u043f\u043b\u0435 \u0438 \u0440\u0430\u0434\u043e\u0441\u0442\u0438, \u0441 \u0432\u043d\u0443\u043a\u043e\u043c \u043d\u0430 \u043a\u043e\u043b\u0435\u043d\u044f\u0445. \u0418\u0431\u043e \u0441\u0438\u043b\u044c\u043d\u044b\u0439 \u0441\u043e\u0442\u0440\u044f\u0441\u0430\u0435\u0442 \u0433\u043e\u0440\u044b, \u043d\u043e \u0434\u0435\u043d\u044c \u0432\u044b\u0438\u0433\u0440\u044b\u0432\u0430\u0435\u0442 \u0441\u0435\u0440\u0434\u0446\u0435 \u0443\u043c\u043d\u043e\u0435 \u0438 \u0434\u043e\u0431\u0440\u043e\u0435.","\u0421\u04e9\u0439\u0442\u0456\u043f \u049a\u0430\u04a3\u0431\u0430\u049b \u0448\u0430\u043b \u2014 \u0436\u0435\u043b \u0431\u0456\u0440 \u043a\u0435\u0437\u0434\u0435\u0440\u0456 \u0434\u043e\u043c\u0430\u043b\u0430\u0442\u044b\u043f \u04d9\u043a\u0435\u0442\u043a\u0435\u043d \u043a\u0435\u0434\u0435\u0439 \u0448\u0430\u043b \u2014 \u0430\u043b\u0442\u044b\u043d\u044b\u043d \u04af\u0439\u0456\u043d\u0435 \u043a\u0456\u0440\u0433\u0456\u0437\u0456\u043f, \u043d\u0435\u043c\u0435\u0440\u0435\u0441\u0456\u043d \u0442\u0456\u0437\u0435\u0441\u0456\u043d\u0435 \u043e\u0442\u044b\u0440\u0493\u044b\u0437\u044b\u043f, \u0434\u04d9\u0443\u043b\u0435\u0442\u0442\u0456, \u0436\u044b\u043b\u044b, \u043a\u04e9\u04a3\u0456\u043b\u0434\u0456 \u04b1\u0437\u0430\u049b \u0493\u04b1\u043c\u044b\u0440 \u043a\u0435\u0448\u0456\u043f\u0442\u0456. \u041a\u04af\u0448\u0442\u0456 \u0442\u0430\u0443\u043b\u0430\u0440 \u0448\u0430\u0439\u049b\u0430\u0440, \u0431\u0456\u0440\u0430\u049b \u043a\u04af\u043d\u0434\u0456 \u0430\u049b\u044b\u043b\u0434\u044b \u04d9\u0440\u0456 \u043c\u0435\u0439\u0456\u0440\u0456\u043c\u0434\u0456 \u0436\u04af\u0440\u0435\u043a \u04b1\u0442\u0430\u0434\u044b.")}
   ]}
  ]},
 "dau":{ ending:{title:L("Bested by a Wisp of a Man","\u041f\u043e\u0431\u0435\u0436\u0434\u0451\u043d \u0431\u044b\u043b\u0438\u043d\u043a\u043e\u0439-\u0447\u0435\u043b\u043e\u0432\u0435\u043a\u043e\u043c","\u0411\u0456\u0440 \u0443\u044b\u0441 \u0448\u0430\u043b\u0434\u0430\u043d \u0436\u0435\u04a3\u0456\u043b\u0434\u0456\u043c"),text:L("You could shake the mountains, yet a wisp of an old man emptied your camp of its gold and its courage \u2014 for wit topples what no fist can. Perhaps, next time, you will listen before you boast.","\u0422\u044b \u0441\u043e\u0442\u0440\u044f\u0441\u0430\u043b \u0433\u043e\u0440\u044b, \u043d\u043e \u0431\u044b\u043b\u0438\u043d\u043a\u0430-\u0441\u0442\u0430\u0440\u0438\u043a \u0432\u044b\u0433\u0440\u0435\u0431 \u0438\u0437 \u0442\u0432\u043e\u0435\u0433\u043e \u0441\u0442\u0430\u043d\u0430 \u0438 \u0437\u043e\u043b\u043e\u0442\u043e, \u0438 \u0445\u0440\u0430\u0431\u0440\u043e\u0441\u0442\u044c \u2014 \u0432\u0435\u0434\u044c \u0443\u043c \u0432\u0430\u043b\u0438\u0442 \u0442\u043e, \u0447\u0442\u043e \u043d\u0435 \u043f\u043e\u0434 \u0441\u0438\u043b\u0443 \u043a\u0443\u043b\u0430\u043a\u0443. \u0411\u044b\u0442\u044c \u043c\u043e\u0436\u0435\u0442, \u0432\u043f\u0440\u0435\u0434\u044c \u0442\u044b \u0432\u044b\u0441\u043b\u0443\u0448\u0430\u0435\u0448\u044c, \u043f\u0440\u0435\u0436\u0434\u0435 \u0447\u0435\u043c \u0445\u0432\u0430\u0441\u0442\u0430\u0442\u044c.","\u0421\u0435\u043d \u0442\u0430\u0443\u043b\u0430\u0440\u0434\u044b \u0448\u0430\u0439\u049b\u0430\u0434\u044b\u04a3, \u0431\u0456\u0440\u0430\u049b \u0431\u0456\u0440 \u0443\u044b\u0441 \u0448\u0430\u043b \u0430\u0443\u044b\u043b\u044b\u04a3\u043d\u044b\u04a3 \u0434\u0430 \u0430\u043b\u0442\u044b\u043d\u044b\u043d, \u0434\u0430 \u0431\u0430\u0442\u044b\u043b\u0434\u044b\u0493\u044b\u043d \u04d9\u043a\u0435\u0442\u0442\u0456 \u2014 \u0430\u049b\u044b\u043b \u0436\u04b1\u0434\u044b\u0440\u044b\u049b \u0436\u0435\u04a3\u0431\u0435\u0433\u0435\u043d\u0434\u0456 \u0436\u0435\u04a3\u0435\u0434\u0456. \u0411\u04d9\u043b\u043a\u0456\u043c, \u043a\u0435\u043b\u0435\u0441\u0456\u0434\u0435 \u043c\u0430\u049b\u0442\u0430\u043d\u0431\u0430\u0441 \u0431\u04b1\u0440\u044b\u043d \u0442\u044b\u04a3\u0434\u0430\u0440\u0441\u044b\u04a3.")},
  chapters:[
  {title:L("A Contest of Strength","\u0421\u043e\u0441\u0442\u044f\u0437\u0430\u043d\u0438\u0435 \u0432 \u0441\u0438\u043b\u0435","\u041a\u04af\u0448 \u0441\u044b\u043d\u0430\u0441\u0443"), scene:"mountains", obj:L("Challenge the tiny old man to a test of strength","\u0412\u044b\u0437\u043e\u0432\u0438 \u043a\u0440\u043e\u0445\u043e\u0442\u043d\u043e\u0433\u043e \u0441\u0442\u0430\u0440\u0438\u043a\u0430 \u043f\u043e\u043c\u0435\u0440\u0438\u0442\u044c\u0441\u044f \u0441\u0438\u043b\u043e\u0439","\u041a\u0456\u0448\u043a\u0435\u043d\u0442\u0430\u0439 \u0448\u0430\u043b\u0434\u044b \u043a\u04af\u0448 \u0441\u044b\u043d\u0430\u0441\u0443\u0493\u0430 \u0448\u0430\u049b\u044b\u0440"),
   beats:[
     {narr:L("You are a giant of the steppe, and there is nothing in the world you love better than smashing two mountains together to watch the sparks fly. Then one windy day a tiny old man came rolling into your valley like a ball of dry grass.","\u0422\u044b \u2014 \u0432\u0435\u043b\u0438\u043a\u0430\u043d \u0441\u0442\u0435\u043f\u0435\u0439, \u0438 \u043d\u0435\u0442 \u0434\u043b\u044f \u0442\u0435\u0431\u044f \u0440\u0430\u0434\u043e\u0441\u0442\u0438 \u0441\u043b\u0430\u0449\u0435, \u0447\u0435\u043c \u0431\u0438\u0442\u044c \u0434\u0432\u0435 \u0433\u043e\u0440\u044b \u0434\u0440\u0443\u0433 \u043e \u0434\u0440\u0443\u0433\u0430, \u043b\u044e\u0431\u0443\u044f\u0441\u044c \u0438\u0441\u043a\u0440\u0430\u043c\u0438. \u0418 \u0432\u043e\u0442 \u0432 \u0432\u0435\u0442\u0440\u0435\u043d\u044b\u0439 \u0434\u0435\u043d\u044c \u0432 \u0442\u0432\u043e\u044e \u0434\u043e\u043b\u0438\u043d\u0443 \u0432\u043a\u0430\u0442\u0438\u043b\u0441\u044f \u043a\u0440\u043e\u0445\u043e\u0442\u043d\u044b\u0439 \u0441\u0442\u0430\u0440\u0438\u043a, \u0442\u043e\u0447\u043d\u043e \u043a\u043b\u0443\u0431\u043e\u043a \u0441\u0443\u0445\u043e\u0439 \u0442\u0440\u0430\u0432\u044b.","\u0421\u0435\u043d \u2014 \u0434\u0430\u043b\u0430 \u0434\u04d9\u0443\u0456\u0441\u0456\u04a3, \u0434\u04af\u043d\u0438\u0435\u0434\u0435 \u0435\u043a\u0456 \u0442\u0430\u0443\u0434\u044b \u0441\u043e\u0493\u044b\u0441\u0442\u044b\u0440\u044b\u043f, \u04b1\u0448\u049b\u044b\u043d\u044b\u043d\u0430 \u049b\u0430\u0440\u0430\u0443\u0434\u0430\u043d \u0430\u0441\u049b\u0430\u043d \u0440\u0430\u0445\u0430\u0442 \u0436\u043e\u049b \u0441\u0430\u0493\u0430\u043d. \u0411\u0456\u0440 \u0436\u0435\u043b\u0434\u0456 \u043a\u04af\u043d\u0456 \u0430\u04a3\u0493\u0430\u0440\u044b\u04a3\u0430 \u049b\u0430\u04a3\u0431\u0430\u049b\u0442\u0430\u0439 \u0434\u043e\u043c\u0430\u043b\u0430\u043f \u043a\u0456\u0448\u043a\u0435\u043d\u0442\u0430\u0439 \u0448\u0430\u043b \u043a\u0456\u0440\u0456\u043f \u043a\u0435\u043b\u0434\u0456.")},
     {dialog:[{who:"dau",em:"boast",line:L("Ho! Where are you bound, little old man? Come \u2014 let the two of us test our strength! Watch: I throw this boulder to the sky and catch it. Now you.","\u0425\u043e! \u041a\u0443\u0434\u0430 \u043f\u0443\u0442\u044c \u0434\u0435\u0440\u0436\u0438\u0448\u044c, \u0441\u0442\u0430\u0440\u0438\u0447\u043e\u043a? \u0410 \u043d\u0443 \u2014 \u043f\u043e\u043c\u0435\u0440\u0438\u043c\u0441\u044f \u0441\u0438\u043b\u043e\u0439! \u0413\u043b\u044f\u0434\u0438: \u043f\u043e\u0434\u0431\u0440\u043e\u0448\u0443 \u044d\u0442\u043e\u0442 \u0432\u0430\u043b\u0443\u043d \u0434\u043e \u043d\u0435\u0431\u0430 \u0438 \u043f\u043e\u0439\u043c\u0430\u044e. \u0422\u0435\u043f\u0435\u0440\u044c \u0442\u044b.","\u04ba\u0435! \u049a\u0430\u0439\u0434\u0430 \u0431\u0430\u0440\u0430 \u0436\u0430\u0442\u049b\u0430\u043d \u0448\u0430\u043b\u0441\u044b\u04a3? \u041a\u0435\u043b, \u043a\u04af\u0448 \u0441\u044b\u043d\u0430\u0441\u0430\u0439\u044b\u049b! \u049a\u0430\u0440\u0430: \u043c\u044b\u043d\u0430 \u0442\u0430\u0441\u0442\u044b \u0430\u0441\u043f\u0430\u043d\u0493\u0430 \u043b\u0430\u049b\u0442\u044b\u0440\u044b\u043f, \u049b\u0430\u0493\u044b\u043f \u0430\u043b\u0430\u043c\u044b\u043d. \u0415\u043d\u0434\u0456 \u0441\u0435\u043d.")},{who:"qanbaq",em:"wise",line:L("I dare not. Throw it too hard, and the sky will crack and fall. Miss the catch, and it holes the earth clean through. I am sparing us both.","\u041d\u0435 \u0441\u043c\u0435\u044e. \u0411\u0440\u043e\u0441\u044c \u0441\u043b\u0438\u0448\u043a\u043e\u043c \u0441\u0438\u043b\u044c\u043d\u043e \u2014 \u043d\u0435\u0431\u043e \u0442\u0440\u0435\u0441\u043d\u0435\u0442 \u0438 \u0440\u0443\u0445\u043d\u0435\u0442. \u041d\u0435 \u043f\u043e\u0439\u043c\u0430\u0435\u0448\u044c \u2014 \u043f\u0440\u043e\u0431\u044c\u0451\u0442 \u0437\u0435\u043c\u043b\u044e \u043d\u0430\u0441\u043a\u0432\u043e\u0437\u044c. \u042f \u0431\u0435\u0440\u0435\u0433\u0443 \u043d\u0430\u0441 \u043e\u0431\u043e\u0438\u0445.","\u0411\u0430\u0442\u044b\u043b\u044b\u043c \u0431\u0430\u0440\u043c\u0430\u0439\u0434\u044b. \u049a\u0430\u0442\u0442\u044b \u043b\u0430\u049b\u0442\u044b\u0440\u0441\u0430\u043c, \u0430\u0441\u043f\u0430\u043d \u0436\u0430\u0440\u044b\u043b\u044b\u043f \u049b\u04b1\u043b\u0430\u0439\u0434\u044b. \u04b0\u0441\u0442\u0430\u0439 \u0430\u043b\u043c\u0430\u0441\u0430\u043c, \u0436\u0435\u0440\u0434\u0456 \u0442\u0435\u0441\u0456\u043f \u04e9\u0442\u0435\u0434\u0456. \u0415\u043a\u0435\u0443\u043c\u0456\u0437\u0434\u0456 \u0430\u044f\u043f \u0442\u04b1\u0440\u043c\u044b\u043d.")}]},
     {dialog:[{who:"dau",em:"afraid",line:L("(seizing his hands) Put it down, aksakal! Don't throw it! You'll destroy us all!","(\u0445\u0432\u0430\u0442\u0430\u044f \u0435\u0433\u043e \u0437\u0430 \u0440\u0443\u043a\u0438) \u041e\u043f\u0443\u0441\u0442\u0438, \u0430\u043a\u0441\u0430\u043a\u0430\u043b! \u041d\u0435 \u0431\u0440\u043e\u0441\u0430\u0439! \u0422\u044b \u0432\u0441\u0435\u0445 \u043f\u043e\u0433\u0443\u0431\u0438\u0448\u044c!","(\u049b\u043e\u043b\u044b\u043d\u0430\u043d \u04b1\u0441\u0442\u0430\u0439 \u0430\u043b\u044b\u043f) \u049a\u043e\u0439, \u0430\u049b\u0441\u0430\u049b\u0430\u043b! \u041b\u0430\u049b\u0442\u044b\u0440\u043c\u0430! \u0411\u04d9\u0440\u0456\u043c\u0456\u0437\u0434\u0456 \u049b\u04b1\u0440\u0442\u0430\u0441\u044b\u04a3!")}]}
   ]},
  {title:L("The Guts of the Earth","\u041f\u043e\u0442\u0440\u043e\u0445\u0430 \u0437\u0435\u043c\u043b\u0438","\u0416\u0435\u0440\u0434\u0456\u04a3 \u0456\u0448\u0435\u043a-\u049b\u0430\u0440\u043d\u044b"), scene:"earthtrick", obj:L("Match the old man's terrible earth-magic","\u0421\u0440\u0430\u0432\u043d\u044f\u0439\u0441\u044f \u0441 \u0436\u0443\u0442\u043a\u043e\u0439 \u0437\u0435\u043c\u043b\u044f\u043d\u043e\u0439 \u043c\u0430\u0433\u0438\u0435\u0439 \u0441\u0442\u0430\u0440\u0438\u043a\u0430","\u0428\u0430\u043b\u0434\u044b\u04a3 \u0441\u04b1\u043c\u0434\u044b\u049b \u0436\u0435\u0440 \u0441\u0438\u049b\u044b\u0440\u044b\u043d\u0430 \u0442\u0435\u04a3 \u0442\u04af\u0441"),
   beats:[
     {dialog:[{who:"qanbaq",em:"bold",line:L("Let us see who can pull the guts from the earth!","\u041f\u043e\u0433\u043b\u044f\u0434\u0438\u043c, \u043a\u0442\u043e \u0432\u044b\u0442\u044f\u043d\u0435\u0442 \u0438\u0437 \u0437\u0435\u043c\u043b\u0438 \u043f\u043e\u0442\u0440\u043e\u0445\u0430!","\u041a\u04d9\u043d\u0435, \u0436\u0435\u0440\u0434\u0456\u04a3 \u0456\u0448\u0435\u043a-\u049b\u0430\u0440\u043d\u044b\u043d \u043a\u0456\u043c \u0448\u044b\u0493\u0430\u0440\u0430\u0440 \u0435\u043a\u0435\u043d!")}]},
     {narr:L("You stamp with all your monstrous weight \u2014 the ground caves to your knee, but nothing comes. The old man barely taps the earth, and out burst ropes of steaming guts. You stamp again for the brains; again nothing. He taps \u2014 and white brains well up from the ground. Your knees begin to knock.","\u0422\u044b \u0442\u043e\u043f\u0430\u0435\u0448\u044c \u0441\u043e \u0432\u0441\u0435\u0439 \u0447\u0443\u0434\u043e\u0432\u0438\u0449\u043d\u043e\u0439 \u0441\u0438\u043b\u043e\u0439 \u2014 \u0437\u0435\u043c\u043b\u044f \u043f\u0440\u043e\u0441\u0435\u0434\u0430\u0435\u0442 \u043f\u043e \u043a\u043e\u043b\u0435\u043d\u043e, \u043d\u043e \u043f\u0443\u0441\u0442\u043e. \u0421\u0442\u0430\u0440\u0438\u043a \u0435\u0434\u0432\u0430 \u043f\u0440\u0438\u0442\u043e\u043f\u043d\u0443\u043b \u2014 \u0438 \u0432\u044b\u0432\u0430\u043b\u0438\u043b\u0438\u0441\u044c \u0434\u044b\u043c\u044f\u0449\u0438\u0435\u0441\u044f \u043a\u0438\u0448\u043a\u0438. \u0422\u044b \u0442\u043e\u043f\u0430\u0435\u0448\u044c \u0437\u0430 \u043c\u043e\u0437\u0433\u0430\u043c\u0438; \u043e\u043f\u044f\u0442\u044c \u043f\u0443\u0441\u0442\u043e. \u041e\u043d \u043f\u0440\u0438\u0442\u043e\u043f\u043d\u0443\u043b \u2014 \u0438 \u0445\u043b\u044b\u043d\u0443\u043b\u0438 \u0438\u0437 \u0437\u0435\u043c\u043b\u0438 \u0431\u0435\u043b\u044b\u0435 \u043c\u043e\u0437\u0433\u0438. \u041a\u043e\u043b\u0435\u043d\u0438 \u0442\u0432\u043e\u0438 \u0437\u0430\u0442\u0440\u044f\u0441\u043b\u0438\u0441\u044c.","\u0421\u0435\u043d \u0430\u043b\u0430\u043f\u0430\u0442 \u0441\u0430\u043b\u043c\u0430\u0493\u044b\u04a3\u043c\u0435\u043d \u0442\u0435\u0443\u0435\u0441\u0456\u04a3 \u2014 \u0436\u0435\u0440 \u0442\u0456\u0437\u0435\u0434\u0435\u043d \u043e\u0439\u044b\u043b\u0430\u0434\u044b, \u0431\u0456\u0440\u0430\u049b \u0435\u0448\u0442\u0435\u04a3\u0435 \u0436\u043e\u049b. \u0428\u0430\u043b \u0436\u0435\u0440\u0434\u0456 \u04d9\u0440\u0435\u04a3 \u0442\u04af\u0440\u0442\u0435\u0434\u0456 \u2014 \u0431\u0443\u044b \u0431\u04b1\u0440\u049b\u044b\u0440\u0430\u0493\u0430\u043d \u0456\u0448\u0435\u043a-\u049b\u0430\u0440\u044b\u043d \u0430\u0442\u044b\u043b\u044b\u043f \u0448\u044b\u0493\u0430\u0434\u044b. \u041c\u0438\u0434\u044b\u04a3 \u0440\u0435\u0442\u0456\u043d\u0435 \u0442\u0430\u0493\u044b \u0442\u0435\u0443\u0435\u0441\u0456\u04a3; \u0442\u0430\u0493\u044b \u0431\u043e\u0441. \u041e\u043b \u0442\u04af\u0440\u0442\u0435\u0434\u0456 \u2014 \u0436\u0435\u0440\u0434\u0435\u043d \u0430\u043f\u043f\u0430\u049b \u043c\u0438 \u0431\u04b1\u0440\u049b \u0435\u0442\u0435\u0434\u0456. \u0422\u0456\u0437\u0435\u04a3 \u0434\u0456\u0440\u0456\u043b\u0434\u0435\u0439 \u0431\u0430\u0441\u0442\u0430\u0439\u0434\u044b.")},
     {dialog:[{who:"dau",em:"afraid",line:L("What manner of old man is this?! Come home with me, aksakal. Be our honoured guest \u2014 please!","\u0427\u0442\u043e \u044d\u0442\u043e \u0437\u0430 \u0441\u0442\u0430\u0440\u0438\u043a \u0442\u0430\u043a\u043e\u0439?! \u0418\u0434\u0451\u043c \u043a\u043e \u043c\u043d\u0435, \u0430\u043a\u0441\u0430\u043a\u0430\u043b. \u0411\u0443\u0434\u044c \u0434\u043e\u0440\u043e\u0433\u0438\u043c \u0433\u043e\u0441\u0442\u0435\u043c \u2014 \u043f\u0440\u043e\u0448\u0443!","\u041c\u044b\u043d\u0430\u0443 \u049b\u0430\u043d\u0434\u0430\u0439 \u0448\u0430\u043b \u04e9\u0437\u0456?! \u04ae\u0439\u0456\u043c\u0435 \u0436\u04af\u0440, \u0430\u049b\u0441\u0430\u049b\u0430\u043b. \u049a\u0430\u0434\u0456\u0440\u043b\u0456 \u049b\u043e\u043d\u0430\u0493\u044b\u043c \u0431\u043e\u043b \u2014 \u04e9\u0442\u0456\u043d\u0435\u043c\u0456\u043d!")}]}
   ]},
  {title:L("The River and the Forest","\u0420\u0435\u043a\u0430 \u0438 \u043b\u0435\u0441","\u04e8\u0437\u0435\u043d \u043c\u0435\u043d \u043e\u0440\u043c\u0430\u043d"), scene:"river", obj:L("Save your river and your forest from the old man","\u0421\u043f\u0430\u0441\u0438 \u0441\u0432\u043e\u044e \u0440\u0435\u043a\u0443 \u0438 \u043b\u0435\u0441 \u043e\u0442 \u0441\u0442\u0430\u0440\u0438\u043a\u0430","\u04e8\u0437\u0435\u043d\u0456\u04a3\u0434\u0456, \u043e\u0440\u043c\u0430\u043d\u044b\u04a3\u0434\u044b \u0448\u0430\u043b\u0434\u0430\u043d \u0430\u043c\u0430\u043d \u0441\u0430\u049b\u0442\u0430"),
   beats:[
     {narr:L("Back at camp your elder set the old man simple tasks \u2014 fetch water, fetch wood. But the little terror only tried to carry off your whole RIVER, and then to drag home your whole FOREST!","\u0412 \u0441\u0442\u0430\u043d\u0435 \u0441\u0442\u0430\u0440\u0435\u0439\u0448\u0438\u043d\u0430 \u0437\u0430\u0434\u0430\u043b \u0441\u0442\u0430\u0440\u0438\u043a\u0443 \u043f\u0440\u043e\u0441\u0442\u044b\u0435 \u0434\u0435\u043b\u0430 \u2014 \u043f\u0440\u0438\u043d\u0435\u0441\u0442\u0438 \u0432\u043e\u0434\u044b, \u043f\u0440\u0438\u043d\u0435\u0441\u0442\u0438 \u0434\u0440\u043e\u0432. \u041d\u043e \u043a\u0440\u043e\u0448\u0435\u0447\u043d\u043e\u0435 \u0447\u0443\u0434\u0438\u0449\u0435 \u0432\u0437\u0434\u0443\u043c\u0430\u043b\u043e \u0443\u043d\u0435\u0441\u0442\u0438 \u0432\u0441\u044e \u0432\u0430\u0448\u0443 \u0420\u0415\u041a\u0423, \u0430 \u043f\u043e\u0441\u043b\u0435 \u0443\u0432\u043e\u043b\u043e\u0447\u044c \u0432\u0435\u0441\u044c \u0432\u0430\u0448 \u041b\u0415\u0421!","\u0410\u0443\u044b\u043b\u0434\u0430 \u0430\u049b\u0441\u0430\u049b\u0430\u043b\u044b\u04a3 \u0448\u0430\u043b\u0493\u0430 \u043e\u04a3\u0430\u0439 \u0436\u04b1\u043c\u044b\u0441 \u0442\u0430\u043f\u0441\u044b\u0440\u0434\u044b \u2014 \u0441\u0443 \u04d9\u043a\u0435\u043b, \u043e\u0442\u044b\u043d \u04d9\u043a\u0435\u043b. \u0411\u0456\u0440\u0430\u049b \u04d9\u043b\u0433\u0456 \u043a\u0456\u0448\u043a\u0435\u043d\u0442\u0430\u0439 \u043a\u0435\u0441\u0435\u043f\u0430\u0442 \u0431\u04af\u043a\u0456\u043b \u04e8\u0417\u0415\u041d\u0414\u0406 \u043a\u04e9\u0442\u0435\u0440\u0456\u043f \u043a\u0435\u0442\u043f\u0435\u043a \u0431\u043e\u043b\u0434\u044b, \u0441\u043e\u0441\u044b\u043d \u0431\u04af\u043a\u0456\u043b \u041e\u0420\u041c\u0410\u041d\u0414\u042b \u0441\u04af\u0439\u0440\u0435\u043f \u04d9\u043a\u0435\u0442\u043f\u0435\u043a \u0431\u043e\u043b\u0434\u044b!")},
     {dialog:[{who:"dau",em:"afraid",line:L("Stop, stop! Give me the skin \u2014 I'll fetch the water! Leave the trees \u2014 I'll carry the wood! Just don't take everything away!","\u0421\u0442\u043e\u0439, \u0441\u0442\u043e\u0439! \u0414\u0430\u0439 \u0431\u0443\u0440\u0434\u044e\u043a \u2014 \u0441\u0430\u043c \u043f\u0440\u0438\u043d\u0435\u0441\u0443 \u0432\u043e\u0434\u044b! \u041e\u0441\u0442\u0430\u0432\u044c \u0434\u0435\u0440\u0435\u0432\u044c\u044f \u2014 \u0441\u0430\u043c \u043f\u0440\u0438\u043d\u0435\u0441\u0443 \u0434\u0440\u043e\u0432\u0430! \u0422\u043e\u043b\u044c\u043a\u043e \u043d\u0435 \u0443\u043d\u043e\u0441\u0438 \u0432\u0441\u0451!","\u0422\u043e\u049b\u0442\u0430, \u0442\u043e\u049b\u0442\u0430! \u0421\u0430\u0431\u0430\u043d\u044b \u0431\u0435\u0440 \u2014 \u0441\u0443\u0434\u044b \u04e9\u0437\u0456\u043c \u04d9\u043a\u0435\u043b\u0435\u043c! \u0410\u0493\u0430\u0448\u0442\u0430\u0440\u0434\u044b \u049b\u0430\u043b\u0434\u044b\u0440 \u2014 \u043e\u0442\u044b\u043d\u0434\u044b \u04e9\u0437\u0456\u043c \u0442\u0430\u0441\u0438\u043c\u044b\u043d! \u0422\u0435\u043a \u0431\u04d9\u0440\u0456\u043d \u0430\u043b\u044b\u043f \u043a\u0435\u0442\u043f\u0435\u0448\u0456!")}]},
     {narr:L("You carried the water. You carried the wood. The old man carried nothing at all \u2014 and somehow you were the one gasping for breath.","\u0422\u044b \u043d\u0451\u0441 \u0432\u043e\u0434\u0443. \u0422\u044b \u043d\u0451\u0441 \u0434\u0440\u043e\u0432\u0430. \u0421\u0442\u0430\u0440\u0438\u043a \u043d\u0435 \u043d\u0451\u0441 \u043d\u0438\u0447\u0435\u0433\u043e \u2014 \u0438 \u043f\u043e\u0447\u0435\u043c\u0443-\u0442\u043e \u044d\u0442\u043e \u0442\u044b \u0437\u0430\u0434\u044b\u0445\u0430\u043b\u0441\u044f \u043e\u0442 \u0443\u0441\u0442\u0430\u043b\u043e\u0441\u0442\u0438.","\u0421\u0443\u0434\u044b \u0441\u0435\u043d \u0442\u0430\u0441\u044b\u0434\u044b\u04a3. \u041e\u0442\u044b\u043d\u0434\u044b \u0441\u0435\u043d \u0442\u0430\u0441\u044b\u0434\u044b\u04a3. \u0428\u0430\u043b \u0442\u04af\u043a \u043a\u04e9\u0442\u0435\u0440\u043c\u0435\u0434\u0456 \u2014 \u04d9\u0439\u0442\u0435\u0443\u0456\u0440 \u0435\u043d\u0442\u0456\u0433\u0456\u043f \u049b\u0430\u043b\u0493\u0430\u043d \u0441\u0435\u043d \u0431\u043e\u043b\u0434\u044b\u04a3.")}
   ]},
  {title:L("Pay Him and Pray He Goes","\u0417\u0430\u043f\u043b\u0430\u0442\u0438 \u0438 \u043c\u043e\u043b\u0438\u0441\u044c, \u0447\u0442\u043e\u0431 \u0443\u0448\u0451\u043b","\u0410\u049b\u044b\u0441\u044b\u043d \u0431\u0435\u0440 \u0434\u0435, \u043a\u0435\u0442\u0443\u0456\u043d \u0442\u0456\u043b\u0435"), scene:"night", obj:L("End the night \u2014 and the old man \u2014 once and for all","\u041f\u043e\u043a\u043e\u043d\u0447\u0438 \u0441 \u043d\u043e\u0447\u044c\u044e \u2014 \u0438 \u0441\u043e \u0441\u0442\u0430\u0440\u0438\u043a\u043e\u043c \u2014 \u0440\u0430\u0437 \u0438 \u043d\u0430\u0432\u0441\u0435\u0433\u0434\u0430","\u0422\u04af\u043d\u0434\u0456 \u0434\u0435, \u0448\u0430\u043b\u0434\u044b \u0434\u0430 \u0431\u0456\u0440\u0436\u043e\u043b\u0430 \u0442\u044b\u043d\u044b\u0448\u0442\u0430"),
   beats:[
     {narr:L("That night you and your brothers crept in and dashed a yurt-sized boulder onto his bed until it was splinters. But at dawn out he strolled, alive, complaining only that a flea had tickled his cheek in the night.","\u0422\u043e\u0439 \u043d\u043e\u0447\u044c\u044e \u0442\u044b \u0441 \u0431\u0440\u0430\u0442\u044c\u044f\u043c\u0438 \u043f\u043e\u0434\u043a\u0440\u0430\u043b\u0441\u044f \u0438 \u0431\u0438\u043b \u043f\u043e \u0435\u0433\u043e \u043f\u043e\u0441\u0442\u0435\u043b\u0438 \u0432\u0430\u043b\u0443\u043d\u043e\u043c \u0441 \u044e\u0440\u0442\u0443, \u043f\u043e\u043a\u0430 \u043d\u0435 \u0440\u0430\u0437\u043b\u0435\u0442\u0435\u043b\u0430\u0441\u044c \u0432 \u0449\u0435\u043f\u043a\u0438. \u041d\u043e \u043d\u0430 \u0440\u0430\u0441\u0441\u0432\u0435\u0442\u0435 \u043e\u043d \u0432\u044b\u0448\u0435\u043b \u0436\u0438\u0432\u043e\u0439, \u0436\u0430\u043b\u0443\u044f\u0441\u044c \u043b\u0438\u0448\u044c, \u0447\u0442\u043e \u0431\u043b\u043e\u0445\u0430 \u0449\u0435\u043a\u043e\u0442\u0430\u043b\u0430 \u0435\u043c\u0443 \u0449\u0451\u043a\u0443.","\u0421\u043e\u043b \u0442\u04af\u043d\u0456 \u0441\u0435\u043d \u0430\u0493\u0430\u043b\u0430\u0440\u044b\u04a3\u043c\u0435\u043d \u0436\u0430\u0441\u044b\u0440\u044b\u043d \u043a\u0456\u0440\u0456\u043f, \u0442\u04e9\u0441\u0435\u0433\u0456\u043d\u0435 \u043a\u0438\u0456\u0437 \u04af\u0439\u0434\u0435\u0439 \u0442\u0430\u0441\u0442\u044b \u0436\u0430\u04a3\u049b\u0430 \u0431\u043e\u043b\u0493\u0430\u043d\u0448\u0430 \u04b1\u0440\u0434\u044b\u04a3. \u0411\u0456\u0440\u0430\u049b \u0442\u0430\u04a3\u0434\u0430 \u043e\u043b \u0430\u043c\u0430\u043d \u0448\u044b\u0493\u044b\u043f, \u0442\u04af\u043d\u0434\u0435 \u0431\u0456\u0440 \u0431\u04af\u0440\u0433\u0435 \u0431\u0435\u0442\u0456\u043d \u049b\u044b\u0442\u044b\u049b\u0442\u0430\u0434\u044b \u0434\u0435\u043f \u049b\u0430\u043d\u0430 \u0448\u0430\u0493\u044b\u043c\u0434\u0430\u043d\u0434\u044b.")},
     {dialog:[{who:"elder",em:"pleading",line:L("Take our gold, great one \u2014 all of it \u2014 and go in peace!","\u0412\u043e\u0437\u044c\u043c\u0438 \u043d\u0430\u0448\u0435 \u0437\u043e\u043b\u043e\u0442\u043e, \u0432\u0435\u043b\u0438\u043a\u0438\u0439 \u2014 \u0432\u0441\u0451 \u2014 \u0438 \u0441\u0442\u0443\u043f\u0430\u0439 \u0441 \u043c\u0438\u0440\u043e\u043c!","\u0410\u043b\u0442\u044b\u043d\u044b\u043c\u044b\u0437\u0434\u044b \u0430\u043b, \u04b1\u043b\u044b \u0436\u0430\u043d \u2014 \u0431\u04d9\u0440\u0456\u043d \u2014 \u0430\u043c\u0430\u043d-\u0435\u0441\u0435\u043d \u049b\u0430\u0439\u0442!")},{who:"dau",em:"afraid",line:L("(to himself) A boulder like a yurt, and he felt a flea. Give him the gold. Give him anything. Only let him GO.","(\u043f\u0440\u043e \u0441\u0435\u0431\u044f) \u0412\u0430\u043b\u0443\u043d \u043a\u0430\u043a \u044e\u0440\u0442\u0430, \u0430 \u043e\u043d \u043f\u043e\u0447\u0443\u044f\u043b \u0431\u043b\u043e\u0445\u0443. \u041e\u0442\u0434\u0430\u0439 \u0435\u043c\u0443 \u0437\u043e\u043b\u043e\u0442\u043e. \u041e\u0442\u0434\u0430\u0439 \u0447\u0442\u043e \u0443\u0433\u043e\u0434\u043d\u043e. \u041b\u0438\u0448\u044c \u0431\u044b \u0423\u0428\u0401\u041b.","(\u0456\u0448\u0456\u043d\u0435\u043d) \u041a\u0438\u0456\u0437 \u04af\u0439\u0434\u0435\u0439 \u0442\u0430\u0441, \u0430\u043b \u043e\u043b \u0431\u04af\u0440\u0433\u0435\u043d\u0456 \u0441\u0435\u0437\u0434\u0456. \u0410\u043b\u0442\u044b\u043d\u0434\u044b \u0431\u0435\u0440. \u041d\u0435 \u0431\u043e\u043b\u0441\u0430 \u0434\u0430 \u0431\u0435\u0440. \u0422\u0435\u043a \u041a\u0415\u0422\u0421\u0406\u041d.")}]},
     {narr:L("And when your youngest carried the gold to the old man's hut and heard a child cry out for 'giant-meat for supper,' he dropped the sack and fled \u2014 and your kind never troubled that steppe again.","\u0418 \u043a\u043e\u0433\u0434\u0430 \u043c\u043b\u0430\u0434\u0448\u0438\u0439 \u0442\u0432\u043e\u0439 \u043e\u0442\u043d\u0451\u0441 \u0437\u043e\u043b\u043e\u0442\u043e \u043a \u0434\u043e\u043c\u0438\u043a\u0443 \u0441\u0442\u0430\u0440\u0438\u043a\u0430 \u0438 \u0443\u0441\u043b\u044b\u0445\u0430\u043b, \u043a\u0430\u043a \u0434\u0438\u0442\u044f \u043a\u0440\u0438\u0447\u0438\u0442 \u043f\u0440\u043e \u00ab\u043c\u044f\u0441\u043e \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u0430 \u043d\u0430 \u0443\u0436\u0438\u043d\u00bb, \u043e\u043d \u0431\u0440\u043e\u0441\u0438\u043b \u043c\u0435\u0448\u043e\u043a \u0438 \u0443\u043c\u0447\u0430\u043b\u0441\u044f \u2014 \u0438 \u0440\u043e\u0434 \u0442\u0432\u043e\u0439 \u0431\u043e\u043b\u044c\u0448\u0435 \u043d\u0435 \u0442\u0440\u0435\u0432\u043e\u0436\u0438\u043b \u0442\u0443 \u0441\u0442\u0435\u043f\u044c.","\u041a\u0435\u043d\u0436\u0435 \u0431\u0430\u0443\u044b\u0440\u044b\u04a3 \u0430\u043b\u0442\u044b\u043d\u0434\u044b \u0448\u0430\u043b\u0434\u044b\u04a3 \u0430\u043b\u0430\u0448\u044b\u0493\u044b\u043d\u0430 \u0430\u043f\u0430\u0440\u044b\u043f, \u0431\u0456\u0440 \u0431\u0430\u043b\u0430\u043d\u044b\u04a3 \u00ab\u043a\u0435\u0448\u043a\u0456\u0433\u0435 \u0434\u04d9\u0443\u0434\u0456\u04a3 \u0435\u0442\u0456\u00bb \u0434\u0435\u043f \u0430\u0439\u049b\u0430\u0439\u043b\u0430\u0493\u0430\u043d\u044b\u043d \u0435\u0441\u0442\u0456\u0433\u0435\u043d\u0434\u0435, \u049b\u0430\u043f\u0442\u044b \u0442\u0430\u0441\u0442\u0430\u0439 \u0441\u0430\u043b\u044b\u043f \u049b\u0430\u0448\u0442\u044b \u2014 \u0441\u043e\u0434\u0430\u043d \u0442\u04b1\u049b\u044b\u043c\u044b\u04a3 \u043e\u043b \u0434\u0430\u043b\u0430\u043d\u044b \u049b\u0430\u0439\u0442\u044b\u043f \u043c\u0430\u0437\u0430\u043b\u0430\u043c\u0430\u0434\u044b.")}
   ]}
  ]},
 "tulki":{ ending:{title:L("The Fox Outfoxed","\u041f\u0435\u0440\u0435\u0445\u0438\u0442\u0440\u0451\u043d\u043d\u0430\u044f \u043b\u0438\u0441\u0430","\u0410\u0439\u043b\u0430\u0441\u044b \u0430\u0441\u049b\u0430\u043d \u0442\u04af\u043b\u043a\u0456"),text:L("You thought yourself the cunning one of the river \u2014 until the humble old man you robbed proved the sharpest mind on the whole steppe. The true trickster wins not with teeth, but with wit.","\u0422\u044b \u043c\u043d\u0438\u043b\u0430 \u0441\u0435\u0431\u044f \u0445\u0438\u0442\u0440\u0435\u0439\u0448\u0435\u0439 \u043d\u0430 \u0440\u0435\u043a\u0435 \u2014 \u043f\u043e\u043a\u0430 \u0441\u043c\u0438\u0440\u0435\u043d\u043d\u044b\u0439 \u0441\u0442\u0430\u0440\u0438\u043a, \u043a\u043e\u0442\u043e\u0440\u043e\u0433\u043e \u0442\u044b \u043e\u0431\u0438\u0440\u0430\u043b\u0430, \u043d\u0435 \u043e\u043a\u0430\u0437\u0430\u043b\u0441\u044f \u043e\u0441\u0442\u0440\u0435\u0439\u0448\u0438\u043c \u0443\u043c\u043e\u043c \u0432\u0441\u0435\u0439 \u0441\u0442\u0435\u043f\u0438. \u041d\u0430\u0441\u0442\u043e\u044f\u0449\u0438\u0439 \u0445\u0438\u0442\u0440\u0435\u0446 \u043f\u043e\u0431\u0435\u0436\u0434\u0430\u0435\u0442 \u043d\u0435 \u0437\u0443\u0431\u0430\u043c\u0438, \u0430 \u0443\u043c\u043e\u043c.","\u04e8\u0437\u0456\u04a3\u0434\u0456 \u04e9\u0437\u0435\u043d\u043d\u0456\u04a3 \u0435\u04a3 \u049b\u0443\u044b \u0441\u0430\u043d\u0430\u0434\u044b\u04a3 \u2014 \u0431\u0456\u0440\u0430\u049b \u0442\u043e\u043d\u0430\u043f \u0436\u04af\u0440\u0433\u0435\u043d \u043c\u043e\u043c\u044b\u043d \u0448\u0430\u043b \u0431\u04af\u043a\u0456\u043b \u0434\u0430\u043b\u0430\u043d\u044b\u04a3 \u0435\u04a3 \u04e9\u0442\u043a\u0456\u0440 \u0430\u049b\u044b\u043b\u044b \u0431\u043e\u043b\u044b\u043f \u0448\u044b\u049b\u0442\u044b. \u041d\u0430\u0493\u044b\u0437 \u0430\u0439\u043b\u0430\u043a\u0435\u0440 \u0442\u0456\u0441\u043f\u0435\u043d \u0435\u043c\u0435\u0441, \u0430\u049b\u044b\u043b\u043c\u0435\u043d \u0436\u0435\u04a3\u0435\u0434\u0456.")},
  chapters:[
  {title:L("The Fox's Easy Toll","\u041b\u0451\u0433\u043a\u0430\u044f \u0434\u0430\u043d\u044c \u043b\u0438\u0441\u044b","\u0422\u04af\u043b\u043a\u0456\u043d\u0456\u04a3 \u0436\u0435\u04a3\u0456\u043b \u043e\u043b\u0436\u0430\u0441\u044b"), scene:"shore", obj:L("Collect your daily toll from the old fisherman","\u0421\u043e\u0431\u0435\u0440\u0438 \u0441\u0432\u043e\u044e \u0435\u0436\u0435\u0434\u043d\u0435\u0432\u043d\u0443\u044e \u0434\u0430\u043d\u044c \u0441\u043e \u0441\u0442\u0430\u0440\u0438\u043a\u0430-\u0440\u044b\u0431\u0430\u043a\u0430","\u041a\u04d9\u0440\u0456 \u0431\u0430\u043b\u044b\u049b\u0448\u044b\u0434\u0430\u043d \u043a\u04af\u043d\u0434\u0435\u043b\u0456\u043a\u0442\u0456 \u043e\u043b\u0436\u0430\u04a3\u0434\u044b \u0436\u0438\u043d\u0430"),
   beats:[
     {narr:L("You are the cleverest fox on the whole riverbank \u2014 or so you have always believed. Every dawn the poor old man Qa\u00f1baq casts his net, and every dawn you saunter down to take half his catch. Easy. Delicious.","\u0422\u044b \u2014 \u0441\u0430\u043c\u0430\u044f \u0445\u0438\u0442\u0440\u0430\u044f \u043b\u0438\u0441\u0430 \u043d\u0430 \u0432\u0441\u0451\u043c \u0431\u0435\u0440\u0435\u0433\u0443 \u2014 \u0438\u043b\u0438 \u0442\u0430\u043a \u0442\u044b \u0432\u0441\u0435\u0433\u0434\u0430 \u0441\u0447\u0438\u0442\u0430\u043b\u0430. \u041a\u0430\u0436\u0434\u044b\u0439 \u0440\u0430\u0441\u0441\u0432\u0435\u0442 \u0431\u0435\u0434\u043d\u044b\u0439 \u0441\u0442\u0430\u0440\u0438\u043a \u041a\u0430\u0144\u0431\u0430\u043a \u0437\u0430\u043a\u0438\u0434\u044b\u0432\u0430\u0435\u0442 \u0441\u0435\u0442\u044c, \u0438 \u043a\u0430\u0436\u0434\u044b\u0439 \u0440\u0430\u0441\u0441\u0432\u0435\u0442 \u0442\u044b \u0432\u0440\u0430\u0437\u0432\u0430\u043b\u043e\u0447\u043a\u0443 \u0438\u0434\u0451\u0448\u044c \u0437\u0430\u0431\u0440\u0430\u0442\u044c \u043f\u043e\u043b\u043e\u0432\u0438\u043d\u0443 \u0443\u043b\u043e\u0432\u0430. \u041b\u0435\u0433\u043a\u043e. \u0412\u043a\u0443\u0441\u043d\u043e.","\u0421\u0435\u043d \u0431\u04af\u043a\u0456\u043b \u04e9\u0437\u0435\u043d \u0436\u0430\u0493\u0430\u0441\u044b\u043d\u0434\u0430\u0493\u044b \u0435\u04a3 \u049b\u0443 \u0442\u04af\u043b\u043a\u0456\u0441\u0456\u04a3 \u2014 \u04d9\u0440\u049b\u0430\u0448\u0430\u043d \u0441\u043e\u043b\u0430\u0439 \u0441\u0435\u043d\u0433\u0435\u043d\u0441\u0456\u04a3. \u04d8\u0440 \u0442\u0430\u04a3\u0434\u0430 \u043a\u0435\u0434\u0435\u0439 \u0448\u0430\u043b \u049a\u0430\u04a3\u0431\u0430\u049b \u0430\u0443\u044b\u043d \u0441\u0430\u043b\u0430\u0434\u044b, \u04d9\u0440 \u0442\u0430\u04a3\u0434\u0430 \u0441\u0435\u043d \u0442\u0435\u04a3\u0441\u0435\u043b\u0456\u043f \u0431\u0430\u0440\u044b\u043f, \u043e\u043b\u0436\u0430\u0441\u044b\u043d\u044b\u04a3 \u0436\u0430\u0440\u0442\u044b\u0441\u044b\u043d \u0430\u043b\u0430\u0441\u044b\u04a3. \u041e\u04a3\u0430\u0439. \u0414\u04d9\u043c\u0434\u0456.")},
     {dialog:[{who:"tulki",em:"sly",line:L("Good morning, Grandfather. One fish for you\u2026 and one for me. Only fair \u2014 I am so much cleverer than you. Do try to catch something plump tomorrow.","\u0414\u043e\u0431\u0440\u043e\u0435 \u0443\u0442\u0440\u043e, \u0434\u0435\u0434\u0443\u0448\u043a\u0430. \u041e\u0434\u043d\u0430 \u0440\u044b\u0431\u043a\u0430 \u0442\u0435\u0431\u0435\u2026 \u0438 \u043e\u0434\u043d\u0430 \u043c\u043d\u0435. \u0421\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e \u2014 \u044f \u0432\u0435\u0434\u044c \u043a\u0443\u0434\u0430 \u0443\u043c\u043d\u0435\u0435. \u041f\u043e\u0441\u0442\u0430\u0440\u0430\u0439\u0441\u044f \u0437\u0430\u0432\u0442\u0440\u0430 \u043f\u043e\u0439\u043c\u0430\u0442\u044c \u0447\u0442\u043e \u043f\u043e\u0436\u0438\u0440\u043d\u0435\u0435.","\u049a\u0430\u0439\u044b\u0440\u043b\u044b \u0442\u0430\u04a3, \u0430\u0442\u0430. \u0411\u0456\u0440 \u0431\u0430\u043b\u044b\u049b \u0441\u0430\u0493\u0430\u043d\u2026 \u0431\u0456\u0440 \u043c\u0430\u0493\u0430\u043d. \u04d8\u0434\u0456\u043b \u2014 \u043c\u0435\u043d \u04d9\u043b\u0434\u0435\u049b\u0430\u0439\u0434\u0430 \u0430\u049b\u044b\u043b\u0434\u044b\u043c\u044b\u043d \u0493\u043e\u0439. \u0415\u0440\u0442\u0435\u04a3 \u0441\u0435\u043c\u0456\u0437\u0456\u0440\u0435\u0433\u0456\u043d \u04b1\u0441\u0442\u0430\u0443\u0493\u0430 \u0442\u044b\u0440\u044b\u0441.")},{who:"qanbaq",em:"sad",line:L("Take it, and choke on your fairness. A poor man cannot argue with sharp teeth.","\u0411\u0435\u0440\u0438, \u0438 \u043f\u043e\u0434\u0430\u0432\u0438\u0441\u044c \u0441\u043f\u0440\u0430\u0432\u0435\u0434\u043b\u0438\u0432\u043e\u0441\u0442\u044c\u044e. \u0411\u0435\u0434\u043d\u044f\u043a\u0443 \u043d\u0435 \u0441\u043f\u043e\u0440\u0438\u0442\u044c \u0441 \u043e\u0441\u0442\u0440\u044b\u043c\u0438 \u0437\u0443\u0431\u0430\u043c\u0438.","\u0410\u043b\u0430 \u0493\u043e\u0439, \u04d9\u0434\u0456\u043b\u0434\u0456\u0433\u0456\u04a3\u0435 \u0448\u0430\u0448\u0430\u043b\u044b\u043f \u049b\u0430\u043b. \u041a\u0435\u0434\u0435\u0439 \u0430\u0434\u0430\u043c \u04e9\u0442\u043a\u0456\u0440 \u0442\u0456\u0441\u043a\u0435 \u0434\u0430\u0443 \u0430\u0439\u0442\u0430 \u0430\u043b\u043c\u0430\u0439\u0434\u044b.")}]}
   ]},
  {title:L("The Empty Shore","\u041e\u043f\u0443\u0441\u0442\u0435\u0432\u0448\u0438\u0439 \u0431\u0435\u0440\u0435\u0433","\u0411\u043e\u0441 \u0436\u0430\u0493\u0430"), scene:"road", obj:L("Discover the old man has slipped away","\u041e\u0431\u043d\u0430\u0440\u0443\u0436\u044c, \u0447\u0442\u043e \u0441\u0442\u0430\u0440\u0438\u043a \u0443\u0441\u043a\u043e\u043b\u044c\u0437\u043d\u0443\u043b","\u0428\u0430\u043b\u0434\u044b\u04a3 \u0441\u044b\u0442\u044b\u043b\u044b\u043f \u043a\u0435\u0442\u043a\u0435\u043d\u0456\u043d \u0431\u0456\u043b"),
   beats:[
     {narr:L("One dawn you saunter down as always \u2014 but the net is gone, the reeds are still, and the old man's footprints trail away over the hills. Your easy breakfast has walked off across the steppe.","\u041d\u0430 \u043e\u0434\u0438\u043d \u0440\u0430\u0441\u0441\u0432\u0435\u0442 \u0442\u044b \u0432\u0440\u0430\u0437\u0432\u0430\u043b\u043e\u0447\u043a\u0443 \u0441\u043f\u0443\u0441\u043a\u0430\u0435\u0448\u044c\u0441\u044f, \u043a\u0430\u043a \u0432\u0441\u0435\u0433\u0434\u0430 \u2014 \u043d\u043e \u0441\u0435\u0442\u0438 \u043d\u0435\u0442, \u043a\u0430\u043c\u044b\u0448 \u043d\u0435\u0434\u0432\u0438\u0436\u0438\u043c, \u0430 \u0441\u043b\u0435\u0434\u044b \u0441\u0442\u0430\u0440\u0438\u043a\u0430 \u0442\u044f\u043d\u0443\u0442\u0441\u044f \u043f\u0440\u043e\u0447\u044c \u0437\u0430 \u0445\u043e\u043b\u043c\u044b. \u0422\u0432\u043e\u0439 \u043b\u0451\u0433\u043a\u0438\u0439 \u0437\u0430\u0432\u0442\u0440\u0430\u043a \u0443\u0448\u0451\u043b \u0447\u0435\u0440\u0435\u0437 \u0441\u0442\u0435\u043f\u044c.","\u0411\u0456\u0440 \u0442\u0430\u04a3\u0434\u0430 \u04d9\u0434\u0435\u0442\u0442\u0435\u0433\u0456\u0434\u0435\u0439 \u0442\u0435\u04a3\u0441\u0435\u043b\u0456\u043f \u0431\u0430\u0440\u0441\u0430\u04a3 \u2014 \u0430\u0443 \u0436\u043e\u049b, \u049b\u0430\u043c\u044b\u0441 \u0442\u044b\u043d\u044b\u0448, \u0430\u043b \u0448\u0430\u043b\u0434\u044b\u04a3 \u0456\u0437\u0456 \u0442\u04e9\u0431\u0435\u043b\u0435\u0440\u0434\u0435\u043d \u0430\u0441\u044b\u043f \u043a\u0435\u0442\u043a\u0435\u043d. \u0416\u0435\u04a3\u0456\u043b \u0442\u0430\u04a3\u0493\u044b \u0430\u0441\u044b\u04a3 \u0434\u0430\u043b\u0430 \u0430\u0441\u044b\u043f \u0436\u04af\u0440\u0435 \u0431\u0435\u0440\u0433\u0435\u043d.")},
     {dialog:[{who:"tulki",em:"worried",line:L("Gone? He simply\u2026 left? But who will fill my net now? A clever creature never lets its supper wander off. I have grown fat and lazy on that old man's kindness.","\u0423\u0448\u0451\u043b? \u041e\u043d \u043f\u0440\u043e\u0441\u0442\u043e\u2026 \u0443\u0448\u0451\u043b? \u041d\u043e \u043a\u0442\u043e \u0442\u0435\u043f\u0435\u0440\u044c \u043d\u0430\u043f\u043e\u043b\u043d\u0438\u0442 \u043c\u043e\u044e \u0441\u0435\u0442\u044c? \u0425\u0438\u0442\u0440\u044b\u0439 \u0437\u0432\u0435\u0440\u044c \u043d\u0435 \u0434\u0430\u0451\u0442 \u0443\u0436\u0438\u043d\u0443 \u0440\u0430\u0437\u0431\u0440\u0435\u0441\u0442\u0438\u0441\u044c. \u0420\u0430\u0437\u0436\u0438\u0440\u0435\u043b\u0430 \u044f \u0438 \u043e\u0431\u043b\u0435\u043d\u0438\u043b\u0430\u0441\u044c \u043d\u0430 \u0434\u043e\u0431\u0440\u043e\u0442\u0435 \u0441\u0442\u0430\u0440\u0438\u043a\u0430.","\u041a\u0435\u0442\u0442\u0456 \u043c\u0435? \u041e\u043b \u0436\u0430\u0439 \u0493\u0430\u043d\u0430\u2026 \u043a\u0435\u0442\u0442\u0456 \u043c\u0435? \u0415\u043d\u0434\u0456 \u0430\u0443\u044b\u043c\u0434\u044b \u043a\u0456\u043c \u0442\u043e\u043b\u0442\u044b\u0440\u0430\u0434\u044b? \u049a\u0443 \u0430\u04a3 \u0442\u0430\u043c\u0430\u0493\u044b\u043d \u0442\u0435\u043d\u0442\u0456\u0440\u0435\u0442\u0456\u043f \u0436\u0456\u0431\u0435\u0440\u043c\u0435\u0439\u0434\u0456. \u041c\u0435\u043d \u0441\u043e\u043b \u0448\u0430\u043b\u0434\u044b\u04a3 \u043c\u0435\u0439\u0456\u0440\u0456\u043c\u0456\u043d\u0435 \u0441\u0435\u043c\u0456\u0440\u0456\u043f, \u0435\u0440\u0456\u043d\u0448\u0435\u043a \u0431\u043e\u043f \u043a\u0435\u0442\u0456\u043f\u043f\u0456\u043d.")}]}
   ]},
  {title:L("Who Was the Clever One?","\u041a\u0442\u043e \u0436\u0435 \u0431\u044b\u043b \u0443\u043c\u0451\u043d?","\u0410\u049b\u044b\u043b\u0434\u044b \u043a\u0456\u043c \u0435\u0434\u0456?"), scene:"home", obj:L("Learn how the 'simple' old man ended up rich","\u0423\u0437\u043d\u0430\u0439, \u043a\u0430\u043a \u00ab\u043f\u0440\u043e\u0441\u0442\u0430\u043a\u00bb-\u0441\u0442\u0430\u0440\u0438\u043a \u0440\u0430\u0437\u0431\u043e\u0433\u0430\u0442\u0435\u043b","\u00ab\u0410\u04a3\u049b\u0430\u0443\u00bb \u0448\u0430\u043b\u0434\u044b\u04a3 \u049b\u0430\u043b\u0430\u0439 \u0431\u0430\u0439\u044b\u0493\u0430\u043d\u044b\u043d \u0431\u0456\u043b"),
   beats:[
     {narr:L("Seasons later, word drifts down the river: the 'simple' old fisherman outwitted a whole valley of giants \u2014 the sky-bluff, the guts and brains, the river, the forest, the flea in the night \u2014 and came home with a giant's sack of gold.","\u0421\u043f\u0443\u0441\u0442\u044f \u0432\u0440\u0435\u043c\u0435\u043d\u0430 \u043f\u043e \u0440\u0435\u043a\u0435 \u0434\u043e\u0445\u043e\u0434\u0438\u0442 \u043c\u043e\u043b\u0432\u0430: \u00ab\u043f\u0440\u043e\u0441\u0442\u0430\u043a\u00bb-\u0440\u044b\u0431\u0430\u043a \u043f\u0435\u0440\u0435\u0445\u0438\u0442\u0440\u0438\u043b \u0446\u0435\u043b\u0443\u044e \u0434\u043e\u043b\u0438\u043d\u0443 \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u043e\u0432 \u2014 \u043d\u0435\u0431\u043e, \u043f\u043e\u0442\u0440\u043e\u0445\u0430 \u0438 \u043c\u043e\u0437\u0433\u0438, \u0440\u0435\u043a\u0443, \u043b\u0435\u0441, \u0431\u043b\u043e\u0445\u0443 \u0432 \u043d\u043e\u0447\u0438 \u2014 \u0438 \u0432\u0435\u0440\u043d\u0443\u043b\u0441\u044f \u0441 \u0432\u0435\u043b\u0438\u043a\u0430\u043d\u044c\u0438\u043c \u043c\u0435\u0448\u043a\u043e\u043c \u0437\u043e\u043b\u043e\u0442\u0430.","\u041c\u0430\u0443\u0441\u044b\u043c\u0434\u0430\u0440 \u04e9\u0442\u0456\u043f, \u04e9\u0437\u0435\u043d \u0431\u043e\u0439\u044b\u043c\u0435\u043d \u0445\u0430\u0431\u0430\u0440 \u0436\u0435\u0442\u0435\u0434\u0456: \u00ab\u0430\u04a3\u049b\u0430\u0443\u00bb \u0431\u0430\u043b\u044b\u049b\u0448\u044b \u0431\u0456\u0440 \u0430\u04a3\u0493\u0430\u0440 \u0434\u04d9\u0443\u0434\u0456 \u0430\u043b\u0434\u0430\u043f \u043a\u0435\u0442\u0456\u043f\u0442\u0456 \u2014 \u0430\u0441\u043f\u0430\u043d \u0430\u0439\u043b\u0430\u0441\u044b, \u0456\u0448\u0435\u043a-\u049b\u0430\u0440\u044b\u043d \u043c\u0435\u043d \u043c\u0438, \u04e9\u0437\u0435\u043d, \u043e\u0440\u043c\u0430\u043d, \u0442\u04af\u043d\u0433\u0456 \u0431\u04af\u0440\u0433\u0435 \u2014 \u0441\u04e9\u0439\u0442\u0456\u043f \u0434\u04d9\u0443\u0434\u0456\u04a3 \u0431\u0456\u0440 \u049b\u0430\u043f \u0430\u043b\u0442\u044b\u043d\u044b\u043c\u0435\u043d \u043e\u0440\u0430\u043b\u044b\u043f\u0442\u044b.")},
     {dialog:[{who:"tulki",em:"gentle",line:L("All this time I preened myself the clever one, and stole his fish \u2014 while HE was the sharpest wit on the steppe. Ah, Grandfather. You taught the fox a lesson at last: never mistake a kind face for a soft mind.","\u0412\u0441\u0451 \u044d\u0442\u043e \u0432\u0440\u0435\u043c\u044f \u044f \u043c\u043d\u0438\u043b\u0430 \u0441\u0435\u0431\u044f \u0443\u043c\u043d\u0438\u0446\u0435\u0439 \u0438 \u043a\u0440\u0430\u043b\u0430 \u0435\u0433\u043e \u0440\u044b\u0431\u0443 \u2014 \u0430 \u041e\u041d \u0431\u044b\u043b \u043e\u0441\u0442\u0440\u0435\u0439\u0448\u0438\u043c \u0443\u043c\u043e\u043c \u0432 \u0441\u0442\u0435\u043f\u0438. \u0410\u0445, \u0434\u0435\u0434\u0443\u0448\u043a\u0430. \u041f\u0440\u043e\u0443\u0447\u0438\u043b \u0442\u044b \u043d\u0430\u043a\u043e\u043d\u0435\u0446 \u043b\u0438\u0441\u0443: \u043d\u0435 \u043f\u0443\u0442\u0430\u0439 \u0434\u043e\u0431\u0440\u043e\u0435 \u043b\u0438\u0446\u043e \u0441 \u043c\u044f\u0433\u043a\u0438\u043c \u0443\u043c\u043e\u043c.","\u041e\u0441\u044b \u0443\u0430\u049b\u044b\u0442 \u0431\u043e\u0439\u044b \u04e9\u0437\u0456\u043c\u0434\u0456 \u0430\u049b\u044b\u043b\u0434\u044b \u0441\u0430\u043d\u0430\u043f, \u0431\u0430\u043b\u044b\u0493\u044b\u043d \u04b1\u0440\u043b\u0430\u0434\u044b\u043c \u2014 \u0430\u043b \u0415\u04a2 \u04e9\u0442\u043a\u0456\u0440 \u0430\u049b\u044b\u043b \u0434\u0430\u043b\u0430 \u04af\u0441\u0442\u0456\u043d\u0434\u0435 \u041e\u041b \u0435\u043a\u0435\u043d. \u0410\u04bb, \u0430\u0442\u0430. \u0422\u04af\u043b\u043a\u0456\u0433\u0435 \u0430\u049b\u044b\u0440\u044b \u0441\u0430\u0431\u0430\u049b \u0431\u0435\u0440\u0434\u0456\u04a3: \u043c\u0435\u0439\u0456\u0440\u043b\u0456 \u0436\u04af\u0437\u0434\u0456 \u0436\u04b1\u043c\u0441\u0430\u049b \u0430\u049b\u044b\u043b\u043c\u0435\u043d \u0448\u0430\u0442\u0430\u0441\u0442\u044b\u0440\u043c\u0430.")}]}
   ]}
  ]}
};

