const LRRH_DISCOVERIES={
  cottage:[
    {id:"lrrh_hood",x:30,y:40,ic:"🧥",name:L("The Red Riding Hood"),text:L("A 'riding hood' was a hooded cloak worn for journeys. This one was such a bright and cheerful red, and suited the little girl so well, that everyone forgot her real name and simply called her Little Red Riding Hood.")},
    {id:"lrrh_cake",x:68,y:52,ic:"🧁",name:L("The Basket of Cakes"),text:L("Carrying food to the sick was an age-old kindness. A fresh-baked cake and a pot of golden butter were a fine gift indeed for an ailing grandmother, in days when such treats were rare and dearly loved.")}
  ],
  deep_wood:[
    {id:"lrrh_wolf",x:34,y:36,ic:"🐺",name:L("The Grey Wolf"),text:L("Real wolves are shy of people and hunt together in family groups called packs. But long ago, when vast dark forests covered Europe, a lone wolf crossing a traveller's path was a true danger — and so it crept into a thousand fireside tales.")},
    {id:"lrrh_oak",x:72,y:58,ic:"🌳",name:L("The Trackless Wood"),text:L("For centuries, deep and pathless woods ringed every village. The path was the only safe way through, and to leave it was to risk being truly lost — which is why every mother's warning was the same: keep to the path.")}
  ],
  flower_glade:[
    {id:"lrrh_flowers",x:28,y:44,ic:"🌼",name:L("Woodland Flowers"),text:L("Bluebells, wood anemones and foxgloves carpet a sunlit glade in spring. Gathering a posy for a poorly relative was a real kindness — but a child who lingered picking them could lose all track of time, and of the way home.")},
    {id:"lrrh_butterfly",x:70,y:34,ic:"🦋",name:L("The Butterflies"),text:L("Chasing butterflies from flower to flower is exactly how a wandering child strays, one small step at a time, from a safe path — each one always fluttering just a little further on.")}
  ],
  mill:[
    {id:"lrrh_mill",x:40,y:40,ic:"🏚️",name:L("The Old Mill"),text:L("A watermill ground the village grain into flour. Standing at the meadow's edge, it was the landmark everyone steered by — 'just past the old mill' was how you found the way to Grandmother's door.")}
  ],
  granny_house:[
    {id:"lrrh_herbs",x:60,y:46,ic:"🌿",name:L("Grandmother's Herbs"),text:L("Before doctors were near at hand, folk healed with herbs — chamomile for calm, thyme for coughs, honey for a sore throat. A poorly grandmother's cottage would smell of drying bunches hung from the rafters.")}
  ]
};

const LRRH_PLAYABLE = [
  {key:"red", name:LRRH_NAME.red, role:L("The Girl in the Red Hood"), path:"red",
   power:L("Kind, trusting and merry, you carry cakes to your grandmother through the great wood. Your open heart is your gift — and your danger. Learn, the hard way, why a child keeps to the path and holds her tongue before a stranger's flattering voice.")},
  {key:"wolf", name:LRRH_NAME.wolf, role:L("The Cunning Wolf"), path:"wolf",
   power:L("Grey, hungry and sly, you flatter and you scheme. You could snatch the child at once — but you are far too clever for that. And cleverness, in the end, is a trap that closes on the schemer himself.")},
  {key:"huntsman", name:LRRH_NAME.huntsman, role:L("The Huntsman"), path:"huntsman",
   power:L("Strong, watchful and kind, you walk the wood with your axe upon your shoulder. You have tracked this old wolf for many a season. When a grandmother's cottage falls too quiet, it is you who will set things right.")}
];

const LRRH_STORY = {
 red:{
  ending:{ title:L("The Path Well Kept"),
    text:L("You set out with an open heart and a basket of cakes, and you learned the hardest lesson the wood can teach: that not every sweet voice is a kind one, and that a child stays safe by keeping to the path. Grandmother is well again, the huntsman is thanked, and the cake — a little squashed — is eaten at last beside the fire. And never again did the girl in the red hood leave the path for a stranger's flattering word.") },
  chapters:[
   { title:L("The Little Red Hood"), scene:"cottage",
     obj:L("Meet Little Red Riding Hood and set out for Grandmother's"),
     beats:[
      {narr:L("Once upon a time, in a little village at the edge of a great wood, there lived the sweetest little girl that ever was seen. Her grandmother, who loved her dearly, had sewn her a hood and cloak of the brightest red — and it suited her so well that everyone called her only Little Red Riding Hood.")},
      {narr:L("One morning her mother, who had been baking, called the child to her side. 'Your poor grandmother is ill and all alone beyond the wood,' she said, 'and a visit would do her a world of good.'")},
      {dialog:[
        {who:"mother",em:"warm",line:L("Come here, my darling. Take this basket to Grandmother — a fresh cake and a little pot of golden butter — and see that she wants for nothing.")},
        {who:"red",em:"kind",line:L("I will, Mother! I shall go straight there and cheer her up. Grandmother does so love my visits.")},
        {who:"mother",em:"gentle",line:L("Then go, and my blessing go with you. But keep to the path through the wood, child — do not wander, and never stop to talk with strangers.")}
      ]},
      {narr:L("So Little Red Riding Hood kissed her mother, took up the basket, and set off down the lane toward the great dark wood, humming a little tune as she went.")}
     ]},
   { title:L("Into the Wood"), scene:"deep_wood",
     obj:L("Follow the path through the wood — and beware who you meet"),
     beats:[
      {narr:L("The path wound in beneath the tall old trees, where the light fell green and soft. Little Red Riding Hood had not gone far when, out from the shadows, stepped a great grey wolf.")},
      {dialog:[
        {who:"wolf",em:"alluring",line:L("Good morning, little one. What a fine red hood you wear. And where might such a sweet child be going, all alone in my wood?")},
        {who:"red",em:"warm",line:L("Good morning, sir! I am going to my grandmother's cottage, on the far side of the wood, to bring her a cake and a pot of butter, for she has been ill.")}
      ]},
      {dialog:[
        {who:"wolf",em:"cool",line:L("And does your grandmother live very far from here?")},
        {who:"red",em:"kind",line:L("Oh, a little way yet — her cottage stands just past the old mill, the very first house beyond the meadow.")}
      ]},
      {dialog:[
        {who:"wolf",em:"alluring",line:L("What a good little girl. But see how the sun is shining, and how the flowers nod in the glade! Surely your grandmother would love a fresh bouquet. Why not gather her a few?")},
        {who:"red",em:"hope",line:L("What a lovely thought! She would smile so to see them. Just a few, and then straight on my way.")}
      ]},
      {narr:L("And so, while Little Red Riding Hood turned aside to pick flowers, the wolf ran off by the shortest way — straight and swift toward the grandmother's cottage.")}
     ]},
   { title:L("The Sunlit Glade"), scene:"flower_glade",
     obj:L("Gather flowers in the glade — but do not stray too far"),
     beats:[
      {narr:L("The glade was warm and golden. Each time she picked one flower, a lovelier one seemed to bloom just a little further on, and so, step by step, she strayed deeper from the path — and never once saw how long the shadows had grown.")},
      {dialog:[
        {who:"red",em:"warm",line:L("One more for Grandmother's table... and this tall one for the jug by her window. Oh, she will be so pleased with them all!")}
      ]},
      {narr:L("But far ahead, the wolf had already reached the cottage. He knocked — tap, tap — and, softening his rough voice, called that he was her grandchild come with cakes. The trusting old woman bade him lift the latch — and in a single bound the wolf sprang in and swallowed her down whole. Then he pulled on her cap and gown, climbed into her bed, and drew the curtains close, and lay very still, waiting.")}
     ]},
   { title:L("Grandmother's Cottage"), scene:"granny_room",
     obj:L("Reach Grandmother's bedside — and trust the shiver of warning"),
     beats:[
      {narr:L("At last Little Red Riding Hood came to the cottage. The door stood open, and a strange hush lay over everything. She stepped inside, and though she could not say why, a small cold shiver ran through her.")},
      {dialog:[
        {who:"red",em:"worried",line:L("Grandmother? ...How odd you look today. Why, Grandmother, what big ears you have!")},
        {who:"wolf",em:"soft",line:L("All the better to hear you with, my dear.")},
        {who:"red",em:"worried",line:L("And Grandmother, what big eyes you have!")},
        {who:"wolf",em:"soft",line:L("All the better to see you with, my dear.")}
      ]},
      {dialog:[
        {who:"red",em:"worried",line:L("But Grandmother — what big teeth you have!")},
        {who:"wolf",em:"fierce",line:L("All the better to EAT you with!")}
      ], act:"pounce"},
      {narr:L("And with a snarl the wolf leapt from the bed and swallowed poor Little Red Riding Hood too. Then, his belly full at last, he sank back upon the pillows and fell fast asleep, snoring loud enough to rattle the shutters.")}
     ]},
   { title:L("The Huntsman"), scene:"granny_room",
     obj:L("Hold on — for help is nearer than you know"),
     beats:[
      {narr:L("Now a huntsman was passing the cottage upon his round, and he heard the snoring roll out through the open door. 'How loudly the old woman snores,' he thought. 'I had best make sure that all is well.'")},
      {dialog:[
        {who:"huntsman",em:"worried",line:L("Grandmother? ...Why — it is that old wolf I have hunted these many seasons! And what has become of the good woman?")}
      ]},
      {narr:L("Guessing at once what had happened, the huntsman took his knife and, snip by careful snip, cut open the sleeping wolf. Out stepped Little Red Riding Hood, blinking at the light — and after her came her grandmother, frightened, but quite unharmed.")},
      {dialog:[
        {who:"red",em:"grateful",line:L("Oh! How dark and close it was in there! I shall never, ever stray from the path again.")},
        {who:"granny",em:"warm",line:L("Bless you, good huntsman. You have given me back my dear grandchild — and my own life besides.")},
        {who:"huntsman",em:"warm",line:L("You are both safe now. And this old rogue shall trouble the wood no more.")}
      ]},
      {narr:L("Quickly they filled the wolf's belly with heavy stones, and when he woke and tried to spring away, the weight was too great, and down he tumbled, and troubled no one ever again. And from that day on, whenever Little Red Riding Hood walked through the wood, she kept to the path, held her tongue before strangers, and hurried straight to her grandmother's door.")}
     ]}
  ]},

 wolf:{
  ending:{ title:L("Undone by His Own Cunning"),
    text:L("You were the sharpest wolf in the whole wood — far too clever to pounce when patience would win you twice as much. But greed is a heavier thing than any wolf guesses, and in the end it was greed, not the huntsman, that was your true undoing. Better one honest meal than two won by a lie. So the wood remembers the wolf who wanted everything — and was left, at the very last, with a belly full of stones.") },
  chapters:[
   { title:L("A Hungry Wolf"), scene:"deep_wood",
     obj:L("Spy the little girl upon the path — and scheme"),
     beats:[
      {narr:L("You are the grey wolf of the great wood — lean, and sly, and very, very hungry. For three long days you have caught nothing, when down the path comes a little girl in a red hood, a basket on her arm, humming to herself.")},
      {dialog:[
        {who:"wolf",em:"alluring",line:L("Good morning, little one. What a fine red hood. And where might you be going, all alone in my wood?")},
        {who:"red",em:"warm",line:L("To my grandmother's cottage past the old mill, sir, with a cake and a pot of butter, for she has been ill.")}
      ]},
      {narr:L("How easily you could snap her up, here and now! But woodcutters are working near by, and their axes ring through the trees. No — a clever wolf is patient. You will have them both, the tender child and the old woman too, and no one the wiser.")}
     ]},
   { title:L("The Short Way"), scene:"mill",
     obj:L("Race the short path and reach the cottage first"),
     beats:[
      {narr:L("So you send the child off to gather flowers, and away you race by the shortest path, past the old mill, until you reach the grandmother's cottage first. You knock upon the door — tap, tap.")},
      {dialog:[
        {who:"granny",em:"soft",line:L("Who is there?")},
        {who:"wolf",em:"soft",line:L("It is your grandchild, little Red Riding Hood, come with a cake and a little pot of butter.")}
      ]},
      {narr:L("The poor grandmother, ill in her bed, called out for you to lift the latch. The door swung open — and in a single bound you sprang inside and swallowed her whole. Then you pulled on her cap and her gown, drew the curtains, and lay down in her bed to wait for the sweeter meal still to come.")}
     ]},
   { title:L("In Grandmother's Bed"), scene:"granny_room",
     obj:L("Lie in wait, and play the part of Grandmother"),
     beats:[
      {narr:L("You lie very still beneath the blankets, your grey ears hidden in her cap, and soon a small bright voice calls at the door. In she steps — your second supper — and looks at you with puzzled eyes.")},
      {dialog:[
        {who:"red",em:"worried",line:L("Grandmother, what big ears you have!")},
        {who:"wolf",em:"soft",line:L("All the better to hear you with, my dear.")},
        {who:"red",em:"worried",line:L("And what big eyes you have!")},
        {who:"wolf",em:"soft",line:L("All the better to see you with, my dear.")}
      ]},
      {dialog:[
        {who:"red",em:"worried",line:L("But Grandmother — what big teeth you have!")},
        {who:"wolf",em:"fierce",line:L("All the better to EAT you with!")}
      ], act:"pounce"}
     ]},
   { title:L("The Weight of Greed"), scene:"granny_room",
     obj:L("Feast, and sleep — and never hear the danger come"),
     beats:[
      {narr:L("Two meals in a single morning! Fat and heavy and pleased with yourself, you sprawl back upon the pillows and fall into a deep, snoring sleep. You never hear the huntsman's boots upon the step.")},
      {narr:L("While you dream, the huntsman opens your belly and sets the girl and her grandmother free, and fills you up instead with heavy stones. When you wake and try to leap away, the stones drag you down — and so the cleverest wolf in all the wood is undone, in the end, by nothing but his own greed.")}
     ]}
  ]},

 huntsman:{
  ending:{ title:L("The Keeper of the Wood"),
    text:L("You have hunted that old wolf for many a long season, and today, at last, you brought him down — not with the axe, but with a steady hand and a quicker wit. A grandmother lives, a child is wiser, and the path through the wood is safe once more. That is the huntsman's truest reward: not the pelt, but the peace. And the girl in the red hood will never forget the day your boots came up the step.") },
  chapters:[
   { title:L("The Woodsman's Round"), scene:"deep_wood",
     obj:L("Walk your round of the wood, and read its signs"),
     beats:[
      {narr:L("You are the huntsman of the great wood, strong of arm and kind of heart, your good axe upon your shoulder. For many a season you have tracked one old grey wolf — cleverer and crueller than all the rest — who has slipped your snares every time.")},
      {dialog:[
        {who:"huntsman",em:"wise",line:L("There is mischief in the air today. I saw that old wolf's tracks upon the path — heading toward the cottages, too. I had best keep my eyes wide open.")}
      ]},
      {narr:L("Along the way you pass a little girl in a red hood, singing to herself as she picks flowers in a sunlit glade. You tip your cap to her and walk on — but a shadow of worry follows you down the path.")}
     ]},
   { title:L("Something Amiss"), scene:"granny_house",
     obj:L("Pass the cottage — and trust that something is wrong"),
     beats:[
      {narr:L("Your round brings you past the cottage of the kind old grandmother who lives beyond the mill. But this morning her door hangs open, and from within rolls a snoring so loud it shakes the very shutters.")},
      {dialog:[
        {who:"huntsman",em:"worried",line:L("How loudly the old woman snores! That is no natural sleep. Something here is wrong — I had best look in.")}
      ]},
      {narr:L("You step softly inside — and there, in the grandmother's bed, wrapped in her cap and gown, lies the old grey wolf himself, his belly round and tight, fast asleep. Of the grandmother, and of the little girl from the glade, there is no sign at all.")}
     ]},
   { title:L("The Rescue"), scene:"granny_room",
     obj:L("Set the wolf's captives free, and end his mischief"),
     beats:[
      {narr:L("You raise your axe — but a thought stays your hand. What if the wolf has swallowed them whole? So instead you take your knife, and snip by careful snip you open the sleeping beast — and out step Little Red Riding Hood and her grandmother, pale and frightened, but alive and unharmed.")},
      {dialog:[
        {who:"red",em:"grateful",line:L("Oh, thank you, huntsman! How dark it was in there. I shall never leave the path again!")},
        {who:"granny",em:"warm",line:L("You have saved us both, good huntsman. However can we thank you?")},
        {who:"huntsman",em:"warm",line:L("Your safety is thanks enough. But let us make sure this old rogue never harms another soul.")}
      ]},
      {narr:L("Together you filled the wolf's belly with heavy stones and sewed him up again. When he woke and tried to spring away, the weight dragged him down, and he troubled the wood no more. Then the three of you sat by the fire and shared the little cake — and Little Red Riding Hood promised, this time for good, to keep to the path and heed her mother's word.")}
     ]}
  ]}
};

