const AYAZ_RELICS = {
  torn_coat:{name:L("The Ragged Coat and Fur Hat","Драная шуба и тымак","Жыртық тон мен тымақ"),lore:L("The old herdsman's coat and hat that Ayaz Bi nailed above his palace door, to remind himself each morning who he truly is.","Шуба и шапка старого пастуха, что Аяз би прибил над дверью дворца, чтобы каждое утро помнить, кто он есть на самом деле.","Аяз би сарайының есігіне қаққан кәрі шопанның тоны мен тымағы — әр таңда өзінің кім екенін ұмытпас үшін.")},
  gauhar:{name:L("The Ancient Gem","Древний самоцвет","Ежелгі гауһар"),lore:L("A jewel said to hold the power of Solomon's ring — yet two pale worms gnaw it hollow from within, unseen.","Самоцвет, в котором, говорят, сила перстня Сулеймана — но два бледных червя точат его изнутри, незримо.","Сүлейменнің жүзігіндей қасиеті бар дейтін тас — бірақ ішін екі ақ құрт көзге көрінбей кеміріп жатыр.")},
  riddle_gifts:{name:L("The Bride's Four Gifts","Четыре дара невесты","Қалыңдықтың төрт сыйы"),lore:L("A whetstone, a plate, a knife and a gem — a silent riddle sent by a woman who would only wed a man wiser than herself.","Точило, тарелка, нож и самоцвет — немая загадка от женщины, что выйдет лишь за того, кто мудрее её.","Қайрақ, тәрелке, пышақ пен гауһар — өзінен ақылды жанға ғана тиемін деген қыздың үнсіз жұмбағы.")},
  tulpar:{name:L("The Khan's Tulpar","Ханский тулпар","Ханның тұлпары"),lore:L("A prized steed of the khan — though a keen eye can tell it was raised on the milk of a cow.","Драгоценный скакун хана — хотя зоркий глаз распознает, что вскормлен он коровьим молоком.","Ханның асыл тұлпары — бірақ өткір көз оның сиыр сүтімен өскенін таниды.")}
};
