const AYAZ_COLD_SCENES={};
const AYAZ_AMBIENT = {
  khan:[{line:L("Bring my viziers — I have a question no one can answer.","Позовите визирей — у меня вопрос, на который никто не ответит.","Уәзірлерімді шақыр — ешкім жауап бере алмайтын сұрағым бар."),em:"bold"}],
  vizier:[{line:L("Eleven months, and still no answer. The khan will have our heads.","Одиннадцать месяцев — и всё нет ответа. Хан снимет нам головы.","Он бір ай өтті, әлі жауап жоқ. Хан басымызды алады."),em:"worried"}],
  mother:[{line:L("Some secrets are heavier than a whole life, child.","Иные тайны тяжелее целой жизни, дитя.","Кейбір сыр бүкіл өмірден ауыр, балам."),em:"sad"}],
  elder:[{line:L("Sit awhile, traveler. The sheep are in no hurry, and neither am I.","Присядь, путник. Овцам спешить некуда, и мне тоже.","Отыра кет, жолаушы. Қойдың асығары жоқ, менің де."),em:"wise"}],
  zhenge:[{line:L("Another suitor at the door — and this one has no beard and no horse!","Ещё один жених у порога — и этот без бороды и без коня!","Есік алдында тағы бір күйеу — бұл сақалсыз да, атсыз да!"),em:"gossip"}],
  villager:[{line:L("They say the khan's new vizier was a beggar only yesterday.","Говорят, новый визирь хана ещё вчера был нищим.","Ханның жаңа уәзірі кеше ғана қайыршы еді дейді."),em:"gossip"}],
  guard:[{line:L("Move along. The khan's business is not for idle ears.","Проходи. Дела хана не для праздных ушей.","Жүре бер. Ханның ісі бос құлаққа арналмаған."),em:"cool"}]
};
