const AYAZ_DISCOVERIES={
  steppe_foot:[
    {id:"ay_tymak",x:26,y:42,ic:"🧢",name:L("The Fur Hat (Tymak)","Тымак","Тымақ"),text:L("A tymak of sheepskin turned fleece-inward keeps a herdsman's head warm through the fiercest steppe blizzard. A worn one marks a life of honest, humble labour.","Тымак из овчины мехом внутрь хранит голову пастуха в самый лютый буран. Потёртый — знак честного, скромного труда.","Жүні ішіне қаратылған қой терісі тымақ шопанның басын ең қатты боранда да жылы ұстайды. Тозығы — адал, қарапайым еңбектің белгісі.")},
    {id:"ay_shengel",x:70,y:36,ic:"🌾",name:L("Camel-thorn (Shengel)","Верблюжья колючка (шенгель)","Шеңгел"),text:L("A thorny bush that tears at cloth and no beast will eat — yet burns through the night like the embers of saxaul. Even the useless-seeming has its worth.","Колючий куст, что рвёт одежду и не по зубам скоту, — но горит всю ночь, как угли саксаула. Даже с виду бесполезное имеет цену.","Киім жыртатын, мал жемейтін тікенді бұта — бірақ сексеуілдің шоғындай түні бойы жанады. Пайдасыз көрінген нәрсенің де құны бар.")}],
  khan_orda:[
    {id:"ay_shanyrak",x:50,y:20,ic:"☀️",name:L("The Shanyrak","Шанырак","Шаңырақ"),text:L("The wooden crown at the top of the yurt, open to the sky. It is the emblem of the family and the nation — the sun on the Kazakh flag is its very shape.","Деревянный венец на вершине юрты, открытый небу. Символ семьи и народа — солнце на флаге Казахстана и есть его очертания.","Аспанға ашылған киіз үйдің ағаш тәжі. Отбасы мен елдің нышаны — Қазақстан туындағы күн — оның нақ бейнесі.")},
    {id:"ay_syrmak",x:30,y:64,ic:"🟥",name:L("The Felt Carpet (Syrmak)","Войлочный ковёр (сырмак)","Сырмақ"),text:L("Every curl of the ram's-horn pattern is stitched by hand over long winter months. The floor of a khan tells the wealth and patience of his house.","Каждый завиток узора «бараний рог» вышит вручную за долгие зимние месяцы. Пол хана говорит о богатстве и терпении его дома.","Қошқар мүйіз өрнегінің әр иірімі ұзақ қыс бойы қолмен тігіледі. Ханның кілемі оның үйінің байлығы мен төзімін айтады.")}],
  river_ford:[
    {id:"ay_tulpar",x:40,y:46,ic:"🐎",name:L("The Tulpar","Тулпар","Тұлпар"),text:L("The winged steed of Kazakh legend, swift as thought. A true horseman reads a horse's blood in the way it drinks and steps — as Jaman read the cow in the khan's.","Крылатый конь казахских легенд, быстрый как мысль. Настоящий наездник читает кровь коня по тому, как тот пьёт и ступает — как Жаман распознал корову в ханском.","Қазақ аңызындағы қанатты тұлпар, ойдай жүйрік. Нағыз атбегі жылқының қанын оның су ішісі мен басуынан таниды — Жаман ханның тұлпарынан сиырды танығандай.")}]
};
const AYAZ_PLAYABLE = [
  {key:"jaman", name:AYAZ_NAME.jaman, role:L("The Humble Sage","Скромный мудрец","Қарапайым дана"),
   power:L("You own nothing but a torn coat and a clear mind — yet you weigh a horse, a jewel and a khan's own blood with a single glance, and never once let power turn your head.","У тебя нет ничего, кроме драной шубы и ясного ума — но ты одним взглядом взвешиваешь коня, самоцвет и кровь самого хана, и власть ни разу не вскружит тебе голову.","Жыртық тон мен таза ақылдан басқа дәулетің жоқ — бірақ атты, гауһарды, тіпті ханның тегін бір қараумен өлшейсің, әрі билік басыңды бір рет те айналдырмайды.")},
  {key:"khan", name:AYAZ_NAME.khan, role:L("The Khan Who Was Weighed","Хан, которого взвесили","Өлшенген хан"),
   power:L("You rule a great steppe and command forty viziers — but a beggar in a torn coat will hold up a mirror to your throne, your blood and your heart, and you must be brave enough to look.","Ты правишь великой степью и повелеваешь сорока визирями — но нищий в драной шубе поднесёт зеркало к твоему трону, твоей крови и твоему сердцу, и хватит ли тебе смелости взглянуть.","Ұлы даланы билеп, қырық уәзірге әмір етесің — бірақ жыртық тонды бір қайыршы тағыңа, тегіңе, жүрегіңе айна тосады, ал оған қарауға батылың жете ме.")},
  {key:"mendi", name:AYAZ_NAME.mendi, role:L("The Bride Wiser Than Her Suitors","Невеста мудрее женихов","Күйеулерінен ақылды қалыңдық"),
   power:L("For twenty years you have turned away every rich fool with a silent riddle of four small things. You will marry only a mind that matches your own — and when he is condemned, you will ride to cut the rope yourself.","Двадцать лет ты немой загадкой из четырёх мелочей отваживаешь всякого богатого глупца. Ты выйдешь лишь за равный тебе ум — а когда его осудят, сама поскачешь перерезать верёвку.","Жиырма жыл бойы төрт кішкене заттан құралған үнсіз жұмбақпен әрбір бай ақымақты қайтарасың. Тек өзіңдей ақылға ғана тиесің — ал ол дарға тартылғанда, жіпті кесуге өзің шабасың.")}
];
const AYAZ_STORY = {
 jaman:{
  ending:{ title:L("Ayaz Bi, the Just","Аяз би Справедливый","Әділ Аяз би"),
    text:L("Without a single battle, Jaman — now Ayaz Bi — joined the pastures of five khanates and set friendship between their peoples. Whoever could not find justice in his own land came to him, and found it. And above his palace door he nailed his old torn coat and fur hat, so that whenever his heart began to stray he might look up and say: 'Hey, Ayaz — do not swell because you are rich, do not strut because you are khan. Ayaz Bi, know your measure; ant, know your path.'",
      "Без единой битвы Жаман — теперь Аяз би — соединил пастбища пяти ханств и установил дружбу меж их народами. Кто не находил правды в своей земле, шёл к нему и находил её. А над дверью дворца он прибил свою старую драную шубу и тымак, чтобы всякий раз, как сердце начнёт заноситься, поднять взгляд и сказать: «Эй, Аяз, — не пыжься, что богат, не заносись, что хан. Аяз би, знай свою меру; муравей, знай свою тропу».",
      "Бір соғыссыз-ақ Жаман — енді Аяз би — бес хандықтың қонысын біріктіріп, халықтар арасында достық орнатты. Өз елінен әділдік таппаған әркім оған келіп, әділдікті тапты. Ал сарайының есігіне ескі жыртық тоны мен тымағын қақты — көңілі аси бастаған сайын соған қарап: «Ай, Аяз, баймын деп аспа, ханмын деп таспа! Аяз би, әліңді біл, құмырсқа жолыңды біл!» — деп айту үшін.") },
  chapters:[
   { title:L("The Worst on Earth","Худшее на свете","Дүниедегі ең жаман"), scene:"steppe_foot",
     obj:L("Meet Jaman at the foot of the mountain","Встретьте Жамана у подножия горы","Тау етегінде Жаманмен таныс"),
     beats:[
      {narr:L("Long ago there ruled a khan named Madan, and under him served forty viziers, each reckoned the wisest of the wise. One day the khan set them a task: 'Bring me the worst of all men, the worst of all plants, and the worst of all birds. I give you eleven months — fail, and you answer for it.'",
        "Давным-давно правил хан по имени Мадан, и служили при нём сорок визирей, каждый из которых слыл мудрейшим из мудрых. Однажды хан задал им задачу: «Отыщите мне худшего из людей, худшую из трав и худшую из птиц. Даю одиннадцать месяцев — не сыщете, ответите головой».",
        "Ертеде Мадан деген хан болыпты, оның қырық уәзірі болыпты, әрқайсысы данадан дана саналған. Бірде хан оларға тапсырма берді: «Маған адамның жаманын, шөптің жаманын, құстың жаманын тауып келіңдер. Он бір ай беремін — таппасаңдар, жазаласыңдар».")},
      {narr:L("The viziers searched far and long. For the worst plant they chose the camel-thorn, that tears the clothes and feeds no beast; for the worst bird, the ragged pheasant. But the worst of men they could not find — until, at the foot of a mountain, they saw a poor herdsman in a torn coat and fur hat, minding a handful of sheep.",
        "Долго искали визири. Худшей травой сочли верблюжью колючку, что рвёт одежду и не кормит скот; худшей птицей — облезлого фазана. А худшего из людей найти не могли — пока у подножия горы не увидели бедного пастуха в драной шубе и тымаке при десятке овец.",
        "Уәзірлер ұзақ іздеді. Шөптің жаманы деп киім жыртатын, мал жемейтін шеңгелді, құстың жаманы деп жүні жоқ қырғауылды алды. Ал адамның жаманын таба алмай жүргенде, тау етегінде жыртық тон мен тымақ киген, бес-он қой баққан кедей адамды көрді.")},
      {dialog:[
        {who:"villager",em:"gossip",line:L("There — that wretch in rags. Surely the worst of men, if ever there was one.","Вон тот оборванец. Уж верно худший из людей, коли есть такой.","Әне — жыртық киімді сорлы. Адамның жаманы болса, осы шығар.")},
        {who:"jaman",em:"warm",line:L("Peace be on your road, my lords. What sends so grand a company to so poor a hillside?","Мир вашей дороге, господа. Что привело столь знатных людей на столь бедный склон?","Жол болсын, мырзалар. Мұндай мәртебелі жұртты мынадай кедей белге не айдап келді?")},
        {who:"jaman",em:"resolve",line:L("The worst of men, you say? Then look no further. If a worst man is what your khan needs — I am he.","Худший из людей, говорите? Так не ищите дальше. Коли хану нужен худший — это я.","Адамның жаманы дейсіңдер ме? Ендеше әрі іздемеңдер. Ханға жаман керек болса — сол менмін.")}
      ]},
      {narr:L("They set him on a horse and rode for the court. But along the way Jaman looked at their bundles and shook his head. 'You have the wrong plant and the wrong bird,' he said. 'The worst plant is the reed-mace; the worst bird, the magpie.' And he made them throw away the thorn and the pheasant, and gather reed-mace and a magpie instead.",
        "Посадили его на коня и поехали ко двору. Но по пути Жаман глянул на их поклажу и покачал головой: «Не та трава и не та птица. Худшая трава — рогоз, худшая птица — сорока». И заставил выбросить колючку с фазаном, а взять рогоз да сороку.",
        "Оны атқа мінгізіп, ордаға тартты. Бірақ жолда Жаман олардың бумасына қарап басын шайқады: «Шөп те, құс та қате. Шөптің жаманы — қарақоға, құстың жаманы — сауысқан». Сөйтіп шеңгел мен қырғауылды тастатып, орнына қарақоға мен сауысқанды алдырды.")}
     ]},

   { title:L("The Khan's Court","Двор хана","Ханның ордасы"), scene:"khan_orda",
     obj:L("Explain to Khan Madan why the worst is worst","Объясните хану Мадану, отчего худшее — худшее","Хан Маданға жаманның неге жаман екенін түсіндір"),
     beats:[
      {narr:L("At the court, the khan barely glanced at the ragged stranger. 'Take him to the kitchen — give him soup and bread.' Then he turned on his viziers, for he believed the thorn and the pheasant were the right answers, and demanded why they had brought reed-mace and a magpie.",
        "При дворе хан едва взглянул на оборванца: «В кухню его — дайте похлёбки и хлеба». А после накинулся на визирей, ибо считал верными колючку и фазана, и спросил, зачем принесли рогоз да сороку.",
        "Ордада хан жыртық киімді бейтанысқа көзінің қиығын да салмады: «Ас үйге апарыңдар — көже мен нан беріңдер». Сосын уәзірлеріне тап берді, өйткені шеңгел мен қырғауылды дұрыс деп ойлаған, қарақоға мен сауысқанды неге әкелгенін сұрады.")},
      {dialog:[
        {who:"vizier",em:"worried",line:L("Great khan, we chose them ourselves — but a ragged man on the road unchose them, and made us bring these instead.","Великий хан, мы сами их выбрали — но оборванец на дороге переиначил и велел взять эти.","Ұлы хан, өзіміз таңдап едік — бірақ жолдағы жыртық киімді адам өзгертіп, мыналарды алдырды.")},
        {who:"khan",em:"bold",line:L("A beggar overrules my forty wise men? Bring him back. Let him answer to me.","Нищий переспорил моих сорок мудрецов? Верните его. Пусть ответит мне.","Қайыршы қырық данамды жеңді ме? Қайтарыңдар оны. Маған жауап берсін.")}
      ]},
      {dialog:[
        {who:"khan",em:"bold",line:L("So. Why is the reed-mace worse than the thorn that tears our clothes?","Итак. Отчего рогоз хуже колючки, что рвёт нам одежду?","Ал енді. Киім жыртатын шеңгелден қарақоға неге жаман?")},
        {who:"jaman",em:"wise",line:L("Because the thorn, for all its spite, burns through the night like the embers of saxaul — it warms a poor man's tent. But reed-mace will not catch; blow on it and flame and ember die together, and the ash fills the whole house. No beast will eat it. A thing that gives nothing at all — that is the worst.","Оттого, что колючка при всей злобе горит всю ночь, как угли саксаула, — греет юрту бедняка. А рогоз не займётся; дунешь — и пламя с углями гаснут разом, а зола заполняет весь дом. И скот его не ест. То, что не даёт вовсе ничего, и есть худшее.","Өйткені шеңгел бар зәрімен түні бойы сексеуілдің шоғындай жанады — кедейдің үйін жылытады. Ал қарақоға тұтанбайды; үрлесең — жалыны мен шоғы бірге сөнеді, күлі бүкіл үйді алады. Мал да жемейді. Түк бермейтін нәрсе — ең жаман сол.")}
      ], act:"riddle",
        riddle:{ q:L("By Jaman's reckoning, which is truly the worst plant?","По разумению Жамана, какая трава хуже всех?","Жаманның пайымынша, шөптің қайсысы ең жаман?"),
          opts:[ {t:L("Reed-mace — it gives nothing at all","Рогоз — не даёт вовсе ничего","Қарақоға — түк те бермейді"),ok:true},
                 {t:L("Camel-thorn — it tears our clothes","Верблюжья колючка — рвёт одежду","Шеңгел — киім жыртады"),ok:false},
                 {t:L("Whatever no beast will eat","Что не ест скот","Мал жемейтіні"),ok:false},
                 {t:L("The one with the sharpest spines","С самыми острыми шипами","Тікені өткірі"),ok:false} ] }},
      {dialog:[
        {who:"khan",em:"bold",line:L("And the magpie? The pheasant is the uglier bird by far.","А сорока? Фазан-то куда безобразнее.","Ал сауысқан ше? Қырғауыл әлдеқайда ұсқынсыз ғой.")},
        {who:"jaman",em:"wise",line:L("Ugliness is only how a creature was born, khan — the pheasant still serves. But the magpie is mottled without and mottled within: two never fly as one, never settle as one. A creature with no loyalty in it — that is the worst bird.","Безобразие — лишь то, каким тварь родилась, хан; фазан всё же служит. А сорока пестра снаружи и пестра внутри: две вместе не взлетят, вместе не сядут. Тварь без верности — вот худшая птица.","Ұсқынсыздық — жаратылысы ғана, хан; қырғауыл сонда да пайдаға жарайды. Ал сауысқан сырты да ала, іші де ала: екеуі бірге ұшпайды, бірге қонбайды. Бірлігі жоқ жәндік — құстың жаманы сол.")},
        {who:"khan",em:"resolve",line:L("Well argued. And yourself — you called yourself the worst of men. On what grounds?","Ловко сказано. А сам — назвался худшим из людей. На каком основании?","Тауып айттың. Ал өзің — адамның жаманымын дедің. Не негізде?")},
        {who:"jaman",em:"sad",line:L("I am fifty, khan. My age-mates have wives, sons, daughters-in-law to serve them, and comfort in their tents. And I still ride behind other men, in another's service, owning nothing. If that is not the worst of men — what is?","Мне пятьдесят, хан. У ровесников — жёны, сыновья, невестки на услужении, покой в юрте. А я всё еду позади других, в чужом услужении, без кола и двора. Коли это не худший из людей — то что же?","Елудемін, хан. Құрбыларымның әйелі, ұлы, қызмет ететін келіні, үйінде қызығы бар. Ал мен әлі кісі артында, біреудің қызметінде, түгім жоқ жүрмін. Бұл адамның жаманы болмаса — не?")}
      ]}
     ]},

   { title:L("The Three Tests","Три испытания","Үш сынақ"), scene:"river_ford",
     obj:L("Pass the khan's tests of the eye and the mind","Пройдите ханские испытания глаза и ума","Ханның көз бен ақыл сынағынан өт"),
     beats:[
      {narr:L("The khan was no longer amused — he was intent. 'I have a prized tulpar. Ride it, and tell me its fault.' Jaman mounted, crossed the river to the far bank and back, and returned wearing a small smile.",
        "Хану стало уже не до забавы — он был поглощён. «Есть у меня драгоценный тулпар. Проедь на нём и скажи изъян». Жаман сел верхом, переправился за реку и обратно и вернулся с лёгкой усмешкой.",
        "Ханға енді күлкі емес, ынта болды. «Асыл тұлпарым бар. Мініп көр де, мінін айт». Жаман мінді, өзеннен арғы бетке өтіп қайтты, бетінде жеңіл жымиыспен оралды.")},
      {dialog:[
        {who:"jaman",em:"resolve",line:L("A fine beast, khan — but it was raised on the milk of a cow.","Славный конь, хан, — только вскормлен коровьим молоком.","Жақсы жануар, хан — бірақ сиыр сүтімен өскен.")},
        {who:"khan",em:"waking",line:L("...You are right. Its dam died foaling, and we saved the foal and reared it on a cow. But how — how could your eye see it?","...Верно. Матка пала в родах, мы спасли жеребёнка и вскормили коровой. Но как — как разглядел твой глаз?","...Рас. Биесі құлындай алмай өлді, құлынды сиырмен асырадық. Бірақ қалай — көзің қалай көрді?")},
        {who:"jaman",em:"wise",line:L("At the water it dipped its muzzle deep and shook a hind leg as it stepped — the way of a cow, never of a horse. A creature carries how it was raised in the smallest of its movements.","У воды оно окунуло морду глубоко и дёрнуло задней ногой при шаге — повадка коровья, не конская. Тварь несёт своё воспитание в самом малом движении.","Суда тұмсығын тереңге малып, басқанда артқы аяғын сілкіді — сиырдың әдеті, аттың емес. Жануар тәрбиесін ең кішкене қимылында алып жүреді.")}
      ]},
      {narr:L("Then the khan brought out an ancient gem, said to hold the power of Solomon's ring. 'Tell me its secret.' Jaman weighed it in his palm a long moment.",
        "Затем хан вынес древний самоцвет, в котором, сказывали, сила перстня Сулеймана. «Открой его тайну». Жаман долго взвешивал камень на ладони.",
        "Сосын хан Сүлейменнің жүзігіндей қасиеті бар дейтін ежелгі гауһарды шығарды. «Сырын аш». Жаман тасты алақанында ұзақ салмақтады."), place:"khan_orda"},
      {dialog:[
        {who:"jaman",em:"wise",line:L("It is a true gem, khan — but its power has two years left. Two pale worms gnaw within; the shell is a knife's-back thick. When they break through, it will be worth nothing.","Самоцвет истинный, хан, — но силы в нём на два года. Внутри точат два бледных червя; скорлупа толщиной с обух ножа. Прогрызут — и грош ему цена.","Тас шын қасиетті, хан — бірақ қуаты екі жылдық. Ішінде екі ақ құрт кеміреді; қабығы пышақ сыртындай. Тесіп шыққанда — түкке тұрмайды.")},
        {who:"khan",em:"urgent",line:L("Worms, inside a stone? Break it open!","Черви, в камне? Расколоть его!","Тас ішінде құрт па? Жарыңдар!")}
      ]},
      {narr:L("They cracked the gem — and there within were two pale worms, all but through the shell. The court fell silent. 'How,' breathed the khan, 'could you know what no eye could see?' 'A gem should weigh as much as its power,' said Jaman. 'This one had grown too light.'",
        "Раскололи самоцвет — а внутри два бледных червя, почти уж проточившие скорлупу. Двор онемел. «Как, — выдохнул хан, — ты узнал незримое?» «Самоцвет должен весить в меру своей силы, — сказал Жаман. — А этот стал слишком лёгок».",
        "Гауһарды жарса — ішінде екі ақ құрт, қабығын тесуге аз-ақ қалған. Орда тынды. «Қалай, — деді хан демін ішіне тартып, — көзге көрінбесті білдің?» «Тас қасиетіне сай салмақты болуы керек, — деді Жаман. — Ал бұл тым жеңілдеп кеткен».")},
      {dialog:[
        {who:"jaman",em:"wise",line:L("The heaviness had left it. And where weight leaves a stone, khan, something has eaten the good out from the inside.","Тяжесть ушла из него. А где камень теряет вес, хан, там что-то выело добро изнутри.","Салмағы кетіпті. Тас салмақ жоғалтқан жерде, хан, іштен бірдеңе жақсылығын жеп қойған.")}
      ], act:"riddle",
        riddle:{ q:L("How did Jaman know the gem was hollowed within?","Как Жаман узнал, что самоцвет выеден изнутри?","Жаман гауһардың іші кемірілгенін қайдан білді?"),
          opts:[ {t:L("It had grown too light for its power","Стал слишком лёгок для своей силы","Қасиетіне қарай тым жеңілдеген"),ok:true},
                 {t:L("He heard the worms moving","Услышал, как двигались черви","Құрттың қозғалысын естіді"),ok:false},
                 {t:L("He saw a crack on the surface","Увидел трещину на поверхности","Бетінен жарықшақ көрді"),ok:false},
                 {t:L("The gem had lost its colour","Камень потерял цвет","Тас түсін жоғалтқан"),ok:false} ] }}
     ]},

   { title:L("The Secret of the Throne","Тайна трона","Тақ сыры"), scene:"khan_orda",
     obj:L("Weigh the khan himself — and speak the truth","Взвесьте самого хана — и скажите правду","Ханның өзін өлше — де шындықты айт"),
     beats:[
      {dialog:[
        {who:"khan",em:"bold",line:L("You have weighed my thorn, my bird, my horse and my jewel. Now weigh me. How many generations of khans stand behind my throne?","Ты взвесил мою колючку, птицу, коня и самоцвет. Теперь взвесь меня. Сколько поколений ханов за моим троном?","Шеңгелімді, құсымды, атымды, гауһарымды өлшедің. Енді мені өлше. Тағымның артында неше атадан хан тұр?")},
        {who:"jaman",em:"resolve",line:L("Your mind, khan, is second to no man's. But the khanship is yours and yours alone. No khan stands behind you. In truth — you are the son of a baker.","Ум твой, хан, никому не уступит. Но ханство — твоё, и только твоё. Ни один хан не стоит за тобой. По правде — ты сын пекаря.","Ақылың, хан, ешкімнен кем емес. Бірақ хандық — тек өзіңдікі. Артыңда бірде-бір хан жоқ. Шынында — сен наубайдың баласысың.")},
        {who:"khan",em:"fierce",line:L("A baker's son? I have been khan seven generations deep! Guard your tongue — or lose it. Bring my mother. Let her deny it to your face.","Сын пекаря? Я хан в седьмом колене! Придержи язык — не то лишишься его. Позовите мать. Пусть в глаза тебе солжёт обратное.","Наубайдың баласы? Мен жеті атадан ханмын! Тіліңді тый — әйтпесе айырыласың. Шешемді шақыр. Бетіңе қарап терістесін.")}
      ]},
      {narr:L("The khan's aged mother was brought in. When she heard what Jaman had said, she sank down, sighed from the bottom of her soul, and at last unlocked a secret she had carried for eighty years.",
        "Привели старую мать хана. Услышав слова Жамана, она осела, вздохнула из самой глубины души и наконец отомкнула тайну, что несла восемьдесят лет.",
        "Ханның кәрі шешесін алып келді. Жаманның сөзін естігенде, ол отыра кетті, жан тереңінен күрсініп, сексен жыл сақтаған сырын ақыры ашты.")},
      {dialog:[
        {who:"mother",em:"tears",line:L("Your father was Zarly Khan — the Poison Khan. Before me he took nineteen wives, and killed every one for bearing only daughters. I was the twentieth, and I too carried a girl.","Твой отец был Зарлы-хан — Ядовитый хан. До меня он взял девятнадцать жён и всех убил за то, что рожали дочерей. Я была двадцатой, и я тоже носила девочку.","Әкең Зәрлі хан еді. Менен бұрын он тоғыз әйел алып, қыз тапқаны үшін бәрін өлтірген. Мен жиырмасыншысы едім, мен де қыз көтердім.")},
        {who:"mother",em:"tears",line:L("The baker's wife was with child in the same days — with a son. In secret I begged her: give me your boy, take my girl, and tell no living soul. On the night we both gave birth, we changed the children with our own hands. The son I lifted up was you.","В те же дни жена пекаря носила сына. Тайно я умолила её: дай мне мальчика, возьми мою девочку и не скажи ни единой живой душе. В ночь, когда мы обе родили, мы своими руками поменяли детей. Сын, что я подняла, — ты.","Сол күндері наубайдың әйелі ұл көтеріп жүрген. Жасырын жалындым: ұлыңды бер, қызымды ал, ешкімге айтпа. Екеуміз босанған түні балаларды өз қолымызбен ауыстырдық. Менің көтерген ұлым — сен едің.")},
        {who:"khan",em:"empty",line:L("...Then there is no arguing with the truth. I am not fit for this throne. You who saw it — you are.","...Тогда с правдой не поспоришь. Я недостоин трона. Ты, кто это разглядел, — достоин.","...Ендеше шындықпен таласуға болмас. Мен таққа лайық емеспін. Оны көрген сен — лайықсың.")}
      ]},
      {dialog:[
        {who:"jaman",em:"gentle",line:L("No, khan. Yesterday I came riding behind a horse as 'the worst of men.' I will not sit your throne today. Let me walk in your shadow — that is enough.","Нет, хан. Вчера я въехал позади коня «худшим из людей». Не сяду сегодня на трон. Дай мне идти в твоей тени — этого довольно.","Жоқ, хан. Кеше ат артында «адамның жаманы» боп келдім. Бүгін таққа отырмаймын. Көлеңкеңде жүрсем болды.")},
        {who:"khan",em:"waking",line:L("But tell me this — how did you know I was a baker's son before my own mother spoke?","Но скажи — как ты узнал, что я сын пекаря, ещё до слов матери?","Бірақ айтшы — шешем айтпай тұрып, наубайдың баласы екенімді қайдан білдің?")},
        {who:"jaman",em:"wise",line:L("I was your guest, khan. A khan by blood sets horse-fat and choice meat before a guest. You sent me soup and bread and packed me off to the kitchen — the habit of common folk. Blood keeps its old customs, whatever crown it wears.","Я был твоим гостем, хан. Хан по крови ставит гостю конский жир и лучшее мясо. Ты послал похлёбку с хлебом и спровадил на кухню — обычай простолюдина. Кровь хранит старые привычки, какой венец ни надень.","Қонағың едім, хан. Тектi хан қонаққа жал мен жая тартады. Сен көже мен нан беріп, ас үйге жібердің — қарапайым жұрттың салты. Қандай тәж кисең де, тек ескі әдетін сақтайды.")}
      ]}
     ]},

   { title:L("The Clever Bride","Мудрая невеста","Ақылды қалыңдық"), scene:"mendi_yurt",
     obj:L("Read the riddle of the four gifts","Разгадайте загадку четырёх даров","Төрт сыйдың жұмбағын шеш"),
     beats:[
      {narr:L("Jaman became the khan's dearest counsellor. One day he saw a great white yurt raised in the town, ringed by a crowd. Within lived Mendi, daughter of the rich Uälibai — who for twenty years had turned away every suitor, vowing to wed only a man wiser than herself.",
        "Жаман стал ближайшим советником хана. Однажды он увидел в городе большую белую юрту в кольце толпы. В ней жила Менди, дочь богача Уалибая, — что двадцать лет отваживала женихов, поклявшись выйти лишь за того, кто мудрее её.",
        "Жаман ханның ең жақын кеңесшісі болды. Бірде қалада халық қаумалаған үлкен ақ отауды көрді. Онда бай Уәлібайдың қызы Менді тұратын — жиырма жыл бойы күйеулерді қайтарып, тек өзінен ақылдыға тиемін деп ант еткен.")},
      {dialog:[
        {who:"zhenge",em:"gossip",line:L("Another one at the door, mistress — and this one has no beard and no horse! Shall I send him off like the rest?","Ещё один у порога, госпожа, — и без бороды, без коня! Спровадить, как прочих?","Есік алдында тағы біреу, бикеш — сақалы да, аты да жоқ! Басқалардай қайтарайын ба?")},
        {who:"mendi",em:"calm",line:L("How would you know his worth by his beard, sister? Take him these four, and we shall see.","По бороде ли судить о человеке, женге? Отнеси ему эти четыре — там и увидим.","Сақалынан адамның бағасын қайдан білесің, жеңеше? Мына төртеуін апар — сонда көреміз.")}
      ]},
      {narr:L("The sister-in-law carried out four small things: a whetstone, a plate, a knife, and a gem. Jaman looked at them, called for a hammer and anvil, and set to work. He ground the whetstone to dust, smashed the plate to shards, snapped the knife at its base — and split the gem clean in two.",
        "Женге вынесла четыре мелочи: точило, тарелку, нож и самоцвет. Жаман посмотрел, велел подать молот и наковальню и взялся за дело. Он стёр точило в пыль, разбил тарелку вдребезги, сломал нож у основания — и раскроил самоцвет надвое.",
        "Жеңге төрт затты алып шықты: қайрақ, тәрелке, пышақ, гауһар. Жаман қарап, балға мен төс сұратып, іске кірісті. Қайрақты күлге ұнтады, тәрелкені шағып уатты, пышақты жетесінен сындырды — гауһарды қақ бөлді.")},
      {dialog:[
        {who:"jaman",em:"resolve",line:L("Carry these back to your mistress. Tell her the answer is given.","Отнеси это назад госпоже. Скажи — ответ дан.","Мынаны бикешке қайтар. Айт — жауап берілді.")},
        {who:"mendi",em:"waking",line:L("Ground like a whetstone, shattered like a plate, beheaded like a knife — yet he split me like the gem and won me. If that man is no devil but flesh and blood, he is the one I take. Call him in!","Стёрт, как точило, разбит, как тарелка, обезглавлен, как нож, — но раскроил меня, как самоцвет, и добыл. Коли он не бес, а плоть и кровь — за него и пойду. Зовите!","Қайрақтай езілгенше, тәрелкедей уатылғанша, пышақтай басы кесілгенше — бірақ гауһардай жарып, мені алды. Ол шайтан емес, адам болса — соған тием. Шақыр!")}
      ], act:"riddle",
        riddle:{ q:L("What did the four gifts secretly ask of a man?","О чём тайно спрашивали четыре дара?","Төрт сый адамнан жасырын нені сұрады?"),
          opts:[ {t:L("To keep a secret though ground, smashed and beheaded","Хранить тайну, хоть сотрут, разобьют и обезглавят","Езілсе де, уатылса да, басы кесілсе де сыр сақтауды"),ok:true},
                 {t:L("To be the richest man in the land","Быть богатейшим в краю","Елдегі ең бай болуды"),ok:false},
                 {t:L("To be a great and mighty warrior","Быть великим воином","Ұлы батыр болуды"),ok:false},
                 {t:L("To bring the finest wedding gifts","Принести лучшие свадебные дары","Ең жақсы той сыйын әкелуді"),ok:false} ] }},
      {cine:[
        {narr:L("But the woman's brothers, suspicious that she had waited so long, had set a guard. At first light, as Jaman left, they seized him and dragged him before the khan, swearing he had insulted them.","Но братья невесты, дивясь, отчего она столько ждёт, выставили дозор. На рассвете, едва Жаман вышел, его схватили и поволокли к хану, клянясь, что он их оскорбил.","Бірақ қыздың ағалары, неге сонша күткеніне күдіктеніп, қарауыл қойған. Таң ата Жаман шыға бергенде, ұстап алып, ханға сүйреп, бізді балағаттады деп ант етті."), cam:"up", fx:"dust", wait:2600},
        {narr:L("Jaman had sworn to guard the secret unto death, and so he denied everything. The khan, enraged, ordered him hanged. They led him to the square and drew the rope tight.","Жаман поклялся хранить тайну до смерти и оттого всё отрицал. Разгневанный хан велел его повесить. Повели на площадь и затянули петлю.","Жаман сырды өлгенше сақтауға ант еткен, сондықтан бәрін терістеді. Ашуланған хан оны дарға асуға бұйырды. Алаңға апарып, дұзақты тартты."), cam:[0,-3,1.12,2.2], fx:"dust", wait:3000, place:"town_square"}
      ]},
      {cine:[
        {narr:L("As his breath was failing, a rider on a white horse, all in white with a veil across the face, cut the rope with a single stroke, laid a sword flat across his chest, and rode away.","Когда дыхание уж покидало его, всадник на белом коне, весь в белом и с покрывалом на лице, единым махом рассёк верёвку, положил меч поперёк его груди и ускакал прочь.","Демі бітуге айналғанда, ақ атты, ақ киімді, бетіне перде жапқан салт атты жіпті бір-ақ шауып кесіп, кеудесіне қылышты көлденең тастап, кетіп қалды."), cam:[0,-4,1.2,2.4], fx:"gleam", wait:3000}
      ],
      dialog:[
        {who:"jaman",em:"resolve",line:L("Take me back to the khan. Now I will speak the truth.","Ведите меня к хану. Теперь я скажу правду.","Мені ханға апарыңдар. Енді шындықты айтам.")}
      ]},
      {dialog:[
        {who:"jaman",em:"gentle",line:L("Yes, khan — I went to her, and I gave my word. I hid it because her four gifts asked for a man who keeps a secret though ground, smashed and beheaded. The veiled rider was Mendi herself: 'Do not die innocent for my sake,' she said. 'A vow holds no power over a blade — take back your oath.' She freed me, and so I speak.","Да, хан, — я был у неё и дал слово. Скрывал, ибо четыре дара просили того, кто хранит тайну, хоть сотрут, разобьют и обезглавят. Всадник под покрывалом — сама Менди: «Не умирай безвинно за меня, — сказала она. — Над клинком клятва не властна — возьми свой обет назад». Она освободила меня — потому и говорю.","Иә, хан — бардым, уәде бердім. Жасырғаным — төрт сый езілсе де, уатылса да, басы кесілсе де сыр сақтайтын жанды сұраған. Перделі салт атты — Мендінің өзі: «Мен үшін жазықсыз өлме, — деді. — Қылыш үстінде ант жүрмейді — сертіңді қайтып ал». Ол мені босатты — сондықтан айтып тұрмын.")},
        {who:"khan",em:"grateful",line:L("Then the fault was never yours. Such a man, and such a woman, must not be kept apart. She is yours — with thirty days of games and forty days of feasting.","Стало быть, вины на тебе и не было. Такого мужа с такой женой разлучать нельзя. Она твоя — с тридцатью днями игр и сорока днями пира.","Ендеше кінә сенде болмаған. Мұндай ер мен мұндай әйелді айыруға болмас. Ол сенікі — отыз күн ойын, қырық күн тоймен.")}
      ]}
     ]},

   { title:L("The Journey of No Return","Дорога, откуда не возвращаются","Барсакелмес сапары"), scene:"jaman_yurt",
     obj:L("Outlast the khan's envy with your wife's counsel","Переживите зависть хана советом жены","Әйеліңнің ақылымен ханның қызғанышын жең"),
     beats:[
      {narr:L("The forty viziers, long pushed aside, plotted to part the friends. They praised Jaman's wife to the khan until he came to see her — and, seeing her grace, coveted her, and asked the viziers how she might be won.",
        "Сорок визирей, давно оттеснённые, замыслили рассорить друзей. Они так расхваливали хану жену Жамана, что он пришёл взглянуть — и, увидев её стать, возжелал и спросил визирей, как её добыть.",
        "Ежелден шетте қалған қырық уәзір достарды айырмақ болды. Жаманның әйелін ханға сонша мақтады, хан келіп көрді — көркін көріп, қызығып, оны қалай алуды уәзірлерден сұрады.")},
      {narr:L("At home, Jaman's wife sat gazing into the great round mirror, marvelling at her own beauty. 'God matches earth with sky,' she teased. 'I am like the moon on its fourteenth night — and you like a lake gone dry, a bucket black with grease.'",
        "Дома жена Жамана сидела перед круглым зеркалом, дивясь своей красе. «Бог сводит землю с небом, — поддразнила она. — Я как луна в четырнадцатую ночь, а ты — как высохшее озеро, как ведро, чёрное от жира».",
        "Үйде Жаманның әйелі дөңгелек айнаға қарап, өз көркіне таңырқап отырды. «Құдай жермен көкті қосады, — деп қалжыңдады. — Мен он төртінші түнгі айдай, ал сен — суы тартылған көлдей, қара майы біткен шелектей».")},
      {dialog:[
        {who:"jaman",em:"warm",line:L("Not so, wife. When Adam left paradise, God offered him three treasures — Grace, Fortune, and Reason. Adam chose Reason. And Grace and Fortune both bowed to it, saying, 'Where Reason does not stand, neither can we.'","Не так, жена. Когда Адам покидал рай, Бог предложил ему три сокровища — Благодать, Счастье и Разум. Адам выбрал Разум. И Благодать со Счастьем склонились пред ним: «Где нет Разума, там нет и нас».","Олай емес, әйел. Адам пейіштен шыққанда, Тәңірі оған үш қазына ұсынды — Қыдыр, Бақыт, Ақыл. Адам Ақылды таңдады. Қыдыр мен Бақыт оған бас иіп: «Ақыл тұрмаған жерде біз де тұрмаймыз» деді.")},
        {who:"jaman",em:"warm",line:L("So you were the red gold in the treasury, and I was Reason. You did not wed my blackness or my age — you wed my mind. And Grace and Fortune came with it.","Так вот: ты была красным золотом в казне, а я — Разумом. Не за черноту мою пошла и не за годы — за ум. А с ним пришли Благодать и Счастье.","Сонымен: сен қазынадағы қызыл алтын едің, мен Ақыл едім. Қаралығыма да, қартлығыма да тиген жоқсың — ақылыма тидің. Онымен бірге Қыдыр мен Бақыт та келді.")},
        {who:"mendi",em:"resolve",line:L("Then let your reason save us now, husband. The khan means to send you to Barsa-kelmes — the place of no return. Go, and agree. But ride the fattest slow horse, not the swiftest. When the viziers turn back, turn back too. Slaughter the horse in the wood, and we will live quietly, out of sight.","Так пусть твой разум и спасёт нас, муж. Хан задумал послать тебя в Барсакелмес — откуда не возвращаются. Ступай и соглашайся. Но возьми жирного тихохода, не резвого. Как визири повернут назад — вернись и ты. Заколи коня в лесу, и будем жить тихо, с глаз долой.","Ендеше ақылың бізді енді құтқарсын, байым. Хан сені Барсакелмеске — қайтпас жерге жұмсамақ. Бар да, келіс. Бірақ жүйрікті емес, семіз аяңшылды мін. Уәзірлер қайтқанда, сен де қайт. Атты орманда сой, көзден таса, тыныш тіршілік етеміз.")}
      ]},
      {narr:L("So the khan sent Jaman after a pearl-fleeced sheep, a duck of gold and silver, and a giant's steed that runs a hundred miles at a gallop — all things that never were. Jaman rode out on a fat horse, turned back when the escort was gone, slaughtered it in the Qaratogai wood, and dug a man-deep pit beneath his bed. By night he lay beside his wife; by day he hid below. A year passed.",
        "И послал хан Жамана за жемчужнорунной овцой, за уткой из золота и серебра, за исполинским конём, что за один скок сто вёрст берёт, — за тем, чего нет и не было. Жаман выехал на жирном коне, повернул назад, как отстала свита, заколол его в лесу Каратогай и выкопал под ложем яму в рост человека. Ночью лежал подле жены, днём таился внизу. Прошёл год.",
        "Сөйтіп хан Жаманды інжулі қой, алтын-күміс үйрек, бір шапқанда жүз шақырым жүретін дәудің арғымағы — жоқ нәрсеге жұмсады. Жаман семіз атпен шықты, шоғыр артта қалғанда қайтты, Қаратоғай орманында сойып, төсек астынан адам бойы шұңқыр қазды. Түнде әйелінің қасында, күндіз астында жатты. Бір жыл өтті.")},
      {narr:L("At last the khan came himself, to 'console the widow' and take her. But she met him with a riddle of her own: 'You once had a precious gem, and split it with its own tongue — and once split, it was worth nothing. So it is with me. My season has passed; I am that broken gem. Trouble yourself no more.' Defeated, the khan went home.",
        "Наконец хан явился сам — «утешить вдову» и взять её. Но она встретила его своей загадкой: «Был у тебя драгоценный камень, и ты расколол его же языком — а раз расколот, ему и цена ничто. Так и со мной. Пора моя минула; я тот разбитый камень. Не утруждай себя». Побеждённый, хан ушёл.",
        "Ақыры хан өзі келді — «жесірді жұбатып», алмаққа. Бірақ ол ханды өз жұмбағымен қарсы алды: «Қасиетті тасың бар еді, оны өз тілімен жардың — жарылған соң түкке тұрмады. Мен де сондаймын. Мезгілім өтті; мен сол жарылған таспын. Әуре болма». Жеңілген хан үйіне қайтты.")},
      {dialog:[
        {who:"jaman",em:"bold",line:L("You look pale, khan. As I rode for Barsa-kelmes a starving lion took my trail, so I drew my sword and chased it — penned it in my own aul, but it slipped free. I wondered if it had run into your palace.","Ты бледен, хан. Как ехал я в Барсакелмес, увязался за мной голодный лев, — я выхватил меч и погнал его, загнал в свой аул, да он вырвался. Вот и думаю: не вбежал ли он в твой дворец?","Өңің қашыпты, хан. Барсакелмеске бара жатқанда, аш арыстан ізіме түсті, қылышымды суырып қудым, ауылыма қамадым, ол шығып кетті. Ордаңа кірген жоқ па деп ойладым.")},
        {who:"khan",em:"hurt",line:L("The fault is mine — I followed the devil's whisper, and these viziers were the devil. Take up your household and move to another land, before they bring ruin on us both.","Виноват я — послушал шёпот беса, а бесом были эти визири. Подними свой дом и уходи в иную землю, пока они не сгубили нас обоих.","Кінә менде — шайтанның азғыруына ердім, шайтан осы уәзірлер еді. Екеумізді де құртпай тұрып, іргеңді көтеріп, өзге елге көш.")}
      ], act:"gift", place:"aksha_steppe"},
      {narr:L("The khan loaded camels with fine things and moved Jaman honourably to the land of Aqsha Khan, where he became a man of worth and respect.",
        "Хан навьючил верблюдов добром и с почётом переселил Жамана в землю Акша-хана, где тот стал человеком уважаемым и достойным.",
        "Хан түйелерге асыл зат артып, Жаманды ардақтап Ақша ханның еліне көшірді; онда ол қадірлі, беделді адам болды.")}
     ]},

   { title:L("Ayaz Bi","Аяз би","Аяз би"), scene:"mountain_pasture",
     obj:L("Answer the old shepherd's riddle and set the viziers straight","Разгадайте загадку старого пастуха и вразумите визирей","Кәрі шопанның жұмбағын шешіп, уәзірлерді түзет"),
     beats:[
      {narr:L("The khan could not forget Jaman. Riding out one day, he met a very old shepherd and spoke to him in riddles — asking how many years since frost touched the mountain's crown, since a spring first ran from its peak, and how many he was. The old man's answers were riddles too, and the khan set them before his viziers on pain of death.",
        "Хан не мог забыть Жамана. Выехав однажды, он встретил древнего пастуха и заговорил загадками — сколько лет, как иней лёг на темя горы, как побежал родник с вершины, и сколько ему самому. Ответы старика тоже были загадками, и хан задал их визирям под страхом смерти.",
        "Хан Жаманды ұмыта алмады. Бірде шығып, кәрі шопанды кездестіріп, жұмбақтап сөйледі — таудың басын қырау шалғалы, шыңынан бұлақ аққалы неше жыл, өзі нешеде деп. Шалдың жауаптары да жұмбақ еді, ханды оларды өлім жазасымен уәзірлерге тапсырды.")},
      {narr:L("The viziers, helpless, came crawling to Jaman. He honoured them, then unrolled the meaning like a carpet. 'The frost on the mountain's crown — that is the white in the old man's hair; the frost at its foot, the white in his beard; the spring from the peak, the tears from his eyes. And when he said, «Lying down we are two, standing up we are four» — he meant his living wife beside him, and the dead spouses each of them still mourns.'",
        "Беспомощные визири приползли к Жаману. Он оказал им честь, а после развернул смысл, как ковёр. «Иней на темени горы — седина в волосах старика; иней у подножья — седина в бороде; родник с вершины — слёзы из глаз. А «лёжа нас двое, стоя четверо» — это живая жена рядом да умершие супруги, о ком каждый ещё тоскует».",
        "Дәрменсіз уәзірлер Жаманға еңбектеп келді. Ол оларды сыйлап, мәнін кілемдей жайды. «Таудың басындағы қырау — шалдың шашындағы ақ; етегіндегі қырау — сақалындағы ақ; шыңнан аққан бұлақ — көзінен аққан жас. Ал «жатқанда екеу, тұрғанда төртеу» — қасындағы тірі әйелі мен әрқайсысы әлі жоқтап жүрген өлген жары».")},
      {dialog:[
        {who:"jaman",em:"wise",line:L("And the khan's last riddle — 'forty pet geese, to be plucked unnoticed, cooked unburnt, and slain without a drop of blood' — that is his forty foolish viziers, and he asks: is there a man who can set them straight without a single blow?","А последняя загадка хана — «сорок ручных гусей, ощипать незаметно, сварить не спалив и заколоть без единой капли крови» — это его сорок глупых визирей, и он спрашивает: есть ли, кто вразумит их, не ударив ни разу?","Ал ханның соңғы жұмбағы — «қырық асыранды қаз, білдірмей жұлып, күйдірмей пісіріп, қан шығармай сою» — оның қырық ақымақ уәзірі, ол сұрайды: соларды бір рет ұрмай түзейтін жан бар ма деп?")}
      ], act:"riddle",
        riddle:{ q:L("What were the khan's 'forty pet geese' truly?","Кто были на деле «сорок ручных гусей» хана?","Ханның «қырық асыранды қазы» шын мәнінде кім еді?"),
          opts:[ {t:L("His forty foolish viziers","Его сорок глупых визирей","Оның қырық ақымақ уәзірі"),ok:true},
                 {t:L("Forty fat geese for the feast","Сорок жирных гусей к пиру","Тойға қырық семіз қаз"),ok:false},
                 {t:L("Forty enemy khans","Сорок вражеских ханов","Қырық жау хан"),ok:false},
                 {t:L("Forty prized horses","Сорок драгоценных коней","Қырық асыл ат"),ok:false} ] }},
      {narr:L("So Jaman had the viziers burn their own robes for firewood ('plucked unnoticed, cooked unburnt') and drove them bare and barefoot before the khan ('slain without blood'). The khan, seeing them humbled at last, forgave them — and understood that no games or feasts had ever eased his heart, because it was Jaman he had missed.",
        "И велел Жаман визирям сжечь на растопку собственные халаты («ощипать незаметно, сварить не спалив») и погнал их нагими и босыми пред хана («заколоть без крови»). Хан, увидев их наконец смирёнными, простил их — и понял, что ни игры, ни пиры не унимали его сердца, ибо тосковал он по Жаману.",
        "Сөйтіп Жаман уәзірлерге өз шапандарын отынға жақтырды («білдірмей жұлып, күйдірмей пісіріп») және оларды жалаңаш, жалаң аяқ ханға айдап апарды («қан шығармай сою»). Хан оларды ақыры басылған күйде көріп кешірді — әрі ешбір ойын-той жүрегін жеңілдетпегенін ұқты, өйткені ол Жаманды сағынған еді.")},
      {dialog:[
        {who:"khan",em:"grateful",line:L("I have been khan long enough, and enjoyed it. The rest of my rule I give to my friend. Come — it is time you took the throne. In the days I have left, let me serve you.","Довольно я был ханом и натешился. Остаток правления отдаю другу. Иди — пора тебе на трон. В оставшиеся дни дай послужить тебе.","Хан болғаным жетер, қызығын да көрдім. Қалған хандығымды досыма беремін. Кел — таққа отырар кезің жетті. Қалған өмірімде саған қызмет етейін.")},
        {who:"jaman",em:"resolve",line:L("Then I take it not for myself, but for the people — that they may find justice. And I will keep something to remember myself by.","Тогда беру его не для себя, а для народа — чтобы находил он правду. И кое-что оставлю себе на память о себе.","Ендеше оны өзім үшін емес, халық үшін аламын — әділдік тапсын деп. Әрі өзімді есте сақтайтын бір нәрсе қалдырамын.")}
      ], place:"khan_orda"},
      {narr:L("They raised Jaman on a white felt as khan, with thirty days of games and forty days of feasting. And the first thing the new ruler did was nail his old torn coat and fur hat above the palace door.",
        "Подняли Жамана на белом войлоке ханом — с тридцатью днями игр и сорока днями пира. И первое, что сделал новый правитель, — прибил над дверью дворца свою старую драную шубу и тымак.",
        "Жаманды ақ киізге салып хан көтерді — отыз күн ойын, қырық күн той. Жаңа билеушінің алғаш істегені — сарай есігінің үстіне ескі жыртық тоны мен тымағын қағу болды."), act:"puzzle"},
      {dialog:[
        {who:"jaman",em:"wise",line:L("Whenever my heart begins to swell, I look up at these rags and say: Hey, Ayaz — do not swell because you are rich, do not strut because you are khan. Know your measure; ant, know your path.","Как начнёт сердце заноситься, гляну на эти лохмотья и скажу: эй, Аяз, — не пыжься, что богат, не заносись, что хан. Знай свою меру; муравей, знай свою тропу.","Көңілім аси бастаған сайын, мына шүберекке қарап: Ай, Аяз, баймын деп аспа, ханмын деп таспа. Әліңді біл; құмырсқа жолыңды біл, деймін.")}
      ]}
     ]}
  ]},
 khan:{
  ending:{ title:L("The Khan Who Learned His Measure","Хан, узнавший свою меру","Әліңді білген хан"),
    text:L("You set out to find the worst of men, and found instead the wisest — and a mirror held up to your throne, your blood and your envious heart. It cost you your crown to learn it, but you learned it gladly: that a true khan is measured not by his ancestors, but by the justice he keeps. You gave your throne to your friend, and served him to the end of your days, the happiest servant on the steppe.",
      "Ты вышел искать худшего из людей, а нашёл мудрейшего — и зеркало, поднесённое к трону, крови и завистливому сердцу. Это стоило тебе венца, но ты научился с радостью: истинный хан меряется не предками, а правдой, которую хранит. Ты отдал трон другу и служил ему до конца дней — счастливейший слуга в степи.",
      "Адамның жаманын іздеп шығып, ең дананы таптың — әрі тағыңа, тегіңе, қызғаныш жүрегіңе тосылған айнаны. Мұны білу тәжіңе түсті, бірақ қуана үйрендің: шын хан ата-тегімен емес, сақтаған әділдігімен өлшенеді. Тағыңды досыңа беріп, өмір бойы қызмет еттің — даладағы ең бақытты қызметші болып.") },
  chapters:[
   { title:L("The Impossible Errand","Невыполнимое поручение","Орындалмас тапсырма"), scene:"khan_orda",
     obj:L("Send your forty viziers after the worst on earth","Пошлите сорок визирей за худшим на свете","Қырық уәзірді дүниедегі ең жаманды іздеуге жұмса"),
     beats:[
      {narr:L("You are Khan Madan, master of a great steppe and forty wise viziers. To test their famous cleverness, you set them a strange errand: bring back the worst of all men, the worst of all plants, and the worst of all birds — in eleven months, on pain of punishment.",
        "Ты хан Мадан, владыка великой степи и сорока мудрых визирей. Чтобы испытать их хвалёный ум, ты даёшь им странное поручение: доставить худшего из людей, худшую траву и худшую птицу — за одиннадцать месяцев, под страхом кары.",
        "Сен Мадан хансың, ұлы дала мен қырық дана уәзірдің иесі. Олардың атақты ақылын сынау үшін оғаш тапсырма бересің: адамның, шөптің, құстың жаманын әкел — он бір айда, жаза қаупімен.")},
      {dialog:[
        {who:"khan",em:"bold",line:L("You are the sharpest minds in my khanate. So find me the worst the world can offer — and learn what worth even the worthless may hide.","Вы — острейшие умы моего ханства. Так сыщите мне худшее, что есть на свете, — и узнайте, какая ценность таится даже в никчёмном.","Сендер — хандығымдағы ең өткір ақыл. Ендеше дүниедегі ең жаманды тауып келіңдер — түкке тұрғысыздың да қандай құны бар екенін біліңдер.")},
        {who:"vizier",em:"worried",line:L("As you command, great khan... though where a man might find the very worst of everything, only heaven knows.","Как велишь, великий хан... хотя где сыскать худшее из всего — одному небу ведомо.","Әмірің бойынша, ұлы хан... бірақ бәрінің ең жаманын қайдан табарын бір Тәңірі біледі.")}
      ]},
      {narr:L("Eleven months later they return — with reed-mace, a magpie, and a poor herdsman in a torn coat who calls himself the worst of men. You send the ragged stranger off to the kitchen and turn, frowning, on your viziers.",
        "Через одиннадцать месяцев они возвращаются — с рогозом, сорокой и бедным пастухом в драной шубе, что зовёт себя худшим из людей. Оборванца ты отправляешь на кухню и, хмурясь, оборачиваешься к визирям.",
        "Он бір айдан соң олар оралады — қарақоға, сауысқан және өзін адамның жаманымын дейтін жыртық тонды кедей шопанмен. Жыртық киімдіні ас үйге жіберіп, қабағыңды түйіп, уәзірлеріңе бұрыласың.")}
     ]},
   { title:L("The Man Who Cannot Be Fooled","Тот, кого не провести","Алдана алмайтын жан"), scene:"river_ford",
     obj:L("Test the ragged stranger with horse and jewel","Испытайте оборванца конём и самоцветом","Жыртық киімдіні ат пен гауһармен сына"),
     beats:[
      {narr:L("The beggar's answers unsettle you — reed-mace worse than thorn, the magpie worse than the pheasant, each argued so well you cannot fault it. So you test him harder: your prized tulpar, and your most secret jewel.",
        "Ответы нищего смущают тебя — рогоз хуже колючки, сорока хуже фазана, и всё так доказано, что не возразишь. И ты испытываешь строже: драгоценным тулпаром и самым тайным самоцветом.",
        "Қайыршының жауаптары мазаңды алады — қарақоға шеңгелден жаман, сауысқан қырғауылдан жаман, бәрі дәлелденген, қарсы дау таппайсың. Сондықтан қаттырақ сынайсың: асыл тұлпарың мен ең құпия гауһарыңмен.")},
      {dialog:[
        {who:"jaman",em:"wise",line:L("A fine tulpar, khan — but raised on the milk of a cow. And your jewel is true, yet two worms have hollowed it; two years, and its power is gone.","Славный тулпар, хан, — да вскормлен коровьим молоком. И самоцвет твой истинный, только два червя выели его; два года — и силе конец.","Жақсы тұлпар, хан — бірақ сиыр сүтімен өскен. Гауһарың да шын, бірақ екі құрт ішін кеміріпті; екі жыл — қасиеті бітеді.")},
        {who:"khan",em:"waking",line:L("Both true — every word! Who are you, that a single glance tells you what my wisest men never saw? You are no beggar. You are a sage.","И то, и другое — правда, до слова! Кто ты, что одним взглядом видишь незримое моим мудрецам? Ты не нищий. Ты мудрец.","Екеуі де — рас, әр сөзі! Кімсің сен, бір қараумен данамдар көрмегенді көресің? Сен қайыршы емессің. Сен данасың.")}
      ]},
      {dialog:[
        {who:"khan",em:"resolve",line:L("Then answer the hardest thing of all. Look at me, khan of seven generations — and tell me what you see.","Тогда ответь на труднейшее. Взгляни на меня, хана в седьмом колене, — и скажи, что видишь.","Ендеше ең қиынына жауап бер. Жеті атадан хан — маған қара да, не көргеніңді айт.")}
      ], act:"riddle",
        riddle:{ q:L("What lets Jaman read a horse, a jewel — or a man — at a glance?","Что позволяет Жаману с одного взгляда прочесть коня, самоцвет — или человека?","Жаманға атты, гауһарды — я адамды бір қараумен тануға не мүмкіндік береді?"),
          opts:[ {t:L("Each thing betrays its true nature in the smallest sign","Всё выдаёт свою суть в мельчайшем знаке","Әр нәрсе шын болмысын ең кішкене белгіден танытады"),ok:true},
                 {t:L("Magic given to him by spirits","Волшебство, данное духами","Әруақтар берген сиқыр"),ok:false},
                 {t:L("Pure luck and bold guessing","Чистое везение и смелые догадки","Таза сәттілік пен батыл болжам"),ok:false},
                 {t:L("Secret whispers from the viziers","Тайные подсказки визирей","Уәзірлердің құпия сыбыры"),ok:false} ] }}
     ]},
   { title:L("The Mirror to My Blood","Зеркало моей крови","Тегіме тосылған айна"), scene:"khan_orda",
     obj:L("Hear the truth of your own birth","Услышьте правду о своём рождении","Өз тегіңнің шындығын есті"),
     beats:[
      {dialog:[
        {who:"jaman",em:"resolve",line:L("Your mind is second to none, khan. But no khan stands behind your throne. You were born common — you are the son of a baker.","Ум твой никому не уступит, хан. Но за троном твоим нет ханов. Ты рождён простолюдином — ты сын пекаря.","Ақылың ешкімнен кем емес, хан. Бірақ тағыңның артында хан жоқ. Қарадан туғансың — наубайдың баласысың.")},
        {who:"khan",em:"fierce",line:L("Bring my mother! Let her swear before heaven — and if this man lies, his head answers for it.","Позовите мать! Пусть поклянётся пред небом — а солгал этот человек, ответит головой.","Шешемді әкел! Тәңірі алдында ант етсін — бұл адам өтірік айтса, басымен жауап береді.")}
      ]},
      {dialog:[
        {who:"mother",em:"tears",line:L("Forgive me, my son. Your father, Zarly Khan, slew nineteen wives for bearing daughters. Carrying a girl, and in fear for my life, I traded you as a newborn for the baker's son. The child I raised as khan was that baker's boy — was you.","Прости, сын. Отец твой, Зарлы-хан, убил девятнадцать жён за дочерей. Нося девочку и в страхе за жизнь, я обменяла тебя-младенца на сына пекаря. Дитя, что растила ханом, — тот пекарев сын — это ты.","Кешір, балам. Әкең Зәрлі хан қыз тапқаны үшін он тоғыз әйелді өлтірген. Қыз көтеріп, жанымнан қорқып, сені нәресте күнінде наубайдың ұлына айырбастадым. Хан қылып өсірген балам — сол наубайдың ұлы — сен едің.")},
        {who:"khan",em:"empty",line:L("A lifetime a khan — and the throne was never mine. Take it, wise one. You saw the truth; you have the right.","Всю жизнь хан — а трон и не был моим. Возьми его, мудрец. Ты узрел правду — тебе и право.","Өмір бойы хан — ал тақ менікі болмаған екен. Ал, дана, оны ал. Шындықты көрдің — хақың бар.")},
        {who:"jaman",em:"gentle",line:L("Keep your throne, khan. Yesterday I rode in behind a horse. I ask only to walk in your shadow. I knew your blood by one small thing — you fed a guest soup and bread, and sent him to the kitchen. Blood keeps its old habits.","Оставь трон, хан. Вчера я въехал позади коня. Прошу лишь идти в твоей тени. Кровь твою я узнал по малости: гостю подал похлёбку с хлебом и спровадил на кухню. Кровь хранит старые привычки.","Тағыңды сақта, хан. Кеше ат артында келдім. Тек көлеңкеңде жүруді сұраймын. Тегіңді бір кішкене нәрседен таныдым: қонаққа көже мен нан беріп, ас үйге жібердің. Тек ескі әдетін сақтайды.")}
      ]}
     ]},
   { title:L("The Envy of Small Men","Зависть мелких людей","Кіші жандардың қызғанышы"), scene:"jaman_yurt",
     obj:L("Resist the viziers' whispers — or pay the price","Устоите перед шёпотом визирей — или заплатите","Уәзірлердің сыбырына төтеп бер — әйтпесе төле"),
     beats:[
      {narr:L("Your forty viziers, jealous of the friend who eclipsed them, whisper poison. They praise Jaman's wife until you go to see her — and the old greed stirs. They urge you: send him to Barsa-kelmes, the land of no return, and take the widow.",
        "Сорок визирей, завидуя другу, что затмил их, шепчут отраву. Они хвалят жену Жамана, пока ты не идёшь взглянуть, — и старая жадность просыпается. Они подбивают: пошли его в Барсакелмес, откуда нет возврата, и возьми вдову.",
        "Қырық уәзірің, өздерін көлегейлеген досқа қызғанып, у сыбырлайды. Жаманның әйелін мақтап, көруге барасың — ескі сараңдық оянады. Олар айдайды: оны Барсакелмеске — қайтпас жерге жұмса, жесірді ал.")},
      {dialog:[
        {who:"vizier",em:"cool",line:L("Send him for the pearl-fleeced sheep and the giant's steed, great khan. No man returns from Barsa-kelmes. The rest... will follow of itself.","Пошли его за жемчужнорунной овцой да исполинским конём, великий хан. Из Барсакелмеса не возвращаются. Остальное... сложится само.","Оны інжулі қой мен дәудің тұлпарына жұмса, ұлы хан. Барсакелместен ешкім қайтпайды. Қалғаны... өзі-ақ реттеледі.")},
        {who:"khan",em:"worried",line:L("...And if I am wrong to do it? A crown does not make a theft a gift.","...А если я неправ? Венец не превращает кражу в дар.","...Ал бұл қате болса ше? Тәж ұрлықты сыйға айналдырмайды.")}
      ]},
      {narr:L("You send Jaman away on the errand — but a year on, when you go to claim his wife, she meets you with a riddle sharper than any blade: 'You split your own gem with your own tongue, and it was worth nothing after. I am that broken gem now.' You leave defeated. And then Jaman himself walks in, alive, with a sly tale of a lion — and you understand you have been outmatched, and shamed.",
        "Ты отсылаешь Жамана — но через год, придя за женой, встречаешь загадку острее клинка: «Ты сам расколол свой камень своим языком, и после ему цена — ничто. Я и есть теперь тот разбитый камень». Уходишь побеждённым. А после входит сам Жаман, живой, с лукавой сказкой про льва, — и ты понимаешь, что переигран и посрамлён.",
        "Жаманды жұмсайсың — бірақ бір жылдан соң әйеліне келгенде, қылыштан өткір жұмбақ қарсы алады: «Тасыңды өз тілімен өзің жардың, содан кейін түкке тұрмады. Мен енді сол жарылған таспын». Жеңіліп кетесің. Сосын Жаманның өзі тірі кіріп келеді, арыстан жайлы қу әңгімемен — ұтылғаныңды, ұялғаныңды ұғасың.")},
      {dialog:[
        {who:"khan",em:"hurt",line:L("The fault is mine, my friend — I followed the devil, and the devil was these viziers. Take your household to Aqsha Khan's land in honour, before they ruin us both.","Виноват я, друг, — я послушал беса, а бесом были визири. Уходи с почётом в землю Акша-хана, пока они не сгубили нас обоих.","Кінә менде, досым — шайтанға ердім, шайтан осы уәзірлер еді. Екеумізді құртпай тұрып, Ақша ханның еліне ардақпен көш.")},
        {who:"jaman",em:"gentle",line:L("I hold nothing against you, khan. A good heart can lose its way — what matters is that it finds the road home.","Ничего не держу на тебя, хан. Доброе сердце может сбиться — важно, что находит дорогу домой.","Саған кегім жоқ, хан. Жақсы жүрек адасуы мүмкін — бастысы — үйге жолды табуы.")}
      ], act:"gift", place:"aksha_steppe"},
      {narr:L("But the days without him are grey. No feast eases you; you miss his counsel like a lost limb. At last you ride to his new home, take him by the arm, and give him the throne in truth — content, for the rest of your life, to serve the wisest man you ever knew.",
        "Но дни без него серы. Ни пир не радует; ты тоскуешь по его совету, как по потерянной руке. Наконец ты едешь к нему, берёшь под руку и вправду отдаёшь трон — счастливый весь остаток дней служить мудрейшему из людей.",
        "Бірақ онсыз күндер сұр. Ешбір той жұбатпайды; кеңесін жоғалған қолдай сағынасың. Ақыры үйіне барып, қолтығынан алып, тақты шынымен бересің — қалған өміріңде білген ең дана жанға қызмет етуге риза болып.")}
     ]}
  ]},

 mendi:{
  ending:{ title:L("Wiser Than a Kingdom","Мудрее целого царства","Бүкіл елден ақылды"),
    text:L("For twenty years you turned away the rich and the proud, waiting for a mind to match your own — and when at last you found it in a ragged herdsman, you rode through the night in a white veil to cut him down from the gallows and set him free. You became the wife of Ayaz Bi the Just, and the answer that saved you both — the riddle of the broken gem — is still told on the steppe, wherever a woman is reckoned wiser than the men who underestimated her.",
      "Двадцать лет ты отваживала богатых и гордых, ожидая ума под стать своему, — а найдя его наконец в оборванном пастухе, поскакала в ночи под белым покрывалом срезать его с виселицы и освободить. Ты стала женой Аяз би Справедливого, и ответ, что спас вас обоих, — загадка разбитого камня — всё ещё сказывают в степи, где женщину чтут мудрее недооценивших её мужчин.",
      "Жиырма жыл байлар мен тәкаппарларды қайтарып, өзіңдей ақылды күттің — ақыры оны жыртық киімді шопаннан тауып, түнде ақ пердемен шауып, оны дардан кесіп, азат еттің. Әділ Аяз бидің әйелі болдың, ал екеуіңді құтқарған жауап — жарылған тас жұмбағы — даланы кезеді, әйелді өзін бағаламаған еркектерден ақылды деп таныған жерде.") },
  chapters:[
   { title:L("The Suitors at the Door","Женихи у порога","Есік алдындағы күйеулер"), scene:"mendi_yurt",
     obj:L("Turn away the fools with your silent riddle","Отвадите глупцов немой загадкой","Ақымақтарды үнсіз жұмбақпен қайтар"),
     beats:[
      {narr:L("You are Mendi, daughter of the rich Uälibai. From the age of fifteen you have chosen suitors by one vow: you will wed only a man wiser than yourself. Twenty years on, you are thirty-five, and still no suitor has passed your test.",
        "Ты Менди, дочь богача Уалибая. С пятнадцати лет ты выбираешь женихов по одному обету: выйдешь лишь за того, кто мудрее тебя. Двадцать лет спустя тебе тридцать пять, и ни один жених ещё не прошёл испытания.",
        "Сен Мендісің, бай Уәлібайдың қызысың. Он бес жасыңнан бір антпен күйеу таңдайсың: өзіңнен ақылдыға ғана тиесің. Жиырма жыл өтті, отыз бестесің, ешбір күйеу сынағыңнан өтпеді.")},
      {dialog:[
        {who:"zhenge",em:"gossip",line:L("Rich men's sons, khans' sons — all come, all leave in a huff. 'Have I no knife at home? No gem?' they cry. They never once ask what the gifts mean!","Сыновья богачей, сыновья ханов — все приходят, все уходят в сердцах. «Что, у меня ножа нет? Самоцвета?» — кричат. И ни разу не спросят, что дары значат!","Байдың балалары, ханның балалары — бәрі келіп, бәрі ашуланып кетеді. «Үйімде пышақ жоқ па? Гауһар жоқ па?» дейді. Сыйдың мәнін бірде-бірі сұрамайды!")},
        {who:"mendi",em:"calm",line:L("Let them go. A man who cannot read four small things will never read my heart. I would rather wait alone than wed a fool.","Пусть уходят. Кто не прочтёт четырёх мелочей, не прочтёт и сердца моего. Лучше ждать одной, чем идти за глупца.","Кете берсін. Төрт кішкене затты оқи алмаған жан жүрегімді де оқымайды. Ақымаққа тигенше жалғыз күткенім артық.")}
      ]}
     ]},
   { title:L("The One Who Answered","Тот, кто ответил","Жауап берген жан"), scene:"mendi_yurt",
     obj:L("Recognise the mind you have waited for","Узнайте ум, которого ждали","Күткен ақылыңды таны"),
     beats:[
      {narr:L("One night a ragged man comes — no beard, no horse, no wealth. You send out your four gifts as always: a whetstone, a plate, a knife, a gem. But this one asks for a hammer and anvil, and sends them back transformed: whetstone ground to dust, plate in shards, knife snapped, gem split clean in two.",
        "Однажды ночью приходит оборванец — без бороды, без коня, без гроша. Ты выносишь, как всегда, четыре дара: точило, тарелку, нож, самоцвет. Но этот просит молот и наковальню и возвращает их иными: точило в пыль, тарелка вдребезги, нож сломан, самоцвет расколот надвое.",
        "Бір түні жыртық киімді келеді — сақалсыз, атсыз, дәулетсіз. Әдеттегідей төрт сыйды шығарасың: қайрақ, тәрелке, пышақ, гауһар. Бірақ бұл балға мен төс сұрап, оларды өзгертіп қайтарады: қайрақ күлге, тәрелке уатылып, пышақ сынып, гауһар қақ бөлініп.")},
      {dialog:[
        {who:"mendi",em:"waking",line:L("He understood! Ground like the whetstone, broken like the plate, beheaded like the knife — he will keep my secret to the death, and split fate itself like the gem to win me. If he is flesh and not a devil, he is mine. Call him in!","Он понял! Стёрт, как точило, разбит, как тарелка, обезглавлен, как нож, — он до смерти сохранит мою тайну и расколет саму судьбу, как самоцвет, чтобы добыть меня. Коли он плоть, а не бес, — он мой. Зовите!","Түсінген! Қайрақтай езіліп, тәрелкедей уатылып, пышақтай басы кесіліп — сырымды өлгенше сақтайды, тағдырды гауһардай жарып, мені алады. Ол шайтан емес, адам болса — менікі. Шақыр!")},
        {who:"zhenge",em:"hope",line:L("Twenty years, mistress — and it is the beardless beggar who wins you, not the khans! Truly the world is upside down, and rightly so.","Двадцать лет, госпожа, — и добыл тебя безбородый нищий, не ханы! Право, мир перевернулся — и поделом.","Жиырма жыл, бикеш — сені сақалсыз қайыршы алды, хан емес! Шынымен әлем аударылды — әбден дұрыс болды.")}
      ], act:"riddle",
        riddle:{ q:L("Why did you set your suitors a riddle of four small things?","Зачем ты задавала женихам загадку из четырёх мелочей?","Күйеулерге неге төрт кішкене заттан жұмбақ бердің?"),
          opts:[ {t:L("To find a mind, not a purse or a sword","Найти ум, а не кошель и не меч","Ақылды табу үшін — әмиян мен қылыш емес"),ok:true},
                 {t:L("To find the richest man of all","Найти богатейшего из всех","Ең байды табу үшін"),ok:false},
                 {t:L("To find the strongest warrior","Найти сильнейшего воина","Ең күшті батырды табу үшін"),ok:false},
                 {t:L("To delay marrying for as long as I could","Оттянуть замужество как можно дольше","Тұрмысқа шығуды мүмкіндігінше кейінге қалдыру"),ok:false} ] }}
     ]},
   { title:L("The Veiled Rider","Всадница под покрывалом","Перделі салт атты"), scene:"town_square",
     obj:L("Ride to save the innocent man from the rope","Скачите спасти невинного от петли","Кінәсіз жанды дардан құтқаруға шап"),
     beats:[
      {narr:L("Your suspicious brothers set a guard, and at dawn they seize the man leaving your yurt and drag him to the khan. Bound by his silent vow to you, he denies everything — even as the khan, enraged, condemns him to hang. Word reaches you as they lead him to the square.",
        "Подозрительные братья ставят дозор и на рассвете хватают человека, выходящего из юрты, и волокут к хану. Связанный немым обетом тебе, он всё отрицает — а хан в гневе велит его повесить. Весть доходит до тебя, когда его ведут на площадь.",
        "Күдікшіл ағаларың қарауыл қойып, таң ата киіз үйден шыққан адамды ұстап, ханға сүйрейді. Саған берген үнсіз антымен байланып, ол бәрін терістейді — хан ашумен дарға бұйырады. Оны алаңға апарғанда, хабар саған жетеді.")},
      {cine:[
        {narr:L("You will not let a man die innocent for your secret. You throw a white veil over your face, mount a white horse, and ride like the wind for the square.","Ты не дашь человеку умереть безвинно за твою тайну. Набросив на лицо белое покрывало, вскочив на белого коня, ты летишь к площади, как ветер.","Адамды сырың үшін жазықсыз өлтіртпейсің. Бетіңе ақ перде жауып, ақ атқа мініп, алаңға желдей ұшасың."), cam:"up", fx:"gleam", wind:true, wait:2800},
        {narr:L("You reach the gallows as his breath fails, cut the rope with one stroke of your sword, lay the blade flat across his chest — a sign that his oath is released upon a blade — and vanish before any can see your face.","Ты успеваешь к виселице, когда дыхание его гаснет, единым махом рассекаешь верёвку, кладёшь клинок поперёк груди — знак, что клятва снята на лезвии, — и исчезаешь, прежде чем кто-либо увидит лицо.","Демі бітерде дарға жетіп, жіпті бір шауып кесесің, қылышты кеудесіне көлденең қоясың — анты қылыш үстінде шешілгенінің белгісі — әрі бетіңді ешкім көрместен ғайып боласың."), cam:[0,-4,1.2,2.4], fx:"gleam", wait:3200}
      ]},
      {dialog:[
        {who:"mendi",em:"tears",line:L("Do not die innocent for my sake. I have seen your courage — it is answer enough. A vow holds no power over a blade: I give you back your oath. Now live, and speak the truth.","Не умирай безвинно за меня. Я видела твою отвагу — этого довольно. Над клинком клятва не властна: возвращаю тебе твой обет. Живи же и говори правду.","Мен үшін жазықсыз өлме. Ерлігіңді көрдім — сол жеткілікті. Қылыш үстінде ант жүрмейді: сертіңді қайтарамын. Енді өмір сүр де, шындықты айт.")}
      ]},
      {narr:L("Freed of his vow, the man tells the khan all — and the khan, seeing the truth and the love in it, joins you together with thirty days of games and forty of feasting. You have chosen well: not the richest, not the strongest, but the wisest and truest man on the steppe.",
        "Освобождённый от обета, он рассказывает хану всё — и хан, увидев правду и любовь, соединяет вас тридцатью днями игр и сорока днями пира. Ты выбрала верно: не богатейшего, не сильнейшего, а мудрейшего и вернейшего в степи.",
        "Анттан босаған ол ханға бәрін айтады — хан шындық пен махаббатты көріп, отыз күн ойын, қырық күн тоймен қосады. Дұрыс таңдадың: ең байды емес, ең күштіні емес, даладағы ең дана әрі адал жанды.")}
     ]},
   { title:L("The Broken Gem","Разбитый самоцвет","Жарылған гауһар"), scene:"jaman_yurt",
     obj:L("Outwit the khan who covets you","Перехитрите хана, что возжелал тебя","Саған қызыққан ханды алда"),
     beats:[
      {narr:L("Envious viziers turn the khan's eye to you, and he sends your husband to the deadly errand of Barsa-kelmes. But you have foreseen it. You hide Jaman in a pit beneath the bed, and wait. A year later the khan comes to take the 'widow' — and you meet him with the sharpest riddle of your life.",
        "Завистливые визири обращают взор хана к тебе, и он шлёт мужа на гибельное поручение в Барсакелмес. Но ты это предвидела. Ты прячешь Жамана в яме под ложем и ждёшь. Через год хан приходит за «вдовой» — и ты встречаешь его острейшей загадкой в жизни.",
        "Қызғаншақ уәзірлер ханның көзін саған салады, ол күйеуіңді Барсакелместің өлім тапсырмасына жұмсайды. Бірақ сен мұны алдын ала сездің. Жаманды төсек астындағы шұңқырға жасырып, күтесің. Бір жылдан соң хан «жесірді» алмаққа келеді — оны өміріңдегі ең өткір жұмбақпен қарсы аласың.")},
      {dialog:[
        {who:"khan",em:"alluring",line:L("Your husband will not return, and I would not leave you alone and disgraced. Come — be a khan's wife, and want for nothing.","Муж твой не вернётся, а я не оставлю тебя одну в бесчестье. Пойдём — будь женой хана и не знай нужды.","Күйеуің қайтпайды, ал мен сені жалғыз, қорлықта қалдырмаймын. Жүр — ханның әйелі бол, мұқтаждық көрме.")},
        {who:"mendi",em:"cool",line:L("You once had a precious gem, khan, and split it with its own tongue — and once split, it was worth nothing to you. Everything has its season. In my maiden days, perhaps. But now I am that broken gem. Do not trouble yourself.","Был у тебя, хан, драгоценный камень, и ты расколол его же языком — а раз расколот, он тебе уж ничто. Всему свой срок. В девичестве — быть может. А ныне я и есть тот разбитый камень. Не утруждайся.","Қасиетті тасың бар еді, хан, оны өз тілімен жардың — жарылған соң саған түкке тұрмады. Бәрінің мезгілі бар. Қыз күнімде — бәлкім. Ал қазір мен сол жарылған таспын. Әуре болма.")}
      ]},
      {narr:L("The khan leaves defeated. That is your signal — you send your husband out to face him, and Jaman's tale of the 'hungry lion' shames the khan into repentance. He moves you both, richly and with honour, to a new land. There your husband's wisdom rises at last to the throne, and you become the wife of Ayaz Bi the Just.",
        "Хан уходит побеждённым. Это твой знак — ты выпускаешь мужа навстречу, и сказка Жамана о «голодном льве» стыдит хана до раскаяния. Он с почётом и щедро переселяет вас в новую землю. Там мудрость мужа восходит наконец к трону, и ты становишься женой Аяз би Справедливого.",
        "Хан жеңіліп кетеді. Бұл — сенің белгің; күйеуіңді қарсы шығарасың, Жаманның «аш арыстан» әңгімесі ханды өкінішке дейін ұялтады. Ол екеуіңді ардақпен, молынан жаңа елге көшіреді. Онда күйеуіңнің даналығы ақыры таққа көтеріледі, сен Әділ Аяз бидің әйелі боласың.")}
     ]}
  ]}
};
