const ALTYN_RELICS = {
  golden_saqa:{name:alt("The Golden Knucklebone"),lore:alt("An anklebone of pure gold, the boy's dearest toy — and the bait his father was forced to leave behind on the old camping-ground.")},
  tulpar:{name:alt("The Tulpar"),lore:alt("A mangy little colt that no one wanted; bridled, saddled and mounted, it became a winged steed of legend that crossed the steppe in the blink of an eye.")},
  iron_tooth:{name:alt("The Iron Tooth"),lore:alt("The Jalmauyz Kempir tore out her own iron teeth to hurl at the fleeing colt and to dig at the root of the great poplar — one by one, until only a single tooth was left.")},
  hero_bow:{name:alt("The Boy's Bow"),lore:alt("A small horn bow the boy never forgot to carry. When even the five hounds could not stop the crone's daughter, two arrows from it ended the danger for good.")}
};

